#[derive(Clone, Debug, Default, PartialEq)]
pub struct RuntimeData {
    pub tables: Vec<RuntimeTable>,
    pub table_diagnostics: Vec<RuntimeTableDiagnostic>,
    pub table_selections: Vec<RuntimeTableSelection>,
    pub table_transforms: Vec<RuntimeTableTransform>,
    pub sample_tables: Vec<RuntimeSampleTable>,
    pub case_manifests: Vec<RuntimeCaseManifest>,
    pub time_axes: Vec<RuntimeTimeAxis>,
    pub timeseries_coverage: Vec<RuntimeTimeSeriesCoverage>,
    pub timeseries_fill: Vec<RuntimeTimeSeriesFill>,
    pub timeseries_quality: Vec<RuntimeTimeSeriesQuality>,
    pub time_series: Vec<RuntimeTimeSeries>,
    pub structured_reads: Vec<RuntimeStructuredRead>,
    pub db_connections: Vec<RuntimeDbConnection>,
    pub numeric_values: Vec<RuntimeNumericValue>,
    pub statistics: Vec<RuntimeStatistics>,
    pub integrations: Vec<RuntimeIntegration>,
    pub timeseries_uncertainty_calculations: Vec<RuntimeTimeSeriesUncertaintyCalculation>,
    pub uncertainties: Vec<RuntimeUncertainty>,
    pub ml_artifacts: Vec<RuntimeMlArtifact>,
    pub policy_results: Vec<RuntimePolicyResult>,
    pub system_solutions: Vec<RuntimeSystemSolution>,
    pub component_solutions: Vec<RuntimeComponentSolution>,
    pub metrics: Vec<RuntimeMetric>,
    pub validations: Vec<RuntimeValidation>,
    pub expectation_suites: Vec<RuntimeExpectationSuite>,
    pub quality_results: Vec<RuntimeQualityResult>,
    pub time_alignments: Vec<RuntimeTimeAlignment>,
    pub plot_options: PlotOptions,
}

#[derive(Clone, Debug, Default, PartialEq)]
pub struct RuntimeDbConnection {
    pub binding: String,
    pub path: String,
    pub table_count: usize,
    pub row_count: usize,
    pub tables: Vec<RuntimeDbTableSummary>,
    pub status: String,
    pub line: usize,
}

#[derive(Clone, Debug, Default, PartialEq)]
pub struct RuntimeDbTableSummary {
    pub name: String,
    pub row_count: usize,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub enum RuntimeJsonValue {
    Null,
    Bool,
    Number,
    String,
    Array,
    Object,
}

impl RuntimeJsonValue {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Null => "null",
            Self::Bool => "bool",
            Self::Number => "number",
            Self::String => "string",
            Self::Array => "array",
            Self::Object => "object",
        }
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub enum RuntimeTomlValue {
    String,
    Integer,
    Float,
    Boolean,
    Datetime,
    Array,
    Table,
}

impl RuntimeTomlValue {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::String => "string",
            Self::Integer => "integer",
            Self::Float => "float",
            Self::Boolean => "boolean",
            Self::Datetime => "datetime",
            Self::Array => "array",
            Self::Table => "table",
        }
    }
}

