impl RuntimeSystemSolution {
    pub fn from_solver_result(
        system: &eng_compiler::SystemInfo,
        binding: Option<&str>,
        state: &eng_compiler::SystemVariableInfo,
        solver_result: &SolverResult,
        reason: &str,
    ) -> Option<Self> {
        let trajectory = solver_result.single_state()?;
        Self::from_solver_trajectory(system, binding, state, solver_result, trajectory, reason)
    }

    pub fn from_solver_trajectory(
        system: &eng_compiler::SystemInfo,
        binding: Option<&str>,
        state: &eng_compiler::SystemVariableInfo,
        solver_result: &SolverResult,
        trajectory: &StateTrajectory,
        reason: &str,
    ) -> Option<Self> {
        let canonical_initial_value = trajectory.initial_value()?;
        let canonical_final_value = trajectory.final_value()?;
        let points = trajectory
            .time_value_points(&solver_result.time_grid)
            .into_iter()
            .map(|(x, value)| RuntimePoint {
                x,
                y: display_variable_value(value, state),
            })
            .collect::<Vec<_>>();

        Some(Self {
            system: system.name.clone(),
            binding: binding.map(str::to_owned),
            status: solver_result.diagnostics.status.clone(),
            method: solver_result.plan.options.method.clone(),
            reason: reason.to_owned(),
            states: solver_result.plan.simulation.states.clone(),
            algebraic_variables: system_variable_names_by_role(system, "algebraic"),
            inputs: solver_result.plan.simulation.inputs.clone(),
            parameters: solver_result.plan.simulation.parameters.clone(),
            outputs: solver_result.plan.simulation.outputs.clone(),
            source_equations: Vec::new(),
            state: trajectory.name.clone(),
            quantity_kind: trajectory.quantity_kind.clone(),
            display_unit: state.display_unit.clone(),
            canonical_unit: trajectory.canonical_unit.clone(),
            time_unit: solver_result.time_grid.unit.clone(),
            duration_s: solver_result.time_grid.duration_s,
            time_step_s: solver_result.time_grid.timestep_s,
            step_count: solver_result.time_grid.step_count,
            tolerance: solver_result.diagnostics.tolerance,
            max_iterations: solver_result.diagnostics.max_iterations,
            iteration_count: solver_result.diagnostics.iteration_count,
            convergence_status: solver_result.diagnostics.convergence_status.clone(),
            failure_code: solver_result
                .diagnostics
                .failure
                .as_ref()
                .map(|failure| failure.code.clone()),
            failure_reason: solver_result
                .diagnostics
                .failure
                .as_ref()
                .map(|failure| failure.message.clone()),
            initial_value: display_variable_value(canonical_initial_value, state),
            final_value: display_variable_value(canonical_final_value, state),
            canonical_initial_value,
            canonical_final_value,
            step_diagnostics: Vec::new(),
            points,
        })
    }

    pub fn failed_from_solver_failure(
        system: &eng_compiler::SystemInfo,
        binding: Option<&str>,
        state: &eng_compiler::SystemVariableInfo,
        solver_input: &SolverInput,
        failure: &SolverFailure,
        reason: &str,
    ) -> Option<Self> {
        let canonical_initial_value = solver_input
            .state_layout
            .index_of(&state.name)
            .and_then(|index| solver_input.initial_state.get(index).copied())
            .or_else(|| canonical_variable_value(state))
            .unwrap_or(0.0);
        let initial_value = display_variable_value(canonical_initial_value, state);

        Some(Self {
            system: system.name.clone(),
            binding: binding.map(str::to_owned),
            status: "failed".to_owned(),
            method: solver_input.plan.options.method.clone(),
            reason: reason.to_owned(),
            states: solver_input.plan.simulation.states.clone(),
            algebraic_variables: system_variable_names_by_role(system, "algebraic"),
            inputs: solver_input.plan.simulation.inputs.clone(),
            parameters: solver_input.plan.simulation.parameters.clone(),
            outputs: solver_input.plan.simulation.outputs.clone(),
            source_equations: Vec::new(),
            state: state.name.clone(),
            quantity_kind: state.quantity_kind.clone(),
            display_unit: state.display_unit.clone(),
            canonical_unit: state.canonical_unit.clone(),
            time_unit: solver_input.time_grid.unit.clone(),
            duration_s: solver_input.time_grid.duration_s,
            time_step_s: solver_input.time_grid.timestep_s,
            step_count: solver_input.time_grid.step_count,
            tolerance: solver_input.plan.options.tolerance,
            max_iterations: solver_input.plan.options.max_iterations,
            iteration_count: 0,
            convergence_status: "failed".to_owned(),
            failure_code: Some(failure.code.clone()),
            failure_reason: Some(failure.message.clone()),
            initial_value,
            final_value: initial_value,
            canonical_initial_value,
            canonical_final_value: canonical_initial_value,
            step_diagnostics: Vec::new(),
            points: vec![RuntimePoint {
                x: solver_input.time_grid.start_s,
                y: initial_value,
            }],
        })
    }

    pub fn to_report_solution(&self) -> ReportSystemSolution {
        ReportSystemSolution {
            binding: self.binding.clone(),
            status: self.status.clone(),
            method: self.method.clone(),
            reason: self.reason.clone(),
            states: self.states.clone(),
            algebraic_variables: self.algebraic_variables.clone(),
            inputs: self.inputs.clone(),
            parameters: self.parameters.clone(),
            outputs: self.outputs.clone(),
            source_equations: self
                .source_equations
                .iter()
                .map(|equation| ReportSystemEquationMetadata {
                    kind: equation.kind.clone(),
                    target: equation.target.clone(),
                    left: equation.left.clone(),
                    right: equation.right.clone(),
                    residual_expression: equation.residual_expression.clone(),
                    quantity_kind: equation.quantity_kind.clone(),
                    display_unit: equation.display_unit.clone(),
                    canonical_unit: equation.canonical_unit.clone(),
                    source_line: equation.source_line,
                })
                .collect(),
            state: self.state.clone(),
            quantity_kind: self.quantity_kind.clone(),
            display_unit: self.display_unit.clone(),
            canonical_unit: self.canonical_unit.clone(),
            time_unit: self.time_unit.clone(),
            duration_s: self.duration_s,
            time_step_s: self.time_step_s,
            step_count: self.step_count,
            tolerance: self.tolerance,
            max_iterations: self.max_iterations,
            iteration_count: self.iteration_count,
            convergence_status: self.convergence_status.clone(),
            failure_code: self.failure_code.clone(),
            failure_reason: self.failure_reason.clone(),
            initial_value: self.initial_value,
            final_value: self.final_value,
            canonical_initial_value: self.canonical_initial_value,
            canonical_final_value: self.canonical_final_value,
            step_diagnostics: self
                .step_diagnostics
                .iter()
                .map(|diagnostic| ReportSystemSolverStepDiagnostic {
                    output_index: diagnostic.output_index,
                    start_time_s: diagnostic.start_time_s,
                    end_time_s: diagnostic.end_time_s,
                    dt_s: diagnostic.dt_s,
                    error_norm: diagnostic.error_norm,
                    status: diagnostic.status.clone(),
                })
                .collect(),
            points: self
                .points
                .iter()
                .map(|point| ReportSystemSolutionPoint {
                    x: point.x,
                    y: point.y,
                })
                .collect(),
        }
    }
}

#[derive(Clone, Debug, PartialEq)]
pub struct RuntimeComponentSolution {
    pub assembly: String,
    pub status: String,
    pub method: String,
    pub reason: String,
    pub equation_count: usize,
    pub unknown_count: usize,
    pub residual_norm: f64,
    pub linear_condition_estimate: Option<f64>,
    pub linear_minimum_pivot_abs: Option<f64>,
    pub linear_maximum_pivot_abs: Option<f64>,
    pub variable_scale_policy: String,
    pub variable_scale_min: Option<f64>,
    pub variable_scale_max: Option<f64>,
    pub tolerance: f64,
    pub max_iterations: usize,
    pub iteration_count: usize,
    pub convergence_status: String,
    pub variables: Vec<RuntimeComponentVariableSolution>,
    pub trajectories: Vec<RuntimeComponentTrajectory>,
    pub step_diagnostics: Vec<RuntimeComponentStepDiagnostic>,
    pub residuals: Vec<RuntimeComponentResidualEvaluation>,
    pub largest_residuals: Vec<RuntimeComponentResidualEvaluation>,
    pub failure_artifact: Option<RuntimeSolverFailureArtifact>,
}

#[allow(dead_code)]
impl RuntimeComponentSolution {
    pub fn from_solver_assembly(assembly_name: &str, solver_assembly: &EquationAssembly) -> Self {
        Self::from_solver_assembly_with_scale_overrides(assembly_name, solver_assembly, &[])
    }

    pub fn from_solver_assembly_with_scale_overrides(
        assembly_name: &str,
        solver_assembly: &EquationAssembly,
        residual_scale_overrides: &[ResidualScaleOverride],
    ) -> Self {
        let residual_graph = ResidualGraph::from_assembly(solver_assembly);
        let equation_count = solver_assembly.equation_count();
        let unknown_count = solver_assembly.unknown_count();
        let mut variable_values = vec![0.0; unknown_count];
        let mut variable_status = "homogeneous_zero_seed".to_owned();
        let mut method = "linear_residual_graph_shape_check".to_owned();
        let mut iteration_count = usize::from(equation_count > 0 && unknown_count > 0);
        let mut linear_condition_estimate = None;
        let mut linear_minimum_pivot_abs = None;
        let mut linear_maximum_pivot_abs = None;

        let (mut status, mut reason, mut failure_artifact, mut convergence_status) =
            if equation_count == 0 {
                (
                    "not_solved_no_equations".to_owned(),
                    "assembly graph has no generated equations".to_owned(),
                    Some(RuntimeSolverFailureArtifact {
                        code: "E-ASSEMBLY-SOLVE-001".to_owned(),
                        message: "component assembly has no generated equations to solve"
                            .to_owned(),
                    }),
                    "linear_residual_not_attempted".to_owned(),
                )
            } else if unknown_count == 0 {
                (
                    "not_solved_no_unknowns".to_owned(),
                    "assembly graph has no classified unknown variables".to_owned(),
                    Some(RuntimeSolverFailureArtifact {
                        code: "E-ASSEMBLY-SOLVE-002".to_owned(),
                        message: "component assembly has equations but no classified unknowns"
                            .to_owned(),
                    }),
                    "linear_residual_not_attempted".to_owned(),
                )
            } else if equation_count < unknown_count {
                (
                "constraint_satisfied_nonunique".to_owned(),
                "homogeneous connection constraints evaluate to zero, but boundary/component equations are missing so the physical solution is non-unique".to_owned(),
                Some(RuntimeSolverFailureArtifact {
                    code: "E-ASSEMBLY-UNDERDETERMINED".to_owned(),
                    message: "assembly has fewer equations than unknowns; add component behavior or boundary conditions before treating this as a physical solve".to_owned(),
                }),
                "linear_residual_satisfied_nonunique".to_owned(),
            )
            } else if equation_count > unknown_count {
                (
                "not_solved_overdetermined".to_owned(),
                "assembly graph has more equations than unknowns, so the dense linear residual solve was not attempted".to_owned(),
                Some(RuntimeSolverFailureArtifact {
                    code: "E-ASSEMBLY-OVERDETERMINED".to_owned(),
                    message: "assembly has more equations than unknowns; review generated constraints before numeric solving".to_owned(),
                }),
                "linear_residual_not_attempted_overdetermined".to_owned(),
            )
            } else {
                method = "dense_linear_residual_graph".to_owned();
                iteration_count = 1;
                match solve_linear_residual_graph(
                    &residual_graph,
                    COMPONENT_LINEAR_SOLVER_TOLERANCE,
                ) {
                    Ok(linear_solution) => {
                        variable_values = linear_solution
                            .variables
                            .iter()
                            .map(|variable| variable.value)
                            .collect();
                        variable_status = "solved_linear".to_owned();
                        iteration_count = linear_solution.iteration_count;
                        linear_condition_estimate =
                            Some(linear_solution.linear_diagnostics.pivot_condition_estimate);
                        linear_minimum_pivot_abs =
                            Some(linear_solution.linear_diagnostics.minimum_pivot_abs);
                        linear_maximum_pivot_abs =
                            Some(linear_solution.linear_diagnostics.maximum_pivot_abs);
                        let converged = linear_solution.status == "converged";
                        (
                        if converged {
                            "solved_linear".to_owned()
                        } else {
                            "linear_residual_above_tolerance".to_owned()
                        },
                        "dense linear residual graph solve completed for the square algebraic assembly"
                            .to_owned(),
                        None,
                        if converged {
                            "linear_converged".to_owned()
                        } else {
                            "linear_residual_above_tolerance".to_owned()
                        },
                    )
                    }
                    Err(failure) => (
                        "linear_solve_failed".to_owned(),
                        failure.message.clone(),
                        Some(RuntimeSolverFailureArtifact {
                            code: failure.code,
                            message: failure.message,
                        }),
                        "linear_failed".to_owned(),
                    ),
                }
            };

        let variables = solver_assembly
            .unknowns
            .iter()
            .zip(variable_values.iter())
            .map(|(variable, value)| RuntimeComponentVariableSolution {
                name: variable.name.clone(),
                role: variable.role.clone(),
                value: *value,
                unit: variable.unit.clone(),
                status: variable_status.clone(),
            })
            .collect::<Vec<_>>();
        let residual_output = match residual_graph.evaluate(
            &ResidualInput::new(&variable_values)
                .with_scale_overrides(residual_scale_overrides)
                .with_tolerance(COMPONENT_LINEAR_SOLVER_TOLERANCE),
        ) {
            Ok(output) => output,
            Err(failure) => {
                if failure_artifact.is_none() {
                    status = "residual_evaluation_failed".to_owned();
                    convergence_status = "residual_evaluation_failed".to_owned();
                    reason = failure.message.clone();
                    failure_artifact = Some(RuntimeSolverFailureArtifact {
                        code: failure.code,
                        message: failure.message,
                    });
                }
                ResidualOutput {
                    values: Vec::new(),
                    residual_norm: f64::INFINITY,
                    tolerance: COMPONENT_LINEAR_SOLVER_TOLERANCE,
                }
            }
        };
        let residuals = component_residual_evaluations_from_graph_with_scale_overrides(
            &residual_graph,
            Some(&residual_output),
            residual_scale_overrides,
        );
        let largest_residuals = largest_component_residuals(&residuals);

        Self {
            assembly: assembly_name.to_owned(),
            status,
            method,
            reason,
            equation_count,
            unknown_count,
            residual_norm: residual_output.residual_norm,
            linear_condition_estimate,
            linear_minimum_pivot_abs,
            linear_maximum_pivot_abs,
            variable_scale_policy: "not_applicable".to_owned(),
            variable_scale_min: None,
            variable_scale_max: None,
            tolerance: COMPONENT_LINEAR_SOLVER_TOLERANCE,
            max_iterations: 1,
            iteration_count,
            convergence_status,
            variables,
            trajectories: Vec::new(),
            step_diagnostics: Vec::new(),
            residuals,
            largest_residuals,
            failure_artifact,
        }
    }

    pub fn from_fixed_point_solver_assembly(
        assembly_name: &str,
        solver_assembly: &EquationAssembly,
        options: FixedPointOptions,
        initial_values: Vec<f64>,
        variable_scale_overrides: Option<Vec<f64>>,
        residual_scale_overrides: &[ResidualScaleOverride],
    ) -> Self {
        let residual_graph = ResidualGraph::from_assembly(solver_assembly);
        let equation_count = solver_assembly.equation_count();
        let unknown_count = solver_assembly.unknown_count();
        let mut variable_values = initial_values.clone();
        let mut variable_status = "fixed_point_not_attempted".to_owned();
        let mut status = "fixed_point_failed".to_owned();
        let mut reason = "fixed-point residual graph solve requested from source".to_owned();
        let mut failure_artifact = None;
        let mut convergence_status = "fixed_point_failed".to_owned();
        let mut iteration_count = 0;
        let mut fixed_point_residual_history = Vec::new();
        let mut fixed_point_residual_value_history = Vec::new();
        let mut fixed_point_update_residual_names: Option<Vec<String>> = None;
        let parameter_values = match source_assembly_parameter_values(solver_assembly) {
            Ok(values) => Some(values),
            Err(failure) => {
                reason = failure.message.clone();
                failure_artifact = Some(RuntimeSolverFailureArtifact {
                    code: failure.code,
                    message: failure.message,
                });
                None
            }
        };

        let mut iteration_options = options.clone();
        iteration_options.tolerance = (options.tolerance * 0.1).max(f64::MIN_POSITIVE);

        if let Some(parameter_values) = parameter_values.as_ref() {
            match fixed_point_update_plan(&residual_graph, solver_assembly, parameter_values) {
                Ok(update_plan) => {
                    fixed_point_update_residual_names = Some(
                        update_plan
                            .iter()
                            .map(|rule| {
                                residual_graph
                                    .residuals
                                    .get(rule.residual_index())
                                    .map(|residual| residual.name.clone())
                                    .unwrap_or_else(|| {
                                        format!("unknown_residual_{}", rule.residual_index())
                                    })
                            })
                            .collect(),
                    );
                    match solve_fixed_point(&initial_values, &iteration_options, |values| {
                        fixed_point_update_values(
                            &residual_graph,
                            &update_plan,
                            values,
                            solver_assembly,
                            parameter_values,
                        )
                    }) {
                        Ok(fixed_point) => {
                            let failed = fixed_point.failure.clone();
                            fixed_point_residual_history = fixed_point.residual_history;
                            fixed_point_residual_value_history = fixed_point.residual_value_history;
                            variable_values = fixed_point.values;
                            variable_status = if failed.is_none() {
                                "solved_fixed_point".to_owned()
                            } else {
                                "fixed_point_not_converged".to_owned()
                            };
                            iteration_count = fixed_point.iteration_count;
                            convergence_status = fixed_point.convergence_status;
                            if let Some(failure) = failed {
                                status = "fixed_point_not_converged".to_owned();
                                reason = failure.message.clone();
                                failure_artifact = Some(RuntimeSolverFailureArtifact {
                                    code: failure.code,
                                    message: failure.message,
                                });
                            } else {
                                status = "solved_fixed_point".to_owned();
                            }
                        }
                        Err(failure) => {
                            status = "fixed_point_failed".to_owned();
                            convergence_status = "fixed_point_failed".to_owned();
                            reason = failure.message.clone();
                            failure_artifact = Some(RuntimeSolverFailureArtifact {
                                code: failure.code,
                                message: failure.message,
                            });
                        }
                    }
                }
                Err(failure) => {
                    status = "fixed_point_not_capable".to_owned();
                    convergence_status = "fixed_point_not_capable".to_owned();
                    reason = failure.message.clone();
                    failure_artifact = Some(RuntimeSolverFailureArtifact {
                        code: failure.code,
                        message: failure.message,
                    });
                }
            }
        }

        let variables = solver_assembly
            .unknowns
            .iter()
            .zip(variable_values.iter())
            .map(|(variable, value)| RuntimeComponentVariableSolution {
                name: variable.name.clone(),
                role: variable.role.clone(),
                value: *value,
                unit: variable.unit.clone(),
                status: variable_status.clone(),
            })
            .collect::<Vec<_>>();
        let (residual_norm, residuals) = match fixed_point_source_residual_evaluation(
            solver_assembly,
            &residual_graph,
            &variable_values,
            parameter_values.as_deref(),
            options.tolerance,
            residual_scale_overrides,
        ) {
            Ok(Some(evaluation)) => (evaluation.residual_norm, evaluation.residuals),
            Ok(None) => match residual_graph.evaluate(
                &ResidualInput::new(&variable_values)
                    .with_scale_overrides(residual_scale_overrides)
                    .with_tolerance(options.tolerance),
            ) {
                Ok(output) => {
                    let residuals = component_residual_evaluations_from_graph_with_scale_overrides(
                        &residual_graph,
                        Some(&output),
                        residual_scale_overrides,
                    );
                    (output.residual_norm, residuals)
                }
                Err(failure) => {
                    if failure_artifact.is_none() {
                        status = "residual_evaluation_failed".to_owned();
                        convergence_status = "residual_evaluation_failed".to_owned();
                        reason = failure.message.clone();
                        failure_artifact = Some(RuntimeSolverFailureArtifact {
                            code: failure.code,
                            message: failure.message,
                        });
                    }
                    (f64::INFINITY, Vec::new())
                }
            },
            Err(failure) => {
                if failure_artifact.is_none() {
                    status = "residual_evaluation_failed".to_owned();
                    convergence_status = "residual_evaluation_failed".to_owned();
                    reason = failure.message.clone();
                    failure_artifact = Some(RuntimeSolverFailureArtifact {
                        code: failure.code,
                        message: failure.message,
                    });
                }
                (f64::INFINITY, Vec::new())
            }
        };
        if failure_artifact.is_none() && residual_norm > options.tolerance {
            status = "fixed_point_residual_above_tolerance".to_owned();
            convergence_status = "fixed_point_residual_above_tolerance".to_owned();
            reason = format!(
                "fixed-point residual norm {} exceeded tolerance {}",
                residual_norm, options.tolerance
            );
            failure_artifact = Some(RuntimeSolverFailureArtifact {
                code: "E-FIXED-POINT-RESIDUAL".to_owned(),
                message: reason.clone(),
            });
        }
        let largest_residuals = largest_component_residuals(&residuals);
        let variable_names = residual_graph
            .variables
            .iter()
            .map(|variable| variable.name.clone())
            .collect::<Vec<_>>();
        let (variable_scales, variable_scale_policy) = match variable_scale_overrides {
            Some(scales) => (scales, "user_provided_variable_scales"),
            None => (
                variable_scales_from_unknowns(&solver_assembly.unknowns),
                "unit_default_from_fixed_point_unknowns",
            ),
        };
        let step_residual_names = fixed_point_update_residual_names
            .as_deref()
            .unwrap_or(variable_names.as_slice());
        let step_diagnostics = fixed_point_residual_history_diagnostics(
            &fixed_point_residual_history,
            &fixed_point_residual_value_history,
            Some(step_residual_names),
            Some(&variable_scales),
            Some(variable_scale_policy),
            &convergence_status,
            failure_artifact.as_ref(),
        );

        Self {
            assembly: assembly_name.to_owned(),
            status,
            method: "fixed_point_residual_graph".to_owned(),
            reason,
            equation_count,
            unknown_count,
            residual_norm,
            linear_condition_estimate: None,
            linear_minimum_pivot_abs: None,
            linear_maximum_pivot_abs: None,
            variable_scale_policy: variable_scale_policy.to_owned(),
            variable_scale_min: finite_minimum(&variable_scales),
            variable_scale_max: finite_maximum(&variable_scales),
            tolerance: options.tolerance,
            max_iterations: options.max_iterations,
            iteration_count,
            convergence_status,
            variables,
            trajectories: Vec::new(),
            step_diagnostics,
            residuals,
            largest_residuals,
            failure_artifact,
        }
    }

    pub fn from_dynamic_component_result(
        assembly_name: &str,
        dynamic_result: &DynamicComponentResult,
        reason: &str,
    ) -> Self {
        let mut solution =
            Self::from_dynamic_solver_result(assembly_name, &dynamic_result.solver_result, reason);
        let algebraic_names = dynamic_result
            .algebraic_layout
            .entries
            .iter()
            .map(|entry| entry.name.clone())
            .collect::<Vec<_>>();
        solution.step_diagnostics = dynamic_result
            .step_diagnostics
            .iter()
            .map(|diagnostic| {
                let largest_residual = largest_newton_residual_diagnostic(
                    Some(diagnostic.residual_values.as_slice()),
                    Some(&algebraic_names),
                );
                RuntimeComponentStepDiagnostic {
                    step_index: diagnostic.step_index,
                    time_s: diagnostic.time_s,
                    algebraic_iteration_count: diagnostic.algebraic_iteration_count,
                    residual_norm: diagnostic.residual_norm,
                    residual_values: diagnostic.residual_values.clone(),
                    normalized_residual_values: diagnostic.normalized_residual_values.clone(),
                    line_search_scale: None,
                    line_search_trial_count: None,
                    jacobian_policy: None,
                    variable_scale_policy: None,
                    linear_condition_estimate: None,
                    linear_minimum_pivot_abs: None,
                    linear_maximum_pivot_abs: None,
                    largest_residual_index: largest_residual
                        .as_ref()
                        .map(|residual| residual.index),
                    largest_residual_name: largest_residual
                        .as_ref()
                        .and_then(|residual| residual.name.clone()),
                    largest_residual_value: largest_residual
                        .as_ref()
                        .map(|residual| residual.value),
                    largest_residual_abs_value: largest_residual
                        .as_ref()
                        .map(|residual| residual.abs_value),
                    convergence_status: diagnostic.convergence_status.clone(),
                    failure_artifact: diagnostic.failure.as_ref().map(|failure| {
                        RuntimeSolverFailureArtifact {
                            code: failure.code.clone(),
                            message: failure.message.clone(),
                        }
                    }),
                }
            })
            .collect();
        solution
    }
    pub fn from_dynamic_component_assembly_result(
        assembly: &EquationAssembly,
        dynamic_result: &DynamicComponentResult,
        reason: &str,
    ) -> Self {
        let mut solution =
            Self::from_dynamic_component_result(&assembly.name, dynamic_result, reason);
        solution.equation_count = assembly.equation_count();
        solution.unknown_count = assembly.unknown_count();
        solution
    }

    pub fn from_dynamic_solver_result(
        assembly_name: &str,
        solver_result: &SolverResult,
        reason: &str,
    ) -> Self {
        let state_trajectories = solver_result
            .output
            .state_trajectories
            .iter()
            .map(|trajectory| {
                component_trajectory_from_solver_trajectory(
                    trajectory,
                    "state",
                    &solver_result.time_grid,
                )
            });
        let algebraic_trajectories =
            solver_result
                .output
                .algebraic_trajectories
                .iter()
                .map(|trajectory| {
                    component_trajectory_from_solver_trajectory(
                        trajectory,
                        "algebraic",
                        &solver_result.time_grid,
                    )
                });
        let trajectories = state_trajectories
            .chain(algebraic_trajectories)
            .collect::<Vec<_>>();
        let variable_status = if solver_result.diagnostics.status == "computed" {
            "trajectory_computed"
        } else {
            "trajectory_failed"
        };
        let variables = trajectories
            .iter()
            .map(|trajectory| RuntimeComponentVariableSolution {
                name: trajectory.name.clone(),
                role: trajectory.role.clone(),
                value: trajectory.final_value,
                unit: trajectory.unit.clone(),
                status: variable_status.to_owned(),
            })
            .collect::<Vec<_>>();

        Self {
            assembly: assembly_name.to_owned(),
            status: solver_result.diagnostics.status.clone(),
            method: solver_result.plan.options.method.clone(),
            reason: reason.to_owned(),
            equation_count: 0,
            unknown_count: variables.len(),
            residual_norm: 0.0,
            linear_condition_estimate: None,
            linear_minimum_pivot_abs: None,
            linear_maximum_pivot_abs: None,
            variable_scale_policy: "not_applicable".to_owned(),
            variable_scale_min: None,
            variable_scale_max: None,
            tolerance: solver_result.diagnostics.tolerance,
            max_iterations: solver_result.diagnostics.max_iterations,
            iteration_count: solver_result.diagnostics.iteration_count,
            convergence_status: solver_result.diagnostics.convergence_status.clone(),
            variables,
            trajectories,
            step_diagnostics: Vec::new(),
            residuals: Vec::new(),
            largest_residuals: Vec::new(),
            failure_artifact: solver_result.diagnostics.failure.as_ref().map(|failure| {
                RuntimeSolverFailureArtifact {
                    code: failure.code.clone(),
                    message: failure.message.clone(),
                }
            }),
        }
    }

    pub fn to_report_solver_result(&self) -> ReportComponentSolverResult {
        ReportComponentSolverResult {
            status: self.status.clone(),
            method: self.method.clone(),
            reason: self.reason.clone(),
            residual_norm: self.residual_norm,
            linear_condition_estimate: self.linear_condition_estimate,
            linear_minimum_pivot_abs: self.linear_minimum_pivot_abs,
            linear_maximum_pivot_abs: self.linear_maximum_pivot_abs,
            variable_scale_policy: self.variable_scale_policy.clone(),
            variable_scale_min: self.variable_scale_min,
            variable_scale_max: self.variable_scale_max,
            tolerance: self.tolerance,
            max_iterations: self.max_iterations,
            iteration_count: self.iteration_count,
            convergence_status: self.convergence_status.clone(),
            variables: self
                .variables
                .iter()
                .map(|variable| ReportComponentSolverVariable {
                    name: variable.name.clone(),
                    role: variable.role.clone(),
                    value: variable.value,
                    unit: variable.unit.clone(),
                    status: variable.status.clone(),
                })
                .collect(),
            trajectories: self
                .trajectories
                .iter()
                .map(|trajectory| ReportComponentSolverTrajectory {
                    name: trajectory.name.clone(),
                    role: trajectory.role.clone(),
                    quantity_kind: trajectory.quantity_kind.clone(),
                    unit: trajectory.unit.clone(),
                    initial_value: trajectory.initial_value,
                    final_value: trajectory.final_value,
                    point_count: trajectory.point_count,
                    points: trajectory
                        .points
                        .iter()
                        .map(|point| ReportSystemSolutionPoint {
                            x: point.x,
                            y: point.y,
                        })
                        .collect(),
                })
                .collect(),
            step_diagnostics: self
                .step_diagnostics
                .iter()
                .map(|diagnostic| {
                    let source_context =
                        largest_residual_source_context(diagnostic, &self.residuals);
                    ReportComponentSolverStepDiagnostic {
                        step_index: diagnostic.step_index,
                        time_s: diagnostic.time_s,
                        algebraic_iteration_count: diagnostic.algebraic_iteration_count,
                        residual_norm: diagnostic.residual_norm,
                        residual_values: diagnostic.residual_values.clone(),
                        normalized_residual_values: diagnostic.normalized_residual_values.clone(),
                        line_search_scale: diagnostic.line_search_scale,
                        line_search_trial_count: diagnostic.line_search_trial_count,
                        jacobian_policy: diagnostic.jacobian_policy.clone(),
                        variable_scale_policy: diagnostic.variable_scale_policy.clone(),
                        linear_condition_estimate: diagnostic.linear_condition_estimate,
                        linear_minimum_pivot_abs: diagnostic.linear_minimum_pivot_abs,
                        linear_maximum_pivot_abs: diagnostic.linear_maximum_pivot_abs,
                        largest_residual_index: diagnostic.largest_residual_index,
                        largest_residual_name: diagnostic.largest_residual_name.clone(),
                        largest_residual_source_expression: source_context
                            .map(|residual| residual.source_expression.clone()),
                        largest_residual_source_line: source_context
                            .and_then(|residual| residual.source_line),
                        largest_residual_source_reason: source_context
                            .and_then(|residual| residual.source_reason.clone()),
                        largest_residual_value: diagnostic.largest_residual_value,
                        largest_residual_abs_value: diagnostic.largest_residual_abs_value,
                        convergence_status: diagnostic.convergence_status.clone(),
                        failure_artifact: diagnostic.failure_artifact.as_ref().map(|failure| {
                            ReportSolverFailureArtifact {
                                code: failure.code.clone(),
                                message: failure.message.clone(),
                            }
                        }),
                    }
                })
                .collect(),
            residuals: self
                .residuals
                .iter()
                .map(|residual| ReportComponentSolverResidual {
                    name: residual.name.clone(),
                    expression: residual.expression.clone(),
                    source_expression: residual.source_expression.clone(),
                    source_line: residual.source_line,
                    source_reason: residual.source_reason.clone(),
                    dependencies: residual.dependencies.clone(),
                    value: residual.value,
                    unit: residual.unit.clone(),
                    expression_unit: residual.expression_unit.clone(),
                    expression_quantity_kind: residual.expression_quantity_kind.clone(),
                    normalized_value: residual.normalized_value,
                    scale: residual.scale,
                    scale_policy: residual.scale_policy.clone(),
                    lowering_status: residual.lowering_status.clone(),
                    lowering_failure_code: residual.lowering_failure_code.clone(),
                    lowering_failure_reason: residual.lowering_failure_reason.clone(),
                    status: residual.status.clone(),
                })
                .collect(),
            largest_residuals: self
                .largest_residuals
                .iter()
                .map(|residual| ReportComponentSolverResidual {
                    name: residual.name.clone(),
                    expression: residual.expression.clone(),
                    source_expression: residual.source_expression.clone(),
                    source_line: residual.source_line,
                    source_reason: residual.source_reason.clone(),
                    dependencies: residual.dependencies.clone(),
                    value: residual.value,
                    unit: residual.unit.clone(),
                    expression_unit: residual.expression_unit.clone(),
                    expression_quantity_kind: residual.expression_quantity_kind.clone(),
                    normalized_value: residual.normalized_value,
                    scale: residual.scale,
                    scale_policy: residual.scale_policy.clone(),
                    lowering_status: residual.lowering_status.clone(),
                    lowering_failure_code: residual.lowering_failure_code.clone(),
                    lowering_failure_reason: residual.lowering_failure_reason.clone(),
                    status: residual.status.clone(),
                })
                .collect(),
            failure_artifact: self.failure_artifact.as_ref().map(|failure| {
                ReportSolverFailureArtifact {
                    code: failure.code.clone(),
                    message: failure.message.clone(),
                }
            }),
        }
    }
}

fn largest_residual_source_context<'a>(
    diagnostic: &RuntimeComponentStepDiagnostic,
    residuals: &'a [RuntimeComponentResidualEvaluation],
) -> Option<&'a RuntimeComponentResidualEvaluation> {
    let name = diagnostic.largest_residual_name.as_deref()?;
    residuals.iter().find(|residual| residual.name == name)
}

fn largest_component_residuals(
    residuals: &[RuntimeComponentResidualEvaluation],
) -> Vec<RuntimeComponentResidualEvaluation> {
    let mut largest = residuals.to_vec();
    largest.sort_by(|left, right| {
        right
            .normalized_value
            .abs()
            .total_cmp(&left.normalized_value.abs())
            .then_with(|| left.name.cmp(&right.name))
    });
    largest.truncate(3);
    largest
}

fn residual_expression_unit(residual: &ResidualEquation) -> String {
    residual
        .expression
        .inferred_unit
        .as_ref()
        .map(|unit| unit.unit.clone())
        .unwrap_or_else(|| residual.unit.unit.clone())
}

fn residual_expression_quantity_kind(residual: &ResidualEquation) -> String {
    residual
        .expression
        .inferred_unit
        .as_ref()
        .map(|unit| unit.quantity_kind.clone())
        .unwrap_or_else(|| residual.unit.quantity_kind.clone())
}

fn component_residual_evaluations_from_graph_with_scale_overrides(
    graph: &ResidualGraph,
    output: Option<&ResidualOutput>,
    scale_overrides: &[ResidualScaleOverride],
) -> Vec<RuntimeComponentResidualEvaluation> {
    graph
        .residuals
        .iter()
        .enumerate()
        .map(|(index, residual)| {
            let value = output.and_then(|output| output.values.get(index));
            let residual_scale = effective_residual_scale(residual, scale_overrides);
            RuntimeComponentResidualEvaluation {
                name: residual.name.clone(),
                expression: residual.expression.text.clone(),
                source_expression: if residual.source.expression.is_empty() {
                    residual.expression.text.clone()
                } else {
                    residual.source.expression.clone()
                },
                source_line: residual.source.line,
                source_reason: residual.source.generated_reason.clone(),
                dependencies: residual
                    .variable_indices
                    .iter()
                    .filter_map(|index| graph.variables.get(*index))
                    .map(|variable| variable.name.clone())
                    .collect(),
                value: value.map(|value| value.value).unwrap_or(0.0),
                unit: residual.unit.unit.clone(),
                expression_unit: residual_expression_unit(residual),
                expression_quantity_kind: residual_expression_quantity_kind(residual),
                normalized_value: value.map(|value| value.normalized_value).unwrap_or(0.0),
                scale: residual_scale.value,
                scale_policy: residual_scale.policy,
                lowering_status: residual.expression.lowering_status.clone(),
                lowering_failure_code: residual.expression.lowering_failure_code.clone(),
                lowering_failure_reason: residual.expression.lowering_failure_reason.clone(),
                status: value.map(|value| value.status.clone()).unwrap_or_else(|| {
                    if residual.expression.lowering_status == "unsupported_linearization" {
                        "unsupported_linearization".to_owned()
                    } else {
                        "not_evaluated".to_owned()
                    }
                }),
            }
        })
        .collect()
}

