impl RuntimeQualityFailure {
    fn from_policy_violation(violation: &RuntimePolicyViolation) -> Self {
        Self {
            row: violation.row,
            field: violation.column.clone(),
            value: violation.value.clone(),
            message: violation.message.clone(),
        }
    }
}

#[derive(Clone, Debug, Default, PartialEq)]
pub struct PlotOptions {
    pub series: Option<String>,
    pub series_list: Vec<String>,
    pub axis: Option<String>,
    pub histogram: Option<String>,
    pub distribution: Option<String>,
    pub model_plot: Option<ModelPlotOptions>,
    pub plot_type: Option<String>,
    pub title: Option<String>,
    pub x_unit: Option<String>,
    pub y_unit: Option<String>,
    pub confidence_band: Option<String>,
}

#[derive(Clone, Debug, PartialEq)]
pub struct ModelPlotOptions {
    pub kind: String,
    pub source: String,
}

pub fn materialize_runtime_data(report: &CheckReport, source: &str) -> RuntimeData {
    materialize_runtime_data_with_result_dir(report, source, None)
}

pub(crate) fn materialize_runtime_data_with_result_dir(
    report: &CheckReport,
    source: &str,
    result_dir: Option<&Path>,
) -> RuntimeData {
    let mut data = RuntimeData {
        plot_options: parse_plot_options(source),
        ..RuntimeData::default()
    };

    for promotion in &report.semantic_program.csv_promotions {
        let Some(schema) = report
            .semantic_program
            .schemas
            .iter()
            .find(|schema| schema.name == promotion.schema_name)
        else {
            continue;
        };
        if let Some(table) = materialize_table(schema, promotion) {
            data.tables.push(table);
        }
    }
    data.tables
        .extend(materialize_generated_sample_tables(report));
    data.tables
        .extend(materialize_db_read_tables(report, result_dir));

    data.policy_results = materialize_policy_results(report, &mut data.tables);
    let derived_tables = materialize_table_transform_tables(report, &data.tables);
    data.tables.extend(derived_tables);
    let explicit_case_tables = materialize_explicit_case_tables(report, &data.tables);
    data.tables.extend(explicit_case_tables);
    let case_apply_output_tables =
        materialize_case_apply_output_tables(report, &data.tables, result_dir);
    data.tables.extend(case_apply_output_tables);
    let case_run_result_tables =
        materialize_case_run_result_tables(report, &data.tables, result_dir);
    data.tables.extend(case_run_result_tables);
    let case_result_collection_tables =
        materialize_case_result_collection_tables(report, &data.tables);
    data.tables.extend(case_result_collection_tables);
    data.time_axes = materialize_time_axes(&data.tables);
    data.timeseries_coverage =
        materialize_timeseries_coverage(report, &data.tables, &data.time_axes);
    data.timeseries_fill =
        materialize_timeseries_fill(report, &data.tables, &data.timeseries_coverage);
    data.timeseries_quality = materialize_timeseries_quality(
        &data.tables,
        &data.timeseries_coverage,
        &data.timeseries_fill,
    );
    data.table_diagnostics = materialize_table_diagnostics(&data.tables, &data.time_axes);
    data.table_selections = materialize_table_selections(report, &data.tables);
    data.table_transforms = materialize_table_transforms(report, &data.tables);
    data.sample_tables =
        materialize_sample_tables(&report.semantic_program.sample_generations, &data.tables);
    data.case_manifests = materialize_case_manifests(&data.tables);
    data.time_series = materialize_time_series(report, &data.tables);
    data.time_series.extend(materialize_timeseries_fill_series(
        &data.timeseries_fill,
        &data.tables,
    ));
    data.system_solutions = materialize_system_solutions(report, &data.time_series);
    data.component_solutions = materialize_component_solutions(report, &data.time_series);
    data.component_solutions
        .extend(materialize_system_algebraic_solutions(report));
    data.time_series
        .extend(materialize_system_solution_series(&data.system_solutions));
    data.time_series
        .extend(materialize_component_solution_series(
            &data.component_solutions,
        ));
    data.structured_reads = materialize_structured_reads(report, result_dir, &data.tables);
    data.db_connections = materialize_db_connections(report, result_dir);
    data.time_alignments = materialize_time_alignments(report, &mut data.time_series);
    data.statistics = materialize_statistics(report, &data.time_series);
    data.integrations = materialize_integrations(report, &data.time_series);
    data.timeseries_uncertainty_calculations = materialize_timeseries_uncertainty_calculations(
        report,
        &data.time_series,
        &data.statistics,
        &data.integrations,
    );
    data.uncertainties = materialize_uncertainties(report);
    data.numeric_values = materialize_numeric_values(report, &data.uncertainties);
    data.ml_artifacts = materialize_ml_artifacts(report, &data.time_series, &data.tables);
    let prediction_tables = materialize_prediction_tables(&data.ml_artifacts, &data.tables);
    if !prediction_tables.is_empty() {
        data.tables.extend(prediction_tables);
        data.table_diagnostics = materialize_table_diagnostics(&data.tables, &data.time_axes);
    }
    data.metrics = materialize_metrics(report, &data.time_series, &data.time_alignments);
    data.validations = materialize_validations(
        report,
        &data.metrics,
        &data.integrations,
        &data.uncertainties,
        &data.timeseries_coverage,
    );
    data.expectation_suites = materialize_expectation_suites(
        report,
        &data.tables,
        &data.timeseries_coverage,
        &data.policy_results,
    );
    data.quality_results = materialize_quality_results(
        &data.timeseries_quality,
        &data.validations,
        &data.policy_results,
        &data.expectation_suites,
    );
    data
}

fn materialize_db_read_tables(
    report: &CheckReport,
    result_dir: Option<&Path>,
) -> Vec<RuntimeTable> {
    report
        .inferred_declarations
        .iter()
        .filter_map(|declaration| {
            let read = eng_compiler::db_read_expression(&declaration.expression)?;
            let schema = report
                .semantic_program
                .schemas
                .iter()
                .find(|schema| schema.name == read.schema_name)?;
            materialize_db_read_table(report, result_dir, declaration, &read, schema)
        })
        .collect()
}

fn materialize_db_read_table(
    report: &CheckReport,
    result_dir: Option<&Path>,
    declaration: &eng_compiler::InferredDeclaration,
    read: &eng_compiler::DbReadExpression,
    schema: &SchemaInfo,
) -> Option<RuntimeTable> {
    let db_path = runtime_db_read_path(report, result_dir, &read.connection)?;
    let connection = crate::sqlite_open_existing(&db_path).ok()?;
    let column_list = schema
        .columns
        .iter()
        .map(|column| crate::sqlite_quote_identifier(&column.name))
        .collect::<Vec<_>>()
        .join(", ");
    let sql = format!(
        "SELECT {} FROM {}",
        column_list,
        crate::sqlite_quote_identifier(&read.table)
    );
    let result = connection.query(&sql).ok()?;
    let headers = schema
        .columns
        .iter()
        .map(|column| column.name.clone())
        .collect::<Vec<_>>();
    let row_count = result.rows.len();
    let mut rows = Vec::with_capacity(row_count + 1);
    rows.push(headers.clone());
    rows.extend(result.rows.iter().map(|row| {
        row.iter()
            .map(|value| sqlite_value_to_cell(Some(value)))
            .collect::<Vec<_>>()
    }));
    let promotion = eng_compiler::CsvPromotion {
        binding: declaration.name.clone(),
        binding_span: None,
        expression_span: Some(declaration.expression_span),
        promote_span: None,
        format_span: None,
        records_span: None,
        as_span: None,
        source_format: "sqlite_table".to_owned(),
        schema_name: read.schema_name.clone(),
        schema_span: None,
        source_literal: declaration.expression.clone(),
        source_span: Some(declaration.expression_span),
        source_value: read.table.clone(),
        resolved_path: db_path.display().to_string(),
        source_hash: crate::sha256_file_if_exists(&db_path),
        headers,
        row_count,
        missing_columns: Vec::new(),
        optional_missing_columns: Vec::new(),
        json_source_binding: None,
        json_records_field: None,
        line: declaration.line,
    };
    materialize_table_from_rows(schema, &promotion, rows)
}

fn runtime_db_read_path(
    report: &CheckReport,
    result_dir: Option<&Path>,
    connection: &str,
) -> Option<PathBuf> {
    let path_text = runtime_db_connection_path_text(report, connection)?;
    let output_path =
        result_dir.and_then(|result_dir| crate::export_output_path(result_dir, &path_text));
    if output_path.as_ref().is_some_and(|path| path.exists()) {
        return output_path;
    }
    let source_path =
        crate::runtime_resolve_source_relative_path(&path_text, report.source_path.parent());
    if source_path.exists() {
        return Some(source_path);
    }
    output_path.or(Some(source_path))
}

fn runtime_db_connection_path_text(report: &CheckReport, connection: &str) -> Option<String> {
    let declaration = report
        .inferred_declarations
        .iter()
        .find(|declaration| declaration.name == connection)?;
    let path_expression = declaration
        .expression
        .trim()
        .strip_prefix("open sqlite ")?
        .trim();
    crate::evaluate_runtime_path_expression(path_expression, report)
}

fn materialize_db_connections(
    report: &CheckReport,
    result_dir: Option<&Path>,
) -> Vec<RuntimeDbConnection> {
    report
        .inferred_declarations
        .iter()
        .filter_map(|declaration| {
            let path_expression = declaration
                .expression
                .trim()
                .strip_prefix("open sqlite ")?
                .trim();
            let path = crate::evaluate_runtime_path_expression(path_expression, report)?;
            let db_path = runtime_db_read_path(report, result_dir, &declaration.name)?;
            if !db_path.exists() {
                return Some(RuntimeDbConnection {
                    binding: declaration.name.clone(),
                    path,
                    table_count: 0,
                    row_count: 0,
                    tables: Vec::new(),
                    status: "missing".to_owned(),
                    line: declaration.line,
                });
            }
            let Some(tables) = sqlite_user_table_summaries(&db_path) else {
                return Some(RuntimeDbConnection {
                    binding: declaration.name.clone(),
                    path,
                    table_count: 0,
                    row_count: 0,
                    tables: Vec::new(),
                    status: "unreadable".to_owned(),
                    line: declaration.line,
                });
            };
            let row_count = tables.iter().map(|table| table.row_count).sum();
            Some(RuntimeDbConnection {
                binding: declaration.name.clone(),
                path,
                table_count: tables.len(),
                row_count,
                tables,
                status: "loaded".to_owned(),
                line: declaration.line,
            })
        })
        .collect()
}

fn sqlite_user_table_summaries(db_path: &Path) -> Option<Vec<RuntimeDbTableSummary>> {
    let connection = crate::sqlite_open_existing(db_path).ok()?;
    let result = connection
        .query("SELECT name FROM sqlite_master WHERE type = 'table' ORDER BY name")
        .ok()?;
    let mut tables = Vec::new();
    for row in result.rows {
        let Some(GraphiteSqlValue::Text(name)) = row.first() else {
            continue;
        };
        if name.starts_with("_eng_") {
            continue;
        }
        tables.push(RuntimeDbTableSummary {
            name: name.clone(),
            row_count: sqlite_table_row_count(&connection, name).unwrap_or(0),
        });
    }
    Some(tables)
}

fn sqlite_table_row_count(connection: &graphitesql::Connection, table_name: &str) -> Option<usize> {
    let sql = format!(
        "SELECT COUNT(*) FROM {}",
        crate::sqlite_quote_identifier(table_name)
    );
    let result = connection.query(&sql).ok()?;
    let value = result.rows.first()?.first()?;
    match value {
        GraphiteSqlValue::Integer(value) if *value >= 0 => Some(*value as usize),
        GraphiteSqlValue::Real(value) if *value >= 0.0 => Some(*value as usize),
        GraphiteSqlValue::Text(value) => value.parse::<usize>().ok(),
        _ => None,
    }
}
fn sqlite_value_to_cell(value: Option<&GraphiteSqlValue>) -> String {
    match value {
        Some(GraphiteSqlValue::Null) | None => String::new(),
        Some(GraphiteSqlValue::Integer(value)) => value.to_string(),
        Some(GraphiteSqlValue::Real(value)) if value.is_finite() => value.to_string(),
        Some(GraphiteSqlValue::Real(_)) => String::new(),
        Some(GraphiteSqlValue::Text(value)) => value.clone(),
        Some(GraphiteSqlValue::Blob(value)) => format!("blob:{} bytes", value.len()),
    }
}

fn materialize_sqlite_structured_reads(
    report: &CheckReport,
    result_dir: Option<&Path>,
    tables: &[RuntimeTable],
) -> Vec<RuntimeStructuredRead> {
    report
        .inferred_declarations
        .iter()
        .filter_map(|declaration| {
            let read = eng_compiler::db_read_expression(&declaration.expression)?;
            let path = runtime_db_read_path(report, result_dir, &read.connection)?;
            let table = tables.iter().find(|table| {
                table.binding == declaration.name && table.schema_name == read.schema_name
            });
            let mut record = RuntimeStructuredRead {
                binding: declaration.name.clone(),
                kind: "sqlite".to_owned(),
                path: path.display().to_string(),
                source_hash: crate::sha256_file_if_exists(&path),
                parse_status: if table.is_some() {
                    "parsed".to_owned()
                } else if path.exists() {
                    "missing_table".to_owned()
                } else {
                    "missing".to_owned()
                },
                root_type: "sqlite_table".to_owned(),
                field_count: table.map(|table| table.columns.len()),
                item_count: table.map(|table| table.row_count),
                error: None,
                line: declaration.line,
            };
            if table.is_none() && path.exists() {
                record.error = Some(format!(
                    "table `{}` could not be read as schema `{}`",
                    read.table, read.schema_name
                ));
            }
            Some(record)
        })
        .collect()
}

fn materialize_structured_reads(
    report: &CheckReport,
    result_dir: Option<&Path>,
    tables: &[RuntimeTable],
) -> Vec<RuntimeStructuredRead> {
    let mut reads = report
        .semantic_program
        .environment_dependencies
        .iter()
        .filter_map(|dependency| {
            let kind = dependency.kind.strip_prefix("filesystem_read_")?;
            if !matches!(kind, "text" | "json" | "toml") {
                return None;
            }
            Some(materialize_structured_read(
                dependency.name.clone(),
                kind,
                dependency.resolved_value.clone(),
                dependency.source_hash.clone(),
                dependency.status.as_str(),
                dependency.line,
            ))
        })
        .collect::<Vec<_>>();
    reads.extend(materialize_sqlite_structured_reads(
        report, result_dir, tables,
    ));
    reads
}

fn materialize_structured_read(
    binding: String,
    kind: &str,
    path: String,
    source_hash: Option<String>,
    source_status: &str,
    line: usize,
) -> RuntimeStructuredRead {
    let mut record = RuntimeStructuredRead {
        binding,
        kind: kind.to_owned(),
        path: path.clone(),
        source_hash,
        parse_status: source_status.to_owned(),
        root_type: "unknown".to_owned(),
        field_count: None,
        item_count: None,
        error: None,
        line,
    };
    if source_status != "read" {
        return record;
    }
    let Ok(source) = fs::read_to_string(&path) else {
        record.parse_status = "missing".to_owned();
        return record;
    };

    match kind {
        "text" => {
            record.root_type = "text".to_owned();
            record.item_count = Some(source.lines().count());
        }
        "json" => match serde_json::from_str::<JsonValue>(&source) {
            Ok(value) => {
                let (root_type, field_count, item_count) = runtime_json_shape(&value);
                record.parse_status = "parsed".to_owned();
                record.root_type = root_type.as_str().to_owned();
                record.field_count = field_count;
                record.item_count = item_count;
            }
            Err(error) => {
                record.parse_status = "parse_error".to_owned();
                record.error = Some(error.to_string());
            }
        },
        "toml" => match source.parse::<TomlValue>() {
            Ok(value) => {
                let (root_type, field_count, item_count) = runtime_toml_shape(&value);
                record.parse_status = "parsed".to_owned();
                record.root_type = root_type.as_str().to_owned();
                record.field_count = field_count;
                record.item_count = item_count;
            }
            Err(error) => {
                record.parse_status = "parse_error".to_owned();
                record.error = Some(error.to_string());
            }
        },
        _ => {}
    }
    record
}

fn runtime_json_shape(value: &JsonValue) -> (RuntimeJsonValue, Option<usize>, Option<usize>) {
    match value {
        JsonValue::Null => (RuntimeJsonValue::Null, None, None),
        JsonValue::Bool(_) => (RuntimeJsonValue::Bool, None, None),
        JsonValue::Number(_) => (RuntimeJsonValue::Number, None, None),
        JsonValue::String(_) => (RuntimeJsonValue::String, None, None),
        JsonValue::Array(items) => (RuntimeJsonValue::Array, None, Some(items.len())),
        JsonValue::Object(fields) => (RuntimeJsonValue::Object, Some(fields.len()), None),
    }
}

fn runtime_toml_shape(value: &TomlValue) -> (RuntimeTomlValue, Option<usize>, Option<usize>) {
    match value {
        TomlValue::String(_) => (RuntimeTomlValue::String, None, None),
        TomlValue::Integer(_) => (RuntimeTomlValue::Integer, None, None),
        TomlValue::Float(_) => (RuntimeTomlValue::Float, None, None),
        TomlValue::Boolean(_) => (RuntimeTomlValue::Boolean, None, None),
        TomlValue::Datetime(_) => (RuntimeTomlValue::Datetime, None, None),
        TomlValue::Array(items) => (RuntimeTomlValue::Array, None, Some(items.len())),
        TomlValue::Table(fields) => (RuntimeTomlValue::Table, Some(fields.len()), None),
    }
}

fn materialize_table(
    schema: &SchemaInfo,
    promotion: &eng_compiler::CsvPromotion,
) -> Option<RuntimeTable> {
    let rows = if promotion.source_format == "json_records" {
        materialize_json_record_rows(schema, promotion)?
    } else {
        let source = fs::read_to_string(&promotion.resolved_path).ok()?;
        parse_csv(&source)
    };
    materialize_table_from_rows(schema, promotion, rows)
}

fn materialize_table_from_rows(
    schema: &SchemaInfo,
    promotion: &eng_compiler::CsvPromotion,
    rows: Vec<Vec<String>>,
) -> Option<RuntimeTable> {
    let headers = rows.first()?.clone();
    let header_index = headers
        .iter()
        .enumerate()
        .map(|(index, header)| (header.trim().to_owned(), index))
        .collect::<HashMap<_, _>>();
    let data_rows = rows.into_iter().skip(1).collect::<Vec<_>>();
    let mut parse_failures = Vec::new();
    let mut columns = Vec::new();

    for column in &schema.columns {
        let Some(index) = header_index.get(&column.name).copied() else {
            continue;
        };
        columns.push(materialize_column(
            column,
            index,
            &data_rows,
            &mut parse_failures,
        ));
    }

    Some(RuntimeTable {
        binding: promotion.binding.clone(),
        schema_name: promotion.schema_name.clone(),
        source: promotion.source_literal.clone(),
        source_hash: promotion.source_hash.clone(),
        row_count: data_rows.len(),
        columns,
        parse_failures,
        line: promotion.line,
    })
}

fn materialize_json_record_rows(
    schema: &SchemaInfo,
    promotion: &eng_compiler::CsvPromotion,
) -> Option<Vec<Vec<String>>> {
    let records_field = promotion.json_records_field.as_deref()?;
    let source = fs::read_to_string(&promotion.resolved_path).ok()?;
    let value = serde_json::from_str::<JsonValue>(&source).ok()?;
    let records = runtime_json_records_array(&value, records_field)?;
    let headers = schema
        .columns
        .iter()
        .map(|column| column.name.clone())
        .collect::<Vec<_>>();
    let mut rows = Vec::with_capacity(records.len() + 1);
    rows.push(headers.clone());
    for record in records {
        let object = record.as_object();
        rows.push(
            headers
                .iter()
                .map(|header| {
                    object
                        .and_then(|fields| fields.get(header))
                        .map(json_value_to_cell)
                        .unwrap_or_default()
                })
                .collect(),
        );
    }
    Some(rows)
}

fn runtime_json_records_array<'a>(
    value: &'a JsonValue,
    records_field: &str,
) -> Option<&'a Vec<JsonValue>> {
    let mut current = value;
    for segment in records_field
        .split('.')
        .filter(|segment| !segment.is_empty())
    {
        current = current.get(segment)?;
    }
    current.as_array()
}

fn json_value_to_cell(value: &JsonValue) -> String {
    match value {
        JsonValue::Null => String::new(),
        JsonValue::Bool(value) => value.to_string(),
        JsonValue::Number(value) => value.to_string(),
        JsonValue::String(value) => value.clone(),
        JsonValue::Array(_) | JsonValue::Object(_) => {
            serde_json::to_string(value).unwrap_or_default()
        }
    }
}

fn materialize_generated_sample_tables(report: &CheckReport) -> Vec<RuntimeTable> {
    report
        .semantic_program
        .sample_generations
        .iter()
        .filter(|generation| generation.count > 0 && !generation.distributions.is_empty())
        .map(materialize_generated_sample_table)
        .collect()
}

fn materialize_generated_sample_table(
    generation: &eng_compiler::SampleGenerationInfo,
) -> RuntimeTable {
    let rows = generated_sample_rows(generation);
    let case_width = generation.count.to_string().len().max(3);
    let mut columns = Vec::new();
    columns.push(RuntimeColumn {
        name: "case_id".to_owned(),
        type_name: "String".to_owned(),
        unit: None,
        canonical_unit: None,
        is_index: false,
        values: RuntimeValues::Text(
            (1..=generation.count)
                .map(|index| format!("case_{index:0case_width$}"))
                .collect(),
        ),
        canonical_values: Vec::new(),
        missing_count: 0,
        conversion_failures: Vec::new(),
    });
    for (column_index, distribution) in generation.distributions.iter().enumerate() {
        let values = rows
            .iter()
            .map(|row| row.get(column_index).copied().flatten())
            .collect::<Vec<_>>();
        columns.push(RuntimeColumn {
            name: distribution.name.clone(),
            type_name: distribution.quantity_kind.clone(),
            unit: Some(distribution.display_unit.clone()),
            canonical_unit: Some(distribution.canonical_unit.clone()),
            is_index: false,
            values: RuntimeValues::Number(values.clone()),
            canonical_values: values,
            missing_count: 0,
            conversion_failures: Vec::new(),
        });
    }
    let source = format!("sample {}", generation.method);
    let hash_payload = generated_sample_hash_payload(generation, &rows);
    RuntimeTable {
        binding: generation.binding.clone(),
        schema_name: "GeneratedSample".to_owned(),
        source,
        source_hash: Some(stable_hash_text(&hash_payload)),
        row_count: generation.count,
        columns,
        parse_failures: Vec::new(),
        line: generation.line,
    }
}

fn generated_sample_hash_payload(
    generation: &eng_compiler::SampleGenerationInfo,
    rows: &[Vec<Option<f64>>],
) -> String {
    let mut payload = format!(
        "{}|{}|{}|{:?}",
        generation.binding, generation.method, generation.count, generation.seed
    );
    for distribution in &generation.distributions {
        payload.push_str(&format!(
            "|{}:{}:{}:{}:{}",
            distribution.name,
            distribution.lower,
            distribution.upper,
            distribution.quantity_kind,
            distribution.display_unit
        ));
    }
    for row in rows {
        payload.push('|');
        payload.push_str(
            &row.iter()
                .map(|value| value.map(|value| value.to_string()).unwrap_or_default())
                .collect::<Vec<_>>()
                .join(","),
        );
    }
    payload
}

fn generated_sample_rows(generation: &eng_compiler::SampleGenerationInfo) -> Vec<Vec<Option<f64>>> {
    match generation.method.as_str() {
        "grid" => generated_grid_sample_rows(generation),
        "lhs" => generated_lhs_sample_rows(generation),
        _ => generated_random_sample_rows(generation),
    }
}

fn generated_grid_sample_rows(
    generation: &eng_compiler::SampleGenerationInfo,
) -> Vec<Vec<Option<f64>>> {
    let parameter_count = generation.distributions.len().max(1);
    let levels = (generation.count as f64)
        .powf(1.0 / parameter_count as f64)
        .ceil()
        .max(1.0) as usize;
    (0..generation.count)
        .map(|row_index| {
            generation
                .distributions
                .iter()
                .enumerate()
                .map(|(parameter_index, distribution)| {
                    let divisor = levels.saturating_pow(parameter_index as u32).max(1);
                    let coordinate = (row_index / divisor) % levels;
                    let fraction = if levels <= 1 {
                        0.5
                    } else {
                        coordinate as f64 / (levels - 1) as f64
                    };
                    Some(interpolate_sample_value(distribution, fraction))
                })
                .collect()
        })
        .collect()
}

fn generated_random_sample_rows(
    generation: &eng_compiler::SampleGenerationInfo,
) -> Vec<Vec<Option<f64>>> {
    let mut rng = DeterministicRng::new(generation.seed.unwrap_or(0));
    (0..generation.count)
        .map(|_| {
            generation
                .distributions
                .iter()
                .map(|distribution| Some(interpolate_sample_value(distribution, rng.next_f64())))
                .collect()
        })
        .collect()
}

fn generated_lhs_sample_rows(
    generation: &eng_compiler::SampleGenerationInfo,
) -> Vec<Vec<Option<f64>>> {
    let mut rng = DeterministicRng::new(generation.seed.unwrap_or(0));
    let mut columns = Vec::new();
    for distribution in &generation.distributions {
        let mut strata = (0..generation.count).collect::<Vec<_>>();
        deterministic_shuffle(&mut strata, &mut rng);
        let values = strata
            .iter()
            .map(|stratum| {
                let fraction = (*stratum as f64 + rng.next_f64()) / generation.count as f64;
                interpolate_sample_value(distribution, fraction)
            })
            .collect::<Vec<_>>();
        columns.push(values);
    }
    (0..generation.count)
        .map(|row_index| {
            columns
                .iter()
                .map(|column| column.get(row_index).copied())
                .collect()
        })
        .collect()
}

fn interpolate_sample_value(
    distribution: &eng_compiler::SampleDistributionInfo,
    fraction: f64,
) -> f64 {
    distribution.lower + (distribution.upper - distribution.lower) * fraction.clamp(0.0, 1.0)
}

fn deterministic_shuffle(values: &mut [usize], rng: &mut DeterministicRng) {
    for index in (1..values.len()).rev() {
        let swap_index = rng.next_index(index + 1);
        values.swap(index, swap_index);
    }
}

struct DeterministicRng {
    state: u64,
}

impl DeterministicRng {
    fn new(seed: u64) -> Self {
        Self {
            state: seed ^ 0x9e3779b97f4a7c15,
        }
    }

    fn next_u64(&mut self) -> u64 {
        self.state = self
            .state
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        self.state
    }

    fn next_f64(&mut self) -> f64 {
        let value = self.next_u64() >> 11;
        value as f64 / ((1u64 << 53) as f64)
    }

    fn next_index(&mut self, upper: usize) -> usize {
        if upper <= 1 {
            0
        } else {
            (self.next_u64() as usize) % upper
        }
    }
}

fn materialize_column(
    column: &SchemaColumn,
    index: usize,
    rows: &[Vec<String>],
    parse_failures: &mut Vec<RuntimeParseFailure>,
) -> RuntimeColumn {
    let mut missing_count = 0usize;
    if column.type_name == "DateTime" {
        let mut values = Vec::new();
        for (row_index, row) in rows.iter().enumerate() {
            let value = row.get(index).map(String::as_str).unwrap_or("").trim();
            if value.is_empty() {
                missing_count += 1;
            } else if parse_utc_timestamp_seconds(value).is_none() {
                parse_failures.push(RuntimeParseFailure {
                    row: row_index + 2,
                    column: column.name.clone(),
                    value: value.to_owned(),
                    message:
                        "expected DateTime like 2026-01-01T00:00:00Z or 2026-01-01T09:00:00+09:00"
                            .to_owned(),
                });
            }
            values.push(value.to_owned());
        }
        return RuntimeColumn {
            name: column.name.clone(),
            type_name: column.type_name.clone(),
            unit: column.unit.clone(),
            canonical_unit: None,
            is_index: column.is_index,
            values: RuntimeValues::Text(values),
            canonical_values: Vec::new(),
            missing_count,
            conversion_failures: Vec::new(),
        };
    }

    if is_numeric_schema_type(&column.type_name) {
        let mut values = Vec::new();
        let canonical_unit = canonical_unit_for_quantity(&column.type_name);
        let mut canonical_values = Vec::new();
        let mut conversion_failures = Vec::new();
        for (row_index, row) in rows.iter().enumerate() {
            let value = row.get(index).map(String::as_str).unwrap_or("").trim();
            if value.is_empty() {
                missing_count += 1;
                values.push(None);
                if canonical_unit.is_some() {
                    canonical_values.push(None);
                }
                continue;
            }
            match value.parse::<f64>() {
                Ok(number) if number.is_finite() => {
                    values.push(Some(number));
                    if let Some(target_unit) = canonical_unit.as_deref() {
                        match convert_to_canonical_unit(
                            number,
                            column.unit.as_deref(),
                            target_unit,
                            &column.type_name,
                        ) {
                            Ok(converted) => canonical_values.push(Some(converted)),
                            Err(message) => {
                                canonical_values.push(None);
                                conversion_failures.push(RuntimeConversionFailure {
                                    row: row_index + 2,
                                    column: column.name.clone(),
                                    value: value.to_owned(),
                                    source_unit: column.unit.clone().unwrap_or_default(),
                                    target_unit: target_unit.to_owned(),
                                    message,
                                });
                            }
                        }
                    }
                }
                _ => {
                    parse_failures.push(RuntimeParseFailure {
                        row: row_index + 2,
                        column: column.name.clone(),
                        value: value.to_owned(),
                        message: "expected finite numeric cell".to_owned(),
                    });
                    values.push(None);
                    if canonical_unit.is_some() {
                        canonical_values.push(None);
                    }
                }
            }
        }
        return RuntimeColumn {
            name: column.name.clone(),
            type_name: column.type_name.clone(),
            unit: column.unit.clone(),
            canonical_unit,
            is_index: column.is_index,
            values: RuntimeValues::Number(values),
            canonical_values,
            missing_count,
            conversion_failures,
        };
    }

    let values = rows
        .iter()
        .map(|row| row.get(index).cloned().unwrap_or_default())
        .inspect(|value| {
            if value.trim().is_empty() {
                missing_count += 1;
            }
        })
        .collect();
    RuntimeColumn {
        name: column.name.clone(),
        type_name: column.type_name.clone(),
        unit: column.unit.clone(),
        canonical_unit: None,
        is_index: column.is_index,
        values: RuntimeValues::Text(values),
        canonical_values: Vec::new(),
        missing_count,
        conversion_failures: Vec::new(),
    }
}

fn materialize_time_axes(tables: &[RuntimeTable]) -> Vec<RuntimeTimeAxis> {
    tables
        .iter()
        .map(|table| {
            let (source_column, unit, values, missing_count) =
                if let Some(column) = table.time_index_column() {
                    let parse_failure_count = table
                        .parse_failures
                        .iter()
                        .filter(|failure| failure.column == column.name)
                        .count();
                    (
                        column.name.clone(),
                        "s".to_owned(),
                        table
                            .normalized_time_axis_values()
                            .unwrap_or_else(|| sample_axis_values(table.row_count)),
                        column.missing_count + parse_failure_count,
                    )
                } else {
                    (
                        "row_index".to_owned(),
                        "sample".to_owned(),
                        sample_axis_values(table.row_count),
                        0,
                    )
                };
            let nominal_step = nominal_step_from_values(&values);
            let irregular = missing_count > 0 || axis_values_irregular(&values, nominal_step);
            RuntimeTimeAxis {
                name: format!("{}.Time", table.binding),
                source_table: table.binding.clone(),
                source_column,
                axis: "Time".to_owned(),
                unit,
                start: values.first().copied(),
                end: values.last().copied(),
                count: table.row_count,
                nominal_step,
                irregular,
                missing_count,
            }
        })
        .collect()
}

fn materialize_timeseries_coverage(
    report: &CheckReport,
    tables: &[RuntimeTable],
    axes: &[RuntimeTimeAxis],
) -> Vec<RuntimeTimeSeriesCoverage> {
    let mut coverage = axes
        .iter()
        .filter_map(|axis| materialize_axis_timeseries_coverage(tables, axis))
        .collect::<Vec<_>>();
    coverage.extend(materialize_explicit_timeseries_coverage(report, tables));
    coverage
}

fn materialize_axis_timeseries_coverage(
    tables: &[RuntimeTable],
    axis: &RuntimeTimeAxis,
) -> Option<RuntimeTimeSeriesCoverage> {
    let table = tables
        .iter()
        .find(|table| table.binding == axis.source_table)?;
    let time_column = table.time_index_column()?;
    let values = table.normalized_time_axis_values()?;
    let missing_intervals = coverage_missing_intervals(&values, axis.nominal_step);
    let gap_missing_count = missing_intervals
        .iter()
        .map(|interval| interval.missing_count)
        .sum::<usize>();
    let expected_count = coverage_expected_count(axis.start, axis.end, axis.nominal_step);
    let max_gap = coverage_max_gap(&values);
    let (source_start, source_end) = time_column_text_bounds(time_column);
    let missing_count = axis.missing_count + gap_missing_count;
    let status = coverage_status(
        axis.missing_count,
        axis.irregular,
        !missing_intervals.is_empty(),
    );
    Some(RuntimeTimeSeriesCoverage {
        binding: format!("{}.coverage", axis.name),
        name: format!("{}.coverage", axis.name),
        source_table: axis.source_table.clone(),
        source_column: axis.source_column.clone(),
        unit: axis.unit.clone(),
        start: axis.start,
        end: axis.end,
        source_start,
        source_end,
        expected_step: axis.nominal_step,
        expected_count,
        actual_count: axis.count,
        missing_count,
        missing_intervals,
        max_gap,
        coverage_year: None,
        leap_year_policy: "axis_span_only".to_owned(),
        status: status.to_owned(),
        line: table.line,
    })
}

fn materialize_explicit_timeseries_coverage(
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Vec<RuntimeTimeSeriesCoverage> {
    report
        .semantic_program
        .command_styles
        .iter()
        .filter(|command| command.verb == "check" && command.status == "lowered")
        .filter_map(|command| {
            materialize_explicit_timeseries_coverage_command(report, tables, command)
        })
        .collect()
}

fn materialize_explicit_timeseries_coverage_command(
    report: &CheckReport,
    tables: &[RuntimeTable],
    command: &eng_compiler::CommandStyleInfo,
) -> Option<RuntimeTimeSeriesCoverage> {
    let source = command.target.trim().strip_prefix("coverage ")?.trim();
    let (table_name, column_name) = source.rsplit_once('.')?;
    let table = tables
        .iter()
        .find(|table| table.binding == table_name.trim())?;
    let time_column = table
        .columns
        .iter()
        .find(|column| column.name == column_name.trim() && column.type_name == "DateTime")?;
    let values = normalized_time_values_from_column(time_column)?;
    let options = report
        .semantic_program
        .with_blocks
        .iter()
        .find(|block| block.owner_line == Some(command.line))
        .map(|block| block.options.as_slice())
        .unwrap_or(&[]);
    let expected_step = option_value(options, "expected_step")
        .or_else(|| option_value(options, "step"))
        .and_then(parse_duration_seconds)
        .or_else(|| nominal_step_from_values(&values));
    let coverage_year =
        option_value(options, "year").and_then(|value| resolve_year_option(value, report));
    let (source_start, source_end) = time_column_text_bounds(time_column);
    let raw_start = raw_timestamp_bounds(time_column).map(|bounds| bounds.0);
    let (coverage_start, coverage_end, leap_year_policy) = if let Some(year) = coverage_year {
        let source_offset = first_timestamp_utc_offset_seconds(time_column).unwrap_or(0);
        let start = (seconds_from_civil(year, 1, 1, 0, 0, 0) - source_offset) as f64;
        let end_exclusive = (seconds_from_civil(year + 1, 1, 1, 0, 0, 0) - source_offset) as f64;
        let end = expected_step
            .filter(|step| step.is_finite() && *step > 0.0)
            .map(|step| end_exclusive - step)
            .unwrap_or(end_exclusive);
        (Some(start), Some(end), "gregorian_year".to_owned())
    } else if let Some(start) = raw_start {
        let first = values.first().copied()?;
        (
            Some(start as f64),
            values.last().map(|end| start as f64 + (*end - first)),
            "axis_span_only".to_owned(),
        )
    } else {
        (None, None, "axis_span_only".to_owned())
    };
    let observed_values = if let Some(start) = raw_start {
        let first = values.first().copied()?;
        values
            .iter()
            .map(|value| start as f64 + (*value - first))
            .collect::<Vec<_>>()
    } else {
        values.clone()
    };
    let (missing_intervals, expected_count, actual_count) =
        if let (Some(start), Some(end), Some(step)) = (coverage_start, coverage_end, expected_step)
        {
            let (intervals, count) =
                coverage_missing_intervals_in_range(&observed_values, start, end, step);
            let actual_count = coverage_actual_count_in_range(&observed_values, start, end, step);
            (intervals, count, actual_count)
        } else {
            (
                coverage_missing_intervals(&values, expected_step),
                coverage_expected_count(
                    values.first().copied(),
                    values.last().copied(),
                    expected_step,
                ),
                values.len(),
            )
        };
    let gap_missing_count = missing_intervals
        .iter()
        .map(|interval| interval.missing_count)
        .sum::<usize>();
    let parse_missing_count = time_column.missing_count
        + table
            .parse_failures
            .iter()
            .filter(|failure| failure.column == time_column.name)
            .count();
    let status = coverage_status(parse_missing_count, false, !missing_intervals.is_empty());
    Some(RuntimeTimeSeriesCoverage {
        binding: command
            .owner
            .clone()
            .unwrap_or_else(|| format!("{source}.coverage")),
        name: command
            .owner
            .clone()
            .unwrap_or_else(|| format!("{source}.coverage")),
        source_table: table.binding.clone(),
        source_column: time_column.name.clone(),
        unit: "s".to_owned(),
        start: coverage_start,
        end: coverage_end,
        source_start,
        source_end,
        expected_step,
        expected_count,
        actual_count,
        missing_count: parse_missing_count + gap_missing_count,
        missing_intervals,
        max_gap: coverage_max_gap(&values),
        coverage_year,
        leap_year_policy,
        status: status.to_owned(),
        line: command.line,
    })
}

fn materialize_timeseries_fill(
    report: &CheckReport,
    tables: &[RuntimeTable],
    coverage: &[RuntimeTimeSeriesCoverage],
) -> Vec<RuntimeTimeSeriesFill> {
    report
        .semantic_program
        .command_styles
        .iter()
        .filter(|command| command.verb == "fill" && command.status == "lowered")
        .filter_map(|command| {
            materialize_timeseries_fill_command(report, tables, coverage, command)
        })
        .collect()
}

fn materialize_timeseries_fill_command(
    report: &CheckReport,
    tables: &[RuntimeTable],
    coverage: &[RuntimeTimeSeriesCoverage],
    command: &eng_compiler::CommandStyleInfo,
) -> Option<RuntimeTimeSeriesFill> {
    let source = command.target.trim().strip_prefix("missing ")?.trim();
    let (table_name, column_name) = source.rsplit_once('.')?;
    let table = tables
        .iter()
        .find(|table| table.binding == table_name.trim())?;
    let source_column = table.column(column_name.trim())?;
    let time_column = table.time_index_column()?;
    let values = table.normalized_time_axis_values()?;
    let options = report
        .semantic_program
        .with_blocks
        .iter()
        .find(|block| block.owner_line == Some(command.line))
        .map(|block| block.options.as_slice())
        .unwrap_or(&[]);
    let expected_step = option_value(options, "expected_step")
        .or_else(|| option_value(options, "step"))
        .and_then(parse_duration_seconds)
        .or_else(|| {
            coverage
                .iter()
                .find(|coverage| {
                    coverage.source_table == table.binding
                        && coverage.source_column == time_column.name
                })
                .and_then(|coverage| coverage.expected_step)
        })
        .or_else(|| nominal_step_from_values(&values));
    let max_gap = option_value(options, "max_gap").and_then(parse_duration_seconds);
    let method = option_value(options, "method")
        .map(normalize_fill_method)
        .unwrap_or_else(|| "record_only".to_owned());
    let interpolation = (method == "interpolate")
        .then(|| interpolate_timeseries_fill_points(table, source_column, expected_step, max_gap))
        .flatten();
    let (missing_count, fillable_count, filled_count, skipped_count) =
        if let Some(interpolation) = &interpolation {
            (
                interpolation.missing_count,
                interpolation.filled_count,
                interpolation.filled_count,
                interpolation.skipped_count,
            )
        } else {
            let missing_intervals = coverage_missing_intervals(&values, expected_step);
            let gap_missing_count = missing_intervals
                .iter()
                .map(|interval| interval.missing_count)
                .sum::<usize>();
            let gap_fillable_count = missing_intervals
                .iter()
                .filter(|interval| fill_interval_within_max_gap(interval, expected_step, max_gap))
                .map(|interval| interval.missing_count)
                .sum::<usize>();
            let source_parse_failures = table
                .parse_failures
                .iter()
                .filter(|failure| failure.column == source_column.name)
                .count();
            let value_missing_count = source_column.missing_count
                + source_column.conversion_failures.len()
                + source_parse_failures;
            let missing_count = gap_missing_count + value_missing_count;
            let value_fillable_count = if method == "record_only" {
                0
            } else {
                value_missing_count
            };
            let fillable_count = gap_fillable_count + value_fillable_count;
            let skipped_count = missing_count.saturating_sub(fillable_count);
            (missing_count, fillable_count, 0, skipped_count)
        };
    let (status, reason, fallback_required) = timeseries_fill_command_status(
        missing_count,
        fillable_count,
        filled_count,
        skipped_count,
        &method,
    );

    Some(RuntimeTimeSeriesFill {
        binding: command
            .owner
            .clone()
            .unwrap_or_else(|| format!("{source}.fill")),
        source_table: table.binding.clone(),
        source_column: source_column.name.clone(),
        time_column: time_column.name.clone(),
        strategy: "fill_missing".to_owned(),
        method,
        expected_step,
        max_gap,
        missing_count,
        fillable_count,
        filled_count,
        skipped_count,
        fallback_required,
        status: status.to_owned(),
        reason: reason.to_owned(),
        line: command.line,
    })
}

#[derive(Clone, Debug)]
struct TimeseriesInterpolationResult {
    points: Vec<RuntimePoint>,
    missing_count: usize,
    filled_count: usize,
    skipped_count: usize,
}

fn interpolate_timeseries_fill_points(
    table: &RuntimeTable,
    source_column: &RuntimeColumn,
    expected_step: Option<f64>,
    max_gap: Option<f64>,
) -> Option<TimeseriesInterpolationResult> {
    let values = numeric_values(source_column);
    let x_values = table.normalized_time_axis_values()?;
    if values.is_empty() || x_values.len() != values.len() {
        return None;
    }
    let step = expected_step
        .filter(|step| step.is_finite() && *step > 0.0)
        .or_else(|| nominal_step_from_values(&x_values))?;
    let start = *x_values.first()?;
    let end = *x_values.last()?;
    let expected_count = coverage_expected_count(Some(start), Some(end), Some(step))?;
    let tolerance = time_step_tolerance(step);
    let mut observed = vec![None::<f64>; expected_count];
    let mut known_points = Vec::<RuntimePoint>::new();
    for (index, value) in values.iter().enumerate() {
        let x = x_values.get(index).copied().unwrap_or(index as f64);
        if let Some(value) = value {
            known_points.push(RuntimePoint { x, y: *value });
        }
        if !x.is_finite() || x < start - tolerance || x > end + tolerance {
            continue;
        }
        let slot = ((x - start) / step).round();
        if slot < 0.0 {
            continue;
        }
        let slot = slot as usize;
        if slot >= expected_count {
            continue;
        }
        let expected_x = start + slot as f64 * step;
        if (x - expected_x).abs() <= tolerance {
            observed[slot] = *value;
        }
    }
    known_points.sort_by(|left, right| left.x.total_cmp(&right.x));
    let mut points = Vec::new();
    let mut missing_count = 0usize;
    let mut filled_count = 0usize;
    let mut skipped_count = 0usize;
    for (slot, observed_value) in observed.iter().enumerate().take(expected_count) {
        let x = start + slot as f64 * step;
        if let Some(value) = observed_value {
            points.push(RuntimePoint { x, y: *value });
            continue;
        }
        missing_count += 1;
        if let Some(value) = interpolate_runtime_points(&known_points, x, max_gap) {
            points.push(RuntimePoint { x, y: value });
            filled_count += 1;
        } else {
            skipped_count += 1;
        }
    }
    Some(TimeseriesInterpolationResult {
        points,
        missing_count,
        filled_count,
        skipped_count,
    })
}

fn interpolate_runtime_points(
    known_points: &[RuntimePoint],
    x: f64,
    max_gap: Option<f64>,
) -> Option<f64> {
    let previous = known_points
        .iter()
        .rev()
        .find(|point| point.x < x && point.x.is_finite() && point.y.is_finite())?;
    let next = known_points
        .iter()
        .find(|point| point.x > x && point.x.is_finite() && point.y.is_finite())?;
    let gap = next.x - previous.x;
    if !gap.is_finite() || gap <= 0.0 {
        return None;
    }
    if max_gap.is_some_and(|max_gap| {
        !max_gap.is_finite() || max_gap <= 0.0 || gap > max_gap + time_step_tolerance(max_gap)
    }) {
        return None;
    }
    let fraction = (x - previous.x) / gap;
    Some(previous.y + (next.y - previous.y) * fraction)
}

fn materialize_timeseries_fill_series(
    fills: &[RuntimeTimeSeriesFill],
    tables: &[RuntimeTable],
) -> Vec<RuntimeTimeSeries> {
    fills
        .iter()
        .filter(|fill| matches!(fill.status.as_str(), "applied" | "partial"))
        .filter_map(|fill| {
            let table = tables
                .iter()
                .find(|table| table.binding == fill.source_table)?;
            let source_column = table.column(&fill.source_column)?;
            let interpolation = interpolate_timeseries_fill_points(
                table,
                source_column,
                fill.expected_step,
                fill.max_gap,
            )?;
            let display_unit = source_column
                .unit
                .clone()
                .or_else(|| source_column.canonical_unit.clone())
                .unwrap_or_else(|| "1".to_owned());
            Some(RuntimeTimeSeries {
                name: fill.binding.clone(),
                axis: "Time".to_owned(),
                x_unit: "s".to_owned(),
                quantity_kind: source_column.type_name.clone(),
                display_unit,
                source_table: table.binding.clone(),
                source_expression: format!(
                    "fill missing {}.{}",
                    fill.source_table, fill.source_column
                ),
                points: interpolation.points,
            })
        })
        .collect()
}

fn normalize_fill_method(value: &str) -> String {
    value.trim().to_ascii_lowercase().replace([' ', '-'], "_")
}

fn fill_interval_within_max_gap(
    interval: &RuntimeMissingInterval,
    expected_step: Option<f64>,
    max_gap: Option<f64>,
) -> bool {
    let Some(max_gap) = max_gap else {
        return true;
    };
    if !max_gap.is_finite() || max_gap <= 0.0 {
        return false;
    }
    let gap = expected_step
        .filter(|step| step.is_finite() && *step > 0.0)
        .map(|step| (interval.missing_count + 1) as f64 * step)
        .unwrap_or_else(|| interval.end - interval.start);
    gap.is_finite() && gap <= max_gap + time_step_tolerance(max_gap)
}

fn timeseries_fill_command_status(
    missing_count: usize,
    fillable_count: usize,
    filled_count: usize,
    skipped_count: usize,
    method: &str,
) -> (&'static str, &'static str, bool) {
    if missing_count == 0 {
        return (
            "not_required",
            "source TimeSeries has no missing samples for the selected fill policy",
            false,
        );
    }
    if method == "interpolate" {
        if filled_count > 0 && skipped_count == 0 {
            return (
                "applied",
                "missing samples were linearly interpolated into a filled TimeSeries",
                false,
            );
        }
        if filled_count > 0 {
            return (
                "partial",
                "some missing samples were linearly interpolated; others remain outside policy",
                true,
            );
        }
        return (
            "deferred",
            "interpolation could not fill any missing samples with the selected policy",
            true,
        );
    }
    if method == "record_only" {
        return (
            "deferred",
            "fill missing command recorded without a value-filling method",
            true,
        );
    }
    if fillable_count == 0 {
        return (
            "deferred",
            "missing samples are outside the selected fill policy",
            true,
        );
    }
    (
        "recorded",
        "explicit fill missing policy recorded; values are not mutated in this runtime slice",
        skipped_count > 0,
    )
}

fn materialize_timeseries_quality(
    tables: &[RuntimeTable],
    coverages: &[RuntimeTimeSeriesCoverage],
    fills: &[RuntimeTimeSeriesFill],
) -> Vec<RuntimeTimeSeriesQuality> {
    let mut quality = Vec::new();
    let mut summarized_coverage = HashSet::new();
    for fill in fills {
        let matching_coverage = matching_timeseries_fill_coverage(coverages, fill);
        if let Some(coverage) = matching_coverage {
            summarized_coverage.insert(coverage.binding.clone());
        }
        quality.push(materialize_timeseries_fill_quality(
            tables,
            matching_coverage,
            fill,
        ));
    }
    for coverage in coverages {
        if summarized_coverage.contains(&coverage.binding) {
            continue;
        }
        quality.push(materialize_timeseries_coverage_quality(coverage));
    }
    quality
}

fn matching_timeseries_fill_coverage<'a>(
    coverage: &'a [RuntimeTimeSeriesCoverage],
    fill: &RuntimeTimeSeriesFill,
) -> Option<&'a RuntimeTimeSeriesCoverage> {
    coverage
        .iter()
        .filter(|coverage| {
            coverage.source_table == fill.source_table && coverage.source_column == fill.time_column
        })
        .max_by_key(|coverage| usize::from(coverage.line > 0))
}

fn materialize_timeseries_fill_quality(
    tables: &[RuntimeTable],
    coverage: Option<&RuntimeTimeSeriesCoverage>,
    fill: &RuntimeTimeSeriesFill,
) -> RuntimeTimeSeriesQuality {
    let expected_step = fill
        .expected_step
        .or_else(|| coverage.and_then(|coverage| coverage.expected_step));
    let expected_count = coverage.and_then(|coverage| coverage.expected_count);
    let actual_count = coverage
        .map(|coverage| coverage.actual_count)
        .unwrap_or_else(|| {
            tables
                .iter()
                .find(|table| table.binding == fill.source_table)
                .map(|table| table.row_count)
                .unwrap_or_default()
        });
    let coverage_missing_count = coverage
        .map(|coverage| coverage.missing_count)
        .unwrap_or(fill.missing_count);
    let missing_count = coverage_missing_count.max(fill.missing_count);
    let remaining_missing_count = missing_count
        .saturating_sub(fill.filled_count)
        .max(fill.skipped_count);
    let quality_score = timeseries_quality_score(expected_count, remaining_missing_count);
    let coverage_status = coverage
        .map(|coverage| coverage.status.clone())
        .unwrap_or_else(|| "unknown".to_owned());
    let (status, reason) = timeseries_quality_status_reason(
        missing_count,
        fill.filled_count,
        remaining_missing_count,
        &coverage_status,
        Some(&fill.status),
    );

    RuntimeTimeSeriesQuality {
        binding: fill.binding.clone(),
        source_table: fill.source_table.clone(),
        source_column: fill.source_column.clone(),
        time_column: fill.time_column.clone(),
        coverage_binding: coverage.map(|coverage| coverage.binding.clone()),
        fill_binding: Some(fill.binding.clone()),
        expected_step,
        expected_count,
        actual_count,
        missing_count,
        filled_count: fill.filled_count,
        remaining_missing_count,
        coverage_status,
        fill_status: Some(fill.status.clone()),
        quality_score,
        status: status.to_owned(),
        reason: reason.to_owned(),
        line: fill.line,
    }
}

fn materialize_timeseries_coverage_quality(
    coverage: &RuntimeTimeSeriesCoverage,
) -> RuntimeTimeSeriesQuality {
    let filled_count = 0;
    let remaining_missing_count = coverage.missing_count;
    let quality_score = timeseries_quality_score(coverage.expected_count, remaining_missing_count);
    let (status, reason) = timeseries_quality_status_reason(
        coverage.missing_count,
        filled_count,
        remaining_missing_count,
        &coverage.status,
        None,
    );

    RuntimeTimeSeriesQuality {
        binding: coverage.binding.clone(),
        source_table: coverage.source_table.clone(),
        source_column: coverage.source_column.clone(),
        time_column: coverage.source_column.clone(),
        coverage_binding: Some(coverage.binding.clone()),
        fill_binding: None,
        expected_step: coverage.expected_step,
        expected_count: coverage.expected_count,
        actual_count: coverage.actual_count,
        missing_count: coverage.missing_count,
        filled_count,
        remaining_missing_count,
        coverage_status: coverage.status.clone(),
        fill_status: None,
        quality_score,
        status: status.to_owned(),
        reason: reason.to_owned(),
        line: coverage.line,
    }
}

fn timeseries_quality_score(
    expected_count: Option<usize>,
    remaining_missing_count: usize,
) -> Option<f64> {
    let expected_count = expected_count?;
    if expected_count == 0 {
        return Some(1.0);
    }
    let usable_count = expected_count.saturating_sub(remaining_missing_count.min(expected_count));
    Some(usable_count as f64 / expected_count as f64)
}

fn timeseries_quality_status_reason(
    missing_count: usize,
    filled_count: usize,
    remaining_missing_count: usize,
    coverage_status: &str,
    fill_status: Option<&String>,
) -> (&'static str, &'static str) {
    if remaining_missing_count == 0 {
        if missing_count > 0 && filled_count > 0 {
            return (
                "passed",
                "fill policy resolved all detected TimeSeries missing samples",
            );
        }
        return ("passed", "TimeSeries coverage has no missing samples");
    }
    if filled_count > 0 {
        return (
            "warning",
            "fill policy resolved some TimeSeries missing samples; missing samples remain",
        );
    }
    if fill_status.is_some_and(|status| status == "deferred") {
        return (
            "warning",
            "fill policy was deferred and TimeSeries missing samples remain",
        );
    }
    if coverage_status != "complete" {
        return (
            "warning",
            "TimeSeries coverage is incomplete and requires an explicit fill or acceptance policy",
        );
    }
    (
        "warning",
        "TimeSeries quality has missing samples after coverage and fill evaluation",
    )
}

fn materialize_expectation_suites(
    report: &CheckReport,
    tables: &[RuntimeTable],
    coverage: &[RuntimeTimeSeriesCoverage],
    policy_results: &[RuntimePolicyResult],
) -> Vec<RuntimeExpectationSuite> {
    report
        .semantic_program
        .expectation_suites
        .iter()
        .map(|suite| {
            let expectations = suite
                .expectations
                .iter()
                .map(|expectation| {
                    materialize_expectation_result(
                        expectation,
                        &suite.target,
                        tables,
                        coverage,
                        policy_results,
                    )
                })
                .collect::<Vec<_>>();
            let passed_count = expectations
                .iter()
                .filter(|expectation| expectation.status == "passed")
                .count();
            let warning_count = expectations
                .iter()
                .filter(|expectation| expectation.status == "warning")
                .count();
            let failed_count = expectations
                .iter()
                .filter(|expectation| expectation.status == "failed")
                .count();
            let status = if failed_count > 0 {
                "failed"
            } else if warning_count > 0 {
                "warning"
            } else {
                "passed"
            };
            RuntimeExpectationSuite {
                binding: suite.binding.clone(),
                target: suite.target.clone(),
                expectation_count: expectations.len(),
                passed_count,
                warning_count,
                failed_count,
                status: status.to_owned(),
                expectations,
                line: suite.line,
            }
        })
        .collect()
}

fn materialize_expectation_result(
    expectation: &eng_compiler::ExpectationInfo,
    suite_target: &str,
    tables: &[RuntimeTable],
    coverage: &[RuntimeTimeSeriesCoverage],
    policy_results: &[RuntimePolicyResult],
) -> RuntimeExpectation {
    let text = expectation.text.trim();
    let policy_match =
        matching_policy_result(suite_target, text, &expectation.subject, policy_results);
    let evaluated = if text.contains(" is continuous") {
        evaluate_continuous_expectation(suite_target, &expectation.subject, coverage)
    } else if text.contains(" is monotonic") {
        evaluate_monotonic_expectation(suite_target, &expectation.subject, tables)
    } else if let Some((column, min, max)) = parse_between_constraint(text) {
        evaluate_between_expectation(suite_target, &column, min, max, tables)
    } else if let Some(bound) = parse_bound_constraint(text) {
        evaluate_bound_expectation(suite_target, &bound, tables)
    } else {
        None
    };
    let (status, reason, matched_result) = if let Some(result) = evaluated {
        result
    } else if let Some(policy) = policy_match {
        (
            policy_quality_status(policy).to_owned(),
            policy_quality_reason(policy).to_owned(),
            Some(format!(
                "policy_result:{}.{}",
                policy.binding, policy.target
            )),
        )
    } else {
        (
            "warning".to_owned(),
            "expectation was recorded but no runtime evaluator matched it".to_owned(),
            None,
        )
    };
    RuntimeExpectation {
        kind: expectation.kind.clone(),
        subject: expectation.subject.clone(),
        text: expectation.text.clone(),
        matched_result,
        status,
        reason,
        line: expectation.line,
    }
}

fn matching_policy_result<'a>(
    suite_target: &str,
    text: &str,
    subject: &str,
    policy_results: &'a [RuntimePolicyResult],
) -> Option<&'a RuntimePolicyResult> {
    policy_results.iter().find(|policy| {
        policy.kind == "constraint"
            && policy.binding == suite_target
            && (policy.policy.trim() == text.trim() || policy.target == subject)
    })
}

fn evaluate_continuous_expectation(
    suite_target: &str,
    subject: &str,
    coverage: &[RuntimeTimeSeriesCoverage],
) -> Option<(String, String, Option<String>)> {
    let coverage = coverage.iter().find(|coverage| {
        coverage.source_table == suite_target
            && (coverage.source_column == subject
                || coverage.binding == format!("{suite_target}.{subject}.coverage"))
    })?;
    if coverage.status == "complete" {
        Some((
            "passed".to_owned(),
            "time axis coverage is complete".to_owned(),
            Some(format!("timeseries_coverage:{}", coverage.binding)),
        ))
    } else {
        Some((
            "failed".to_owned(),
            "time axis coverage is incomplete".to_owned(),
            Some(format!("timeseries_coverage:{}", coverage.binding)),
        ))
    }
}

fn evaluate_between_expectation(
    suite_target: &str,
    column_name: &str,
    min: f64,
    max: f64,
    tables: &[RuntimeTable],
) -> Option<(String, String, Option<String>)> {
    let table = tables.iter().find(|table| table.binding == suite_target)?;
    let column = table.column(column_name)?;
    let values = numeric_values(column);
    let failed_count = values
        .iter()
        .filter(|value| value.is_some_and(|value| value < min || value > max))
        .count();
    if failed_count == 0 {
        Some((
            "passed".to_owned(),
            "all numeric values are inside the expected range".to_owned(),
            None,
        ))
    } else {
        Some((
            "failed".to_owned(),
            format!("{failed_count} numeric value(s) are outside the expected range"),
            None,
        ))
    }
}

fn evaluate_bound_expectation(
    suite_target: &str,
    bound: &BoundConstraint,
    tables: &[RuntimeTable],
) -> Option<(String, String, Option<String>)> {
    let table = tables.iter().find(|table| table.binding == suite_target)?;
    let column = table.column(&bound.column)?;
    let values = numeric_values(column);
    let failed_count = values
        .iter()
        .filter(|value| value.is_some_and(|value| !bound.accepts(value)))
        .count();
    if failed_count == 0 {
        Some((
            "passed".to_owned(),
            "all numeric values satisfy the expected bound".to_owned(),
            None,
        ))
    } else {
        Some((
            "failed".to_owned(),
            format!("{failed_count} numeric value(s) violate the expected bound"),
            None,
        ))
    }
}

fn evaluate_monotonic_expectation(
    suite_target: &str,
    column_name: &str,
    tables: &[RuntimeTable],
) -> Option<(String, String, Option<String>)> {
    let table = tables.iter().find(|table| table.binding == suite_target)?;
    let column = table.column(column_name)?;
    let failed = match &column.values {
        RuntimeValues::Number(values) => values
            .iter()
            .flatten()
            .try_fold(None, |previous: Option<f64>, value| {
                if previous.is_some_and(|previous| *value < previous) {
                    Err(())
                } else {
                    Ok(Some(*value))
                }
            })
            .is_err(),
        RuntimeValues::Text(values) => values
            .iter()
            .filter_map(|value| parse_utc_timestamp_seconds(value))
            .try_fold(None, |previous: Option<i64>, value| {
                if previous.is_some_and(|previous| value < previous) {
                    Err(())
                } else {
                    Ok(Some(value))
                }
            })
            .is_err(),
    };
    if failed {
        Some((
            "failed".to_owned(),
            "column values are not monotonic".to_owned(),
            None,
        ))
    } else {
        Some((
            "passed".to_owned(),
            "column values are monotonic".to_owned(),
            None,
        ))
    }
}

fn materialize_quality_results(
    timeseries_quality: &[RuntimeTimeSeriesQuality],
    validations: &[RuntimeValidation],
    policy_results: &[RuntimePolicyResult],
    expectation_suites: &[RuntimeExpectationSuite],
) -> Vec<RuntimeQualityResult> {
    let mut results = timeseries_quality
        .iter()
        .map(|quality| {
            let passed = quality.status == "passed";
            let warning = quality.status == "warning";
            RuntimeQualityResult {
                binding: format!("{}.quality_result", quality.binding),
                kind: "timeseries_quality_result".to_owned(),
                category: "timeseries".to_owned(),
                target: quality.binding.clone(),
                subject: format!("{}.{}", quality.source_table, quality.source_column),
                source_table: Some(quality.source_table.clone()),
                source_column: Some(quality.source_column.clone()),
                time_column: Some(quality.time_column.clone()),
                score: quality.quality_score,
                passed_count: usize::from(passed),
                warning_count: usize::from(warning),
                failed_count: usize::from(!passed && !warning),
                status: quality.status.clone(),
                reason: quality.reason.clone(),
                failures: Vec::new(),
                line: quality.line,
            }
        })
        .collect::<Vec<_>>();
    results.extend(validations.iter().enumerate().map(|(index, validation)| {
        let status = quality_result_status(&validation.status);
        let passed = status == "passed";
        let failed = status == "failed";
        RuntimeQualityResult {
            binding: format!("validation_{}.quality_result", index + 1),
            kind: "validation_result".to_owned(),
            category: "validation".to_owned(),
            target: validation.expression.clone(),
            subject: validation.left.clone(),
            source_table: None,
            source_column: None,
            time_column: None,
            score: validation_score(status),
            passed_count: usize::from(passed),
            warning_count: usize::from(status == "warning"),
            failed_count: usize::from(failed),
            status: status.to_owned(),
            reason: validation_quality_reason(validation).to_owned(),
            failures: Vec::new(),
            line: validation.line,
        }
    }));
    let constraint_results = materialize_constraint_results(policy_results);
    results.extend(
        constraint_results
            .iter()
            .map(|constraint| RuntimeQualityResult {
                binding: format!("{}.quality_result", constraint.binding),
                kind: "schema_constraint_result".to_owned(),
                category: "schema_constraint".to_owned(),
                target: constraint.binding.clone(),
                subject: format!("{}.{}", constraint.schema, constraint.target),
                source_table: Some(constraint.source_table.clone()),
                source_column: Some(constraint.target.clone()),
                time_column: None,
                score: constraint.score,
                passed_count: constraint.passed_count,
                warning_count: constraint.warning_count,
                failed_count: constraint.failed_count,
                status: constraint.status.clone(),
                reason: constraint_quality_reason(constraint).to_owned(),
                failures: constraint.failures.clone(),
                line: constraint.line,
            }),
    );
    results.extend(expectation_suites.iter().map(|suite| {
        let score = if suite.expectation_count == 0 {
            None
        } else {
            Some(suite.passed_count as f64 / suite.expectation_count as f64)
        };
        RuntimeQualityResult {
            binding: format!("{}.quality_result", suite.binding),
            kind: "expectation_suite_result".to_owned(),
            category: "expectation_suite".to_owned(),
            target: suite.binding.clone(),
            subject: suite.target.clone(),
            source_table: Some(suite.target.clone()),
            source_column: None,
            time_column: None,
            score,
            passed_count: suite.passed_count,
            warning_count: suite.warning_count,
            failed_count: suite.failed_count,
            status: suite.status.clone(),
            reason: expectation_suite_quality_reason(suite).to_owned(),
            failures: Vec::new(),
            line: suite.line,
        }
    }));
    results
}

fn materialize_constraint_results(
    policy_results: &[RuntimePolicyResult],
) -> Vec<RuntimeConstraintResult> {
    policy_results
        .iter()
        .filter(|policy| policy.kind == "constraint")
        .enumerate()
        .map(|(index, policy)| {
            let status = policy_quality_status(policy);
            let failed_count = policy.violations.len();
            let warning_count = usize::from(status == "warning");
            let passed_count =
                if policy.checked_rows > 0 && matches!(status, "passed" | "failed" | "warning") {
                    policy.checked_rows.saturating_sub(failed_count)
                } else if failed_count == 0 && status == "passed" {
                    1
                } else {
                    0
                };
            RuntimeConstraintResult {
                binding: format!("{}.constraint_{}", policy.binding, index + 1),
                source_table: policy.binding.clone(),
                schema: policy.schema.clone(),
                target: policy.target.clone(),
                policy: policy.policy.clone(),
                status: status.to_owned(),
                checked_rows: policy.checked_rows,
                passed_count,
                warning_count,
                failed_count,
                score: policy_quality_score(policy),
                failures: policy
                    .violations
                    .iter()
                    .map(RuntimeQualityFailure::from_policy_violation)
                    .collect(),
                line: policy.line,
            }
        })
        .collect()
}

fn quality_result_status(status: &str) -> &'static str {
    match status {
        "passed" | "ok" | "complete" | "computed" => "passed",
        "failed" | "violation" | "violated" | "invalid" => "failed",
        "unavailable" | "unknown" => "unavailable",
        "warning" | "gapped" | "irregular" => "warning",
        _ if status.contains("fail") || status.contains("violation") => "failed",
        _ if status.contains("warn") || status.contains("gap") => "warning",
        _ => "warning",
    }
}

fn validation_score(status: &str) -> Option<f64> {
    match status {
        "passed" => Some(1.0),
        "failed" => Some(0.0),
        _ => None,
    }
}

fn validation_quality_reason(validation: &RuntimeValidation) -> &'static str {
    match validation.status.as_str() {
        "passed" => "validation statement passed",
        "failed" => "validation statement failed",
        _ => "validation statement could not be evaluated",
    }
}

fn policy_quality_score(policy: &RuntimePolicyResult) -> Option<f64> {
    if policy.checked_rows == 0 {
        return None;
    }
    let failed = policy.violations.len().min(policy.checked_rows);
    Some((policy.checked_rows - failed) as f64 / policy.checked_rows as f64)
}

fn policy_quality_status(policy: &RuntimePolicyResult) -> &'static str {
    if !policy.violations.is_empty() {
        return "failed";
    }
    match policy.status.as_str() {
        "executed" | "validated" => "passed",
        other => quality_result_status(other),
    }
}

fn policy_quality_reason(policy: &RuntimePolicyResult) -> &'static str {
    if !policy.violations.is_empty() {
        "schema constraint policy reported row-level violations"
    } else if matches!(policy.status.as_str(), "executed" | "validated") {
        "schema constraint policy passed"
    } else {
        "schema constraint policy was recorded but not executed"
    }
}

fn constraint_quality_reason(constraint: &RuntimeConstraintResult) -> &'static str {
    if !constraint.failures.is_empty() {
        "schema constraint reported row-level field failures"
    } else if constraint.status == "passed" {
        "schema constraint passed"
    } else {
        "schema constraint was recorded but not executed"
    }
}

fn expectation_suite_quality_reason(suite: &RuntimeExpectationSuite) -> &'static str {
    if suite.failed_count > 0 {
        "expectation suite reported failed expectations"
    } else if suite.warning_count > 0 {
        "expectation suite has expectations that could not be fully evaluated"
    } else {
        "expectation suite passed"
    }
}

fn coverage_status(
    missing_count: usize,
    irregular: bool,
    has_missing_intervals: bool,
) -> &'static str {
    if missing_count > 0 {
        "axis_missing_or_invalid"
    } else if has_missing_intervals {
        "gapped"
    } else if irregular {
        "irregular"
    } else {
        "complete"
    }
}

fn raw_timestamp_bounds(column: &RuntimeColumn) -> Option<(i64, i64)> {
    let RuntimeValues::Text(values) = &column.values else {
        return None;
    };
    let parsed = values
        .iter()
        .filter_map(|value| parse_utc_timestamp_seconds(value.trim()))
        .collect::<Vec<_>>();
    Some((*parsed.first()?, *parsed.last()?))
}

fn normalized_time_values_from_column(column: &RuntimeColumn) -> Option<Vec<f64>> {
    let RuntimeValues::Text(raw_values) = &column.values else {
        return None;
    };
    let parsed = raw_values
        .iter()
        .filter_map(|value| parse_utc_timestamp_seconds(value.trim()))
        .collect::<Vec<_>>();
    let first = *parsed.first()?;
    Some(parsed.iter().map(|value| (*value - first) as f64).collect())
}

fn resolve_year_option(value: &str, report: &CheckReport) -> Option<i32> {
    resolve_table_selection_value(value, report)?
        .parse::<i32>()
        .ok()
}

fn coverage_expected_count(
    start: Option<f64>,
    end: Option<f64>,
    expected_step: Option<f64>,
) -> Option<usize> {
    let (Some(start), Some(end), Some(expected_step)) = (start, end, expected_step) else {
        return None;
    };
    if !start.is_finite() || !end.is_finite() || !expected_step.is_finite() || expected_step <= 0.0
    {
        return None;
    }
    if end < start {
        return None;
    }
    Some(((end - start) / expected_step).floor() as usize + 1)
}

fn coverage_missing_intervals_in_range(
    observed_values: &[f64],
    start: f64,
    end: f64,
    expected_step: f64,
) -> (Vec<RuntimeMissingInterval>, Option<usize>) {
    let expected_count = coverage_expected_count(Some(start), Some(end), Some(expected_step));
    let Some(expected_count) = expected_count else {
        return (Vec::new(), None);
    };
    if expected_count == 0 || !expected_step.is_finite() || expected_step <= 0.0 {
        return (Vec::new(), Some(expected_count));
    }
    let observed_slots =
        coverage_observed_slots(observed_values, start, end, expected_step, expected_count);
    let mut intervals = Vec::new();
    let mut index = 0usize;
    while index < expected_count {
        if observed_slots.contains(&index) {
            index += 1;
            continue;
        }
        let interval_start = index;
        while index < expected_count && !observed_slots.contains(&index) {
            index += 1;
        }
        let interval_end = index - 1;
        intervals.push(RuntimeMissingInterval {
            start: start + interval_start as f64 * expected_step,
            end: start + interval_end as f64 * expected_step,
            missing_count: interval_end - interval_start + 1,
        });
    }
    (intervals, Some(expected_count))
}

fn coverage_actual_count_in_range(
    observed_values: &[f64],
    start: f64,
    end: f64,
    expected_step: f64,
) -> usize {
    let Some(expected_count) = coverage_expected_count(Some(start), Some(end), Some(expected_step))
    else {
        return observed_values.len();
    };
    coverage_observed_slots(observed_values, start, end, expected_step, expected_count).len()
}

fn coverage_observed_slots(
    observed_values: &[f64],
    start: f64,
    end: f64,
    expected_step: f64,
    expected_count: usize,
) -> HashSet<usize> {
    if expected_step <= 0.0 || !expected_step.is_finite() {
        return HashSet::new();
    }
    let tolerance = time_step_tolerance(expected_step);
    observed_values
        .iter()
        .filter_map(|value| {
            if !value.is_finite() || *value < start - tolerance || *value > end + tolerance {
                return None;
            }
            let slot = ((*value - start) / expected_step).round();
            if slot < 0.0 {
                return None;
            }
            let slot = slot as usize;
            if slot >= expected_count {
                return None;
            }
            let expected_value = start + slot as f64 * expected_step;
            ((*value - expected_value).abs() <= tolerance).then_some(slot)
        })
        .collect()
}

fn coverage_missing_intervals(
    values: &[f64],
    expected_step: Option<f64>,
) -> Vec<RuntimeMissingInterval> {
    let Some(expected_step) = expected_step else {
        return Vec::new();
    };
    if expected_step <= 0.0 || !expected_step.is_finite() {
        return Vec::new();
    }
    let tolerance = time_step_tolerance(expected_step);
    values
        .windows(2)
        .filter_map(|window| {
            let gap = window[1] - window[0];
            if !gap.is_finite() || gap <= expected_step + tolerance {
                return None;
            }
            let missing_count = ((gap / expected_step).floor() as usize).saturating_sub(1);
            if missing_count == 0 {
                return None;
            }
            let start = window[0] + expected_step;
            let end = (window[1] - expected_step).max(start);
            Some(RuntimeMissingInterval {
                start,
                end,
                missing_count,
            })
        })
        .collect()
}

fn coverage_max_gap(values: &[f64]) -> Option<f64> {
    values
        .windows(2)
        .filter_map(|window| {
            let gap = window[1] - window[0];
            (gap.is_finite() && gap > 0.0).then_some(gap)
        })
        .max_by(|left, right| left.total_cmp(right))
}

fn time_column_text_bounds(column: &RuntimeColumn) -> (Option<String>, Option<String>) {
    let RuntimeValues::Text(values) = &column.values else {
        return (None, None);
    };
    let mut non_empty = values.iter().filter(|value| !value.trim().is_empty());
    let start = non_empty.next().cloned();
    let end = values
        .iter()
        .rev()
        .find(|value| !value.trim().is_empty())
        .cloned();
    (start, end)
}

fn sample_axis_values(row_count: usize) -> Vec<f64> {
    (0..row_count).map(|index| index as f64).collect()
}

fn materialize_table_selections(
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Vec<RuntimeTableSelection> {
    report
        .inferred_declarations
        .iter()
        .filter_map(|declaration| materialize_table_selection(declaration, report, tables))
        .collect()
}

#[derive(Clone, Debug)]
struct TableSelectionSpec {
    table: String,
    return_column: String,
    equality_filters: Vec<(String, String)>,
    start: Option<String>,
    end: Option<String>,
    valid_from_column: String,
    valid_to_column: String,
}

fn materialize_table_selection(
    declaration: &eng_compiler::InferredDeclaration,
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Option<RuntimeTableSelection> {
    let spec = parse_table_selection_expression(&declaration.expression)?;
    let table = tables.iter().find(|table| table.binding == spec.table)?;
    let equality_filters = spec
        .equality_filters
        .iter()
        .map(|(column, value)| {
            (
                column.clone(),
                resolve_table_selection_value(value, report).unwrap_or_else(|| value.clone()),
            )
        })
        .collect::<Vec<_>>();
    let start = spec
        .start
        .as_deref()
        .and_then(|value| resolve_table_selection_value(value, report));
    let end = spec
        .end
        .as_deref()
        .and_then(|value| resolve_table_selection_value(value, report));

    let matched_rows = (0..table.row_count)
        .filter(|row| {
            table_selection_row_matches(table, *row, &equality_filters, &spec, &start, &end)
        })
        .collect::<Vec<_>>();
    let selected_row_index = matched_rows.first().copied();
    let selected_value =
        selected_row_index.and_then(|row| table_column_value(table, &spec.return_column, row));
    let selected_row = selected_row_index
        .map(|row| table_selection_row_values(table, row))
        .unwrap_or_default();
    let filters = table_selection_filters(
        table,
        selected_row_index,
        &equality_filters,
        &spec,
        &start,
        &end,
    );
    let status = match matched_rows.len() {
        0 => "no_match",
        1 => "selected",
        _ => "selected_first_multiple",
    }
    .to_owned();
    let reason = match matched_rows.len() {
        0 => "no row matched equality filters and validity period",
        1 => "matched equality filters and validity period",
        _ => "multiple rows matched; selected first row for deterministic workflow",
    }
    .to_owned();

    Some(RuntimeTableSelection {
        binding: declaration.name.clone(),
        source_table: spec.table,
        return_column: spec.return_column,
        selected_value,
        selected_row_index: selected_row_index.map(|row| row + 1),
        matched_count: matched_rows.len(),
        filters,
        selected_row,
        status,
        reason,
        line: declaration.line,
    })
}

fn parse_table_selection_expression(expression: &str) -> Option<TableSelectionSpec> {
    let inner = strip_call_inner(expression.trim(), "select_first_row")?;
    let mut parts = split_selection_top_level(inner, ',');
    let table = parts.first()?.trim().to_owned();
    if table.is_empty() {
        return None;
    }
    parts.remove(0);
    let mut return_column = None;
    let mut equality_filters = Vec::new();
    let mut start = None;
    let mut end = None;
    let mut valid_from_column = "valid_from".to_owned();
    let mut valid_to_column = "valid_to".to_owned();

    for part in parts {
        let (key, value) = part.split_once('=')?;
        let key = key.trim();
        let value = value.trim();
        match key {
            "return" | "return_column" => return_column = Some(strip_selection_quotes(value)),
            "start" => start = Some(value.to_owned()),
            "end" => end = Some(value.to_owned()),
            "valid_from_column" => valid_from_column = strip_selection_quotes(value),
            "valid_to_column" => valid_to_column = strip_selection_quotes(value),
            _ => equality_filters.push((key.to_owned(), value.to_owned())),
        }
    }

    Some(TableSelectionSpec {
        table,
        return_column: return_column.unwrap_or_else(|| "id".to_owned()),
        equality_filters,
        start,
        end,
        valid_from_column,
        valid_to_column,
    })
}

fn table_selection_row_matches(
    table: &RuntimeTable,
    row: usize,
    equality_filters: &[(String, String)],
    spec: &TableSelectionSpec,
    start: &Option<String>,
    end: &Option<String>,
) -> bool {
    for (column, expected) in equality_filters {
        let Some(actual) = table_column_value(table, column, row) else {
            return false;
        };
        if actual.trim() != expected.trim() {
            return false;
        }
    }
    if let Some(start) = start {
        let Some(valid_from) = table_column_value(table, &spec.valid_from_column, row) else {
            return false;
        };
        if table_selection_value_after(&valid_from, start) {
            return false;
        }
    }
    if let Some(end) = end {
        let Some(valid_to) = table_column_value(table, &spec.valid_to_column, row) else {
            return false;
        };
        let valid_to = valid_to.trim();
        if !selection_value_is_none(valid_to) && table_selection_value_before(valid_to, end) {
            return false;
        }
    }
    true
}

fn table_selection_filters(
    table: &RuntimeTable,
    row: Option<usize>,
    equality_filters: &[(String, String)],
    spec: &TableSelectionSpec,
    start: &Option<String>,
    end: &Option<String>,
) -> Vec<RuntimeTableSelectionFilter> {
    let mut filters = Vec::new();
    for (column, expected) in equality_filters {
        let matched = row
            .and_then(|row| table_column_value(table, column, row))
            .is_some_and(|actual| actual.trim() == expected.trim());
        filters.push(RuntimeTableSelectionFilter {
            column: column.clone(),
            operator: "==".to_owned(),
            value: expected.clone(),
            matched,
        });
    }
    if let Some(start) = start {
        let matched = row
            .and_then(|row| table_column_value(table, &spec.valid_from_column, row))
            .is_some_and(|actual| !table_selection_value_after(&actual, start));
        filters.push(RuntimeTableSelectionFilter {
            column: spec.valid_from_column.clone(),
            operator: "<=".to_owned(),
            value: start.clone(),
            matched,
        });
    }
    if let Some(end) = end {
        let matched = row
            .and_then(|row| table_column_value(table, &spec.valid_to_column, row))
            .is_some_and(|actual| {
                let actual = actual.trim();
                selection_value_is_none(actual) || !table_selection_value_before(actual, end)
            });
        filters.push(RuntimeTableSelectionFilter {
            column: spec.valid_to_column.clone(),
            operator: "is_none_or_>=".to_owned(),
            value: end.clone(),
            matched,
        });
    }
    filters
}

fn table_selection_row_values(table: &RuntimeTable, row: usize) -> Vec<RuntimeTableSelectionValue> {
    table
        .columns
        .iter()
        .filter_map(|column| {
            table_column_value(table, &column.name, row).map(|value| RuntimeTableSelectionValue {
                column: column.name.clone(),
                value,
            })
        })
        .collect()
}

fn table_column_value(table: &RuntimeTable, column_name: &str, row: usize) -> Option<String> {
    let column = table
        .columns
        .iter()
        .find(|column| column.name == column_name)?;
    match &column.values {
        RuntimeValues::Text(values) => values.get(row).cloned(),
        RuntimeValues::Number(values) => values
            .get(row)
            .and_then(|value| value.map(|value| value.to_string()))
            .or_else(|| Some(String::new())),
    }
}

fn resolve_table_selection_value(value: &str, report: &CheckReport) -> Option<String> {
    let value = value.trim();
    if let Some(inner) = strip_call_inner(value, "date") {
        return resolve_table_selection_date(inner, report);
    }
    if let Some(arg_name) = value.strip_prefix("args.") {
        return report
            .semantic_program
            .arg_values
            .iter()
            .find(|arg| arg.name == arg_name.trim())
            .map(|arg| arg.value.clone());
    }
    Some(strip_selection_quotes(value))
}

fn resolve_table_selection_date(inner: &str, report: &CheckReport) -> Option<String> {
    let parts = split_selection_top_level(inner, ',');
    if parts.len() != 3 {
        return None;
    }
    let year = resolve_table_selection_value(&parts[0], report)?
        .parse::<i32>()
        .ok()?;
    let month = resolve_table_selection_value(&parts[1], report)?
        .parse::<u32>()
        .ok()?;
    let day = resolve_table_selection_value(&parts[2], report)?
        .parse::<u32>()
        .ok()?;
    if !(1..=12).contains(&month) || !(1..=31).contains(&day) {
        return None;
    }
    Some(format!("{year:04}-{month:02}-{day:02}"))
}

fn table_selection_value_after(actual: &str, expected: &str) -> bool {
    match (
        table_selection_date_prefix(actual),
        table_selection_date_prefix(expected),
    ) {
        (Some(actual), Some(expected)) => actual > expected,
        _ => actual.trim() > expected.trim(),
    }
}

fn table_selection_value_before(actual: &str, expected: &str) -> bool {
    match (
        table_selection_date_prefix(actual),
        table_selection_date_prefix(expected),
    ) {
        (Some(actual), Some(expected)) => actual < expected,
        _ => actual.trim() < expected.trim(),
    }
}

fn table_selection_date_prefix(value: &str) -> Option<&str> {
    let value = value.trim();
    let date = value.get(..10)?;
    let bytes = date.as_bytes();
    if bytes.len() == 10
        && bytes[0].is_ascii_digit()
        && bytes[1].is_ascii_digit()
        && bytes[2].is_ascii_digit()
        && bytes[3].is_ascii_digit()
        && bytes[4] == b'-'
        && bytes[5].is_ascii_digit()
        && bytes[6].is_ascii_digit()
        && bytes[7] == b'-'
        && bytes[8].is_ascii_digit()
        && bytes[9].is_ascii_digit()
    {
        Some(date)
    } else {
        None
    }
}

fn strip_call_inner<'a>(expression: &'a str, name: &str) -> Option<&'a str> {
    let expression = expression.trim();
    let prefix = format!("{name}(");
    expression
        .strip_prefix(&prefix)
        .and_then(|value| value.strip_suffix(')'))
        .map(str::trim)
}

fn split_selection_top_level(expression: &str, delimiter: char) -> Vec<String> {
    let mut parts = Vec::new();
    let mut depth = 0i32;
    let mut start = 0usize;
    for (index, character) in expression.char_indices() {
        match character {
            '(' | '[' | '{' => depth += 1,
            ')' | ']' | '}' => depth -= 1,
            other if other == delimiter && depth == 0 => {
                parts.push(expression[start..index].trim().to_owned());
                start = index + other.len_utf8();
            }
            _ => {}
        }
    }
    let tail = expression[start..].trim();
    if !tail.is_empty() {
        parts.push(tail.to_owned());
    }
    parts
}

fn strip_selection_quotes(value: &str) -> String {
    let trimmed = value.trim();
    trimmed
        .strip_prefix('"')
        .and_then(|value| value.strip_suffix('"'))
        .unwrap_or(trimmed)
        .to_owned()
}

fn selection_value_is_none(value: &str) -> bool {
    let value = value.trim();
    value.is_empty() || value.eq_ignore_ascii_case("none") || value.eq_ignore_ascii_case("null")
}

#[derive(Clone, Debug)]
struct TableTransformRows {
    base_table: String,
    schema_name: Option<String>,
    rows: Vec<usize>,
}

fn materialize_table_transforms(
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Vec<RuntimeTableTransform> {
    let mut records = Vec::new();
    let mut transform_rows: HashMap<String, TableTransformRows> = HashMap::new();

    for transform in &report.semantic_program.table_transforms {
        match transform.operation.as_str() {
            "filter" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                let predicates = runtime_table_transform_predicates(
                    report,
                    Some(table),
                    &source_rows,
                    &transform.predicates,
                );
                let row_diagnostics =
                    table_transform_row_diagnostics(report, table, &source_rows, transform);
                let matched_rows = row_diagnostics
                    .iter()
                    .filter(|diagnostic| diagnostic.status == "matched")
                    .map(|diagnostic| diagnostic.row_index.saturating_sub(1))
                    .collect::<Vec<_>>();
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: table.binding.clone(),
                        schema_name: schema_name.clone(),
                        rows: matched_rows.clone(),
                    },
                );
                records.push(RuntimeTableTransform {
                    binding: transform.binding.clone(),
                    operation: transform.operation.clone(),
                    source_table: transform.source_table.clone(),
                    secondary_table: transform.secondary_table.clone(),
                    schema_name,
                    input_row_count: source_rows.len(),
                    secondary_input_row_count: None,
                    output_row_count: matched_rows.len(),
                    matched_row_indices: one_based_rows(&matched_rows),
                    selected_columns: Vec::new(),
                    sort_keys: Vec::new(),
                    derived_columns: Vec::new(),
                    predicates,
                    join_keys: Vec::new(),
                    row_diagnostics,
                    status: "filtered".to_owned(),
                    reason: if transform.predicates.is_empty() {
                        "no predicates; retained all source rows".to_owned()
                    } else {
                        "retained rows matching all predicates".to_owned()
                    },
                    line: transform.line,
                });
            }
            "select" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: table.binding.clone(),
                        schema_name: schema_name.clone(),
                        rows: source_rows.clone(),
                    },
                );
                records.push(RuntimeTableTransform {
                    binding: transform.binding.clone(),
                    operation: transform.operation.clone(),
                    source_table: transform.source_table.clone(),
                    secondary_table: transform.secondary_table.clone(),
                    schema_name,
                    input_row_count: source_rows.len(),
                    secondary_input_row_count: None,
                    output_row_count: source_rows.len(),
                    matched_row_indices: one_based_rows(&source_rows),
                    selected_columns: runtime_table_columns(&transform.selected_columns),
                    sort_keys: Vec::new(),
                    derived_columns: Vec::new(),
                    predicates: Vec::new(),
                    join_keys: Vec::new(),
                    row_diagnostics: retained_row_diagnostics(
                        &source_rows,
                        "row retained by column selection",
                    ),
                    status: "selected_columns".to_owned(),
                    reason: if transform.selected_columns.is_empty() {
                        "no selected columns recorded".to_owned()
                    } else {
                        "recorded selected table columns".to_owned()
                    },
                    line: transform.line,
                });
            }
            "derive" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: table.binding.clone(),
                        schema_name: schema_name.clone(),
                        rows: source_rows.clone(),
                    },
                );
                records.push(RuntimeTableTransform {
                    binding: transform.binding.clone(),
                    operation: transform.operation.clone(),
                    source_table: transform.source_table.clone(),
                    secondary_table: transform.secondary_table.clone(),
                    schema_name,
                    input_row_count: source_rows.len(),
                    secondary_input_row_count: None,
                    output_row_count: source_rows.len(),
                    matched_row_indices: one_based_rows(&source_rows),
                    selected_columns: Vec::new(),
                    sort_keys: Vec::new(),
                    derived_columns: runtime_table_derived_columns(&transform.derived_columns),
                    predicates: Vec::new(),
                    join_keys: Vec::new(),
                    row_diagnostics: retained_row_diagnostics(
                        &source_rows,
                        "row retained by derived-column transform",
                    ),
                    status: "derived_columns".to_owned(),
                    reason: if transform.derived_columns.is_empty() {
                        "no derived columns recorded".to_owned()
                    } else {
                        "recorded derived table columns".to_owned()
                    },
                    line: transform.line,
                });
            }
            "sort" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                let sorted_rows = sorted_table_transform_rows(table, &source_rows, transform);
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: table.binding.clone(),
                        schema_name: schema_name.clone(),
                        rows: sorted_rows.clone(),
                    },
                );
                records.push(RuntimeTableTransform {
                    binding: transform.binding.clone(),
                    operation: transform.operation.clone(),
                    source_table: transform.source_table.clone(),
                    secondary_table: transform.secondary_table.clone(),
                    schema_name,
                    input_row_count: source_rows.len(),
                    secondary_input_row_count: None,
                    output_row_count: sorted_rows.len(),
                    matched_row_indices: one_based_rows(&sorted_rows),
                    selected_columns: Vec::new(),
                    sort_keys: runtime_table_sort_keys(&transform.sort_keys),
                    derived_columns: Vec::new(),
                    predicates: Vec::new(),
                    join_keys: Vec::new(),
                    row_diagnostics: retained_row_diagnostics(
                        &sorted_rows,
                        "row retained after sort",
                    ),
                    status: "sorted".to_owned(),
                    reason: if transform.sort_keys.is_empty() {
                        "no sort keys recorded".to_owned()
                    } else {
                        "ordered rows by sort keys".to_owned()
                    },
                    line: transform.line,
                });
            }
            "require_one" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                let (status, output_row_count, reason) = match source_rows.len() {
                    0 => (
                        "no_match",
                        0,
                        "source table transform produced no rows".to_owned(),
                    ),
                    1 => (
                        "selected",
                        1,
                        "source table transform produced exactly one row".to_owned(),
                    ),
                    _ => (
                        "multiple_matches",
                        0,
                        "source table transform produced multiple rows".to_owned(),
                    ),
                };
                records.push(RuntimeTableTransform {
                    binding: transform.binding.clone(),
                    operation: transform.operation.clone(),
                    source_table: transform.source_table.clone(),
                    secondary_table: transform.secondary_table.clone(),
                    schema_name,
                    input_row_count: source_rows.len(),
                    secondary_input_row_count: None,
                    output_row_count,
                    matched_row_indices: one_based_rows(&source_rows),
                    selected_columns: Vec::new(),
                    sort_keys: Vec::new(),
                    derived_columns: Vec::new(),
                    predicates: runtime_table_transform_predicates(
                        report,
                        Some(table),
                        &source_rows,
                        &transform.predicates,
                    ),
                    join_keys: Vec::new(),
                    row_diagnostics: require_one_row_diagnostics(&source_rows, status),
                    status: status.to_owned(),
                    reason,
                    line: transform.line,
                });
            }
            "join" => {
                let Some(secondary_table) = transform.secondary_table.as_deref() else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                let Some((left_table, left_rows, left_schema_name)) =
                    resolve_table_transform_source(
                        tables,
                        &transform_rows,
                        &transform.source_table,
                    )
                else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                let Some((right_table, right_rows, right_schema_name)) =
                    resolve_table_transform_source(tables, &transform_rows, secondary_table)
                else {
                    records.push(missing_source_table_transform(report, transform));
                    continue;
                };
                let joined_pairs = join_table_transform_pairs(
                    left_table,
                    &left_rows,
                    right_table,
                    &right_rows,
                    transform,
                );
                let mut matched_left_rows = joined_pairs
                    .iter()
                    .map(|(left_row, _right_row)| *left_row)
                    .collect::<HashSet<_>>()
                    .into_iter()
                    .collect::<Vec<_>>();
                matched_left_rows.sort_unstable();
                let schema_name = transform.schema_name.clone().or_else(|| {
                    left_schema_name
                        .zip(right_schema_name)
                        .map(|(left, right)| format!("{left}+{right}"))
                });
                records.push(RuntimeTableTransform {
                    binding: transform.binding.clone(),
                    operation: transform.operation.clone(),
                    source_table: transform.source_table.clone(),
                    secondary_table: transform.secondary_table.clone(),
                    schema_name,
                    input_row_count: left_rows.len(),
                    secondary_input_row_count: Some(right_rows.len()),
                    output_row_count: joined_pairs.len(),
                    matched_row_indices: one_based_rows(&matched_left_rows),
                    selected_columns: Vec::new(),
                    sort_keys: Vec::new(),
                    derived_columns: Vec::new(),
                    predicates: Vec::new(),
                    join_keys: runtime_table_join_keys(
                        left_table,
                        &left_rows,
                        right_table,
                        &right_rows,
                        &transform.join_keys,
                    ),
                    row_diagnostics: join_row_diagnostics(
                        left_table,
                        &left_rows,
                        right_table,
                        &right_rows,
                        &joined_pairs,
                        transform,
                    ),
                    status: "joined".to_owned(),
                    reason: if transform.join_keys.is_empty() {
                        "no join keys; no joined rows materialized".to_owned()
                    } else {
                        "matched rows on join keys".to_owned()
                    },
                    line: transform.line,
                });
            }
            _ => records.push(RuntimeTableTransform {
                binding: transform.binding.clone(),
                operation: transform.operation.clone(),
                source_table: transform.source_table.clone(),
                secondary_table: transform.secondary_table.clone(),
                schema_name: transform.schema_name.clone(),
                input_row_count: 0,
                secondary_input_row_count: None,
                output_row_count: 0,
                matched_row_indices: Vec::new(),
                selected_columns: runtime_table_columns(&transform.selected_columns),
                sort_keys: runtime_table_sort_keys(&transform.sort_keys),
                derived_columns: runtime_table_derived_columns(&transform.derived_columns),
                predicates: runtime_table_transform_predicates(
                    report,
                    None,
                    &[],
                    &transform.predicates,
                ),
                join_keys: Vec::new(),
                row_diagnostics: Vec::new(),
                status: "unsupported".to_owned(),
                reason: "unsupported table transform operation".to_owned(),
                line: transform.line,
            }),
        }
    }

    records
}

fn materialize_table_transform_tables(
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Vec<RuntimeTable> {
    let mut available_tables = tables.to_vec();
    let mut materialized_tables = Vec::new();
    let mut transform_rows: HashMap<String, TableTransformRows> = HashMap::new();

    for transform in &report.semantic_program.table_transforms {
        match transform.operation.as_str() {
            "filter" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    &available_tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    continue;
                };
                let row_diagnostics =
                    table_transform_row_diagnostics(report, table, &source_rows, transform);
                let matched_rows = row_diagnostics
                    .iter()
                    .filter(|diagnostic| diagnostic.status == "matched")
                    .map(|diagnostic| diagnostic.row_index.saturating_sub(1))
                    .collect::<Vec<_>>();
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: table.binding.clone(),
                        schema_name,
                        rows: matched_rows,
                    },
                );
            }
            "select" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    &available_tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    continue;
                };
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: table.binding.clone(),
                        schema_name,
                        rows: source_rows,
                    },
                );
            }
            "sort" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    &available_tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    continue;
                };
                let sorted_rows = sorted_table_transform_rows(table, &source_rows, transform);
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: table.binding.clone(),
                        schema_name,
                        rows: sorted_rows,
                    },
                );
            }
            "derive" => {
                let Some((table, source_rows, schema_name)) = resolve_table_transform_source(
                    &available_tables,
                    &transform_rows,
                    &transform.source_table,
                ) else {
                    continue;
                };
                let source_table = table.clone();
                let Some(derived_table) =
                    materialize_derived_table(transform, &source_table, &source_rows, schema_name)
                else {
                    continue;
                };
                let derived_rows = (0..derived_table.row_count).collect::<Vec<_>>();
                transform_rows.insert(
                    transform.binding.clone(),
                    TableTransformRows {
                        base_table: derived_table.binding.clone(),
                        schema_name: Some(derived_table.schema_name.clone()),
                        rows: derived_rows,
                    },
                );
                available_tables.push(derived_table.clone());
                materialized_tables.push(derived_table);
            }
            _ => {}
        }
    }

    materialized_tables
}

fn materialize_derived_table(
    transform: &eng_compiler::TableTransformInfo,
    source_table: &RuntimeTable,
    source_rows: &[usize],
    _source_schema_name: Option<String>,
) -> Option<RuntimeTable> {
    let accepted_columns = transform
        .derived_columns
        .iter()
        .filter(|column| column.status == "accepted")
        .collect::<Vec<_>>();
    if accepted_columns.is_empty() {
        return None;
    }

    let mut table = RuntimeTable {
        binding: transform.binding.clone(),
        schema_name: transform
            .schema_name
            .clone()
            .unwrap_or_else(|| "DerivedTable".to_owned()),
        source: format!("derive {} column", transform.source_table),
        source_hash: None,
        row_count: source_rows.len(),
        columns: source_table
            .columns
            .iter()
            .map(|column| runtime_column_rows(column, source_rows))
            .collect(),
        parse_failures: runtime_parse_failures_for_rows(&source_table.parse_failures, source_rows),
        line: transform.line,
    };

    for column in accepted_columns {
        let derived_column = materialize_derived_column(column, &table);
        table.columns.push(derived_column);
    }

    let hash_payload = derived_table_hash_payload(transform, &table);
    table.source_hash = Some(stable_hash_text(&hash_payload));
    Some(table)
}

fn runtime_column_rows(column: &RuntimeColumn, source_rows: &[usize]) -> RuntimeColumn {
    if is_identity_rows(source_rows, column.len()) {
        return column.clone();
    }

    let values = match &column.values {
        RuntimeValues::Text(values) => RuntimeValues::Text(
            source_rows
                .iter()
                .map(|row| values.get(*row).cloned().unwrap_or_default())
                .collect(),
        ),
        RuntimeValues::Number(values) => RuntimeValues::Number(
            source_rows
                .iter()
                .map(|row| values.get(*row).copied().flatten())
                .collect(),
        ),
    };
    let canonical_values = source_rows
        .iter()
        .filter_map(|row| column.canonical_values.get(*row).copied())
        .collect::<Vec<_>>();
    let missing_count = match &values {
        RuntimeValues::Text(values) => values
            .iter()
            .filter(|value| value.trim().is_empty())
            .count(),
        RuntimeValues::Number(values) => values.iter().filter(|value| value.is_none()).count(),
    };
    RuntimeColumn {
        name: column.name.clone(),
        type_name: column.type_name.clone(),
        unit: column.unit.clone(),
        canonical_unit: column.canonical_unit.clone(),
        is_index: column.is_index,
        values,
        canonical_values,
        missing_count,
        conversion_failures: runtime_conversion_failures_for_rows(
            &column.conversion_failures,
            source_rows,
        ),
    }
}

fn is_identity_rows(rows: &[usize], len: usize) -> bool {
    rows.len() == len && rows.iter().enumerate().all(|(index, row)| *row == index)
}

fn runtime_parse_failures_for_rows(
    failures: &[RuntimeParseFailure],
    source_rows: &[usize],
) -> Vec<RuntimeParseFailure> {
    failures
        .iter()
        .filter_map(|failure| {
            remapped_source_row(failure.row, source_rows).map(|row| RuntimeParseFailure {
                row,
                column: failure.column.clone(),
                value: failure.value.clone(),
                message: failure.message.clone(),
            })
        })
        .collect()
}

fn runtime_conversion_failures_for_rows(
    failures: &[RuntimeConversionFailure],
    source_rows: &[usize],
) -> Vec<RuntimeConversionFailure> {
    failures
        .iter()
        .filter_map(|failure| {
            remapped_source_row(failure.row, source_rows).map(|row| RuntimeConversionFailure {
                row,
                column: failure.column.clone(),
                value: failure.value.clone(),
                source_unit: failure.source_unit.clone(),
                target_unit: failure.target_unit.clone(),
                message: failure.message.clone(),
            })
        })
        .collect()
}

fn remapped_source_row(row: usize, source_rows: &[usize]) -> Option<usize> {
    let zero_based = row.checked_sub(2)?;
    source_rows
        .iter()
        .position(|source_row| *source_row == zero_based)
        .map(|index| index + 2)
}

fn materialize_derived_column(
    column: &eng_compiler::TableDerivedColumnInfo,
    table: &RuntimeTable,
) -> RuntimeColumn {
    let Some(expression) = parse_derived_column_expression(column, table) else {
        return missing_derived_column(column, table.row_count);
    };
    let referenced_symbols = expression.referenced_symbols();
    let mut values = Vec::with_capacity(table.row_count);
    for row in 0..table.row_count {
        let Some(symbols) = table_numeric_symbols_for_row(table, row, &referenced_symbols) else {
            values.push(None);
            continue;
        };
        values.push(
            expression
                .evaluate(&symbols)
                .ok()
                .filter(|value| value.is_finite()),
        );
    }
    let missing_count = values.iter().filter(|value| value.is_none()).count();
    let unit = derived_column_unit(&expression, column, table);
    RuntimeColumn {
        name: column.name.clone(),
        type_name: unit.quantity_kind,
        unit: Some(unit.display_unit),
        canonical_unit: Some(unit.canonical_unit),
        is_index: false,
        values: RuntimeValues::Number(values.clone()),
        canonical_values: values,
        missing_count,
        conversion_failures: Vec::new(),
    }
}

fn parse_derived_column_expression(
    column: &eng_compiler::TableDerivedColumnInfo,
    table: &RuntimeTable,
) -> Option<ParsedArithmeticExpression> {
    let symbols = table_numeric_symbol_defaults(table);
    let symbol_units = table_numeric_symbol_units(table);
    let mut ignore_units = |value: f64, _unit: Option<&str>| Ok(value);
    parse_arithmetic_expression_with_symbol_metadata_and_unit_converter(
        &column.expression,
        &symbols,
        &symbol_units,
        &mut ignore_units,
        ArithmeticExpressionProfile::SOURCE_RESIDUAL,
    )
    .ok()
}

fn table_numeric_symbol_defaults(table: &RuntimeTable) -> HashMap<String, f64> {
    table
        .columns
        .iter()
        .filter(|column| matches!(column.values, RuntimeValues::Number(_)))
        .map(|column| {
            (
                column.name.clone(),
                numeric_column_value(column, 0).unwrap_or(0.0),
            )
        })
        .collect()
}

fn table_numeric_symbol_units(table: &RuntimeTable) -> HashMap<String, ArithmeticUnitMetadata> {
    table
        .columns
        .iter()
        .filter(|column| matches!(column.values, RuntimeValues::Number(_)))
        .map(|column| {
            let display_unit = column
                .unit
                .clone()
                .or_else(|| column.canonical_unit.clone())
                .unwrap_or_else(|| "1".to_owned());
            let canonical_unit = column
                .canonical_unit
                .clone()
                .unwrap_or_else(|| display_unit.clone());
            (
                column.name.clone(),
                ArithmeticUnitMetadata {
                    display_unit,
                    canonical_unit,
                    quantity_kind: column.type_name.clone(),
                },
            )
        })
        .collect()
}

fn table_numeric_symbols_for_row(
    table: &RuntimeTable,
    row: usize,
    referenced_symbols: &HashSet<String>,
) -> Option<HashMap<String, f64>> {
    let mut symbols = HashMap::new();
    for column in table
        .columns
        .iter()
        .filter(|column| matches!(column.values, RuntimeValues::Number(_)))
    {
        let Some(value) = numeric_column_value(column, row) else {
            if referenced_symbols.contains(&column.name) {
                return None;
            }
            continue;
        };
        symbols.insert(column.name.clone(), value);
    }
    if referenced_symbols
        .iter()
        .all(|symbol| symbols.contains_key(symbol))
    {
        Some(symbols)
    } else {
        None
    }
}

fn derived_column_unit(
    expression: &ParsedArithmeticExpression,
    column: &eng_compiler::TableDerivedColumnInfo,
    table: &RuntimeTable,
) -> ArithmeticUnitMetadata {
    expression
        .root_unit
        .clone()
        .or_else(|| {
            column
                .source_columns
                .first()
                .and_then(|name| table.columns.iter().find(|source| source.name == *name))
                .map(column_unit_metadata)
        })
        .unwrap_or_else(dimensionless_unit_metadata)
}

fn column_unit_metadata(column: &RuntimeColumn) -> ArithmeticUnitMetadata {
    let display_unit = column
        .unit
        .clone()
        .or_else(|| column.canonical_unit.clone())
        .unwrap_or_else(|| "1".to_owned());
    ArithmeticUnitMetadata {
        canonical_unit: column
            .canonical_unit
            .clone()
            .unwrap_or_else(|| display_unit.clone()),
        display_unit,
        quantity_kind: column.type_name.clone(),
    }
}

fn dimensionless_unit_metadata() -> ArithmeticUnitMetadata {
    ArithmeticUnitMetadata {
        display_unit: "1".to_owned(),
        canonical_unit: "1".to_owned(),
        quantity_kind: "DimensionlessNumber".to_owned(),
    }
}

fn missing_derived_column(
    column: &eng_compiler::TableDerivedColumnInfo,
    row_count: usize,
) -> RuntimeColumn {
    RuntimeColumn {
        name: column.name.clone(),
        type_name: "DimensionlessNumber".to_owned(),
        unit: Some("1".to_owned()),
        canonical_unit: Some("1".to_owned()),
        is_index: false,
        values: RuntimeValues::Number(vec![None; row_count]),
        canonical_values: vec![None; row_count],
        missing_count: row_count,
        conversion_failures: Vec::new(),
    }
}

fn derived_table_hash_payload(
    transform: &eng_compiler::TableTransformInfo,
    table: &RuntimeTable,
) -> String {
    let mut payload = format!(
        "{}|{}|{}|{}",
        transform.binding, transform.operation, transform.source_table, table.row_count
    );
    for column in &transform.derived_columns {
        payload.push_str(&format!(
            "|derive:{}:{}:{}",
            column.name, column.expression, column.status
        ));
    }
    for row in 0..table.row_count {
        payload.push('|');
        payload.push_str(&format!("row={row}"));
        for column in &table.columns {
            payload.push_str(&format!(
                ";{}={}",
                column.name,
                table_cell_text(column, row)
            ));
        }
    }
    payload
}

fn resolve_table_transform_source<'a>(
    tables: &'a [RuntimeTable],
    transform_rows: &HashMap<String, TableTransformRows>,
    source: &str,
) -> Option<(&'a RuntimeTable, Vec<usize>, Option<String>)> {
    if let Some(table) = tables.iter().find(|table| table.binding == source) {
        return Some((
            table,
            (0..table.row_count).collect(),
            Some(table.schema_name.clone()),
        ));
    }
    if let Some(rows) = transform_rows.get(source) {
        let table = tables
            .iter()
            .find(|table| table.binding == rows.base_table)?;
        return Some((
            table,
            rows.rows.clone(),
            rows.schema_name
                .clone()
                .or_else(|| Some(table.schema_name.clone())),
        ));
    }
    let table = tables.iter().find(|table| table.binding == source)?;
    Some((
        table,
        (0..table.row_count).collect(),
        Some(table.schema_name.clone()),
    ))
}

fn missing_source_table_transform(
    report: &CheckReport,
    transform: &eng_compiler::TableTransformInfo,
) -> RuntimeTableTransform {
    RuntimeTableTransform {
        binding: transform.binding.clone(),
        operation: transform.operation.clone(),
        source_table: transform.source_table.clone(),
        secondary_table: transform.secondary_table.clone(),
        schema_name: transform.schema_name.clone(),
        input_row_count: 0,
        secondary_input_row_count: None,
        output_row_count: 0,
        matched_row_indices: Vec::new(),
        selected_columns: runtime_table_columns(&transform.selected_columns),
        sort_keys: runtime_table_sort_keys(&transform.sort_keys),
        derived_columns: runtime_table_derived_columns(&transform.derived_columns),
        predicates: runtime_table_transform_predicates(report, None, &[], &transform.predicates),
        join_keys: runtime_table_join_keys_empty(&transform.join_keys),
        row_diagnostics: Vec::new(),
        status: "missing_source".to_owned(),
        reason: "source table or table transform was not materialized".to_owned(),
        line: transform.line,
    }
}

fn runtime_table_columns(columns: &[eng_compiler::TableColumnInfo]) -> Vec<RuntimeTableColumn> {
    columns
        .iter()
        .map(|column| RuntimeTableColumn {
            name: column.name.clone(),
            status: column.status.clone(),
            line: column.line,
        })
        .collect()
}

fn runtime_table_sort_keys(keys: &[eng_compiler::TableSortKeyInfo]) -> Vec<RuntimeTableSortKey> {
    keys.iter()
        .map(|key| RuntimeTableSortKey {
            column: key.column.clone(),
            direction: key.direction.clone(),
            status: key.status.clone(),
            line: key.line,
        })
        .collect()
}

fn runtime_table_derived_columns(
    columns: &[eng_compiler::TableDerivedColumnInfo],
) -> Vec<RuntimeTableDerivedColumn> {
    columns
        .iter()
        .map(|column| RuntimeTableDerivedColumn {
            name: column.name.clone(),
            expression: column.expression.clone(),
            source_columns: column.source_columns.clone(),
            status: column.status.clone(),
            line: column.line,
        })
        .collect()
}

fn sorted_table_transform_rows(
    table: &RuntimeTable,
    source_rows: &[usize],
    transform: &eng_compiler::TableTransformInfo,
) -> Vec<usize> {
    let mut rows = source_rows.to_vec();
    rows.sort_by(|left_row, right_row| {
        for key in transform
            .sort_keys
            .iter()
            .filter(|key| key.status == "accepted")
        {
            let ordering = table_sort_key_ordering(table, *left_row, *right_row, key);
            if ordering != Ordering::Equal {
                return if key.direction == "desc" {
                    ordering.reverse()
                } else {
                    ordering
                };
            }
        }
        Ordering::Equal
    });
    rows
}

fn table_sort_key_ordering(
    table: &RuntimeTable,
    left_row: usize,
    right_row: usize,
    key: &eng_compiler::TableSortKeyInfo,
) -> Ordering {
    let left_value = table_column_value(table, &key.column, left_row).unwrap_or_default();
    let right_value = table_column_value(table, &key.column, right_row).unwrap_or_default();
    match (
        left_value.trim().parse::<f64>(),
        right_value.trim().parse::<f64>(),
    ) {
        (Ok(left), Ok(right)) => left.total_cmp(&right),
        _ => left_value.cmp(&right_value),
    }
}

fn runtime_table_transform_predicates(
    report: &CheckReport,
    table: Option<&RuntimeTable>,
    rows: &[usize],
    predicates: &[eng_compiler::TablePredicateInfo],
) -> Vec<RuntimeTableTransformPredicate> {
    predicates
        .iter()
        .map(|predicate| {
            let matched_count = table
                .map(|table| {
                    rows.iter()
                        .filter(|row| {
                            table_transform_expression_matches(
                                report,
                                table,
                                **row,
                                &predicate.expression,
                            )
                        })
                        .count()
                })
                .unwrap_or(0);
            RuntimeTableTransformPredicate {
                expression: predicate.expression.clone(),
                column: predicate.column.clone(),
                operator: predicate.operator.clone(),
                value: predicate.value.clone(),
                resolved_value: predicate
                    .value
                    .as_deref()
                    .and_then(|value| resolve_table_selection_value(value, report)),
                matched_count,
                status: predicate.status.clone(),
                line: predicate.line,
            }
        })
        .collect()
}

fn table_transform_row_diagnostics(
    report: &CheckReport,
    table: &RuntimeTable,
    rows: &[usize],
    transform: &eng_compiler::TableTransformInfo,
) -> Vec<RuntimeTableRowDiagnostic> {
    rows.iter()
        .map(|row| {
            let predicates =
                runtime_table_row_predicates(report, table, *row, &transform.predicates);
            let matched = table_transform_row_matches(report, table, *row, transform);
            let status = if matched { "matched" } else { "excluded" };
            let reason = if transform.predicates.is_empty() {
                "no predicates; row retained"
            } else if matched {
                "row matched all predicates"
            } else {
                "one or more predicates did not match"
            };
            RuntimeTableRowDiagnostic {
                row_index: row + 1,
                secondary_row_indices: Vec::new(),
                status: status.to_owned(),
                reason: reason.to_owned(),
                predicates,
            }
        })
        .collect()
}

fn runtime_table_row_predicates(
    report: &CheckReport,
    table: &RuntimeTable,
    row: usize,
    predicates: &[eng_compiler::TablePredicateInfo],
) -> Vec<RuntimeTableRowPredicateDiagnostic> {
    predicates
        .iter()
        .map(|predicate| {
            let matched =
                table_transform_expression_matches(report, table, row, &predicate.expression);
            let actual = predicate
                .column
                .as_deref()
                .and_then(|column| table_column_value(table, column, row));
            let expected = table_row_predicate_expected_value(report, predicate);
            let status = if predicate.status == "accepted" {
                if matched {
                    "matched"
                } else {
                    "not_matched"
                }
            } else {
                predicate.status.as_str()
            };
            RuntimeTableRowPredicateDiagnostic {
                expression: predicate.expression.clone(),
                column: predicate.column.clone(),
                operator: predicate.operator.clone(),
                expected,
                actual,
                matched,
                status: status.to_owned(),
                line: predicate.line,
            }
        })
        .collect()
}

fn table_row_predicate_expected_value(
    report: &CheckReport,
    predicate: &eng_compiler::TablePredicateInfo,
) -> Option<String> {
    match predicate.operator.as_str() {
        "is_none" => Some("none".to_owned()),
        "is_not_none" => Some("not none".to_owned()),
        _ => predicate
            .value
            .as_deref()
            .and_then(|value| resolve_table_selection_value(value, report))
            .or_else(|| predicate.value.clone()),
    }
}

fn retained_row_diagnostics(rows: &[usize], reason: &str) -> Vec<RuntimeTableRowDiagnostic> {
    rows.iter()
        .map(|row| RuntimeTableRowDiagnostic {
            row_index: row + 1,
            secondary_row_indices: Vec::new(),
            status: "retained".to_owned(),
            reason: reason.to_owned(),
            predicates: Vec::new(),
        })
        .collect()
}

fn require_one_row_diagnostics(rows: &[usize], status: &str) -> Vec<RuntimeTableRowDiagnostic> {
    let (row_status, reason) = match status {
        "selected" => ("selected", "require_one selected the only candidate row"),
        "multiple_matches" => (
            "multiple_match",
            "require_one rejected this row because multiple candidates were present",
        ),
        "no_match" => ("excluded", "require_one found no candidate rows"),
        _ => ("excluded", "require_one did not select this row"),
    };
    rows.iter()
        .map(|row| RuntimeTableRowDiagnostic {
            row_index: row + 1,
            secondary_row_indices: Vec::new(),
            status: row_status.to_owned(),
            reason: reason.to_owned(),
            predicates: Vec::new(),
        })
        .collect()
}

fn join_row_diagnostics(
    left_table: &RuntimeTable,
    left_rows: &[usize],
    right_table: &RuntimeTable,
    right_rows: &[usize],
    joined_pairs: &[(usize, usize)],
    transform: &eng_compiler::TableTransformInfo,
) -> Vec<RuntimeTableRowDiagnostic> {
    left_rows
        .iter()
        .map(|left_row| {
            let mut secondary_row_indices = joined_pairs
                .iter()
                .filter_map(|(matched_left, matched_right)| {
                    if matched_left == left_row {
                        Some(matched_right + 1)
                    } else {
                        None
                    }
                })
                .collect::<Vec<_>>();
            secondary_row_indices.sort_unstable();
            secondary_row_indices.dedup();
            let matched = !secondary_row_indices.is_empty();
            RuntimeTableRowDiagnostic {
                row_index: left_row + 1,
                secondary_row_indices,
                status: if matched { "matched" } else { "excluded" }.to_owned(),
                reason: if matched {
                    "row matched one or more secondary rows"
                } else {
                    "row did not match join keys"
                }
                .to_owned(),
                predicates: join_row_key_diagnostics(
                    left_table,
                    *left_row,
                    right_table,
                    right_rows,
                    &transform.join_keys,
                ),
            }
        })
        .collect()
}

fn join_row_key_diagnostics(
    left_table: &RuntimeTable,
    left_row: usize,
    right_table: &RuntimeTable,
    right_rows: &[usize],
    keys: &[eng_compiler::TableJoinKeyInfo],
) -> Vec<RuntimeTableRowPredicateDiagnostic> {
    keys.iter()
        .map(|key| {
            let actual = table_column_value(left_table, &key.left_column, left_row);
            let matched_right_values = right_rows
                .iter()
                .filter(|right_row| {
                    table_join_key_matches(left_table, left_row, right_table, **right_row, key)
                })
                .filter_map(|right_row| {
                    table_column_value(right_table, &key.right_column, *right_row)
                })
                .collect::<Vec<_>>();
            let matched = !matched_right_values.is_empty();
            let status = if key.status == "accepted" {
                if matched {
                    "matched"
                } else {
                    "not_matched"
                }
            } else {
                key.status.as_str()
            };
            RuntimeTableRowPredicateDiagnostic {
                expression: key.expression.clone(),
                column: Some(format!("{}.{}", key.left_table, key.left_column)),
                operator: "join_key".to_owned(),
                expected: if matched_right_values.is_empty() {
                    None
                } else {
                    Some(matched_right_values.join(", "))
                },
                actual,
                matched,
                status: status.to_owned(),
                line: key.line,
            }
        })
        .collect()
}

fn join_table_transform_pairs(
    left_table: &RuntimeTable,
    left_rows: &[usize],
    right_table: &RuntimeTable,
    right_rows: &[usize],
    transform: &eng_compiler::TableTransformInfo,
) -> Vec<(usize, usize)> {
    if transform.join_keys.is_empty() {
        return Vec::new();
    }
    let mut pairs = Vec::new();
    for left_row in left_rows {
        for right_row in right_rows {
            if transform.join_keys.iter().all(|key| {
                table_join_key_matches(left_table, *left_row, right_table, *right_row, key)
            }) {
                pairs.push((*left_row, *right_row));
            }
        }
    }
    pairs
}

fn runtime_table_join_keys(
    left_table: &RuntimeTable,
    left_rows: &[usize],
    right_table: &RuntimeTable,
    right_rows: &[usize],
    keys: &[eng_compiler::TableJoinKeyInfo],
) -> Vec<RuntimeTableJoinKey> {
    keys.iter()
        .map(|key| RuntimeTableJoinKey {
            expression: key.expression.clone(),
            left_table: key.left_table.clone(),
            left_column: key.left_column.clone(),
            right_table: key.right_table.clone(),
            right_column: key.right_column.clone(),
            matched_pair_count: if key.status == "accepted" {
                left_rows
                    .iter()
                    .flat_map(|left_row| {
                        right_rows
                            .iter()
                            .map(move |right_row| (*left_row, *right_row))
                    })
                    .filter(|(left_row, right_row)| {
                        table_join_key_matches(left_table, *left_row, right_table, *right_row, key)
                    })
                    .count()
            } else {
                0
            },
            status: key.status.clone(),
            line: key.line,
        })
        .collect()
}

fn runtime_table_join_keys_empty(
    keys: &[eng_compiler::TableJoinKeyInfo],
) -> Vec<RuntimeTableJoinKey> {
    keys.iter()
        .map(|key| RuntimeTableJoinKey {
            expression: key.expression.clone(),
            left_table: key.left_table.clone(),
            left_column: key.left_column.clone(),
            right_table: key.right_table.clone(),
            right_column: key.right_column.clone(),
            matched_pair_count: 0,
            status: key.status.clone(),
            line: key.line,
        })
        .collect()
}

fn table_join_key_matches(
    left_table: &RuntimeTable,
    left_row: usize,
    right_table: &RuntimeTable,
    right_row: usize,
    key: &eng_compiler::TableJoinKeyInfo,
) -> bool {
    if key.status != "accepted" {
        return false;
    }
    let Some(left_value) = table_column_value(left_table, &key.left_column, left_row) else {
        return false;
    };
    let Some(right_value) = table_column_value(right_table, &key.right_column, right_row) else {
        return false;
    };
    left_value.trim() == right_value.trim()
}

fn table_transform_row_matches(
    report: &CheckReport,
    table: &RuntimeTable,
    row: usize,
    transform: &eng_compiler::TableTransformInfo,
) -> bool {
    transform.predicates.iter().all(|predicate| {
        table_transform_expression_matches(report, table, row, &predicate.expression)
    })
}

fn table_transform_expression_matches(
    report: &CheckReport,
    table: &RuntimeTable,
    row: usize,
    expression: &str,
) -> bool {
    let or_parts = split_table_transform_logical(expression, "or");
    if or_parts.len() > 1 {
        return or_parts
            .iter()
            .any(|part| table_transform_expression_matches(report, table, row, part));
    }
    let and_parts = split_table_transform_logical(expression, "and");
    if and_parts.len() > 1 {
        return and_parts
            .iter()
            .all(|part| table_transform_expression_matches(report, table, row, part));
    }
    table_transform_atom_matches(report, table, row, expression.trim())
}

fn table_transform_atom_matches(
    report: &CheckReport,
    table: &RuntimeTable,
    row: usize,
    expression: &str,
) -> bool {
    let lowered = expression.to_ascii_lowercase();
    if let Some(index) = lowered.find(" is not none") {
        let column = expression[..index].trim();
        if !table_transform_identifier(column) {
            return false;
        }
        return table_column_value(table, column, row)
            .is_some_and(|value| !selection_value_is_none(&value));
    }
    if let Some(index) = lowered.find(" is none") {
        let column = expression[..index].trim();
        if !table_transform_identifier(column) {
            return false;
        }
        return table_column_value(table, column, row)
            .is_some_and(|value| selection_value_is_none(&value));
    }
    for operator in ["==", "!=", "<=", ">=", "<", ">"] {
        if let Some((left, right)) = expression.split_once(operator) {
            let column = left.trim();
            if !table_transform_identifier(column) {
                return false;
            }
            let Some(actual) = table_column_value(table, column, row) else {
                return false;
            };
            let expected = resolve_table_selection_value(right, report)
                .unwrap_or_else(|| strip_selection_quotes(right));
            return table_transform_compare_value(table, column, &actual, &expected, operator);
        }
    }
    false
}

fn table_transform_compare_value(
    table: &RuntimeTable,
    column: &str,
    actual: &str,
    expected: &str,
    operator: &str,
) -> bool {
    if table_column_is_temporal(table, column) {
        return table_transform_temporal_compare(actual, expected, operator);
    }
    match operator {
        "==" => actual.trim() == expected.trim(),
        "!=" => actual.trim() != expected.trim(),
        "<=" => !table_transform_value_after(actual, expected),
        ">=" => !table_transform_value_before(actual, expected),
        "<" => table_transform_value_before(actual, expected),
        ">" => table_transform_value_after(actual, expected),
        _ => false,
    }
}

fn table_column_is_temporal(table: &RuntimeTable, column_name: &str) -> bool {
    table
        .columns
        .iter()
        .find(|column| column.name == column_name)
        .is_some_and(|column| matches!(column.type_name.as_str(), "Date" | "DateTime"))
}

fn table_transform_temporal_compare(actual: &str, expected: &str, operator: &str) -> bool {
    let Some(ordering) = table_temporal_ordering(actual, expected) else {
        return false;
    };
    match operator {
        "==" => ordering == Ordering::Equal,
        "!=" => ordering != Ordering::Equal,
        "<=" => matches!(ordering, Ordering::Less | Ordering::Equal),
        ">=" => matches!(ordering, Ordering::Greater | Ordering::Equal),
        "<" => ordering == Ordering::Less,
        ">" => ordering == Ordering::Greater,
        _ => false,
    }
}

fn table_temporal_ordering(actual: &str, expected: &str) -> Option<Ordering> {
    if let (Some(actual), Some(expected)) = (
        parse_utc_timestamp_seconds(actual.trim()),
        parse_utc_timestamp_seconds(expected.trim()),
    ) {
        return Some(actual.cmp(&expected));
    }
    match (
        table_selection_date_prefix(actual),
        table_selection_date_prefix(expected),
    ) {
        (Some(actual), Some(expected)) => Some(actual.cmp(expected)),
        _ => None,
    }
}

fn table_transform_value_after(actual: &str, expected: &str) -> bool {
    match (
        actual.trim().parse::<f64>().ok(),
        expected.trim().parse::<f64>().ok(),
    ) {
        (Some(actual), Some(expected)) => actual > expected,
        _ => table_selection_value_after(actual, expected),
    }
}

fn table_transform_value_before(actual: &str, expected: &str) -> bool {
    match (
        actual.trim().parse::<f64>().ok(),
        expected.trim().parse::<f64>().ok(),
    ) {
        (Some(actual), Some(expected)) => actual < expected,
        _ => table_selection_value_before(actual, expected),
    }
}

fn split_table_transform_logical<'a>(expression: &'a str, keyword: &str) -> Vec<&'a str> {
    let mut parts = Vec::new();
    let mut depth = 0i32;
    let mut in_string = false;
    let mut previous = '\0';
    let mut start = 0usize;
    for (index, character) in expression.char_indices() {
        if character == '"' && previous != '\\' {
            in_string = !in_string;
        } else if !in_string {
            match character {
                '(' | '[' | '{' => depth += 1,
                ')' | ']' | '}' => depth -= 1,
                _ if depth == 0
                    && table_transform_logical_keyword_at(expression, index, keyword) =>
                {
                    parts.push(expression[start..index].trim());
                    start = index + keyword.len();
                }
                _ => {}
            }
        }
        previous = character;
    }
    let tail = expression[start..].trim();
    if !tail.is_empty() {
        parts.push(tail);
    }
    parts
}

fn table_transform_logical_keyword_at(expression: &str, index: usize, keyword: &str) -> bool {
    let Some(slice) = expression.get(index..index + keyword.len()) else {
        return false;
    };
    if !slice.eq_ignore_ascii_case(keyword) {
        return false;
    }
    let before = expression[..index].chars().next_back();
    let after = expression[index + keyword.len()..].chars().next();
    before.is_none_or(|character| !table_transform_identifier_part(character))
        && after.is_none_or(|character| !table_transform_identifier_part(character))
}

fn table_transform_identifier(value: &str) -> bool {
    let mut chars = value.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    (first.is_ascii_alphabetic() || first == '_') && chars.all(table_transform_identifier_part)
}

fn table_transform_identifier_part(character: char) -> bool {
    character.is_ascii_alphanumeric() || character == '_'
}

fn one_based_rows(rows: &[usize]) -> Vec<usize> {
    rows.iter().map(|row| row + 1).collect()
}

fn materialize_table_diagnostics(
    tables: &[RuntimeTable],
    axes: &[RuntimeTimeAxis],
) -> Vec<RuntimeTableDiagnostic> {
    tables
        .iter()
        .map(|table| {
            let missing_cell_count = table
                .columns
                .iter()
                .map(|column| column.missing_count)
                .sum::<usize>();
            let conversion_failure_count = table
                .columns
                .iter()
                .map(|column| column.conversion_failures.len())
                .sum::<usize>();
            let parse_failure_count = table.parse_failures.len();
            let time_axis = axes
                .iter()
                .find(|axis| axis.source_table == table.binding)
                .map(|axis| RuntimeTableTimeAxisDiagnostic {
                    name: axis.name.clone(),
                    source_column: axis.source_column.clone(),
                    unit: axis.unit.clone(),
                    start: axis.start,
                    end: axis.end,
                    count: axis.count,
                    nominal_step: axis.nominal_step,
                    irregular: axis.irregular,
                    missing_count: axis.missing_count,
                    coverage_status: if axis.irregular || axis.missing_count > 0 {
                        "missing_or_irregular".to_owned()
                    } else {
                        "complete".to_owned()
                    },
                });
            let status = table_diagnostic_status(
                missing_cell_count,
                parse_failure_count,
                conversion_failure_count,
                time_axis.as_ref(),
            );
            RuntimeTableDiagnostic {
                binding: table.binding.clone(),
                schema_name: table.schema_name.clone(),
                source: table.source.clone(),
                source_hash: table.source_hash.clone(),
                row_count: table.row_count,
                column_count: table.columns.len(),
                missing_cell_count,
                parse_failure_count,
                conversion_failure_count,
                columns: table
                    .columns
                    .iter()
                    .map(|column| RuntimeTableColumnDiagnostic {
                        name: column.name.clone(),
                        type_name: column.type_name.clone(),
                        unit: column.unit.clone(),
                        canonical_unit: column.canonical_unit.clone(),
                        is_index: column.is_index,
                        len: column.len(),
                        missing_count: column.missing_count,
                        conversion_failure_count: column.conversion_failures.len(),
                        status: if column.missing_count > 0
                            || !column.conversion_failures.is_empty()
                        {
                            "has_diagnostics".to_owned()
                        } else {
                            "ok".to_owned()
                        },
                    })
                    .collect(),
                time_axis,
                status,
            }
        })
        .collect()
}

fn table_diagnostic_status(
    missing_cell_count: usize,
    parse_failure_count: usize,
    conversion_failure_count: usize,
    time_axis: Option<&RuntimeTableTimeAxisDiagnostic>,
) -> String {
    if parse_failure_count > 0 || conversion_failure_count > 0 {
        "has_parse_or_conversion_diagnostics".to_owned()
    } else if missing_cell_count > 0 {
        "has_missing_cells".to_owned()
    } else if time_axis.is_some_and(|axis| axis.coverage_status != "complete") {
        "time_axis_irregular".to_owned()
    } else {
        "ok".to_owned()
    }
}

fn materialize_explicit_case_tables(
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Vec<RuntimeTable> {
    report
        .inferred_declarations
        .iter()
        .filter(|declaration| declaration.quantity_kind == "Table[Case]")
        .filter_map(|declaration| {
            let source_name = materialize_cases_source_table(&declaration.expression)?;
            let source_table = tables.iter().find(|table| table.binding == source_name)?;
            Some(materialize_explicit_case_table(declaration, source_table))
        })
        .collect()
}

fn materialize_explicit_case_table(
    declaration: &eng_compiler::InferredDeclaration,
    source_table: &RuntimeTable,
) -> RuntimeTable {
    let case_id_column = source_table
        .columns
        .iter()
        .find(|column| column.name.eq_ignore_ascii_case("case_id"));
    let case_id_values = case_id_column.and_then(text_column_values);
    let duplicate_ids = case_id_values
        .map(duplicate_case_ids)
        .unwrap_or_default()
        .into_iter()
        .collect::<HashSet<_>>();

    let mut case_ids = Vec::new();
    let mut case_dirs = Vec::new();
    let mut statuses = Vec::new();
    let mut failure_reasons = Vec::new();
    let mut row_hashes = Vec::new();
    for row_index in 0..source_table.row_count {
        let case_id = case_id_values
            .and_then(|values| values.get(row_index))
            .map(|value| value.trim().to_owned())
            .unwrap_or_default();
        let (status, failure_reason, case_dir) = if case_id.is_empty() {
            (
                "failed",
                "case_id is missing for sample row".to_owned(),
                String::new(),
            )
        } else if duplicate_ids.contains(&case_id) {
            (
                "failed",
                format!(
                    "duplicate case_id `{case_id}` in sample table `{}`",
                    source_table.binding
                ),
                default_case_dir(&case_id),
            )
        } else {
            ("pending", "none".to_owned(), default_case_dir(&case_id))
        };
        case_ids.push(case_id);
        case_dirs.push(case_dir);
        statuses.push(status.to_owned());
        failure_reasons.push(failure_reason);
        row_hashes.push(sample_row_hash(source_table, row_index));
    }

    let source = format!("materialize cases {}", source_table.binding);
    let hash_payload = format!(
        "{}|{}|{}|{}",
        declaration.name,
        source,
        source_table.source_hash.clone().unwrap_or_default(),
        row_hashes.join(",")
    );
    RuntimeTable {
        binding: declaration.name.clone(),
        schema_name: "CaseTable".to_owned(),
        source,
        source_hash: Some(stable_hash_text(&hash_payload)),
        row_count: source_table.row_count,
        columns: runtime_columns_with_overrides(
            &source_table.columns,
            vec![
                text_runtime_column("case_id", "String", case_ids),
                text_runtime_column("case_dir", "DirectoryPath", case_dirs),
                text_runtime_column("status", "String", statuses),
                text_runtime_column("failure_reason", "String", failure_reasons),
                text_runtime_column("sample_row_hash", "String", row_hashes),
            ],
        ),
        parse_failures: source_table.parse_failures.clone(),
        line: declaration.line,
    }
}

fn runtime_columns_with_overrides(
    source_columns: &[RuntimeColumn],
    overrides: Vec<RuntimeColumn>,
) -> Vec<RuntimeColumn> {
    let mut columns = source_columns.to_vec();
    for override_column in overrides {
        if let Some(index) = columns
            .iter()
            .position(|column| column.name.eq_ignore_ascii_case(&override_column.name))
        {
            columns[index] = override_column;
        } else {
            columns.push(override_column);
        }
    }
    columns
}

fn text_runtime_column(name: &str, type_name: &str, values: Vec<String>) -> RuntimeColumn {
    let missing_count = values
        .iter()
        .filter(|value| value.trim().is_empty())
        .count();
    RuntimeColumn {
        name: name.to_owned(),
        type_name: type_name.to_owned(),
        unit: None,
        canonical_unit: None,
        is_index: false,
        values: RuntimeValues::Text(values),
        canonical_values: Vec::new(),
        missing_count,
        conversion_failures: Vec::new(),
    }
}

fn materialize_cases_source_table(expression: &str) -> Option<&str> {
    let source = expression.trim().strip_prefix("materialize cases ")?.trim();
    if is_simple_binding_name(source) {
        Some(source)
    } else {
        None
    }
}

fn materialize_case_apply_output_tables(
    report: &CheckReport,
    tables: &[RuntimeTable],
    result_dir: Option<&Path>,
) -> Vec<RuntimeTable> {
    report
        .inferred_declarations
        .iter()
        .filter(|declaration| declaration.quantity_kind == "Table[CaseOutput]")
        .filter_map(|declaration| {
            let cases_binding = case_apply_cases_binding(&declaration.expression)?;
            let cases_table = tables.iter().find(|table| table.binding == cases_binding)?;
            Some(materialize_case_apply_output_table(
                report,
                declaration,
                cases_table,
                result_dir,
            ))
        })
        .collect()
}

fn materialize_case_apply_output_table(
    report: &CheckReport,
    declaration: &eng_compiler::InferredDeclaration,
    cases_table: &RuntimeTable,
    result_dir: Option<&Path>,
) -> RuntimeTable {
    let options = report
        .semantic_program
        .with_blocks
        .iter()
        .find(|block| block.owner_line == Some(declaration.line))
        .map(|block| block.options.as_slice())
        .unwrap_or(&[]);
    let output_pattern = option_value(options, "output")
        .map(strip_runtime_string_literal)
        .unwrap_or_else(|| "outputs/{case_id}/input.txt".to_owned());
    let template_path = option_value(options, "template")
        .map(|value| case_apply_template_path(value, report))
        .unwrap_or_default();
    let case_ids = text_column_values_by_name(cases_table, "case_id").unwrap_or_default();
    let case_dirs = text_column_values_by_name(cases_table, "case_dir").unwrap_or_default();
    let statuses = text_column_values_by_name(cases_table, "status").unwrap_or_default();

    let mut output_case_ids = Vec::new();
    let mut output_case_dirs = Vec::new();
    let mut output_paths = Vec::new();
    let mut manifest_paths = Vec::new();
    let mut output_statuses = Vec::new();
    for row_index in 0..cases_table.row_count {
        let case_id = case_ids
            .get(row_index)
            .map(|value| value.trim().to_owned())
            .unwrap_or_default();
        let case_dir = case_dirs
            .get(row_index)
            .map(|value| value.trim().to_owned())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| default_case_dir(&case_id));
        let output_path =
            render_case_output_pattern(&output_pattern, &case_id, &case_dir, row_index);
        let manifest_path = format!("{output_path}.render_manifest.json");
        let output_status = if statuses
            .get(row_index)
            .is_some_and(|status| status.trim() == "failed")
        {
            "blocked"
        } else if case_apply_output_is_rendered(result_dir, &output_path, &manifest_path) {
            "rendered"
        } else {
            "planned"
        };
        output_case_ids.push(case_id);
        output_case_dirs.push(case_dir);
        manifest_paths.push(manifest_path);
        output_paths.push(output_path);
        output_statuses.push(output_status.to_owned());
    }
    let hash_payload = format!(
        "{}|{}|{}|{}|{}",
        declaration.name,
        declaration.expression,
        cases_table.source_hash.clone().unwrap_or_default(),
        template_path,
        output_paths.join(",")
    );
    RuntimeTable {
        binding: declaration.name.clone(),
        schema_name: "CaseOutput".to_owned(),
        source: declaration.expression.clone(),
        source_hash: Some(stable_hash_text(&hash_payload)),
        row_count: cases_table.row_count,
        columns: runtime_columns_with_overrides(
            &cases_table.columns,
            vec![
                text_runtime_column("case_id", "String", output_case_ids),
                text_runtime_column("case_dir", "DirectoryPath", output_case_dirs),
                text_runtime_column("case_status", "String", statuses.to_vec()),
                text_runtime_column("output_path", "FilePath", output_paths),
                text_runtime_column("manifest_path", "FilePath", manifest_paths),
                text_runtime_column("status", "String", output_statuses),
                text_runtime_column(
                    "template",
                    "TemplateFile",
                    vec![template_path; cases_table.row_count],
                ),
            ],
        ),
        parse_failures: cases_table.parse_failures.clone(),
        line: declaration.line,
    }
}

fn materialize_case_run_result_tables(
    report: &CheckReport,
    tables: &[RuntimeTable],
    result_dir: Option<&Path>,
) -> Vec<RuntimeTable> {
    report
        .semantic_program
        .case_runs
        .iter()
        .filter(|run| run.status == "declared")
        .filter_map(|run| {
            let source_table = tables
                .iter()
                .find(|table| table.binding == run.source_table)?;
            Some(materialize_case_run_result_table(
                run,
                source_table,
                result_dir,
            ))
        })
        .collect()
}

fn materialize_case_run_result_table(
    run: &eng_compiler::CaseRunInfo,
    source_table: &RuntimeTable,
    result_dir: Option<&Path>,
) -> RuntimeTable {
    let mut table = RuntimeTable {
        binding: run.binding.clone(),
        schema_name: "CaseRunResult".to_owned(),
        source: format!("apply run_case over {}", run.source_table),
        source_hash: None,
        row_count: source_table.row_count,
        columns: source_table.columns.clone(),
        parse_failures: source_table.parse_failures.clone(),
        line: run.line,
    };

    for output in run
        .outputs
        .iter()
        .filter(|output| output.status == "accepted")
    {
        let column = eng_compiler::TableDerivedColumnInfo {
            name: output.name.clone(),
            expression: output.expression.clone(),
            source_columns: output.source_columns.clone(),
            status: output.status.clone(),
            line: output.line,
        };
        let derived = materialize_derived_column(&column, &table);
        table.columns = runtime_columns_with_overrides(&table.columns, vec![derived]);
    }

    let case_ids = text_column_values_by_name(source_table, "case_id").unwrap_or_default();
    let case_dirs = text_column_values_by_name(source_table, "case_dir").unwrap_or_default();
    let source_statuses = text_column_values_by_name(source_table, "status").unwrap_or_default();
    let source_failure_reasons =
        text_column_values_by_name(source_table, "failure_reason").unwrap_or_default();
    let source_output_paths =
        text_column_values_by_name(source_table, "output_path").unwrap_or_default();
    let source_manifest_paths =
        text_column_values_by_name(source_table, "manifest_path").unwrap_or_default();

    let mut output_case_ids = Vec::new();
    let mut output_case_dirs = Vec::new();
    let mut input_statuses = Vec::new();
    let mut input_paths = Vec::new();
    let mut input_manifest_paths = Vec::new();
    let mut result_paths = Vec::new();
    let mut manifest_paths = Vec::new();
    let mut result_hashes = Vec::new();
    let mut failure_reasons = Vec::new();
    let mut statuses = Vec::new();

    for row_index in 0..source_table.row_count {
        let case_id = case_ids.get(row_index).cloned().unwrap_or_default();
        let case_dir = case_dirs
            .get(row_index)
            .cloned()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| default_case_dir(&case_id));
        let input_status = source_statuses.get(row_index).cloned().unwrap_or_default();
        let input_path = source_output_paths
            .get(row_index)
            .cloned()
            .unwrap_or_default();
        let input_manifest_path = source_manifest_paths
            .get(row_index)
            .cloned()
            .unwrap_or_default();
        let result_path =
            render_case_output_pattern(&run.result_path, &case_id, &case_dir, row_index);
        let manifest_path =
            render_case_output_pattern(&run.manifest_path, &case_id, &case_dir, row_index);
        let outputs_complete = run.outputs.iter().all(|output| {
            table
                .columns
                .iter()
                .find(|column| column.name == output.name)
                .and_then(|column| numeric_column_value(column, row_index))
                .is_some_and(f64::is_finite)
        });
        let result_hash = case_run_result_hash(run, &table, row_index);
        let source_blocked = match source_table.schema_name.as_str() {
            "CaseOutput" => input_status == "blocked",
            _ => input_status == "failed" || input_status == "blocked",
        };
        let source_waiting = source_table.schema_name == "CaseOutput"
            && !matches!(input_status.as_str(), "rendered" | "succeeded" | "skipped");
        let artifacts_exist = result_dir.is_some_and(|result_dir| {
            result_relative_file_exists(result_dir, &result_path)
                && result_relative_file_exists(result_dir, &manifest_path)
        });
        let (status, failure_reason) = if source_blocked {
            (
                "blocked",
                source_failure_reasons
                    .get(row_index)
                    .cloned()
                    .filter(|value| !value.trim().is_empty() && value != "none")
                    .unwrap_or_else(|| "case input stage is blocked".to_owned()),
            )
        } else if source_waiting {
            (
                "waiting_input",
                "case input artifact has not been rendered".to_owned(),
            )
        } else if !outputs_complete {
            (
                "failed",
                "one or more native result expressions could not be evaluated".to_owned(),
            )
        } else if artifacts_exist {
            ("succeeded", "none".to_owned())
        } else {
            ("ready", "none".to_owned())
        };

        output_case_ids.push(case_id);
        output_case_dirs.push(case_dir);
        input_statuses.push(input_status);
        input_paths.push(input_path);
        input_manifest_paths.push(input_manifest_path);
        result_paths.push(result_path);
        manifest_paths.push(manifest_path);
        result_hashes.push(result_hash);
        failure_reasons.push(failure_reason);
        statuses.push(status.to_owned());
    }

    table.columns = runtime_columns_with_overrides(
        &table.columns,
        vec![
            text_runtime_column("case_id", "String", output_case_ids),
            text_runtime_column("case_dir", "DirectoryPath", output_case_dirs),
            text_runtime_column("input_status", "String", input_statuses),
            text_runtime_column("input_path", "FilePath", input_paths),
            text_runtime_column("input_manifest_path", "FilePath", input_manifest_paths),
            text_runtime_column("result_path", "FilePath", result_paths),
            text_runtime_column("manifest_path", "FilePath", manifest_paths),
            text_runtime_column("result_hash", "String", result_hashes),
            text_runtime_column("failure_reason", "String", failure_reasons),
            text_runtime_column(
                "runner",
                "String",
                vec![run.runner.clone(); source_table.row_count],
            ),
            text_runtime_column(
                "scheduler",
                "String",
                vec![run.scheduler.clone(); source_table.row_count],
            ),
            text_runtime_column("status", "String", statuses),
        ],
    );
    let mut hash_payload = format!(
        "{}|{}|{}|{}|{}",
        run.binding,
        run.source_table,
        source_table.source_hash.clone().unwrap_or_default(),
        run.runner,
        run.scheduler
    );
    for row in 0..table.row_count {
        hash_payload.push_str(&format!("|row={row}"));
        for column in &table.columns {
            hash_payload.push_str(&format!(
                ";{}={}",
                column.name,
                table_cell_text(column, row)
            ));
        }
    }
    table.source_hash = Some(stable_hash_text(&hash_payload));
    table
}

fn case_run_result_hash(
    run: &eng_compiler::CaseRunInfo,
    table: &RuntimeTable,
    row_index: usize,
) -> String {
    let mut payload = format!(
        "{}|{}|{}",
        run.binding,
        run.source_table,
        text_column_values_by_name(table, "sample_row_hash")
            .and_then(|values| values.get(row_index))
            .cloned()
            .unwrap_or_default()
    );
    for output in &run.outputs {
        let value = table
            .columns
            .iter()
            .find(|column| column.name == output.name)
            .map(|column| table_cell_text(column, row_index))
            .unwrap_or_default();
        payload.push_str(&format!("|{}:{}={}", output.name, output.expression, value));
    }
    stable_hash_text(&payload)
}

fn materialize_case_result_collection_tables(
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Vec<RuntimeTable> {
    report
        .inferred_declarations
        .iter()
        .filter(|declaration| declaration.quantity_kind == "Table[CaseResultCollection]")
        .filter_map(|declaration| {
            let source_binding = collect_results_source_binding(&declaration.expression)?;
            let output_table = tables.iter().find(|table| {
                table.binding == source_binding
                    && matches!(table.schema_name.as_str(), "CaseOutput" | "CaseRunResult")
            })?;
            Some(materialize_case_result_collection_table(
                declaration,
                output_table,
            ))
        })
        .collect()
}

fn materialize_case_result_collection_table(
    declaration: &eng_compiler::InferredDeclaration,
    output_table: &RuntimeTable,
) -> RuntimeTable {
    let case_ids = text_column_values_by_name(output_table, "case_id").unwrap_or_default();
    let case_dirs = text_column_values_by_name(output_table, "case_dir").unwrap_or_default();
    let output_paths = if output_table.schema_name == "CaseRunResult" {
        text_column_values_by_name(output_table, "result_path").unwrap_or_default()
    } else {
        text_column_values_by_name(output_table, "output_path").unwrap_or_default()
    };
    let manifest_paths =
        text_column_values_by_name(output_table, "manifest_path").unwrap_or_default();
    let input_statuses = text_column_values_by_name(output_table, "status").unwrap_or_default();

    let mut collection_case_ids = Vec::new();
    let mut collection_case_dirs = Vec::new();
    let mut collection_output_paths = Vec::new();
    let mut collection_manifest_paths = Vec::new();
    let mut collection_input_statuses = Vec::new();
    let mut collection_statuses = Vec::new();
    for row_index in 0..output_table.row_count {
        let case_id = case_ids.get(row_index).cloned().unwrap_or_default();
        let case_dir = case_dirs.get(row_index).cloned().unwrap_or_default();
        let output_path = output_paths.get(row_index).cloned().unwrap_or_default();
        let manifest_path = manifest_paths.get(row_index).cloned().unwrap_or_default();
        let input_status = input_statuses.get(row_index).cloned().unwrap_or_default();
        let status = case_result_collection_row_status(
            &output_table.schema_name,
            &input_status,
            &output_path,
            &manifest_path,
        );
        collection_case_ids.push(case_id);
        collection_case_dirs.push(case_dir);
        collection_output_paths.push(output_path);
        collection_manifest_paths.push(manifest_path);
        collection_input_statuses.push(input_status);
        collection_statuses.push(status);
    }
    let hash_payload = format!(
        "{}|{}|{}|{}|{}",
        declaration.name,
        declaration.expression,
        output_table.source_hash.clone().unwrap_or_default(),
        collection_output_paths.join(","),
        collection_statuses.join(",")
    );
    RuntimeTable {
        binding: declaration.name.clone(),
        schema_name: "CaseResultCollection".to_owned(),
        source: declaration.expression.clone(),
        source_hash: Some(stable_hash_text(&hash_payload)),
        row_count: output_table.row_count,
        columns: runtime_columns_with_overrides(
            &output_table.columns,
            vec![
                text_runtime_column("case_id", "String", collection_case_ids),
                text_runtime_column("case_dir", "DirectoryPath", collection_case_dirs),
                text_runtime_column("output_path", "FilePath", collection_output_paths),
                text_runtime_column("result_path", "FilePath", output_paths.to_vec()),
                text_runtime_column("manifest_path", "FilePath", collection_manifest_paths),
                text_runtime_column(
                    if output_table.schema_name == "CaseRunResult" {
                        "run_status"
                    } else {
                        "input_status"
                    },
                    "String",
                    collection_input_statuses,
                ),
                text_runtime_column("status", "String", collection_statuses),
            ],
        ),
        parse_failures: output_table.parse_failures.clone(),
        line: declaration.line,
    }
}

fn case_result_collection_row_status(
    source_schema: &str,
    input_status: &str,
    output_path: &str,
    manifest_path: &str,
) -> String {
    let input_status = input_status.trim();
    if input_status == "blocked" || input_status == "failed" {
        "blocked".to_owned()
    } else if (source_schema == "CaseRunResult" && !matches!(input_status, "succeeded" | "skipped"))
        || (source_schema != "CaseRunResult" && input_status != "rendered")
        || output_path.trim().is_empty()
        || manifest_path.trim().is_empty()
    {
        "missing".to_owned()
    } else {
        "collected".to_owned()
    }
}

fn case_apply_output_is_rendered(
    result_dir: Option<&Path>,
    output_path: &str,
    manifest_path: &str,
) -> bool {
    let Some(result_dir) = result_dir else {
        return false;
    };
    result_relative_file_exists(result_dir, output_path)
        && result_relative_file_exists(result_dir, manifest_path)
}

fn result_relative_file_exists(result_dir: &Path, relative_path: &str) -> bool {
    let trimmed = relative_path.trim();
    if trimmed.is_empty() {
        return false;
    }
    let path = Path::new(trimmed);
    if path.is_absolute()
        || path.components().any(|component| {
            matches!(
                component,
                std::path::Component::ParentDir
                    | std::path::Component::RootDir
                    | std::path::Component::Prefix(_)
            )
        })
    {
        return false;
    }
    result_dir.join(path).is_file()
}

fn collect_results_source_binding(expression: &str) -> Option<&str> {
    let source = expression.trim().strip_prefix("collect results ")?.trim();
    if is_simple_binding_name(source) {
        Some(source)
    } else {
        None
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct CaseApplyExpression<'a> {
    step: &'a str,
    cases: &'a str,
}

fn case_apply_cases_binding(expression: &str) -> Option<&str> {
    let apply = case_apply_expression(expression)?;
    if apply.step == "case_input_template" {
        Some(apply.cases)
    } else {
        None
    }
}

fn case_apply_expression(expression: &str) -> Option<CaseApplyExpression<'_>> {
    let expression = expression.trim();
    if let Some(inner) = expression
        .strip_prefix("apply(")
        .and_then(|value| value.strip_suffix(')'))
    {
        let mut parts = inner.split(',').map(str::trim);
        let step = parts.next().filter(|value| is_simple_binding_name(value))?;
        let cases = parts.find_map(|part| {
            part.strip_prefix("over=")
                .map(str::trim)
                .filter(|value| is_simple_binding_name(value))
        })?;
        return Some(CaseApplyExpression { step, cases });
    }

    let mut parts = expression.split_whitespace();
    if parts.next()? != "apply" {
        return None;
    }
    let step = parts.next()?;
    if parts.next()? != "over" {
        return None;
    }
    let cases = parts.next()?;
    if parts.next().is_some() || !is_simple_binding_name(step) || !is_simple_binding_name(cases) {
        return None;
    }
    Some(CaseApplyExpression { step, cases })
}

fn case_apply_template_path(expression: &str, report: &CheckReport) -> String {
    crate::evaluate_runtime_path_expression(expression, report)
        .unwrap_or_else(|| strip_runtime_string_literal(expression))
}

fn text_column_values_by_name<'a>(table: &'a RuntimeTable, name: &str) -> Option<&'a [String]> {
    table
        .columns
        .iter()
        .find(|column| column.name.eq_ignore_ascii_case(name))
        .and_then(text_column_values)
}

fn strip_runtime_string_literal(value: &str) -> String {
    let trimmed = value.trim();
    trimmed
        .strip_prefix('"')
        .and_then(|inner| inner.strip_suffix('"'))
        .unwrap_or(trimmed)
        .to_owned()
}

fn render_case_output_pattern(
    pattern: &str,
    case_id: &str,
    case_dir: &str,
    row_index: usize,
) -> String {
    pattern
        .replace("{case_id}", case_id)
        .replace("{case_dir}", case_dir.trim_end_matches(&['/', '\\'][..]))
        .replace("{row}", &(row_index + 1).to_string())
}

fn is_simple_binding_name(value: &str) -> bool {
    let mut chars = value.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    (first.is_ascii_alphabetic() || first == '_')
        && chars.all(|character| character.is_ascii_alphanumeric() || character == '_')
}

fn materialize_sample_tables(
    sample_generations: &[eng_compiler::SampleGenerationInfo],
    tables: &[RuntimeTable],
) -> Vec<RuntimeSampleTable> {
    tables
        .iter()
        .filter_map(|table| materialize_sample_table(sample_generations, table))
        .collect()
}

fn materialize_sample_table(
    sample_generations: &[eng_compiler::SampleGenerationInfo],
    table: &RuntimeTable,
) -> Option<RuntimeSampleTable> {
    if !is_sample_table_candidate(table) {
        return None;
    }
    let generation_info = sample_generations
        .iter()
        .find(|generation| generation.binding == table.binding);

    let case_id_column = table
        .columns
        .iter()
        .find(|column| column.name.eq_ignore_ascii_case("case_id"));
    let case_id_values = case_id_column.and_then(text_column_values);
    let duplicate_case_ids = case_id_values
        .map(duplicate_case_ids)
        .unwrap_or_else(Vec::new);
    let parameter_columns = table
        .columns
        .iter()
        .filter(|column| !column.name.eq_ignore_ascii_case("case_id"))
        .filter(|column| matches!(column.values, RuntimeValues::Number(_)))
        .map(sample_parameter_column)
        .collect::<Vec<_>>();
    let status = if case_id_column.is_none() {
        "missing_case_id"
    } else if !duplicate_case_ids.is_empty() {
        "duplicate_case_ids"
    } else if parameter_columns.is_empty() {
        "no_numeric_parameters"
    } else if generation_info.is_some() {
        "generated_sample_table"
    } else {
        "promoted_sample_table"
    };
    let generation = generation_info
        .map(|generation| format!("sample_{}", generation.method))
        .unwrap_or_else(|| "promoted_csv".to_owned());
    let method = generation_info
        .map(|generation| generation.method.clone())
        .unwrap_or_else(|| "promoted_csv".to_owned());
    let seed = generation_info.and_then(|generation| generation.seed.map(|seed| seed.to_string()));

    Some(RuntimeSampleTable {
        binding: table.binding.clone(),
        schema_name: table.schema_name.clone(),
        source: table.source.clone(),
        source_hash: table.source_hash.clone(),
        sample_count: table.row_count,
        case_id_column: case_id_column.map(|column| column.name.clone()),
        parameter_columns,
        duplicate_case_ids,
        row_hash_count: table.row_count,
        row_hash_preview: sample_row_hash_preview(table),
        row_preview: sample_row_preview(table, case_id_column),
        generation,
        method,
        seed,
        status: status.to_owned(),
    })
}

fn is_sample_table_candidate(table: &RuntimeTable) -> bool {
    let schema = table.schema_name.to_ascii_lowercase();
    let binding = table.binding.to_ascii_lowercase();
    let source = table.source.to_ascii_lowercase();
    schema.contains("sample") || binding.contains("sample") || source.contains("sample")
}

fn text_column_values(column: &RuntimeColumn) -> Option<&[String]> {
    let RuntimeValues::Text(values) = &column.values else {
        return None;
    };
    Some(values)
}

fn duplicate_case_ids(values: &[String]) -> Vec<String> {
    let mut seen = HashSet::new();
    let mut duplicates = HashSet::new();
    for value in values {
        let value = value.trim();
        if value.is_empty() {
            continue;
        }
        if !seen.insert(value.to_owned()) {
            duplicates.insert(value.to_owned());
        }
    }
    let mut duplicates = duplicates.into_iter().collect::<Vec<_>>();
    duplicates.sort();
    duplicates
}

fn sample_parameter_column(column: &RuntimeColumn) -> RuntimeSampleParameterColumn {
    let (min, max) = numeric_min_max(numeric_values(column));
    RuntimeSampleParameterColumn {
        name: column.name.clone(),
        quantity_kind: column.type_name.clone(),
        display_unit: column
            .unit
            .clone()
            .or_else(|| column.canonical_unit.clone())
            .unwrap_or_else(|| "1".to_owned()),
        min,
        max,
        missing_count: column.missing_count,
    }
}

fn numeric_min_max(values: &[Option<f64>]) -> (Option<f64>, Option<f64>) {
    let mut min = None::<f64>;
    let mut max = None::<f64>;
    for value in values.iter().filter_map(|value| *value) {
        min = Some(min.map_or(value, |current| current.min(value)));
        max = Some(max.map_or(value, |current| current.max(value)));
    }
    (min, max)
}

fn sample_row_hash_preview(table: &RuntimeTable) -> Vec<String> {
    (0..table.row_count.min(8))
        .map(|row_index| sample_row_hash(table, row_index))
        .collect()
}

fn sample_row_preview(
    table: &RuntimeTable,
    case_id_column: Option<&RuntimeColumn>,
) -> Vec<RuntimeSampleRowPreview> {
    let parameter_columns = table
        .columns
        .iter()
        .filter(|column| !column.name.eq_ignore_ascii_case("case_id"))
        .filter(|column| matches!(column.values, RuntimeValues::Number(_)))
        .collect::<Vec<_>>();
    (0..table.row_count.min(3))
        .map(|row_index| RuntimeSampleRowPreview {
            row_number: row_index + 1,
            case_id: case_id_column.and_then(|column| {
                let value = table_cell_text(column, row_index);
                (!value.trim().is_empty()).then_some(value)
            }),
            values: parameter_columns
                .iter()
                .map(|column| {
                    let value = table_cell_text(column, row_index);
                    let numeric_value = match &column.values {
                        RuntimeValues::Number(values) => {
                            values.get(row_index).and_then(|value| *value)
                        }
                        RuntimeValues::Text(_) => None,
                    };
                    RuntimeSampleRowPreviewValue {
                        column: column.name.clone(),
                        value: (!value.trim().is_empty()).then_some(value),
                        numeric_value,
                        unit: column
                            .unit
                            .clone()
                            .or_else(|| column.canonical_unit.clone()),
                    }
                })
                .collect(),
        })
        .collect()
}

fn sample_row_hash(table: &RuntimeTable, row_index: usize) -> String {
    let mut payload = format!("{}:{}", table.binding, row_index + 2);
    for column in &table.columns {
        payload.push('|');
        payload.push_str(&column.name);
        payload.push('=');
        payload.push_str(&table_cell_text(column, row_index));
    }
    stable_hash_text(&payload)
}

fn table_cell_text(column: &RuntimeColumn, row_index: usize) -> String {
    match &column.values {
        RuntimeValues::Text(values) => values.get(row_index).cloned().unwrap_or_default(),
        RuntimeValues::Number(values) => values
            .get(row_index)
            .and_then(|value| *value)
            .map(|value| value.to_string())
            .unwrap_or_default(),
    }
}

fn materialize_case_manifests(tables: &[RuntimeTable]) -> Vec<RuntimeCaseManifest> {
    let mut manifests = Vec::new();
    for table in tables
        .iter()
        .filter(|table| is_sample_table_candidate(table))
    {
        let Some(case_id_column) = table
            .columns
            .iter()
            .find(|column| column.name.eq_ignore_ascii_case("case_id"))
        else {
            continue;
        };
        let Some(case_ids) = text_column_values(case_id_column) else {
            continue;
        };
        let duplicate_ids = duplicate_case_ids(case_ids)
            .into_iter()
            .collect::<HashSet<_>>();
        for row_index in 0..table.row_count {
            let case_id = case_ids
                .get(row_index)
                .map(|value| value.trim().to_owned())
                .unwrap_or_default();
            let (status, failure_reason, case_dir) = if case_id.is_empty() {
                (
                    "failed",
                    Some("case_id is missing for sample row".to_owned()),
                    None,
                )
            } else if duplicate_ids.contains(&case_id) {
                (
                    "failed",
                    Some(format!(
                        "duplicate case_id `{case_id}` in sample table `{}`",
                        table.binding
                    )),
                    Some(default_case_dir(&case_id)),
                )
            } else {
                ("pending", None, Some(default_case_dir(&case_id)))
            };
            manifests.push(RuntimeCaseManifest {
                case_id,
                sample_table: table.binding.clone(),
                schema_name: table.schema_name.clone(),
                source: table.source.clone(),
                source_hash: table.source_hash.clone(),
                sample_row_number: row_index + 1,
                source_row: row_index + 2,
                sample_row_hash: sample_row_hash(table, row_index),
                case_dir,
                generated_input_file: None,
                process_bindings: Vec::new(),
                process_statuses: Vec::new(),
                output_artifacts: Vec::new(),
                result_files: Vec::new(),
                metrics: Vec::new(),
                failure_reason,
                status: status.to_owned(),
                line: table.line,
            });
        }
    }
    manifests
}

fn default_case_dir(case_id: &str) -> String {
    format!("outputs/{case_id}")
}

fn stable_hash_text(source: &str) -> String {
    let mut hash = 0xcbf29ce484222325u64;
    for byte in source.as_bytes() {
        hash ^= u64::from(*byte);
        hash = hash.wrapping_mul(0x100000001b3);
    }
    format!("{hash:016x}")
}

fn materialize_time_series(
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Vec<RuntimeTimeSeries> {
    let mut series = Vec::new();
    for binding in &report.semantic_program.typed_bindings {
        let Some((axis, quantity_kind)) =
            time_series_quantity(&binding.semantic_type.quantity_kind)
        else {
            continue;
        };
        let Some(inferred) = report
            .inferred_declarations
            .iter()
            .find(|declaration| declaration.name == binding.name)
        else {
            continue;
        };
        if quantity_kind != "HeatRate" {
            continue;
        }
        if let Some(runtime_series) = heat_rate_series(
            &binding.name,
            &axis,
            &quantity_kind,
            &binding.semantic_type.display_unit,
            &inferred.expression,
            report,
            tables,
        ) {
            series.push(runtime_series);
        }
    }
    for block in &report.semantic_program.where_blocks {
        for binding in &block.bindings {
            let Some((axis, quantity_kind)) = time_series_quantity(&binding.quantity_kind) else {
                continue;
            };
            if quantity_kind != "HeatRate" {
                continue;
            }
            if let Some(runtime_series) = heat_rate_series(
                &binding.name,
                &axis,
                &quantity_kind,
                &binding.display_unit,
                &binding.expression,
                report,
                tables,
            ) {
                series.push(runtime_series);
            }
        }
    }
    for table in tables {
        series.extend(materialize_table_column_series(table));
    }
    series
}

fn materialize_table_column_series(table: &RuntimeTable) -> Vec<RuntimeTimeSeries> {
    let (x_values, x_unit) = table.axis_values();
    table
        .columns
        .iter()
        .filter(|column| !column.is_index)
        .filter_map(|column| {
            let RuntimeValues::Number(values) = &column.values else {
                return None;
            };
            let display_unit = column
                .unit
                .clone()
                .or_else(|| column.canonical_unit.clone())
                .unwrap_or_else(|| "1".to_owned());
            let mut points = Vec::new();
            for (index, value) in values.iter().enumerate() {
                let Some(value) = value else {
                    continue;
                };
                points.push(RuntimePoint {
                    x: x_values.get(index).copied().unwrap_or(index as f64),
                    y: *value,
                });
            }
            Some(RuntimeTimeSeries {
                name: format!("{}.{}", table.binding, column.name),
                axis: "Time".to_owned(),
                x_unit: x_unit.clone(),
                quantity_kind: column.type_name.clone(),
                display_unit,
                source_table: table.binding.clone(),
                source_expression: format!("{}.{}", table.binding, column.name),
                points,
            })
        })
        .collect()
}

fn heat_rate_series(
    name: &str,
    axis: &str,
    quantity_kind: &str,
    display_unit: &str,
    expression: &str,
    report: &CheckReport,
    tables: &[RuntimeTable],
) -> Option<RuntimeTimeSeries> {
    let table = tables
        .iter()
        .find(|table| expression.contains(&format!("{}.", table.binding)))?;
    let mass_flow = table.numeric_column_by_type("MassFlowRate")?;
    let supply = table.temperature_column("supply")?;
    let return_temp = table.temperature_column("return")?;
    let cp = specific_heat_value(report, expression)?;
    let (x_values, x_unit) = table.axis_values();

    let mut points = Vec::new();
    for index in 0..table.row_count {
        let (Some(m_dot), Some(supply), Some(return_temp)) = (
            optional_number_at(mass_flow, index),
            optional_number_at(supply, index),
            optional_number_at(return_temp, index),
        ) else {
            continue;
        };
        let x = x_values.get(index).copied().unwrap_or(index as f64);
        points.push(RuntimePoint {
            x,
            y: m_dot * cp * (return_temp - supply),
        });
    }

    Some(RuntimeTimeSeries {
        name: name.to_owned(),
        axis: axis.to_owned(),
        x_unit,
        quantity_kind: quantity_kind.to_owned(),
        display_unit: display_unit.to_owned(),
        source_table: table.binding.clone(),
        source_expression: expression.to_owned(),
        points,
    })
}

fn materialize_statistics(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
) -> Vec<RuntimeStatistics> {
    report
        .semantic_program
        .stats_infos
        .iter()
        .map(|stats| {
            let runtime_series = series.iter().find(|series| series.name == stats.source);
            let values = runtime_series
                .map(|series| {
                    stats
                        .statistics
                        .iter()
                        .filter_map(|name| statistic_value(name, series))
                        .collect::<Vec<_>>()
                })
                .unwrap_or_default();
            RuntimeStatistics {
                source: stats.source.clone(),
                quantity_kind: runtime_series
                    .map(|series| series.quantity_kind.clone())
                    .unwrap_or_else(|| stats.quantity_kind.clone()),
                axis: runtime_series
                    .map(|series| series.axis.clone())
                    .unwrap_or_else(|| stats.axis.clone()),
                cache_key: stats.cache_key.clone(),
                status: if values.is_empty() {
                    "unavailable".to_owned()
                } else {
                    "computed".to_owned()
                },
                values,
            }
        })
        .collect()
}

fn materialize_integrations(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
) -> Vec<RuntimeIntegration> {
    report
        .semantic_program
        .integrations
        .iter()
        .map(|integration| {
            let runtime_series = series
                .iter()
                .find(|series| series.name == integration.source);
            let integrated = runtime_series
                .filter(|series| {
                    series.quantity_kind == "HeatRate" && series.axis == integration.over_axis
                })
                .and_then(trapezoidal_energy_joules);
            RuntimeIntegration {
                binding: integration.binding.clone(),
                source: integration.source.clone(),
                input_quantity: runtime_series
                    .map(|series| series.quantity_kind.clone())
                    .unwrap_or_else(|| integration.input_quantity.clone()),
                over_axis: integration.over_axis.clone(),
                result_quantity: integration.result_quantity.clone(),
                value: integrated.unwrap_or(0.0),
                unit: "J".to_owned(),
                method: "trapezoidal".to_owned(),
                status: if integrated.is_some() {
                    "computed".to_owned()
                } else {
                    "unavailable".to_owned()
                },
                interval_count: runtime_series
                    .map(|series| series.points.len().saturating_sub(1))
                    .unwrap_or(0),
            }
        })
        .collect()
}

fn materialize_metrics(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
    alignments: &[RuntimeTimeAlignment],
) -> Vec<RuntimeMetric> {
    report
        .inferred_declarations
        .iter()
        .filter_map(|declaration| {
            let (left, right) = parse_rmse_expression(&declaration.expression)?;
            let left_series = series.iter().find(|series| series.name == left)?;
            let right_series = series.iter().find(|series| series.name == right)?;
            let (alignment_reference, alignment_status, alignment_step_status) =
                metric_alignment_reference(&left, &right, alignments);
            let mut actual = Vec::new();
            let mut predicted = Vec::new();
            for point in &left_series.points {
                let Some(right_value) = interpolate_series_value(right_series, point.x) else {
                    continue;
                };
                let left_value = convert_display_value(
                    point.y,
                    &left_series.display_unit,
                    &right_series.display_unit,
                );
                actual.push(left_value);
                predicted.push(right_value);
            }
            if actual.is_empty() {
                return Some(RuntimeMetric {
                    binding: declaration.name.clone(),
                    kind: "rmse".to_owned(),
                    left,
                    right,
                    quantity_kind: "unknown".to_owned(),
                    unit: right_series.display_unit.clone(),
                    value: 0.0,
                    sample_count: 0,
                    alignment_reference,
                    alignment_status,
                    alignment_step_status,
                    status: "unavailable".to_owned(),
                    line: declaration.line,
                });
            }
            let value = regression_metrics(&actual, &predicted).0;
            let quantity_kind = if left_series.quantity_kind == "AbsoluteTemperature"
                && right_series.quantity_kind == "AbsoluteTemperature"
            {
                "TemperatureDelta".to_owned()
            } else {
                left_series.quantity_kind.clone()
            };
            let unit = if quantity_kind == "TemperatureDelta" {
                "K".to_owned()
            } else {
                right_series.display_unit.clone()
            };
            Some(RuntimeMetric {
                binding: declaration.name.clone(),
                kind: "rmse".to_owned(),
                left,
                right,
                quantity_kind,
                unit,
                value,
                sample_count: actual.len(),
                alignment_reference,
                alignment_status,
                alignment_step_status,
                status: "computed".to_owned(),
                line: declaration.line,
            })
        })
        .collect()
}

fn metric_alignment_reference(
    left: &str,
    right: &str,
    alignments: &[RuntimeTimeAlignment],
) -> (Option<String>, Option<String>, Option<String>) {
    alignments
        .iter()
        .find(|alignment| {
            (alignment.left == left && alignment.right == right)
                || (alignment.left == right && alignment.right == left)
                || (alignment.binding == left && alignment.right == right)
                || (alignment.binding == right && alignment.right == left)
        })
        .map(|alignment| {
            (
                Some(format!("{} vs {}", alignment.left, alignment.right)),
                Some(alignment.status.clone()),
                Some(alignment.step_status.clone()),
            )
        })
        .unwrap_or((None, None, None))
}

fn parse_rmse_expression(expression: &str) -> Option<(String, String)> {
    let rest = expression.trim().strip_prefix("rmse ")?;
    let (left, right) = rest.split_once(" vs ")?;
    Some((left.trim().to_owned(), right.trim().to_owned()))
}

fn materialize_timeseries_uncertainty_calculations(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
    statistics: &[RuntimeStatistics],
    integrations: &[RuntimeIntegration],
) -> Vec<RuntimeTimeSeriesUncertaintyCalculation> {
    let mut calculations = Vec::new();
    for stats in statistics {
        let Some(source_series) = series.iter().find(|series| series.name == stats.source) else {
            continue;
        };
        let Some(sensor_std) = sensor_std_for_series(report, source_series) else {
            continue;
        };
        for value in &stats.values {
            let (stddev, method, status) = statistic_uncertainty_stddev(
                &value.name,
                source_series,
                sensor_std.value_in_series_unit,
            );
            calculations.push(RuntimeTimeSeriesUncertaintyCalculation {
                source: stats.source.clone(),
                operation: "statistic".to_owned(),
                statistic: Some(value.name.clone()),
                binding: None,
                nominal_value: Some(value.value),
                stddev,
                unit: value.unit.clone(),
                sensor_std: sensor_std.original_value,
                sensor_std_unit: sensor_std.original_unit.clone(),
                method,
                status,
            });
        }
    }
    for integration in integrations {
        let Some(source_series) = series
            .iter()
            .find(|series| series.name == integration.source)
        else {
            continue;
        };
        let Some(sensor_std) = sensor_std_for_series(report, source_series) else {
            continue;
        };
        let stddev =
            trapezoidal_integral_uncertainty_stddev(source_series, sensor_std.value_in_series_unit);
        calculations.push(RuntimeTimeSeriesUncertaintyCalculation {
            source: integration.source.clone(),
            operation: "integration".to_owned(),
            statistic: None,
            binding: Some(integration.binding.clone()),
            nominal_value: (integration.status == "computed").then_some(integration.value),
            stddev,
            unit: integration.unit.clone(),
            sensor_std: sensor_std.original_value,
            sensor_std_unit: sensor_std.original_unit.clone(),
            method: "independent_pointwise_sensor_std_trapezoidal".to_owned(),
            status: if stddev.is_some() {
                "propagated_sensor_std".to_owned()
            } else {
                "unavailable".to_owned()
            },
        });
    }
    calculations
}

#[derive(Clone, Debug)]
struct RuntimeSensorStd {
    original_value: f64,
    original_unit: String,
    value_in_series_unit: f64,
}

fn sensor_std_for_series(
    report: &CheckReport,
    series: &RuntimeTimeSeries,
) -> Option<RuntimeSensorStd> {
    let sensor_std = accepted_sensor_std_value(report, &series.name)?;
    let (value, unit) = number_with_optional_unit(&sensor_std.value)?;
    let unit = unit?;
    Some(RuntimeSensorStd {
        original_value: value,
        original_unit: unit.clone(),
        value_in_series_unit: convert_delta_value(value, &unit, &series.display_unit),
    })
}

fn statistic_uncertainty_stddev(
    name: &str,
    series: &RuntimeTimeSeries,
    sensor_std: f64,
) -> (Option<f64>, String, String) {
    if name == "mean" {
        let count = series.points.len();
        let stddev = (count > 0).then(|| sensor_std / (count as f64).sqrt());
        return (
            stddev,
            "independent_pointwise_sensor_std_mean".to_owned(),
            if stddev.is_some() {
                "propagated_sensor_std".to_owned()
            } else {
                "unavailable".to_owned()
            },
        );
    }
    if name == "time_weighted_mean" {
        let stddev = time_weighted_mean_uncertainty_stddev(series, sensor_std);
        return (
            stddev,
            "independent_pointwise_sensor_std_time_weighted_mean".to_owned(),
            if stddev.is_some() {
                "propagated_sensor_std".to_owned()
            } else {
                "unavailable".to_owned()
            },
        );
    }
    if name.starts_with("duration_above(") {
        let stddev = duration_above_uncertainty_stddev(name, series, sensor_std);
        return (
            stddev,
            "independent_pointwise_sensor_std_duration_above_finite_difference".to_owned(),
            if stddev.is_some() {
                "propagated_sensor_std".to_owned()
            } else {
                "unavailable".to_owned()
            },
        );
    }
    if percentile_fraction(name).is_some() {
        let stddev = percentile_uncertainty_stddev(name, series, sensor_std);
        return (
            stddev,
            "independent_pointwise_sensor_std_percentile_finite_difference".to_owned(),
            if stddev.is_some() {
                "propagated_sensor_std".to_owned()
            } else {
                "unavailable".to_owned()
            },
        );
    }
    (
        None,
        "unsupported_pointwise_sensor_std_statistic".to_owned(),
        "unsupported_statistic".to_owned(),
    )
}

fn percentile_uncertainty_stddev(
    name: &str,
    series: &RuntimeTimeSeries,
    sensor_std: f64,
) -> Option<f64> {
    let percentile = percentile_fraction(name)?;
    let values = series
        .points
        .iter()
        .map(|point| point.y)
        .collect::<Vec<_>>();
    nearest_rank_percentile(&values, percentile)?;
    let mut variance = 0.0;
    for index in 0..values.len() {
        let step = finite_difference_step(values[index], sensor_std);
        if step <= 0.0 || !step.is_finite() {
            return None;
        }
        let mut plus = values.clone();
        plus[index] += step;
        let plus_percentile = nearest_rank_percentile(&plus, percentile)?;

        let mut minus = values.clone();
        minus[index] -= step;
        let minus_percentile = nearest_rank_percentile(&minus, percentile)?;

        let derivative = (plus_percentile - minus_percentile) / (2.0 * step);
        if !derivative.is_finite() {
            return None;
        }
        variance += derivative * derivative * sensor_std * sensor_std;
    }
    Some(variance.sqrt())
}

fn duration_above_uncertainty_stddev(
    name: &str,
    series: &RuntimeTimeSeries,
    sensor_std: f64,
) -> Option<f64> {
    let threshold = duration_above_threshold(name, &series.display_unit)?;
    duration_above(series, threshold)?;
    let mut variance = 0.0;
    for index in 0..series.points.len() {
        let step = finite_difference_step(series.points[index].y, sensor_std);
        if step <= 0.0 || !step.is_finite() {
            return None;
        }
        let mut plus = series.clone();
        plus.points[index].y += step;
        let plus_duration = duration_above(&plus, threshold)?;

        let mut minus = series.clone();
        minus.points[index].y -= step;
        let minus_duration = duration_above(&minus, threshold)?;

        let derivative = (plus_duration - minus_duration) / (2.0 * step);
        if !derivative.is_finite() {
            return None;
        }
        variance += derivative * derivative * sensor_std * sensor_std;
    }
    Some(variance.sqrt())
}

fn finite_difference_step(value: f64, sensor_std: f64) -> f64 {
    value.abs().max(sensor_std.abs()).max(1.0) * 1.0e-6
}
fn time_weighted_mean_uncertainty_stddev(
    series: &RuntimeTimeSeries,
    sensor_std: f64,
) -> Option<f64> {
    let total_duration = series.points.last()?.x - series.points.first()?.x;
    if total_duration <= 0.0 {
        return None;
    }
    trapezoidal_weight_square_sum(series)
        .map(|weight_square_sum| sensor_std * weight_square_sum.sqrt() / total_duration)
}

fn trapezoidal_integral_uncertainty_stddev(
    series: &RuntimeTimeSeries,
    sensor_std: f64,
) -> Option<f64> {
    let stddev = sensor_std * trapezoidal_weight_square_sum(series)?.sqrt();
    Some(match normalize_unit(&series.display_unit).as_str() {
        "kw" => stddev * 1000.0,
        _ => stddev,
    })
}

fn trapezoidal_weight_square_sum(series: &RuntimeTimeSeries) -> Option<f64> {
    if series.x_unit != "s" || series.points.len() < 2 {
        return None;
    }
    let mut weights = vec![0.0; series.points.len()];
    for (index, window) in series.points.windows(2).enumerate() {
        let dt = window[1].x - window[0].x;
        if dt <= 0.0 {
            return None;
        }
        weights[index] += dt * 0.5;
        weights[index + 1] += dt * 0.5;
    }
    Some(weights.iter().map(|weight| weight * weight).sum())
}

fn materialize_validations(
    report: &CheckReport,
    metrics: &[RuntimeMetric],
    integrations: &[RuntimeIntegration],
    uncertainties: &[RuntimeUncertainty],
    timeseries_coverage: &[RuntimeTimeSeriesCoverage],
) -> Vec<RuntimeValidation> {
    report
        .semantic_program
        .command_styles
        .iter()
        .filter(|command| command.verb == "validate")
        .map(|command| {
            if let Some(between) = command
                .clauses
                .iter()
                .find(|clause| clause.name == "between")
            {
                return materialize_between_validation(
                    command,
                    &between.value,
                    metrics,
                    integrations,
                    uncertainties,
                );
            }

            let expression = command.target.clone();
            if let Some(validation) =
                materialize_coverage_complete_validation(command, timeseries_coverage)
            {
                return validation;
            }
            let Some((left, operator, right)) = parse_validation_expression(&expression) else {
                return unavailable_validation(expression, command.line);
            };
            let left_value = validation_runtime_value(&left, metrics, integrations, uncertainties);
            let right_value =
                validation_runtime_value(&right, metrics, integrations, uncertainties);
            let unit = left_value
                .as_ref()
                .map(|value| value.unit.clone())
                .unwrap_or_default();
            let left_number = left_value.as_ref().map(|value| value.value);
            let right_number = right_value
                .as_ref()
                .map(|value| convert_validation_value(value.value, &value.unit, &unit));
            let status = match (left_number, right_number) {
                (Some(left_number), Some(right_number)) => {
                    if compare_values(left_number, right_number, &operator) {
                        "passed"
                    } else {
                        "failed"
                    }
                }
                _ => "unavailable",
            }
            .to_owned();
            RuntimeValidation {
                expression,
                left,
                operator,
                right,
                left_value: left_number,
                right_value: right_number,
                unit,
                status,
                line: command.line,
            }
        })
        .collect()
}

fn materialize_coverage_complete_validation(
    command: &eng_compiler::CommandStyleInfo,
    timeseries_coverage: &[RuntimeTimeSeriesCoverage],
) -> Option<RuntimeValidation> {
    let binding = command.target.trim().strip_suffix(".complete")?.trim();
    let coverage = timeseries_coverage
        .iter()
        .find(|coverage| coverage.binding == binding || coverage.name == binding)?;
    let passed = coverage.status == "complete";
    Some(RuntimeValidation {
        expression: command.target.clone(),
        left: command.target.clone(),
        operator: "is_true".to_owned(),
        right: "true".to_owned(),
        left_value: Some(if passed { 1.0 } else { 0.0 }),
        right_value: Some(1.0),
        unit: String::new(),
        status: if passed { "passed" } else { "failed" }.to_owned(),
        line: command.line,
    })
}

fn materialize_between_validation(
    command: &eng_compiler::CommandStyleInfo,
    between: &str,
    metrics: &[RuntimeMetric],
    integrations: &[RuntimeIntegration],
    uncertainties: &[RuntimeUncertainty],
) -> RuntimeValidation {
    let expression = format!("{} between {}", command.target.trim(), between.trim());
    let Some((lower, upper)) = split_between_bounds(between) else {
        return unavailable_validation(expression, command.line);
    };
    let value = validation_runtime_value(&command.target, metrics, integrations, uncertainties);
    let unit = value
        .as_ref()
        .map(|value| value.unit.clone())
        .unwrap_or_default();
    let lower_value = validation_runtime_value(&lower, metrics, integrations, uncertainties)
        .map(|value| convert_validation_value(value.value, &value.unit, &unit));
    let upper_value = validation_runtime_value(&upper, metrics, integrations, uncertainties)
        .map(|value| convert_validation_value(value.value, &value.unit, &unit));
    let left_value = value.as_ref().map(|value| value.value);
    let status = match (left_value, lower_value, upper_value) {
        (Some(value), Some(lower), Some(upper)) => {
            if value >= lower && value <= upper {
                "passed"
            } else {
                "failed"
            }
        }
        _ => "unavailable",
    }
    .to_owned();
    RuntimeValidation {
        expression,
        left: command.target.clone(),
        operator: "between".to_owned(),
        right: between.trim().to_owned(),
        left_value,
        right_value: None,
        unit,
        status,
        line: command.line,
    }
}

fn unavailable_validation(expression: String, line: usize) -> RuntimeValidation {
    RuntimeValidation {
        expression,
        left: String::new(),
        operator: String::new(),
        right: String::new(),
        left_value: None,
        right_value: None,
        unit: String::new(),
        status: "unavailable".to_owned(),
        line,
    }
}

#[derive(Clone, Debug)]
struct ValidationRuntimeValue {
    value: f64,
    unit: String,
}

fn validation_runtime_value(
    expression: &str,
    metrics: &[RuntimeMetric],
    integrations: &[RuntimeIntegration],
    uncertainties: &[RuntimeUncertainty],
) -> Option<ValidationRuntimeValue> {
    let expression = expression.trim();
    if let Some(metric) = metrics.iter().find(|metric| metric.binding == expression) {
        return Some(ValidationRuntimeValue {
            value: metric.value,
            unit: metric.unit.clone(),
        });
    }
    if let Some(integration) = integrations
        .iter()
        .find(|integration| integration.binding == expression)
    {
        return Some(ValidationRuntimeValue {
            value: integration.value,
            unit: integration.unit.clone(),
        });
    }
    if let Some((name, argument)) = parse_single_argument_call(expression) {
        if name == "probability" {
            return probability_runtime_value(&argument, metrics, integrations, uncertainties);
        }
        if name == "mean" || percentile_fraction(&name).is_some() {
            return uncertainty_statistic_runtime_value(&name, &argument, uncertainties);
        }
    }
    number_with_optional_unit(expression).map(|(value, unit)| ValidationRuntimeValue {
        value,
        unit: unit.unwrap_or_default(),
    })
}

fn probability_runtime_value(
    expression: &str,
    metrics: &[RuntimeMetric],
    integrations: &[RuntimeIntegration],
    uncertainties: &[RuntimeUncertainty],
) -> Option<ValidationRuntimeValue> {
    let (left, operator, right) = parse_validation_expression(expression)?;
    let left_uncertainty = uncertainties
        .iter()
        .find(|uncertainty| uncertainty.binding == left);
    let right_uncertainty = uncertainties
        .iter()
        .find(|uncertainty| uncertainty.binding == right);
    let (uncertainty, uncertain_on_left, threshold_expression) =
        match (left_uncertainty, right_uncertainty) {
            (Some(uncertainty), None) => (uncertainty, true, right.as_str()),
            (None, Some(uncertainty)) => (uncertainty, false, left.as_str()),
            _ => return None,
        };
    if uncertainty.samples.is_empty() {
        return None;
    }
    let threshold =
        validation_runtime_value(threshold_expression, metrics, integrations, uncertainties)?;
    let threshold =
        convert_validation_value(threshold.value, &threshold.unit, &uncertainty.display_unit);
    let passed = uncertainty
        .samples
        .iter()
        .filter(|sample| {
            let (left_value, right_value) = if uncertain_on_left {
                (**sample, threshold)
            } else {
                (threshold, **sample)
            };
            compare_values(left_value, right_value, &operator)
        })
        .count();
    Some(ValidationRuntimeValue {
        value: passed as f64 / uncertainty.samples.len() as f64,
        unit: "1".to_owned(),
    })
}

fn uncertainty_statistic_runtime_value(
    name: &str,
    binding: &str,
    uncertainties: &[RuntimeUncertainty],
) -> Option<ValidationRuntimeValue> {
    let uncertainty = uncertainties
        .iter()
        .find(|uncertainty| uncertainty.binding == binding.trim())?;
    let value = match name {
        "mean" => uncertainty
            .mean
            .or_else(|| sample_summary(&uncertainty.samples).mean),
        percentile => quantile(&uncertainty.samples, percentile_fraction(percentile)?),
    }?;
    Some(ValidationRuntimeValue {
        value,
        unit: uncertainty.display_unit.clone(),
    })
}

fn convert_validation_value(value: f64, from_unit: &str, to_unit: &str) -> f64 {
    if from_unit.is_empty() || to_unit.is_empty() {
        value
    } else {
        convert_display_value(value, from_unit, to_unit)
    }
}

fn parse_single_argument_call(expression: &str) -> Option<(String, String)> {
    let expression = expression.trim();
    let open = expression.find('(')?;
    if !expression.ends_with(')') {
        return None;
    }
    let name = expression[..open].trim();
    if name.is_empty() {
        return None;
    }
    let argument = expression[open + 1..expression.len().saturating_sub(1)].trim();
    if argument.is_empty() {
        return None;
    }
    Some((name.to_owned(), argument.to_owned()))
}

fn split_between_bounds(value: &str) -> Option<(String, String)> {
    let (lower, upper) = value.split_once(" and ")?;
    let lower = lower.trim();
    let upper = upper.trim();
    if lower.is_empty() || upper.is_empty() {
        return None;
    }
    Some((lower.to_owned(), upper.to_owned()))
}

fn parse_validation_expression(expression: &str) -> Option<(String, String, String)> {
    let (index, operator) = top_level_comparison_operator(expression)?;
    let left = expression[..index].trim();
    let right = expression[index + operator.len()..].trim();
    if left.is_empty() || right.is_empty() {
        return None;
    }
    Some((left.to_owned(), operator.to_owned(), right.to_owned()))
}

fn top_level_comparison_operator(expression: &str) -> Option<(usize, &'static str)> {
    let mut parens = 0i32;
    let mut brackets = 0i32;
    let mut in_string = false;
    let mut previous = '\0';
    for (index, character) in expression.char_indices() {
        if !in_string && parens == 0 && brackets == 0 {
            for operator in ["<=", ">=", "==", "!=", "<", ">"] {
                if expression[index..].starts_with(operator) {
                    return Some((index, operator));
                }
            }
        }
        if character == '"' && previous != '\\' {
            in_string = !in_string;
        } else if !in_string {
            match character {
                '(' => parens += 1,
                ')' => parens -= 1,
                '[' => brackets += 1,
                ']' => brackets -= 1,
                _ => {}
            }
        }
        previous = character;
    }
    None
}
fn compare_values(left: f64, right: f64, operator: &str) -> bool {
    match operator {
        "<" => left < right,
        "<=" => left <= right,
        ">" => left > right,
        ">=" => left >= right,
        "==" => (left - right).abs() <= f64::EPSILON,
        "!=" => (left - right).abs() > f64::EPSILON,
        _ => false,
    }
}

fn nominal_time_step(points: &[RuntimePoint]) -> Option<f64> {
    let values = points.iter().map(|point| point.x).collect::<Vec<_>>();
    nominal_step_from_values(&values)
}

fn nominal_step_from_values(values: &[f64]) -> Option<f64> {
    let mut steps = values
        .windows(2)
        .filter_map(|window| {
            let step = window[1] - window[0];
            (step.is_finite() && step > 0.0).then_some(step)
        })
        .collect::<Vec<_>>();
    if steps.is_empty() {
        return None;
    }
    steps.sort_by(|left, right| left.total_cmp(right));
    Some(steps[(steps.len() - 1) / 2])
}

fn time_step_tolerance(step: f64) -> f64 {
    1e-6_f64.max(step.abs() * 1e-6)
}

fn time_axis_irregular(points: &[RuntimePoint], nominal_step: Option<f64>) -> bool {
    let values = points.iter().map(|point| point.x).collect::<Vec<_>>();
    axis_values_irregular(&values, nominal_step)
}

fn axis_values_irregular(values: &[f64], nominal_step: Option<f64>) -> bool {
    let Some(nominal_step) = nominal_step else {
        return false;
    };
    if values.len() < 3 || nominal_step <= 0.0 || !nominal_step.is_finite() {
        return false;
    }
    let tolerance = time_step_tolerance(nominal_step);
    values.windows(2).any(|window| {
        let step = window[1] - window[0];
        !step.is_finite() || step <= 0.0 || (step - nominal_step).abs() > tolerance
    })
}

fn time_step_status(
    left_step: Option<f64>,
    right_step: Option<f64>,
    left_irregular: bool,
    right_irregular: bool,
) -> &'static str {
    let (Some(left_step), Some(right_step)) = (left_step, right_step) else {
        return "unavailable";
    };
    if left_irregular || right_irregular {
        return "mismatch";
    }
    let tolerance = time_step_tolerance(left_step).max(time_step_tolerance(right_step));
    if (left_step - right_step).abs() <= tolerance {
        "matched"
    } else {
        "mismatch"
    }
}

fn materialize_time_alignments(
    report: &CheckReport,
    series: &mut Vec<RuntimeTimeSeries>,
) -> Vec<RuntimeTimeAlignment> {
    let mut alignments = Vec::new();
    let table_series = series
        .iter()
        .filter(|series| !series.source_table.is_empty())
        .cloned()
        .collect::<Vec<_>>();
    for left_index in 0..table_series.len() {
        for right_index in (left_index + 1)..table_series.len() {
            let left = &table_series[left_index];
            let right = &table_series[right_index];
            if left.source_table == right.source_table || left.axis != right.axis {
                continue;
            }
            alignments.push(runtime_time_alignment_record(
                &format!("{} vs {}", left.name, right.name),
                left,
                right,
                "auto_pairwise",
                "comparison",
                None,
                None,
                0,
            ));
        }
    }
    for command in report
        .semantic_program
        .command_styles
        .iter()
        .filter(|command| matches!(command.verb.as_str(), "align" | "resample"))
        .filter(|command| command.status == "lowered")
    {
        let (alignment, output) =
            materialize_explicit_time_alignment_command(report, series, command);
        if let Some(output) = output {
            series.push(output);
        }
        alignments.push(alignment);
    }
    alignments
}

fn materialize_explicit_time_alignment_command(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
    command: &eng_compiler::CommandStyleInfo,
) -> (RuntimeTimeAlignment, Option<RuntimeTimeSeries>) {
    let left_name = command.target.trim();
    let binding = command
        .owner
        .clone()
        .unwrap_or_else(|| format!("{}:{}", command.verb, command.line));
    let options = report
        .semantic_program
        .with_blocks
        .iter()
        .find(|block| block.owner_line == Some(command.line))
        .map(|block| block.options.as_slice())
        .unwrap_or(&[]);
    let method = option_value(options, "method")
        .map(normalize_time_alignment_method)
        .unwrap_or_else(|| {
            if command.verb == "resample" {
                "linear".to_owned()
            } else {
                "exact".to_owned()
            }
        });
    let resample_step = time_alignment_command_resample_step(command, options);
    let tolerance = option_value(options, "tolerance").and_then(parse_duration_seconds);
    let right_name = time_alignment_command_right(command)
        .map(str::to_owned)
        .unwrap_or_else(|| {
            if command.verb == "resample" && resample_step.is_some() {
                left_name.to_owned()
            } else {
                String::new()
            }
        });

    let Some(left) = find_runtime_series(series, left_name) else {
        return (
            missing_time_alignment_record(
                &binding,
                left_name,
                &right_name,
                &command.verb,
                &method,
                resample_step,
                tolerance,
                command.line,
                &format!("source TimeSeries `{left_name}` is unavailable"),
            ),
            None,
        );
    };
    let Some(right) = find_runtime_series(series, &right_name) else {
        return (
            missing_time_alignment_record(
                &binding,
                left_name,
                &right_name,
                &command.verb,
                &method,
                resample_step,
                tolerance,
                command.line,
                &format!("target TimeSeries `{right_name}` is unavailable"),
            ),
            None,
        );
    };
    let mut alignment = runtime_time_alignment_record(
        &binding,
        left,
        right,
        &command.verb,
        &method,
        resample_step,
        tolerance,
        command.line,
    );
    let Some(output_binding) = command.owner.as_deref() else {
        alignment.materialization_status = "unavailable".to_owned();
        alignment.materialization_reason =
            "an output binding is required to materialize a TimeSeries".to_owned();
        return (alignment, None);
    };
    let materialization = materialize_time_alignment_series(
        output_binding,
        left,
        right,
        &command.verb,
        &method,
        resample_step,
        tolerance,
    );
    alignment.target_count = materialization.target_count;
    alignment.output_count = materialization.output_count;
    alignment.materialization_status = materialization.status;
    alignment.materialization_reason = materialization.reason;
    (alignment, materialization.series)
}

fn normalize_time_alignment_method(value: &str) -> String {
    normalize_fill_method(value.trim().trim_matches('"'))
}

struct TimeAlignmentMaterialization {
    series: Option<RuntimeTimeSeries>,
    target_count: usize,
    output_count: usize,
    status: String,
    reason: String,
}

#[allow(clippy::too_many_arguments)]
fn materialize_time_alignment_series(
    binding: &str,
    left: &RuntimeTimeSeries,
    right: &RuntimeTimeSeries,
    strategy: &str,
    method: &str,
    resample_step: Option<f64>,
    tolerance: Option<f64>,
) -> TimeAlignmentMaterialization {
    if left.axis != right.axis {
        return unavailable_time_alignment_materialization(format!(
            "source axis `{}` does not match target axis `{}`",
            left.axis, right.axis
        ));
    }
    if !matches!(method, "exact" | "nearest" | "linear") {
        return unavailable_time_alignment_materialization(format!(
            "unsupported TimeSeries materialization method `{method}`; use exact, nearest, or linear"
        ));
    }

    let source_points = sorted_time_alignment_points(&left.points);
    if source_points.is_empty() {
        return unavailable_time_alignment_materialization(
            "source TimeSeries has no finite points".to_owned(),
        );
    }
    let target_axis = match time_alignment_target_axis(left, right, strategy, resample_step) {
        Ok(axis) => axis,
        Err(reason) => return unavailable_time_alignment_materialization(reason),
    };
    let target_count = target_axis.len();
    if target_count == 0 {
        return unavailable_time_alignment_materialization(
            "target TimeSeries axis has no finite points in the source range".to_owned(),
        );
    }

    let mut points = Vec::with_capacity(target_count);
    for x in target_axis {
        let value = match method {
            "exact" => exact_time_alignment_value(&source_points, x, tolerance),
            "nearest" => nearest_time_alignment_value(&source_points, x, tolerance),
            "linear" => linear_time_alignment_value(&source_points, x),
            _ => None,
        };
        if let Some(y) = value {
            points.push(RuntimePoint { x, y });
        }
    }

    let output_count = points.len();
    let (status, reason) = if output_count == target_count {
        (
            "materialized",
            format!("materialized all {output_count} target point(s) with {method} sampling"),
        )
    } else if output_count > 0 {
        (
            "partial",
            format!(
                "materialized {output_count} of {target_count} target point(s); values outside the source range or method tolerance were omitted"
            ),
        )
    } else {
        (
            "unavailable",
            format!("no target points could be materialized with {method} sampling"),
        )
    };
    let series = (output_count > 0).then(|| RuntimeTimeSeries {
        name: binding.to_owned(),
        axis: left.axis.clone(),
        x_unit: left.x_unit.clone(),
        quantity_kind: left.quantity_kind.clone(),
        display_unit: left.display_unit.clone(),
        source_table: left.source_table.clone(),
        source_expression: if strategy == "resample" && left.name == right.name {
            format!(
                "resample {} by {} s",
                left.name,
                resample_step.unwrap_or_default()
            )
        } else if strategy == "resample" {
            format!("resample {} to {}", left.name, right.name)
        } else {
            format!("align {} with {}", left.name, right.name)
        },
        points,
    });
    TimeAlignmentMaterialization {
        series,
        target_count,
        output_count,
        status: status.to_owned(),
        reason,
    }
}

fn unavailable_time_alignment_materialization(reason: String) -> TimeAlignmentMaterialization {
    TimeAlignmentMaterialization {
        series: None,
        target_count: 0,
        output_count: 0,
        status: "unavailable".to_owned(),
        reason,
    }
}

fn time_alignment_target_axis(
    left: &RuntimeTimeSeries,
    right: &RuntimeTimeSeries,
    strategy: &str,
    resample_step: Option<f64>,
) -> Result<Vec<f64>, String> {
    if strategy == "resample" {
        if let Some(step) = resample_step {
            if !step.is_finite() || step <= 0.0 {
                return Err("resample step must be a positive finite duration".to_owned());
            }
            let left_range = finite_time_range(&left.points)
                .ok_or_else(|| "source TimeSeries has no finite axis range".to_owned())?;
            let range = if left.name == right.name {
                left_range
            } else {
                let right_range = finite_time_range(&right.points)
                    .ok_or_else(|| "target TimeSeries has no finite axis range".to_owned())?;
                (
                    left_range.0.max(right_range.0),
                    left_range.1.min(right_range.1),
                )
            };
            if range.1 < range.0 {
                return Err("source and target TimeSeries ranges do not overlap".to_owned());
            }
            return regular_time_axis(range.0, range.1, step);
        }
    }
    let mut axis = right
        .points
        .iter()
        .filter_map(|point| point.x.is_finite().then_some(point.x))
        .collect::<Vec<_>>();
    axis.sort_by(f64::total_cmp);
    axis.dedup_by(|left, right| *left == *right);
    Ok(axis)
}

fn regular_time_axis(start: f64, end: f64, step: f64) -> Result<Vec<f64>, String> {
    const MAX_RESAMPLED_POINTS: usize = 1_000_000;
    let span = (end - start).max(0.0);
    let interval_count = span / step;
    if !interval_count.is_finite() {
        return Err("resample range and step do not produce a finite target axis".to_owned());
    }
    let count = interval_count.floor() + 1.0;
    if count > MAX_RESAMPLED_POINTS as f64 {
        return Err(format!(
            "resample step would create more than {MAX_RESAMPLED_POINTS} points"
        ));
    }
    let count = count as usize;
    Ok((0..count)
        .map(|index| start + index as f64 * step)
        .collect())
}

fn finite_time_range(points: &[RuntimePoint]) -> Option<(f64, f64)> {
    let mut values = points
        .iter()
        .filter_map(|point| point.x.is_finite().then_some(point.x));
    let first = values.next()?;
    let mut min = first;
    let mut max = first;
    for value in values {
        min = min.min(value);
        max = max.max(value);
    }
    Some((min, max))
}

fn sorted_time_alignment_points(points: &[RuntimePoint]) -> Vec<RuntimePoint> {
    let mut sorted = points
        .iter()
        .copied()
        .filter(|point| point.x.is_finite() && point.y.is_finite())
        .collect::<Vec<_>>();
    sorted.sort_by(|left, right| left.x.total_cmp(&right.x));
    sorted.dedup_by(|left, right| left.x == right.x);
    sorted
}

fn exact_time_alignment_value(
    points: &[RuntimePoint],
    target: f64,
    tolerance: Option<f64>,
) -> Option<f64> {
    let tolerance = tolerance
        .unwrap_or_else(|| time_coordinate_tolerance(points, target))
        .max(0.0);
    nearest_time_alignment_candidate(points, target)
        .filter(|(distance, _)| *distance <= tolerance)
        .map(|(_, value)| value)
}

fn nearest_time_alignment_value(
    points: &[RuntimePoint],
    target: f64,
    tolerance: Option<f64>,
) -> Option<f64> {
    let first = points.first()?;
    let last = points.last()?;
    let boundary_tolerance = time_coordinate_tolerance(points, target);
    if target < first.x - boundary_tolerance || target > last.x + boundary_tolerance {
        return None;
    }
    nearest_time_alignment_candidate(points, target)
        .filter(|(distance, _)| tolerance.is_none_or(|limit| *distance <= limit.max(0.0)))
        .map(|(_, value)| value)
}

fn linear_time_alignment_value(points: &[RuntimePoint], target: f64) -> Option<f64> {
    let first = points.first()?;
    let last = points.last()?;
    let tolerance = time_coordinate_tolerance(points, target);
    if target < first.x - tolerance || target > last.x + tolerance {
        return None;
    }
    if (target - first.x).abs() <= tolerance {
        return Some(first.y);
    }
    if (target - last.x).abs() <= tolerance {
        return Some(last.y);
    }
    let upper = points.partition_point(|point| point.x < target);
    if upper == 0 || upper >= points.len() {
        return None;
    }
    let left = points[upper - 1];
    let right = points[upper];
    let span = right.x - left.x;
    if span.abs() <= f64::EPSILON {
        return Some(left.y);
    }
    let fraction = (target - left.x) / span;
    Some(left.y + fraction * (right.y - left.y))
}

fn nearest_time_alignment_candidate(points: &[RuntimePoint], target: f64) -> Option<(f64, f64)> {
    let upper = points.partition_point(|point| point.x < target);
    [
        upper.checked_sub(1),
        (upper < points.len()).then_some(upper),
    ]
    .into_iter()
    .flatten()
    .map(|index| {
        let point = points[index];
        ((point.x - target).abs(), point.y)
    })
    .min_by(|left, right| left.0.total_cmp(&right.0))
}

fn time_coordinate_tolerance(points: &[RuntimePoint], target: f64) -> f64 {
    let step_tolerance = nominal_time_step(points)
        .map(time_step_tolerance)
        .unwrap_or(1e-6);
    let coordinate_tolerance = target.abs() * f64::EPSILON * 16.0;
    step_tolerance.max(coordinate_tolerance)
}

fn time_alignment_command_right(command: &eng_compiler::CommandStyleInfo) -> Option<&str> {
    let preferred_clause = if command.verb == "resample" {
        "to"
    } else {
        "with"
    };
    command
        .clauses
        .iter()
        .find(|clause| clause.name == preferred_clause)
        .or_else(|| {
            command
                .clauses
                .iter()
                .find(|clause| matches!(clause.name.as_str(), "with" | "to"))
        })
        .map(|clause| clause.value.trim())
        .filter(|value| !value.is_empty())
}

fn time_alignment_command_resample_step(
    command: &eng_compiler::CommandStyleInfo,
    options: &[eng_compiler::WithOptionInfo],
) -> Option<f64> {
    if command.verb == "resample" {
        if let Some(value) = command_clause_value(command, "by").and_then(parse_duration_seconds) {
            return Some(value);
        }
    }
    option_value(options, "target_step")
        .or_else(|| option_value(options, "step"))
        .and_then(parse_duration_seconds)
}

fn command_clause_value<'a>(
    command: &'a eng_compiler::CommandStyleInfo,
    name: &str,
) -> Option<&'a str> {
    command
        .clauses
        .iter()
        .find(|clause| clause.name == name)
        .map(|clause| clause.value.trim())
        .filter(|value| !value.is_empty())
}

fn find_runtime_series<'a>(
    series: &'a [RuntimeTimeSeries],
    name: &str,
) -> Option<&'a RuntimeTimeSeries> {
    let name = name.trim();
    series
        .iter()
        .find(|series| series.name == name || series.source_expression == name)
}

#[allow(clippy::too_many_arguments)]
fn missing_time_alignment_record(
    binding: &str,
    left: &str,
    right: &str,
    strategy: &str,
    method: &str,
    resample_step: Option<f64>,
    tolerance: Option<f64>,
    line: usize,
    reason: &str,
) -> RuntimeTimeAlignment {
    RuntimeTimeAlignment {
        binding: binding.to_owned(),
        left: left.to_owned(),
        right: right.to_owned(),
        axis: "Time".to_owned(),
        strategy: strategy.to_owned(),
        method: method.to_owned(),
        resample_step,
        tolerance,
        left_count: 0,
        right_count: 0,
        matched_count: 0,
        target_count: 0,
        output_count: 0,
        materialization_status: "unavailable".to_owned(),
        materialization_reason: reason.to_owned(),
        left_nominal_step: None,
        right_nominal_step: None,
        left_irregular: false,
        right_irregular: false,
        step_status: "unavailable".to_owned(),
        overlap_start: None,
        overlap_end: None,
        status: "mismatch".to_owned(),
        line,
    }
}

#[allow(clippy::too_many_arguments)]
fn runtime_time_alignment_record(
    binding: &str,
    left: &RuntimeTimeSeries,
    right: &RuntimeTimeSeries,
    strategy: &str,
    method: &str,
    resample_step: Option<f64>,
    tolerance: Option<f64>,
    line: usize,
) -> RuntimeTimeAlignment {
    let left_range = finite_time_range(&left.points);
    let right_range = finite_time_range(&right.points);
    let overlap_start = match (left_range, right_range) {
        (Some(left), Some(right)) => Some(left.0.max(right.0)),
        _ => None,
    };
    let overlap_end = match (left_range, right_range) {
        (Some(left), Some(right)) => Some(left.1.min(right.1)),
        _ => None,
    };
    let sorted_right = sorted_time_alignment_points(&right.points);
    let matched_count = left
        .points
        .iter()
        .filter(|left_point| left_point.x.is_finite())
        .filter(|left_point| {
            let match_tolerance =
                tolerance.unwrap_or_else(|| time_coordinate_tolerance(&sorted_right, left_point.x));
            nearest_time_alignment_candidate(&sorted_right, left_point.x)
                .is_some_and(|(distance, _)| distance <= match_tolerance)
        })
        .count();
    let status = if matched_count == left.points.len().min(right.points.len())
        && left.points.len() == right.points.len()
    {
        "matched"
    } else if overlap_start
        .zip(overlap_end)
        .is_some_and(|(start, end)| end >= start)
    {
        "overlap"
    } else {
        "mismatch"
    };
    let left_nominal_step = nominal_time_step(&left.points);
    let right_nominal_step = nominal_time_step(&right.points);
    let left_irregular = time_axis_irregular(&left.points, left_nominal_step);
    let right_irregular = time_axis_irregular(&right.points, right_nominal_step);
    let step_status = time_step_status(
        left_nominal_step,
        right_nominal_step,
        left_irregular,
        right_irregular,
    );
    RuntimeTimeAlignment {
        binding: binding.to_owned(),
        left: left.name.clone(),
        right: right.name.clone(),
        axis: left.axis.clone(),
        strategy: strategy.to_owned(),
        method: method.to_owned(),
        resample_step,
        tolerance,
        left_count: left.points.len(),
        right_count: right.points.len(),
        matched_count,
        target_count: 0,
        output_count: 0,
        materialization_status: "not_requested".to_owned(),
        materialization_reason:
            "automatic pairwise comparison does not create a named output TimeSeries".to_owned(),
        left_nominal_step,
        right_nominal_step,
        left_irregular,
        right_irregular,
        step_status: step_status.to_owned(),
        overlap_start,
        overlap_end,
        status: status.to_owned(),
        line,
    }
}

fn materialize_uncertainties(report: &CheckReport) -> Vec<RuntimeUncertainty> {
    let mut uncertainties = Vec::new();
    for info in &report.semantic_program.uncertainty_infos {
        let uncertainty = materialize_uncertainty(info, &uncertainties);
        uncertainties.push(uncertainty);
    }
    uncertainties
}

fn materialize_numeric_values(
    report: &CheckReport,
    uncertainties: &[RuntimeUncertainty],
) -> Vec<RuntimeNumericValue> {
    report
        .semantic_program
        .typed_bindings
        .iter()
        .filter(|binding| runtime_numeric_binding(report, binding))
        .map(|binding| {
            let uncertainty = uncertainties
                .iter()
                .find(|uncertainty| uncertainty.binding == binding.name);
            RuntimeNumericValue {
                binding: binding.name.clone(),
                value_kind: "scalar".to_owned(),
                quantity_kind: binding.semantic_type.quantity_kind.clone(),
                display_unit: binding.semantic_type.display_unit.clone(),
                representation: uncertainty
                    .map(|uncertainty| uncertainty.kind.clone())
                    .unwrap_or_else(|| "Certain".to_owned()),
                value: uncertainty.and_then(|uncertainty| uncertainty.mean),
                uncertainty: uncertainty.map(runtime_numeric_uncertainty_payload),
                status: if uncertainty.is_some() {
                    "uncertainty_attached".to_owned()
                } else {
                    "certain_fast_path".to_owned()
                },
                line: binding.line,
            }
        })
        .collect()
}

fn runtime_numeric_binding(report: &CheckReport, binding: &eng_compiler::TypedBinding) -> bool {
    if binding.semantic_type.display_unit.is_empty() {
        return false;
    }
    if matches!(
        binding.semantic_type.display_unit.as_str(),
        "object" | "vector" | "unknown"
    ) {
        return false;
    }
    if matches!(
        binding.semantic_type.quantity_kind.as_str(),
        "ProcessResult" | "String" | "Path" | "Bool"
    ) {
        return false;
    }
    if binding.semantic_type.quantity_kind.starts_with("Array[")
        || binding
            .semantic_type
            .quantity_kind
            .starts_with("TimeSeries[")
        || binding.semantic_type.quantity_kind.starts_with("Table[")
    {
        return false;
    }
    !report
        .semantic_program
        .csv_promotions
        .iter()
        .any(|promotion| promotion.binding == binding.name)
}

fn runtime_numeric_uncertainty_payload(
    uncertainty: &RuntimeUncertainty,
) -> RuntimeNumericUncertaintyPayload {
    RuntimeNumericUncertaintyPayload {
        binding: uncertainty.binding.clone(),
        kind: uncertainty.kind.clone(),
        distribution: uncertainty.distribution.clone(),
        method: uncertainty.method.clone(),
        mean: uncertainty.mean,
        stddev: uncertainty.stddev,
        error: uncertainty.error.clone(),
        lower: uncertainty.lower,
        upper: uncertainty.upper,
        p05: uncertainty.p05,
        p50: uncertainty.p50,
        p95: uncertainty.p95,
        sample_count: uncertainty.sample_count,
        status: uncertainty.status.clone(),
    }
}

fn materialize_uncertainty(
    info: &eng_compiler::UncertaintyInfo,
    prior: &[RuntimeUncertainty],
) -> RuntimeUncertainty {
    let declared_mean = info.mean.as_deref().and_then(first_numeric_value);
    let declared_error_fraction = info.error.as_deref().and_then(relative_error_fraction);
    let declared_stddev = info
        .stddev
        .as_deref()
        .and_then(first_numeric_value)
        .or_else(|| {
            declared_mean
                .zip(declared_error_fraction)
                .map(|(mean, error)| mean.abs() * error)
        });
    let declared_lower = info.lower.as_deref().and_then(first_numeric_value);
    let declared_upper = info.upper.as_deref().and_then(first_numeric_value);
    let requested_count = info.sample_count.clamp(1, 256);
    let distribution = info
        .distribution
        .clone()
        .unwrap_or_else(|| info.kind.to_ascii_lowercase());
    let method = info.method.clone();
    let source = info.source.as_deref().and_then(|source| {
        prior
            .iter()
            .find(|uncertainty| uncertainty.binding == source)
    });
    let is_propagation = info
        .expression
        .trim_start()
        .to_ascii_lowercase()
        .starts_with("propagate(");
    let is_arithmetic_derivation =
        distribution == "arithmetic" && !info.propagation.is_empty() && !is_propagation;
    let scale = info
        .scale
        .as_deref()
        .and_then(first_numeric_value)
        .unwrap_or(1.0);
    let offset = info
        .offset
        .as_deref()
        .and_then(first_numeric_value)
        .unwrap_or(0.0);
    let source_missing = if is_arithmetic_derivation {
        info.propagation.iter().any(|term| {
            !prior
                .iter()
                .any(|uncertainty| uncertainty.binding == term.source)
        })
    } else {
        (info.kind == "Ensemble" || is_propagation) && source.is_none()
    };

    let arithmetic_propagation = if is_arithmetic_derivation && !source_missing {
        arithmetic_uncertainty_propagation(info, prior, requested_count)
    } else {
        None
    };
    let arithmetic_status = arithmetic_propagation
        .as_ref()
        .map(|propagation| propagation.status.clone());

    let mut samples = match info.kind.as_str() {
        _ if is_arithmetic_derivation && source_missing => Vec::new(),
        _ if is_arithmetic_derivation => arithmetic_propagation
            .as_ref()
            .map(|propagation| propagation.samples.clone())
            .unwrap_or_default(),
        "Measured" => match (declared_mean, declared_stddev) {
            (Some(mean), Some(stddev)) => normal_samples(mean, stddev, requested_count.max(3)),
            (Some(mean), None) => vec![mean],
            _ => Vec::new(),
        },
        "Interval" => interval_samples(declared_lower, declared_upper),
        "Ensemble" if source_missing => Vec::new(),
        "Ensemble" => source
            .map(|source| resample_deterministic(&source.samples, requested_count))
            .unwrap_or_default(),
        "Distribution" if is_propagation && source_missing => Vec::new(),
        "Distribution" if is_propagation => source
            .map(|source| {
                resample_deterministic(&source.samples, requested_count)
                    .into_iter()
                    .map(|value| value * scale + offset)
                    .collect()
            })
            .unwrap_or_default(),
        "Distribution" if distribution == "uniform" => {
            uniform_samples(declared_lower, declared_upper, requested_count)
        }
        "Distribution" => normal_samples(
            declared_mean.unwrap_or(0.0),
            declared_stddev.unwrap_or(1.0),
            requested_count,
        ),
        _ => Vec::new(),
    };
    let arithmetic_evaluation_unavailable =
        is_arithmetic_derivation && !source_missing && samples.is_empty();
    if samples.is_empty() {
        samples.push(declared_mean.unwrap_or(0.0));
    }
    let summary = sample_summary(&samples);
    let p05 = quantile(&samples, 0.05);
    let p50 = quantile(&samples, 0.50);
    let p95 = quantile(&samples, 0.95);

    RuntimeUncertainty {
        binding: info.binding.clone(),
        kind: info.kind.clone(),
        quantity_kind: info.quantity_kind.clone(),
        display_unit: info.display_unit.clone(),
        expression: info.expression.clone(),
        source: info.source.clone(),
        distribution: Some(distribution),
        method,
        scale: info.scale.as_ref().map(|_| scale),
        offset: info.offset.as_ref().map(|_| offset),
        mean: declared_mean.or(summary.mean),
        stddev: declared_stddev.or(summary.stddev),
        error: info.error.clone(),
        lower: declared_lower.or(summary.lower),
        upper: declared_upper.or(summary.upper),
        p05,
        p50,
        p95,
        sample_count: samples.len(),
        propagation_count: info.propagation.len(),
        propagation: info
            .propagation
            .iter()
            .map(|term| ReportUncertaintyPropagationTerm {
                source: term.source.clone(),
                role: term.role.clone(),
                quantity_kind: term.quantity_kind.clone(),
            })
            .collect(),
        samples,
        status: if source_missing {
            "source_unresolved".to_owned()
        } else if arithmetic_evaluation_unavailable {
            "arithmetic_evaluation_unavailable".to_owned()
        } else if is_arithmetic_derivation {
            arithmetic_status.unwrap_or_else(|| {
                if info.method.as_deref() == Some("interval") {
                    "propagated_interval_arithmetic".to_owned()
                } else {
                    "propagated_linear_arithmetic".to_owned()
                }
            })
        } else if is_propagation {
            "propagated_linear".to_owned()
        } else if info.kind == "Measured" {
            "measured_sampled".to_owned()
        } else {
            "sampled_distribution".to_owned()
        },
        line: info.line,
    }
}

#[derive(Clone, Debug)]
struct RuntimeArithmeticPropagation {
    samples: Vec<f64>,
    status: String,
}

fn arithmetic_uncertainty_propagation(
    info: &eng_compiler::UncertaintyInfo,
    prior: &[RuntimeUncertainty],
    requested_count: usize,
) -> Option<RuntimeArithmeticPropagation> {
    let sources = arithmetic_uncertainty_sources(info, prior);
    if sources.is_empty() {
        return None;
    }
    if let Some(samples) = measured_linear_arithmetic_samples(info, &sources, requested_count) {
        let status = if sources.len() > 1 {
            "propagated_independent_linear_arithmetic"
        } else {
            "propagated_linear_arithmetic"
        };
        return Some(RuntimeArithmeticPropagation {
            samples,
            status: status.to_owned(),
        });
    }
    if let Some(samples) = interval_corner_arithmetic_samples(info, &sources) {
        return Some(RuntimeArithmeticPropagation {
            samples,
            status: "propagated_interval_arithmetic".to_owned(),
        });
    }
    sampled_arithmetic_samples(info, &sources, requested_count).map(|samples| {
        RuntimeArithmeticPropagation {
            samples,
            status: if info.method.as_deref() == Some("interval") {
                "propagated_interval_arithmetic".to_owned()
            } else {
                "propagated_linear_arithmetic".to_owned()
            },
        }
    })
}

fn arithmetic_uncertainty_sources<'a>(
    info: &eng_compiler::UncertaintyInfo,
    prior: &'a [RuntimeUncertainty],
) -> Vec<&'a RuntimeUncertainty> {
    info.propagation
        .iter()
        .filter_map(|term| {
            prior
                .iter()
                .find(|uncertainty| uncertainty.binding == term.source)
        })
        .collect()
}

fn measured_linear_arithmetic_samples(
    info: &eng_compiler::UncertaintyInfo,
    sources: &[&RuntimeUncertainty],
    requested_count: usize,
) -> Option<Vec<f64>> {
    if !sources.iter().all(|source| source.kind == "Measured") {
        return None;
    }
    let mut means = HashMap::new();
    for source in sources {
        means.insert(source.binding.clone(), source.mean?);
    }
    let parsed = parse_runtime_arithmetic_expression(info, &means, sources)?;
    let mean = parsed.evaluate(&means).ok()?;
    let mut variance = 0.0;
    for source in sources {
        let stddev = source.stddev?;
        if stddev == 0.0 {
            continue;
        }
        let base = means.get(&source.binding).copied()?;
        let step = (base.abs() * 1.0e-6).max(1.0e-6);
        let mut plus = means.clone();
        plus.insert(source.binding.clone(), base + step);
        let mut minus = means.clone();
        minus.insert(source.binding.clone(), base - step);
        let derivative =
            (parsed.evaluate(&plus).ok()? - parsed.evaluate(&minus).ok()?) / (2.0 * step);
        variance += derivative * derivative * stddev * stddev;
    }
    Some(normal_samples(
        mean,
        variance.sqrt(),
        requested_count.max(3),
    ))
}

fn interval_corner_arithmetic_samples(
    info: &eng_compiler::UncertaintyInfo,
    sources: &[&RuntimeUncertainty],
) -> Option<Vec<f64>> {
    if sources.is_empty() || !sources.iter().all(|source| source.kind == "Interval") {
        return None;
    }
    if sources.len() > 8 {
        return None;
    }
    let bounds = sources
        .iter()
        .map(|source| Some((source.binding.clone(), source.lower?, source.upper?)))
        .collect::<Option<Vec<_>>>()?;
    let symbols = bounds
        .iter()
        .map(|(binding, lower, _upper)| (binding.clone(), *lower))
        .collect::<HashMap<_, _>>();
    let parsed = parse_runtime_arithmetic_expression(info, &symbols, sources)?;
    let corner_count = 1usize << bounds.len();
    let mut samples = Vec::with_capacity(corner_count);
    for mask in 0..corner_count {
        let mut corner = HashMap::new();
        for (index, (binding, lower, upper)) in bounds.iter().enumerate() {
            let value = if (mask & (1usize << index)) == 0 {
                *lower
            } else {
                *upper
            };
            corner.insert(binding.clone(), value);
        }
        samples.push(parsed.evaluate(&corner).ok()?);
    }
    Some(samples)
}

fn sampled_arithmetic_samples(
    info: &eng_compiler::UncertaintyInfo,
    sources: &[&RuntimeUncertainty],
    requested_count: usize,
) -> Option<Vec<f64>> {
    let count = sources
        .iter()
        .map(|source| source.samples.len())
        .max()
        .unwrap_or(0)
        .max(requested_count)
        .clamp(1, 256);
    let resampled = sources
        .iter()
        .map(|source| {
            (
                source.binding.as_str(),
                resample_deterministic(&source.samples, count),
            )
        })
        .collect::<Vec<_>>();
    let first_symbols = resampled
        .iter()
        .filter_map(|(name, samples)| {
            samples
                .first()
                .copied()
                .map(|value| ((*name).to_owned(), value))
        })
        .collect::<HashMap<_, _>>();
    if first_symbols.len() != sources.len() {
        return None;
    }
    let parsed = parse_runtime_arithmetic_expression(info, &first_symbols, sources)?;
    let mut samples = Vec::with_capacity(count);
    for index in 0..count {
        let symbols = resampled
            .iter()
            .filter_map(|(name, values)| {
                values
                    .get(index)
                    .copied()
                    .map(|value| ((*name).to_owned(), value))
            })
            .collect::<HashMap<_, _>>();
        samples.push(parsed.evaluate(&symbols).ok()?);
    }
    Some(samples)
}

fn parse_runtime_arithmetic_expression(
    info: &eng_compiler::UncertaintyInfo,
    symbols: &HashMap<String, f64>,
    sources: &[&RuntimeUncertainty],
) -> Option<ParsedArithmeticExpression> {
    let symbol_units = sources
        .iter()
        .map(|source| {
            (
                source.binding.clone(),
                ArithmeticUnitMetadata {
                    display_unit: source.display_unit.clone(),
                    canonical_unit: source.display_unit.clone(),
                    quantity_kind: source.quantity_kind.clone(),
                },
            )
        })
        .collect::<HashMap<_, _>>();
    let mut ignore_units = |value: f64, _unit: Option<&str>| Ok(value);
    parse_arithmetic_expression_with_symbol_metadata_and_unit_converter(
        &info.expression,
        symbols,
        &symbol_units,
        &mut ignore_units,
        ArithmeticExpressionProfile::SOURCE_RESIDUAL,
    )
    .ok()
}

fn materialize_ml_artifacts(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
    tables: &[RuntimeTable],
) -> Vec<RuntimeMlArtifact> {
    let mut artifacts = Vec::new();
    for info in &report.semantic_program.ml_infos {
        let artifact = materialize_ml_artifact(info, &artifacts, series, tables);
        artifacts.push(artifact);
    }
    artifacts
}

fn materialize_ml_artifact(
    info: &eng_compiler::MlInfo,
    prior: &[RuntimeMlArtifact],
    series: &[RuntimeTimeSeries],
    tables: &[RuntimeTable],
) -> RuntimeMlArtifact {
    match info.kind.as_str() {
        "TrainTestSplit" => materialize_split_artifact(info, series, tables),
        "RegressionModel" | "MlpModel" => materialize_model_artifact(info, prior, series, tables),
        "ModelMetrics" => materialize_metrics_artifact(info, prior),
        "LeakageLint" => materialize_leakage_artifact(info, prior),
        "ModelCard" => materialize_model_card_artifact(info, prior),
        "PredictionResult" => materialize_prediction_artifact(info, prior, tables),
        _ => base_ml_artifact(info, "metadata"),
    }
}

fn materialize_split_artifact(
    info: &eng_compiler::MlInfo,
    series: &[RuntimeTimeSeries],
    tables: &[RuntimeTable],
) -> RuntimeMlArtifact {
    let source_series = info
        .source
        .as_deref()
        .and_then(|source| series.iter().find(|series| series.name == source));
    let target_series = info
        .target
        .as_deref()
        .and_then(|target| series.iter().find(|series| series.name == target))
        .or(source_series);
    let len = source_series.map(|series| series.points.len()).unwrap_or(0);
    let test_fraction = parse_fraction(info.test_fraction.as_deref()).unwrap_or(0.25);
    let test_count = if len > 1 {
        ((len as f64 * test_fraction).round() as usize).clamp(1, len - 1)
    } else {
        0
    };
    let train_count = len.saturating_sub(test_count);
    let mut artifact = base_ml_artifact(info, "prepared");
    artifact.train_count = Some(train_count);
    artifact.test_count = Some(test_count);
    artifact.leakage_findings = leakage_findings(info, source_series, tables);
    artifact.leakage_status = Some(leakage_status_from_findings(&artifact.leakage_findings));
    artifact.target_quantity = target_series.map(|series| series.quantity_kind.clone());
    artifact.display_unit = target_series
        .map(|series| series.display_unit.clone())
        .unwrap_or_else(|| "1".to_owned());
    artifact
}

fn materialize_model_artifact(
    info: &eng_compiler::MlInfo,
    prior: &[RuntimeMlArtifact],
    series: &[RuntimeTimeSeries],
    tables: &[RuntimeTable],
) -> RuntimeMlArtifact {
    let split = info
        .source
        .as_deref()
        .and_then(|source| prior.iter().find(|artifact| artifact.binding == source));
    let source_name = split
        .and_then(|split| split.source.as_deref())
        .or(info.source.as_deref());
    let target = info
        .target
        .clone()
        .or_else(|| split.and_then(|split| split.target.clone()))
        .or_else(|| source_name.map(str::to_owned));
    let features = if info.features.is_empty() {
        split
            .map(|split| split.features.clone())
            .unwrap_or_default()
    } else {
        info.features.clone()
    };
    let source_series =
        source_name.and_then(|source| series.iter().find(|series| series.name == source));
    let target_series = target
        .as_deref()
        .and_then(|target| series.iter().find(|series| series.name == target))
        .or(source_series);
    let mut artifact = base_ml_artifact(info, "unavailable");
    artifact.target = target.clone();
    artifact.features = features.clone();
    artifact.target_quantity = target_series.map(|series| series.quantity_kind.clone());
    artifact.display_unit = target_series
        .map(|series| series.display_unit.clone())
        .unwrap_or_else(|| "1".to_owned());
    artifact.leakage_status = split.and_then(|split| split.leakage_status.clone());
    artifact.leakage_findings = split
        .map(|split| split.leakage_findings.clone())
        .unwrap_or_default();

    let Some(source_name) = source_name else {
        artifact.leakage_findings.push("missing_source".to_owned());
        artifact.leakage_status = Some(leakage_status_from_findings(&artifact.leakage_findings));
        return artifact;
    };
    let dataset = match ml_dataset(source_name, target.as_deref(), &features, series, tables) {
        Ok(dataset) => dataset,
        Err(mut findings) => {
            artifact.leakage_findings.append(&mut findings);
            artifact.leakage_status =
                Some(leakage_status_from_findings(&artifact.leakage_findings));
            return artifact;
        }
    };
    let total_count = dataset.rows.len();
    let requested_train_count = split
        .and_then(|split| split.train_count)
        .unwrap_or_else(|| {
            let test_fraction = parse_fraction(info.test_fraction.as_deref()).unwrap_or(0.25);
            let test_count = ((total_count as f64 * test_fraction).round() as usize)
                .clamp(1, total_count.saturating_sub(1).max(1));
            total_count.saturating_sub(test_count)
        });
    let train_count = requested_train_count
        .min(total_count.saturating_sub(1))
        .max((total_count > 1) as usize);
    let requested_test_count = split
        .and_then(|split| split.test_count)
        .unwrap_or_else(|| total_count.saturating_sub(train_count));
    let test_count = requested_test_count
        .min(total_count.saturating_sub(train_count))
        .max((total_count > train_count) as usize);
    let training = if info.kind == "MlpModel" {
        train_mlp_model(info, &dataset, train_count, test_count)
    } else {
        train_linear_model(info, &dataset, train_count, test_count)
    };
    artifact.target_quantity = Some(dataset.target_quantity.clone());
    artifact.display_unit = dataset.display_unit.clone();
    artifact.training_data_hash = Some(ml_training_data_hash(&dataset, train_count));
    artifact.status = training.status;
    artifact.train_count = Some(train_count);
    artifact.test_count = Some(training.actual.len());
    artifact.rmse = Some(training.rmse);
    artifact.mae = Some(training.mae);
    artifact.r2 = Some(training.r2);
    artifact.coefficients = training.coefficients;
    artifact.intercept = Some(training.intercept);
    artifact.loss_history = training.loss_history;
    artifact.parity_points = training
        .actual
        .iter()
        .zip(&training.predicted)
        .map(|(actual, predicted)| RuntimePoint {
            x: *actual,
            y: *predicted,
        })
        .collect();
    artifact.residual_points = training
        .actual
        .iter()
        .zip(&training.predicted)
        .enumerate()
        .map(|(index, (actual, predicted))| RuntimePoint {
            x: index as f64,
            y: actual - predicted,
        })
        .collect();
    artifact.model_artifact_hash = Some(ml_model_artifact_hash(&artifact));
    artifact.model_card = Some(model_card_text(info, &artifact, &dataset));
    artifact
}

fn materialize_metrics_artifact(
    info: &eng_compiler::MlInfo,
    prior: &[RuntimeMlArtifact],
) -> RuntimeMlArtifact {
    let source = info
        .source
        .as_deref()
        .and_then(|source| prior.iter().find(|artifact| artifact.binding == source));
    let mut artifact = base_ml_artifact(info, "evaluated");
    if let Some(source) = source {
        artifact.target = source.target.clone();
        artifact.target_quantity = source.target_quantity.clone();
        artifact.features = source.features.clone();
        artifact.algorithm = source.algorithm.clone();
        artifact.test_fraction = source.test_fraction.clone();
        artifact.seed = source.seed.clone();
        artifact.hidden_layers = source.hidden_layers.clone();
        artifact.epochs = source.epochs;
        artifact.train_count = source.train_count;
        artifact.test_count = source.test_count;
        artifact.rmse = source.rmse;
        artifact.mae = source.mae;
        artifact.r2 = source.r2;
        artifact.leakage_status = source.leakage_status.clone();
        artifact.leakage_findings = source.leakage_findings.clone();
        artifact.coefficients = source.coefficients.clone();
        artifact.intercept = source.intercept;
        artifact.loss_history = source.loss_history.clone();
        artifact.model_card = source.model_card.clone();
        artifact.training_data_hash = source.training_data_hash.clone();
        artifact.model_artifact_hash = source.model_artifact_hash.clone();
        artifact.display_unit = source.display_unit.clone();
        artifact.parity_points = source.parity_points.clone();
        artifact.residual_points = source.residual_points.clone();
    }
    artifact
}

fn materialize_prediction_artifact(
    info: &eng_compiler::MlInfo,
    prior: &[RuntimeMlArtifact],
    tables: &[RuntimeTable],
) -> RuntimeMlArtifact {
    let model = info
        .source
        .as_deref()
        .and_then(|source| prior.iter().find(|artifact| artifact.binding == source));
    let input_table = info
        .prediction_input
        .as_deref()
        .and_then(|input| tables.iter().find(|table| table.binding == input));
    let mut artifact = base_ml_artifact(info, "unavailable");
    artifact.prediction_input = info.prediction_input.clone();

    if let Some(model) = model {
        artifact.target = model.target.clone();
        artifact.target_quantity = model.target_quantity.clone();
        artifact.features = model.features.clone();
        artifact.algorithm = model.algorithm.clone();
        artifact.test_fraction = model.test_fraction.clone();
        artifact.seed = model.seed.clone();
        artifact.hidden_layers = model.hidden_layers.clone();
        artifact.epochs = model.epochs;
        artifact.train_count = model.train_count;
        artifact.test_count = input_table.map(|table| table.row_count);
        artifact.rmse = model.rmse;
        artifact.mae = model.mae;
        artifact.r2 = model.r2;
        artifact.leakage_status = model.leakage_status.clone();
        artifact.leakage_findings = model.leakage_findings.clone();
        artifact.coefficients = model.coefficients.clone();
        artifact.intercept = model.intercept;
        artifact.loss_history = model.loss_history.clone();
        artifact.model_card = model.model_card.clone();
        artifact.training_data_hash = model.training_data_hash.clone();
        artifact.model_artifact_hash = model.model_artifact_hash.clone();
        artifact.display_unit = model.display_unit.clone();
        artifact.status =
            prediction_artifact_status(model, input_table, info.prediction_input.as_deref());
    }
    artifact
}

fn prediction_artifact_status(
    model: &RuntimeMlArtifact,
    input_table: Option<&RuntimeTable>,
    input_name: Option<&str>,
) -> String {
    if input_name.is_none() {
        return "missing_input".to_owned();
    }
    if input_table.is_none() {
        return "missing_input_table".to_owned();
    }
    if model.intercept.is_none() || model.coefficients.is_empty() || model.features.is_empty() {
        return "missing_model_coefficients".to_owned();
    }
    "predicted".to_owned()
}

fn materialize_leakage_artifact(
    info: &eng_compiler::MlInfo,
    prior: &[RuntimeMlArtifact],
) -> RuntimeMlArtifact {
    let source = info
        .source
        .as_deref()
        .and_then(|source| prior.iter().find(|artifact| artifact.binding == source));
    let mut artifact = base_ml_artifact(info, "executed");
    artifact.leakage_status = Some(
        source
            .and_then(|source| source.leakage_status.clone())
            .unwrap_or_else(|| leakage_status_from_findings(&leakage_findings(info, None, &[]))),
    );
    artifact.leakage_findings = source
        .map(|source| source.leakage_findings.clone())
        .unwrap_or_else(|| leakage_findings(info, None, &[]));
    artifact
}

fn materialize_model_card_artifact(
    info: &eng_compiler::MlInfo,
    prior: &[RuntimeMlArtifact],
) -> RuntimeMlArtifact {
    let source = info
        .source
        .as_deref()
        .and_then(|source| prior.iter().find(|artifact| artifact.binding == source));
    let mut artifact = base_ml_artifact(info, "documented");
    if let Some(source) = source {
        artifact.target = source.target.clone();
        artifact.target_quantity = source.target_quantity.clone();
        artifact.features = source.features.clone();
        artifact.algorithm = source.algorithm.clone();
        artifact.test_fraction = source.test_fraction.clone();
        artifact.seed = source.seed.clone();
        artifact.hidden_layers = source.hidden_layers.clone();
        artifact.epochs = source.epochs;
        artifact.train_count = source.train_count;
        artifact.test_count = source.test_count;
        artifact.model_card = source.model_card.clone().or_else(|| {
            Some(format!(
                "{} model card: status={}, train={}, test={}",
                source.binding,
                source.status,
                source.train_count.unwrap_or(0),
                source.test_count.unwrap_or(0)
            ))
        });
        artifact.rmse = source.rmse;
        artifact.mae = source.mae;
        artifact.r2 = source.r2;
        artifact.leakage_status = source.leakage_status.clone();
        artifact.leakage_findings = source.leakage_findings.clone();
        artifact.coefficients = source.coefficients.clone();
        artifact.intercept = source.intercept;
        artifact.loss_history = source.loss_history.clone();
        artifact.training_data_hash = source.training_data_hash.clone();
        artifact.model_artifact_hash = source.model_artifact_hash.clone();
        artifact.display_unit = source.display_unit.clone();
        artifact.parity_points = source.parity_points.clone();
        artifact.residual_points = source.residual_points.clone();
    }
    artifact
}

fn base_ml_artifact(info: &eng_compiler::MlInfo, status: &str) -> RuntimeMlArtifact {
    RuntimeMlArtifact {
        binding: info.binding.clone(),
        kind: info.kind.clone(),
        source: info.source.clone(),
        prediction_input: info.prediction_input.clone(),
        target: info.target.clone(),
        target_quantity: None,
        features: info.features.clone(),
        algorithm: info.algorithm.clone(),
        test_fraction: info.test_fraction.clone(),
        seed: info.seed.clone(),
        hidden_layers: info.hidden_layers.clone(),
        epochs: info.epochs,
        status: status.to_owned(),
        train_count: None,
        test_count: None,
        rmse: None,
        mae: None,
        r2: None,
        leakage_status: None,
        leakage_findings: Vec::new(),
        coefficients: Vec::new(),
        intercept: None,
        loss_history: Vec::new(),
        model_card: None,
        training_data_hash: None,
        model_artifact_hash: None,
        expression: info.expression.clone(),
        display_unit: "1".to_owned(),
        parity_points: Vec::new(),
        residual_points: Vec::new(),
        line: info.line,
    }
}

fn materialize_prediction_tables(
    artifacts: &[RuntimeMlArtifact],
    tables: &[RuntimeTable],
) -> Vec<RuntimeTable> {
    artifacts
        .iter()
        .filter(|artifact| artifact.kind == "PredictionResult")
        .filter_map(|artifact| materialize_prediction_table(artifact, tables))
        .collect()
}

fn materialize_prediction_table(
    artifact: &RuntimeMlArtifact,
    tables: &[RuntimeTable],
) -> Option<RuntimeTable> {
    let input_name = artifact.prediction_input.as_deref()?;
    let input_table = tables.iter().find(|table| table.binding == input_name)?;
    let row_count = input_table.row_count;
    let predictions = prediction_values(artifact, input_table);
    let missing_predictions = predictions.iter().filter(|value| value.is_none()).count();
    let confidence_values = predictions
        .iter()
        .map(|value| value.map(|_| 1.0))
        .collect::<Vec<_>>();
    let confidence_missing = confidence_values
        .iter()
        .filter(|value| value.is_none())
        .count();
    let target_unit = prediction_target_unit(artifact);
    let output_column = prediction_output_column_name(artifact.target.as_deref());
    let case_ids = prediction_case_ids(input_table);
    let mut columns = Vec::new();
    columns.push(RuntimeColumn {
        name: "case_id".to_owned(),
        type_name: "String".to_owned(),
        unit: None,
        canonical_unit: None,
        is_index: false,
        values: RuntimeValues::Text(case_ids),
        canonical_values: Vec::new(),
        missing_count: 0,
        conversion_failures: Vec::new(),
    });
    columns.push(RuntimeColumn {
        name: output_column,
        type_name: artifact
            .target_quantity
            .clone()
            .unwrap_or_else(|| "Prediction".to_owned()),
        unit: Some(target_unit.clone()),
        canonical_unit: Some(target_unit),
        is_index: false,
        values: RuntimeValues::Number(predictions.clone()),
        canonical_values: predictions,
        missing_count: missing_predictions,
        conversion_failures: Vec::new(),
    });
    columns.push(RuntimeColumn {
        name: "confidence".to_owned(),
        type_name: "Ratio".to_owned(),
        unit: Some("1".to_owned()),
        canonical_unit: Some("1".to_owned()),
        is_index: false,
        values: RuntimeValues::Number(confidence_values.clone()),
        canonical_values: confidence_values,
        missing_count: confidence_missing,
        conversion_failures: Vec::new(),
    });

    Some(RuntimeTable {
        binding: artifact.binding.clone(),
        schema_name: "PredictionResult".to_owned(),
        source: format!(
            "predict {} using {}",
            artifact.source.as_deref().unwrap_or("model"),
            input_name
        ),
        source_hash: Some(prediction_table_source_hash(artifact, input_table)),
        row_count,
        columns,
        parse_failures: Vec::new(),
        line: artifact.line,
    })
}

fn prediction_values(artifact: &RuntimeMlArtifact, input_table: &RuntimeTable) -> Vec<Option<f64>> {
    let coefficients = artifact
        .coefficients
        .iter()
        .map(|coefficient| (coefficient.feature.as_str(), coefficient.value))
        .collect::<HashMap<_, _>>();
    (0..input_table.row_count)
        .map(|row_index| {
            let mut value = artifact.intercept?;
            for feature in &artifact.features {
                let coefficient = coefficients.get(feature.as_str()).copied()?;
                let column = input_table.column(feature)?;
                value += coefficient * numeric_column_value(column, row_index)?;
            }
            Some(value)
        })
        .collect()
}

fn prediction_case_ids(input_table: &RuntimeTable) -> Vec<String> {
    let case_column = input_table
        .columns
        .iter()
        .find(|column| column.name.eq_ignore_ascii_case("case_id"));
    let case_width = input_table.row_count.to_string().len().max(3);
    (0..input_table.row_count)
        .map(|row_index| {
            case_column
                .map(|column| table_cell_text(column, row_index))
                .filter(|value| !value.trim().is_empty())
                .unwrap_or_else(|| format!("row_{:0case_width$}", row_index + 1))
        })
        .collect()
}

fn prediction_output_column_name(target: Option<&str>) -> String {
    let raw = target.unwrap_or("value");
    let sanitized = raw
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() {
                character.to_ascii_lowercase()
            } else {
                '_'
            }
        })
        .collect::<String>()
        .trim_matches('_')
        .to_owned();
    format!(
        "predicted_{}",
        if sanitized.is_empty() {
            "value"
        } else {
            sanitized.as_str()
        }
    )
}

fn prediction_target_unit(artifact: &RuntimeMlArtifact) -> String {
    if artifact.display_unit.trim().is_empty() {
        "1".to_owned()
    } else {
        artifact.display_unit.clone()
    }
}

fn prediction_table_source_hash(
    artifact: &RuntimeMlArtifact,
    input_table: &RuntimeTable,
) -> String {
    let mut payload = format!(
        "prediction={}\nmodel={}\ninput={}\nmodel_hash={}\ninput_hash={}\n",
        artifact.binding,
        artifact.source.as_deref().unwrap_or(""),
        input_table.binding,
        artifact.model_artifact_hash.as_deref().unwrap_or(""),
        input_table.source_hash.as_deref().unwrap_or("")
    );
    for row_index in 0..input_table.row_count {
        payload.push_str(&format!("row={row_index}"));
        for column in &input_table.columns {
            payload.push('|');
            payload.push_str(&column.name);
            payload.push('=');
            payload.push_str(&table_cell_text(column, row_index));
        }
        payload.push('\n');
    }
    stable_hash_text(&payload)
}

fn materialize_system_solutions(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
) -> Vec<RuntimeSystemSolution> {
    let mut solutions = Vec::new();
    for system in &report.semantic_program.systems {
        let requests = simulate_requests(report, &system.name);
        if requests.is_empty() {
            if let Some(mut state_space_solutions) =
                materialize_state_space_solutions(report, system, None, &[], series)
            {
                solutions.append(&mut state_space_solutions);
            } else if let Some(solution) =
                materialize_first_order_thermal_solution(system, None, &[], series)
            {
                solutions.push(solution);
            } else if let Some(mut source_ode_solutions) =
                materialize_source_ode_solutions(system, None, &[], series)
            {
                solutions.append(&mut source_ode_solutions);
            }
        } else {
            for request in requests {
                if let Some(mut state_space_solutions) = materialize_state_space_solutions(
                    report,
                    system,
                    Some(request.binding.as_str()),
                    &request.options,
                    series,
                ) {
                    solutions.append(&mut state_space_solutions);
                } else if let Some(solution) = materialize_first_order_thermal_solution(
                    system,
                    Some(request.binding.as_str()),
                    &request.options,
                    series,
                ) {
                    solutions.push(solution);
                } else if let Some(mut source_ode_solutions) = materialize_source_ode_solutions(
                    system,
                    Some(request.binding.as_str()),
                    &request.options,
                    series,
                ) {
                    solutions.append(&mut source_ode_solutions);
                } else {
                    solutions.push(skipped_system_solution(
                        system,
                        Some(request.binding.as_str()),
                        &request.options,
                    ));
                }
            }
        }
    }
    solutions
}

fn materialize_component_solutions(
    report: &CheckReport,
    series: &[RuntimeTimeSeries],
) -> Vec<RuntimeComponentSolution> {
    let mut solutions = Vec::new();
    for assembly in &report.semantic_program.component_assemblies {
        let solver_assembly = solver_equation_assembly_from_component_info(report, assembly);
        let requests = component_solve_requests(report, &assembly.name);
        if requests.is_empty() {
            let mut solution =
                RuntimeComponentSolution::from_solver_assembly(&assembly.name, &solver_assembly);
            annotate_component_behavior_solution(&mut solution, assembly);
            solutions.push(solution);
            continue;
        }
        for request in requests {
            let solver = option_value(&request.options, "solver").unwrap_or("dense_linear");
            let mut solution = match solver.trim() {
                "fixed_point" => fixed_point_component_solution_from_solve_request(
                    &solver_assembly,
                    &request,
                    FixedPointSourceSolveContext {
                        assembly_name: &assembly.name,
                        method: "fixed_point_residual_graph",
                        initial_reason:
                            "fixed-point source solve initial values could not be materialized",
                        residual_scale_reason:
                            "fixed-point source solve residual scale overrides could not be materialized",
                        variable_scale_reason:
                            "fixed-point source solve variable scales could not be materialized",
                        failure_convergence_status: "fixed_point_source_failed",
                    },
                ),
                "newton" | "nonlinear_newton" => {
                    nonlinear_component_solution_from_solve_request(&solver_assembly, &request)
                }
                "implicit_euler_dae" | "dae_implicit_euler" => {
                    dae_component_solution_from_solve_request(
                        report,
                        assembly,
                        &solver_assembly,
                        &request,
                        series,
                    )
                }
                "dynamic_component_explicit_euler"
                | "dynamic_component_semi_implicit_euler"
                | "dynamic_component_adaptive_heun" => {
                    dynamic_component_solution_from_solve_request(
                        report,
                        assembly,
                        &solver_assembly,
                        &request,
                        series,
                    )
                }
                "dense_linear" | "linear" => {
                    let residual_graph = ResidualGraph::from_assembly(&solver_assembly);
                    match residual_scale_overrides_from_solve_request(
                        &request.options,
                        &residual_graph,
                    ) {
                        Ok(residual_scale_overrides) => {
                            RuntimeComponentSolution::from_solver_assembly_with_scale_overrides(
                                &assembly.name,
                                &solver_assembly,
                                &residual_scale_overrides,
                            )
                        }
                        Err(failure) => failed_source_component_solution(
                            &solver_assembly,
                            "dense_linear_residual_graph",
                            "dense linear source solve residual scale overrides could not be materialized",
                            &failure,
                            COMPONENT_LINEAR_SOLVER_TOLERANCE,
                            1,
                            "dense_linear_source_failed",
                        ),
                    }
                }
                _ => {
                    RuntimeComponentSolution::from_solver_assembly(&assembly.name, &solver_assembly)
                }
            };
            append_component_solution_reason(
                &mut solution,
                &format!("source solve binding `{}`", request.binding),
            );
            annotate_component_behavior_solution(&mut solution, assembly);
            solutions.push(solution);
        }
    }
    solutions
}

struct FixedPointSourceSolveContext<'a> {
    assembly_name: &'a str,
    method: &'a str,
    initial_reason: &'a str,
    residual_scale_reason: &'a str,
    variable_scale_reason: &'a str,
    failure_convergence_status: &'a str,
}

fn fixed_point_component_solution_from_solve_request(
    solver_assembly: &EquationAssembly,
    request: &ComponentSolveRequest,
    context: FixedPointSourceSolveContext<'_>,
) -> RuntimeComponentSolution {
    let FixedPointSourceSolveContext {
        assembly_name,
        method,
        initial_reason,
        residual_scale_reason,
        variable_scale_reason,
        failure_convergence_status,
    } = context;
    let options = fixed_point_options_from_solve_request(&request.options);
    let initial_values = match fixed_point_initial_values_from_solve_request(
        &request.options,
        &solver_assembly.unknowns,
    ) {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                initial_reason,
                &failure,
                options.tolerance,
                options.max_iterations,
                failure_convergence_status,
            );
        }
    };
    let residual_graph = ResidualGraph::from_assembly(solver_assembly);
    let residual_scale_overrides =
        match residual_scale_overrides_from_solve_request(&request.options, &residual_graph) {
            Ok(overrides) => overrides,
            Err(failure) => {
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    residual_scale_reason,
                    &failure,
                    options.tolerance,
                    options.max_iterations,
                    failure_convergence_status,
                );
            }
        };
    let variable_scale_overrides = match fixed_point_variable_scales_from_solve_request(
        &request.options,
        &solver_assembly.unknowns,
    ) {
        Ok(scales) => scales,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                variable_scale_reason,
                &failure,
                options.tolerance,
                options.max_iterations,
                failure_convergence_status,
            );
        }
    };
    RuntimeComponentSolution::from_fixed_point_solver_assembly(
        assembly_name,
        solver_assembly,
        options,
        initial_values,
        variable_scale_overrides,
        &residual_scale_overrides,
    )
}
fn materialize_system_algebraic_solutions(report: &CheckReport) -> Vec<RuntimeComponentSolution> {
    let mut solutions = Vec::new();
    for system in &report.semantic_program.systems {
        let requests = component_solve_requests(report, &system.name);
        if requests.is_empty() {
            continue;
        }
        let solver_assembly = solver_equation_assembly_from_system_info(system);
        for request in requests {
            let solver = option_value(&request.options, "solver").unwrap_or("dense_linear");
            let mut solution = match solver.trim() {
                "dense_linear" | "linear" => {
                    let residual_graph = ResidualGraph::from_assembly(&solver_assembly);
                    match residual_scale_overrides_from_solve_request(
                        &request.options,
                        &residual_graph,
                    ) {
                        Ok(residual_scale_overrides) => {
                            RuntimeComponentSolution::from_solver_assembly_with_scale_overrides(
                                &system.name,
                                &solver_assembly,
                                &residual_scale_overrides,
                            )
                        }
                        Err(failure) => failed_source_component_solution(
                            &solver_assembly,
                            "source_system_dense_linear_residual_graph",
                            "source system dense linear residual scale overrides could not be materialized",
                            &failure,
                            COMPONENT_LINEAR_SOLVER_TOLERANCE,
                            1,
                            "source_system_dense_linear_failed",
                        ),
                    }
                }
                "fixed_point" => fixed_point_component_solution_from_solve_request(
                    &solver_assembly,
                    &request,
                    FixedPointSourceSolveContext {
                        assembly_name: &system.name,
                        method: "source_system_fixed_point_residual_graph",
                        initial_reason:
                            "source system fixed-point initial values could not be materialized",
                        residual_scale_reason:
                            "source system fixed-point residual scale overrides could not be materialized",
                        variable_scale_reason:
                            "source system fixed-point variable scales could not be materialized",
                        failure_convergence_status: "source_system_fixed_point_failed",
                    },
                ),
                "newton" | "nonlinear_newton" => {
                    nonlinear_component_solution_from_solve_request(&solver_assembly, &request)
                }
                unsupported => failed_source_component_solution(
                    &solver_assembly,
                    "source_system_residual_graph",
                    "source system solve supports dense_linear/linear, fixed_point, or newton/nonlinear_newton static algebraic solves",
                    &SolverFailure::new(
                        "E-SYSTEM-SOLVE-SOLVER",
                        format!("unsupported source system solve solver `{unsupported}`"),
                    ),
                    COMPONENT_LINEAR_SOLVER_TOLERANCE,
                    1,
                    "source_system_solve_failed",
                ),
            };
            append_component_solution_reason(
                &mut solution,
                &format!("source system solve binding `{}`", request.binding),
            );
            solutions.push(solution);
        }
    }
    solutions
}
const COMPONENT_LINEAR_SOLVER_TOLERANCE: f64 = 1e-9;
const COMPONENT_BEHAVIOR_NOT_INTEGRATED_CODE: &str = "E-BEHAVIOR-NOT-INTEGRATED";
const COMPONENT_BEHAVIOR_NOT_INTEGRATED_NOTE: &str =
    "behavior graph nodes are present but not yet integrated into numeric residual evaluation";

#[derive(Clone, Debug, PartialEq)]
struct ComponentSolveRequest {
    binding: String,
    options: Vec<eng_compiler::WithOptionInfo>,
}

fn component_solve_requests(
    report: &CheckReport,
    assembly_name: &str,
) -> Vec<ComponentSolveRequest> {
    report
        .inferred_declarations
        .iter()
        .filter_map(|declaration| {
            let requested_assembly = declaration.expression.trim().strip_prefix("solve ")?.trim();
            if requested_assembly != assembly_name {
                return None;
            }
            let options = report
                .semantic_program
                .with_blocks
                .iter()
                .find(|block| block.owner_line == Some(declaration.line))
                .map(|block| block.options.clone())
                .unwrap_or_default();
            Some(ComponentSolveRequest {
                binding: declaration.name.clone(),
                options,
            })
        })
        .collect()
}

fn nonlinear_component_solution_from_solve_request(
    solver_assembly: &EquationAssembly,
    request: &ComponentSolveRequest,
) -> RuntimeComponentSolution {
    let mut options = newton_options_from_solve_request(&request.options);
    let tolerance = options.tolerance;
    match newton_variable_scales_from_solve_request(&request.options, &solver_assembly.unknowns) {
        Ok(Some(scales)) => {
            options.variable_scales = scales;
            options.variable_scale_policy = "user_provided_variable_scales".to_owned();
        }
        Ok(None) => apply_newton_variable_scales_from_unknowns(
            &mut options,
            &solver_assembly.unknowns,
            "unit_default_from_assembly_unknowns",
        ),
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                "newton_source_residual_graph",
                "Newton source solve variable scales could not be materialized",
                &failure,
                tolerance,
                options.max_iterations,
                "newton_source_failed",
            );
        }
    }

    if !solver_assembly.states.is_empty() {
        return failed_source_component_solution(
            solver_assembly,
            "newton_source_residual_graph",
            "Newton source solve requires an algebraic-only component residual graph; use implicit_euler_dae for state derivatives",
            &SolverFailure::new(
                "E-NEWTON-SOURCE-SHAPE",
                "source Newton solve cannot solve residual graphs with state derivatives",
            ),
            tolerance,
            options.max_iterations,
            "newton_source_failed",
        );
    }
    if solver_assembly.generated_equations.is_empty()
        || solver_assembly.unknowns.is_empty()
        || solver_assembly.generated_equations.len() != solver_assembly.unknowns.len()
    {
        return failed_source_component_solution(
            solver_assembly,
            "newton_source_residual_graph",
            "Newton source solve requires a non-empty square algebraic residual graph",
            &SolverFailure::new(
                "E-NEWTON-SOURCE-SHAPE",
                format!(
                    "source Newton solve expected a square graph, got {} residual(s) and {} unknown(s)",
                    solver_assembly.generated_equations.len(),
                    solver_assembly.unknowns.len()
                ),
            ),
            tolerance,
            options.max_iterations,
            "newton_source_failed",
        );
    }

    let residual_graph = ResidualGraph::from_assembly(solver_assembly);
    let residual_scale_overrides =
        match residual_scale_overrides_from_solve_request(&request.options, &residual_graph) {
            Ok(overrides) => overrides,
            Err(failure) => {
                return failed_source_component_solution(
                    solver_assembly,
                    "newton_source_residual_graph",
                    "Newton source solve residual scale overrides could not be materialized",
                    &failure,
                    tolerance,
                    options.max_iterations,
                    "newton_source_failed",
                );
            }
        };
    let initial_values = source_initial_values_from_options(
        &request.options,
        "initial",
        &solver_assembly.unknowns,
        1.0,
        "Newton source",
        "E-NEWTON-SOURCE-INITIAL",
        "E-NEWTON-SOURCE-INITIAL-LAYOUT",
    );
    let initial_values = match initial_values {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                "newton_source_residual_graph",
                "Newton source solve initial values could not be materialized",
                &failure,
                tolerance,
                options.max_iterations,
                "newton_source_failed",
            );
        }
    };

    let parameter_values = match source_assembly_parameter_values(solver_assembly) {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                "newton_source_residual_graph",
                "Newton source solve parameters could not be materialized",
                &failure,
                tolerance,
                options.max_iterations,
                "newton_source_failed",
            );
        }
    };
    let parse_symbols = match source_algebraic_parse_symbols(solver_assembly, &parameter_values) {
        Ok(symbols) => symbols,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                "newton_source_residual_graph",
                "Newton source solve could not materialize residual parse symbols",
                &failure,
                tolerance,
                options.max_iterations,
                "newton_source_failed",
            );
        }
    };
    let parsed_residuals = match parse_source_residual_expressions(solver_assembly, &parse_symbols)
    {
        Ok(expressions) => expressions,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                "newton_source_residual_graph",
                "Newton source solve could not parse residual expressions",
                &failure,
                tolerance,
                options.max_iterations,
                "newton_source_failed",
            );
        }
    };

    let jacobian_policy = option_value(&request.options, "jacobian")
        .map(str::trim)
        .unwrap_or("finite_difference");
    let solve_result = if jacobian_policy == "source_linear_terms" {
        let scaled_jacobian = match source_linear_terms_jacobian(
            &residual_graph,
            &residual_scale_overrides,
        ) {
            Ok(jacobian) => jacobian,
            Err(failure) => {
                return failed_source_component_solution(
                    solver_assembly,
                    "newton_source_residual_graph_with_provided_jacobian",
                    "Newton source solve could not materialize the requested source-linear Jacobian hook",
                    &failure,
                    tolerance,
                    options.max_iterations,
                    "newton_source_failed",
                );
            }
        };
        solve_newton_with_jacobian(
            &initial_values,
            &options,
            |values| {
                source_algebraic_residual_values(
                    solver_assembly,
                    &residual_graph,
                    &parsed_residuals,
                    values,
                    &parameter_values,
                    &residual_scale_overrides,
                )
            },
            |_values, _baseline| Ok(scaled_jacobian.clone()),
        )
    } else {
        solve_newton(&initial_values, &options, |values| {
            source_algebraic_residual_values(
                solver_assembly,
                &residual_graph,
                &parsed_residuals,
                values,
                &parameter_values,
                &residual_scale_overrides,
            )
        })
    };

    let mut newton = match solve_result {
        Ok(result) => result,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                "newton_source_residual_graph",
                "Newton source solve failed before iteration",
                &failure,
                tolerance,
                options.max_iterations,
                "newton_source_failed",
            );
        }
    };
    if jacobian_policy == "source_linear_terms" {
        newton.jacobian_policy = jacobian_policy.to_owned();
    }
    let method_name = if jacobian_policy == "source_linear_terms" {
        "newton_source_residual_graph_with_provided_jacobian"
    } else {
        "newton_source_residual_graph"
    };
    let evaluation = match source_residual_evaluation_for_unknowns(
        solver_assembly,
        &residual_graph,
        &parsed_residuals,
        &newton.values,
        &parameter_values,
        tolerance,
        &residual_scale_overrides,
    ) {
        Ok(evaluation) => evaluation,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method_name,
                "Newton source solve residual evaluation failed after iteration",
                &failure,
                tolerance,
                options.max_iterations,
                "newton_source_failed",
            );
        }
    };
    let failed = newton.failure.clone();
    let status = if failed.is_some() {
        "newton_not_converged"
    } else {
        "solved_nonlinear"
    };
    let variable_status = if failed.is_some() {
        "newton_not_converged"
    } else {
        "solved_newton"
    };
    let variables = solver_assembly
        .unknowns
        .iter()
        .zip(newton.values.iter())
        .map(|(variable, value)| RuntimeComponentVariableSolution {
            name: variable.name.clone(),
            role: variable.role.clone(),
            value: *value,
            unit: variable.unit.clone(),
            status: variable_status.to_owned(),
        })
        .collect::<Vec<_>>();
    let residual_names = residual_graph
        .residuals
        .iter()
        .map(|residual| residual.name.clone())
        .collect::<Vec<_>>();
    let residual_scales = evaluation
        .residuals
        .iter()
        .map(|residual| residual.scale)
        .collect::<Vec<_>>();
    let step_diagnostics = source_newton_residual_history_diagnostics(
        &newton,
        failed.as_ref(),
        Some(&residual_names),
        Some(&residual_scales),
    );

    RuntimeComponentSolution {
        assembly: solver_assembly.name.clone(),
        status: status.to_owned(),
        method: method_name.to_owned(),
        reason: if failed.is_some() {
            "Newton source solve returned a failure artifact".to_owned()
        } else {
            "Newton source solve executed source-level residual graph".to_owned()
        },
        equation_count: solver_assembly.equation_count(),
        unknown_count: solver_assembly.unknown_count(),
        residual_norm: evaluation.residual_norm,
        linear_condition_estimate: None,
        linear_minimum_pivot_abs: None,
        linear_maximum_pivot_abs: None,
        variable_scale_policy: newton.variable_scale_policy.clone(),
        variable_scale_min: finite_minimum(&newton.variable_scales),
        variable_scale_max: finite_maximum(&newton.variable_scales),
        tolerance,
        max_iterations: options.max_iterations,
        iteration_count: newton.iteration_count,
        convergence_status: newton.convergence_status,
        variables,
        trajectories: Vec::new(),
        step_diagnostics,
        largest_residuals: largest_component_residuals(&evaluation.residuals),
        residuals: evaluation.residuals,
        failure_artifact: failed.map(|failure| RuntimeSolverFailureArtifact {
            code: failure.code,
            message: failure.message,
        }),
    }
}

fn dae_component_solution_from_solve_request(
    report: &CheckReport,
    component_info: &eng_compiler::ComponentAssemblyInfo,
    solver_assembly: &EquationAssembly,
    request: &ComponentSolveRequest,
    series: &[RuntimeTimeSeries],
) -> RuntimeComponentSolution {
    let has_behavior_seed = component_assembly_has_behavior_seed(component_info);
    let method = if has_behavior_seed {
        "behavior_graph_implicit_euler_dae_source"
    } else {
        "implicit_euler_dae_source_residual_graph"
    };
    let mut newton_options = newton_options_from_solve_request(&request.options);
    let tolerance = newton_options.tolerance;
    let dae_method = match dae_method_from_solve_request(&request.options) {
        Ok(method) => method,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve requested an unsupported integration method",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let timestep_s =
        match option_value(&request.options, "timestep").and_then(parse_duration_seconds) {
            Some(value) => value,
            None => {
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    "DAE source solve requires a positive timestep duration",
                    &SolverFailure::new(
                        "E-DAE-SOURCE-TIMESTEP",
                        "DAE source solve requires a positive timestep duration",
                    ),
                    tolerance,
                    newton_options.max_iterations,
                    "dae_source_failed",
                );
            }
        };
    let duration_s =
        match option_value(&request.options, "duration").and_then(parse_duration_seconds) {
            Some(value) => value,
            None => {
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    "DAE source solve requires a positive duration",
                    &SolverFailure::new(
                        "E-DAE-SOURCE-DURATION",
                        "DAE source solve requires a positive duration",
                    ),
                    tolerance,
                    newton_options.max_iterations,
                    "dae_source_failed",
                );
            }
        };
    let time_grid = match TimeGrid::fixed_step(duration_s, timestep_s) {
        Ok(grid) => grid,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve time grid could not be materialized",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let split = match solver_assembly.dynamic_component_split() {
        Ok(split) => split,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve could not split state and algebraic variables from assembly",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let mass_matrix =
        match dae_mass_matrix_from_solve_request(&request.options, solver_assembly.states.len()) {
            Ok(matrix) => matrix,
            Err(failure) => {
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    "DAE source solve mass matrix could not be materialized",
                    &failure,
                    tolerance,
                    newton_options.max_iterations,
                    "dae_source_failed",
                );
            }
        };
    let residual_graph = ResidualGraph::from_assembly(solver_assembly);
    let residual_scale_overrides =
        match residual_scale_overrides_from_solve_request(&request.options, &residual_graph) {
            Ok(overrides) => overrides,
            Err(failure) => {
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    "DAE source solve residual scale overrides could not be materialized",
                    &failure,
                    tolerance,
                    newton_options.max_iterations,
                    "dae_source_failed",
                );
            }
        };
    let parameter_values = match source_assembly_parameter_values(solver_assembly) {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve parameters could not be materialized",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let input_materialization = match source_input_values_from_options(
        &request.options,
        &solver_assembly.inputs,
        series,
        DAE_SOURCE_INPUT_PROFILE,
    ) {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve inputs could not be materialized",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let (mut behavior_graph, behavior_output_symbols) = if has_behavior_seed {
        match source_behavior_graph_from_report(
            report,
            solver_assembly,
            SourceBehaviorGraphMode::DaeImplicitEuler,
        ) {
            Ok(graph) => (Some(graph.0), graph.1),
            Err(failure) => {
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    "DAE behavior graph source solve could not materialize behavior nodes",
                    &failure,
                    tolerance,
                    newton_options.max_iterations,
                    "dae_source_failed",
                );
            }
        }
    } else {
        (None, Vec::new())
    };
    let mut parse_symbols = match source_dae_parse_symbols(solver_assembly, &parameter_values) {
        Ok(symbols) => symbols,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve could not materialize residual parse symbols",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    for output in &behavior_output_symbols {
        parse_symbols.insert(output.name.clone(), 0.0);
    }
    let parsed_residuals = match parse_source_residual_expressions_with_extra_symbol_metadata(
        solver_assembly,
        &parse_symbols,
        &source_behavior_output_symbol_metadata(&behavior_output_symbols),
    ) {
        Ok(expressions) => expressions,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve could not parse residual expressions",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let residual_context = SourceResidualEvaluationContext {
        assembly: solver_assembly,
        graph: &residual_graph,
        parsed_residuals: &parsed_residuals,
        scale_overrides: &residual_scale_overrides,
    };
    let initial_state = match source_initial_values_from_options(
        &request.options,
        "initial",
        &solver_assembly.states,
        0.0,
        "DAE source",
        "E-DAE-SOURCE-INITIAL",
        "E-DAE-SOURCE-INITIAL-LAYOUT",
    ) {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve initial state could not be materialized",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let derivative_variables = derivative_variables_for_states(&solver_assembly.states);
    let initial_state_derivatives = match source_initial_values_from_options(
        &request.options,
        "initial_derivative",
        &derivative_variables,
        0.0,
        "DAE source",
        "E-DAE-SOURCE-INITIAL-DERIVATIVE",
        "E-DAE-SOURCE-INITIAL-DERIVATIVE-LAYOUT",
    ) {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve initial state derivatives could not be materialized",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let mut initial_algebraic = match source_initial_values_from_options(
        &request.options,
        "initial_algebraic",
        &solver_assembly.algebraic_variables,
        0.0,
        "DAE source",
        "E-DAE-SOURCE-INITIAL-ALGEBRAIC",
        "E-DAE-SOURCE-INITIAL-ALGEBRAIC-LAYOUT",
    ) {
        Ok(values) => values,
        Err(failure) => {
            return failed_source_component_solution(
                solver_assembly,
                method,
                "DAE source solve initial algebraic values could not be materialized",
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };
    let algebraic_initialization = option_value(&request.options, "algebraic_initialization")
        .map(str::trim)
        .unwrap_or("newton");
    if algebraic_initialization == "newton" && !initial_algebraic.is_empty() {
        let mut algebraic_newton_options = newton_options.clone();
        apply_newton_variable_scales_from_unknowns(
            &mut algebraic_newton_options,
            &solver_assembly.algebraic_variables,
            "unit_default_from_dae_algebraic_layout",
        );
        let initialized = initialize_algebraic_variables(
            AlgebraicInitializationInput {
                state: &initial_state,
                state_derivative: &initial_state_derivatives,
                algebraic_guess: &initial_algebraic,
                inputs: &input_materialization.values,
                parameters: &parameter_values,
                time_s: 0.0,
            },
            &algebraic_newton_options,
            |sample| {
                if let Some(graph) = behavior_graph.as_mut() {
                    source_dae_residual_values_with_behavior(
                        residual_context,
                        graph,
                        &behavior_output_symbols,
                        sample,
                        SourceResidualSubset::AlgebraicOnly,
                    )
                } else {
                    source_dae_residual_values(
                        residual_context,
                        sample,
                        SourceResidualSubset::AlgebraicOnly,
                    )
                }
            },
        );
        match initialized {
            Ok(result) if result.failure.is_none() => {
                initial_algebraic = result.values;
            }
            Ok(result) => {
                let failure = result.failure.unwrap_or_else(|| {
                    SolverFailure::new(
                        "E-DAE-ALGEBRAIC-INITIALIZATION",
                        "DAE algebraic initialization did not converge",
                    )
                });
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    "DAE source solve algebraic initialization failed",
                    &failure,
                    tolerance,
                    newton_options.max_iterations,
                    "dae_source_failed",
                );
            }
            Err(failure) => {
                return failed_source_component_solution(
                    solver_assembly,
                    method,
                    "DAE source solve algebraic initialization could not be evaluated",
                    &failure,
                    tolerance,
                    newton_options.max_iterations,
                    "dae_source_failed",
                );
            }
        }
    }

    let consistency_tolerance = option_value(&request.options, "consistency_tolerance")
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value > 0.0)
        .unwrap_or(tolerance);
    let mut dae_unknowns = solver_assembly.states.clone();
    dae_unknowns.extend(solver_assembly.algebraic_variables.clone());
    apply_newton_variable_scales_from_unknowns(
        &mut newton_options,
        &dae_unknowns,
        "unit_default_from_dae_state_algebraic_layout",
    );

    let dae_input = DaeInput {
        states: solver_assembly
            .states
            .iter()
            .zip(initial_state.iter().copied())
            .map(|(state, initial)| DaeVariable::new(state.name.clone(), initial))
            .collect(),
        initial_state_derivatives,
        algebraic: solver_assembly
            .algebraic_variables
            .iter()
            .zip(initial_algebraic.iter().copied())
            .map(|(variable, initial)| DaeVariable::new(variable.name.clone(), initial))
            .collect(),
        inputs: input_materialization.values.clone(),
        parameters: parameter_values.clone(),
    };
    let dae_options = DaeOptions {
        method: dae_method,
        timestep_s,
        step_count: time_grid.step_count,
        consistency_tolerance,
        newton: newton_options.clone(),
        mass_matrix: mass_matrix.clone(),
        ..DaeOptions::default()
    };
    let dae = solve_implicit_euler_dae(&dae_input, &dae_options, |sample| {
        let sampled_inputs = sampled_source_input_values(
            &input_materialization.values,
            &input_materialization.series_indices,
            series,
            &solver_assembly.inputs,
            sample.time_s,
            DAE_SOURCE_INPUT_PROFILE,
        )?;
        let dae_sample = DaeSample {
            time_s: sample.time_s,
            state: sample.state,
            state_derivative: sample.state_derivative,
            mass_state_derivative: sample.mass_state_derivative,
            algebraic: sample.algebraic,
            inputs: &sampled_inputs,
            parameters: sample.parameters,
        };
        if let Some(graph) = behavior_graph.as_mut() {
            source_dae_residual_values_with_behavior(
                residual_context,
                graph,
                &behavior_output_symbols,
                dae_sample,
                SourceResidualSubset::All,
            )
        } else {
            source_dae_residual_values(residual_context, dae_sample, SourceResidualSubset::All)
        }
    });
    let dae = match dae {
        Ok(result) => result,
        Err(failure) => {
            let reason = if failure.code == "E-DAE-METHOD-UNSUPPORTED" {
                "DAE source solve requested an unsupported integration method"
            } else {
                "DAE source solve failed during initial consistency checks"
            };
            return failed_source_component_solution(
                solver_assembly,
                method,
                reason,
                &failure,
                tolerance,
                newton_options.max_iterations,
                "dae_source_failed",
            );
        }
    };

    let state_trajectories = dae
        .state_trajectories
        .iter()
        .filter_map(|trajectory| {
            solver_assembly
                .states
                .iter()
                .find(|state| state.name == trajectory.name)
                .map(|state| StateTrajectory {
                    name: trajectory.name.clone(),
                    quantity_kind: state.quantity_kind.clone(),
                    canonical_unit: state.unit.clone(),
                    values: trajectory.values.clone(),
                })
        })
        .collect::<Vec<_>>();
    let algebraic_trajectories = dae
        .algebraic_trajectories
        .iter()
        .filter_map(|trajectory| {
            solver_assembly
                .algebraic_variables
                .iter()
                .find(|variable| variable.name == trajectory.name)
                .map(|variable| StateTrajectory {
                    name: trajectory.name.clone(),
                    quantity_kind: variable.quantity_kind.clone(),
                    canonical_unit: variable.unit.clone(),
                    values: trajectory.values.clone(),
                })
        })
        .collect::<Vec<_>>();
    let diagnostics = SolverDiagnostics {
        status: if dae.failure.is_some() {
            "failed".to_owned()
        } else {
            "computed".to_owned()
        },
        convergence_status: dae.convergence_status.clone(),
        failure: dae.failure.clone(),
        iteration_count: dae
            .step_reports
            .iter()
            .map(|report| report.newton.iteration_count)
            .sum(),
        tolerance,
        max_iterations: newton_options.max_iterations,
    };
    let solver_result = SolverResult {
        plan: SolverPlan::new(
            solver_assembly.name.clone(),
            SimulationPlan {
                inputs: layout_names_from_unknowns(&solver_assembly.inputs),
                outputs: layout_names_from_unknowns(&solver_assembly.states),
                states: layout_names_from_unknowns(&solver_assembly.states),
                parameters: layout_names_from_unknowns(&solver_assembly.parameters),
            },
            SolverOptions {
                method: method.to_owned(),
                timestep_s,
                tolerance,
                max_iterations: newton_options.max_iterations,
            },
        ),
        time_grid: time_grid.clone(),
        state_layout: split.state_layout.clone(),
        output_layout: OutputLayout {
            entries: split.state_layout.entries.clone(),
        },
        output: crate::solver::SolverOutput {
            state_trajectories,
            algebraic_trajectories,
        },
        diagnostics,
    };
    let mass_matrix_reason = if mass_matrix.is_some() {
        "configured source mass matrix"
    } else {
        "identity mass-matrix fallback"
    };
    let input_reason = if input_materialization
        .series_indices
        .iter()
        .any(Option::is_some)
    {
        " and TimeSeries input materialization"
    } else if solver_assembly.inputs.is_empty() {
        ""
    } else {
        " and source input materialization"
    };
    let behavior_reason = if has_behavior_seed {
        " and behavior graph residual evaluation"
    } else {
        ""
    };
    let dae_reason = format!(
        "DAE source solve executed source-level residual graph with {mass_matrix_reason}{input_reason}{behavior_reason}"
    );
    let mut solution = RuntimeComponentSolution::from_dynamic_solver_result(
        &solver_assembly.name,
        &solver_result,
        &dae_reason,
    );
    solution.equation_count = solver_assembly.equation_count();
    solution.unknown_count = solver_assembly.unknown_count();
    if let Some(report) = dae.step_reports.last() {
        solution.variable_scale_policy = report.newton.variable_scale_policy.clone();
        solution.variable_scale_min = finite_minimum(&report.newton.variable_scales);
        solution.variable_scale_max = finite_maximum(&report.newton.variable_scales);
    }
    let residual_names = residual_graph
        .residuals
        .iter()
        .map(|residual| residual.name.clone())
        .collect::<Vec<_>>();
    let residual_scales = residual_graph
        .residuals
        .iter()
        .map(|residual| effective_residual_scale(residual, &residual_scale_overrides).value)
        .collect::<Vec<_>>();
    solution.step_diagnostics = dae
        .step_reports
        .iter()
        .map(|report| {
            let residual_values = report
                .newton
                .residual_value_history
                .last()
                .cloned()
                .unwrap_or_default();
            let largest_residual = largest_newton_residual_diagnostic(
                report
                    .newton
                    .residual_value_history
                    .last()
                    .map(Vec::as_slice),
                Some(&residual_names),
            );
            RuntimeComponentStepDiagnostic {
                step_index: report.step_index,
                time_s: report.time_s,
                algebraic_iteration_count: report.newton.iteration_count,
                residual_norm: report
                    .newton
                    .residual_history
                    .last()
                    .copied()
                    .unwrap_or(f64::INFINITY),
                residual_values,
                normalized_residual_values: Vec::new(),
                line_search_scale: report
                    .newton
                    .line_search_history
                    .last()
                    .map(|step| step.scale),
                line_search_trial_count: report
                    .newton
                    .line_search_history
                    .last()
                    .map(|step| step.trial_count),
                jacobian_policy: (report.newton.iteration_count > 0)
                    .then(|| report.newton.jacobian_policy.clone()),
                variable_scale_policy: (report.newton.iteration_count > 0)
                    .then(|| report.newton.variable_scale_policy.clone()),
                linear_condition_estimate: report
                    .newton
                    .linear_step_history
                    .last()
                    .map(|step| step.linear_condition_estimate),
                linear_minimum_pivot_abs: report
                    .newton
                    .linear_step_history
                    .last()
                    .map(|step| step.linear_minimum_pivot_abs),
                linear_maximum_pivot_abs: report
                    .newton
                    .linear_step_history
                    .last()
                    .map(|step| step.linear_maximum_pivot_abs),
                largest_residual_index: largest_residual.as_ref().map(|residual| residual.index),
                largest_residual_name: largest_residual
                    .as_ref()
                    .and_then(|residual| residual.name.clone()),
                largest_residual_value: largest_residual.as_ref().map(|residual| residual.value),
                largest_residual_abs_value: largest_residual
                    .as_ref()
                    .map(|residual| residual.abs_value),
                convergence_status: report.newton.convergence_status.clone(),
                failure_artifact: report.newton.failure.as_ref().map(|failure| {
                    RuntimeSolverFailureArtifact {
                        code: failure.code.clone(),
                        message: failure.message.clone(),
                    }
                }),
            }
            .with_source_residual_scales(Some(&residual_names), Some(&residual_scales))
        })
        .collect();
    if let Ok(final_inputs) = sampled_source_input_values(
        &input_materialization.values,
        &input_materialization.series_indices,
        series,
        &solver_assembly.inputs,
        time_grid.duration_s,
        DAE_SOURCE_INPUT_PROFILE,
    ) {
        if let Ok(evaluation) = source_residual_evaluation_for_dae_final(
            residual_context,
            behavior_graph.as_mut(),
            &behavior_output_symbols,
            SourceResidualFinalSample {
                input: &dae_input,
                mass_matrix: dae_options.mass_matrix.as_ref(),
                solver_result: &solver_result,
                inputs: &final_inputs,
                tolerance,
            },
        ) {
            solution.residual_norm = evaluation.residual_norm;
            solution.residuals = evaluation.residuals;
            solution.largest_residuals = largest_component_residuals(&solution.residuals);
        }
    }
    solution
}

fn dynamic_component_solution_from_solve_request(
    report: &CheckReport,
    component_info: &eng_compiler::ComponentAssemblyInfo,
    solver_assembly: &EquationAssembly,
    request: &ComponentSolveRequest,
    series: &[RuntimeTimeSeries],
) -> RuntimeComponentSolution {
    let solver = option_value(&request.options, "solver")
        .map(str::trim)
        .unwrap_or("dynamic_component_semi_implicit_euler");
    let options = DynamicComponentOptions {
        algebraic: fixed_point_options_from_solve_request(&request.options),
        ..DynamicComponentOptions::default()
    };
    if solver == "dynamic_component_explicit_euler"
        && component_assembly_has_behavior_seed(component_info)
    {
        return behavior_dynamic_component_solution_from_solve_request(
            report,
            solver_assembly,
            request,
            series,
            &options,
        );
    }
    let explicit_assembly = if solver == "dynamic_component_explicit_euler"
        || solver == "dynamic_component_adaptive_heun"
    {
        match explicit_dynamic_component_source_assembly(solver_assembly) {
            Ok(assembly) => Some(assembly),
            Err(failure) => {
                return failed_dynamic_component_source_solution(
                    solver_assembly,
                    solver,
                    &options,
                    &failure,
                    "dynamic component explicit source solve could not isolate derivative residuals",
                );
            }
        }
    } else {
        None
    };
    let dynamic_assembly = explicit_assembly.as_ref().unwrap_or(solver_assembly);
    let split = match dynamic_assembly.dynamic_component_split() {
        Ok(split) => split,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                dynamic_assembly,
                solver,
                &options,
                &failure,
                "dynamic component source solve could not split the component assembly",
            );
        }
    };
    let solve_input = match dynamic_component_solve_input_from_request(
        dynamic_assembly,
        &split,
        &request.options,
        series,
    ) {
        Ok(input) => input,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                dynamic_assembly,
                solver,
                &options,
                &failure,
                "dynamic component source solve options could not be materialized",
            );
        }
    };

    if solver == "dynamic_component_explicit_euler" {
        return match expression_dynamic_component_solution_from_solve_request(
            dynamic_assembly,
            &split,
            solve_input,
            series,
            options.clone(),
        ) {
            Ok(solution) => solution,
            Err(failure) => failed_dynamic_component_source_solution(
                dynamic_assembly,
                solver,
                &options,
                &failure,
                "dynamic component explicit source solve failed during parsed residual RHS evaluation",
            ),
        };
    }
    if solver == "dynamic_component_adaptive_heun" {
        let adaptive_options = adaptive_heun_options_from_simulation(
            &request.options,
            solve_input.solve_input.timestep_s,
        );
        return match expression_dynamic_component_adaptive_solution_from_solve_request(
            dynamic_assembly,
            &split,
            solve_input,
            series,
            adaptive_options,
            options.clone(),
        ) {
            Ok(solution) => solution,
            Err(failure) => failed_dynamic_component_source_solution(
                dynamic_assembly,
                solver,
                &options,
                &failure,
                "dynamic component adaptive source solve failed during parsed residual RHS evaluation",
            ),
        };
    }

    match expression_dynamic_component_semi_implicit_solution_from_solve_request(
        dynamic_assembly,
        solve_input,
        series,
        options.clone(),
    ) {
        Ok(solution) => solution,
        Err(failure) => failed_dynamic_component_source_solution(
            dynamic_assembly,
            solver,
            &options,
            &failure,
            "dynamic component semi-implicit source solve failed during parsed residual RHS evaluation",
        ),
    }
}

#[derive(Clone, Debug)]
struct DynamicComponentSourceSolveInput {
    solve_input: DynamicComponentAssemblySolveInput,
    input_series: Vec<Option<usize>>,
    residual_scale_overrides: Vec<ResidualScaleOverride>,
}

fn expression_dynamic_component_semi_implicit_solution_from_solve_request(
    assembly: &EquationAssembly,
    source_input: DynamicComponentSourceSolveInput,
    series: &[RuntimeTimeSeries],
    options: DynamicComponentOptions,
) -> Result<RuntimeComponentSolution, SolverFailure> {
    let DynamicComponentSourceSolveInput {
        solve_input,
        input_series,
        residual_scale_overrides,
    } = source_input;
    let derivative_residual_names = source_residual_derivative_residual_names(assembly);
    let derivative_scale_overrides =
        residual_scale_overrides_for_names(&residual_scale_overrides, &derivative_residual_names);
    let uses_time_series_inputs = input_series.iter().any(Option::is_some);
    let algebraic_assembly = semi_implicit_algebraic_dynamic_component_source_assembly(assembly)?;
    let parse_symbols = source_dynamic_component_parse_symbols(assembly, &solve_input.parameters)?;
    let parsed_residuals = parse_source_residual_expressions(assembly, &parse_symbols)?;
    let linear_static_inputs = solve_input.inputs.clone();
    let linear_input_series = input_series.clone();
    let split_for_derivatives = assembly.dynamic_component_split()?;
    let mut linear_rhs_derivative_guess = vec![0.0; split_for_derivatives.state_layout.len()];
    let mut linear_derivative_step_diagnostics = Vec::new();
    let has_algebraic_residual_scale_overrides =
        has_algebraic_residual_scale_overrides(assembly, &residual_scale_overrides);
    let algebraic_residual_names = source_residual_algebraic_residual_names(assembly);
    let algebraic_residual_scales = source_residual_scales_for_names(
        assembly,
        &algebraic_residual_names,
        &residual_scale_overrides,
    )?;
    let linear_result = if has_algebraic_residual_scale_overrides {
        Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-ALGEBRAIC-SHAPE",
            "dynamic component algebraic residual scale overrides require Newton algebraic residual solving",
        ))
    } else {
        solve_dynamic_component_assembly_with_rhs_and_input_sampler(
            &algebraic_assembly,
            solve_input.clone(),
            options.clone(),
            |time_s| {
                sampled_dynamic_component_inputs(
                    &linear_static_inputs,
                    &linear_input_series,
                    series,
                    assembly,
                    time_s,
                )
            },
            |sample| {
                let symbols = source_dynamic_component_symbols(
                    assembly,
                    sample.time_s,
                    sample.state,
                    sample.algebraic,
                    sample.inputs,
                    sample.parameters,
                );
                let derivatives = source_residual_derivatives_from_terms_or_newton(
                    assembly,
                    &parsed_residuals,
                    &symbols,
                    &linear_rhs_derivative_guess,
                    "dynamic component semi-implicit source",
                    &options,
                    &derivative_scale_overrides,
                )?;
                let failure = derivatives.failure.clone();
                record_source_derivative_solve_diagnostics(
                    assembly,
                    &derivatives,
                    sample.time_s,
                    &mut linear_derivative_step_diagnostics,
                );
                if let Some(failure) = failure {
                    return Err(failure);
                }
                if !derivatives.values.is_empty() {
                    linear_rhs_derivative_guess.clone_from(&derivatives.values);
                }
                Ok(derivatives.values)
            },
        )
    };
    let (dynamic_result, reason, derivative_step_diagnostics) = match linear_result {
        Ok(dynamic_result) => {
            let uses_derivative_newton = !linear_derivative_step_diagnostics.is_empty();
            (
                dynamic_result,
                if uses_derivative_newton && uses_time_series_inputs {
                    "dynamic component source solve executed semi-implicit algebraic residual graph with parsed nonlinear derivative residual Newton solves and TimeSeries input materialization"
                } else if uses_derivative_newton {
                    "dynamic component source solve executed semi-implicit algebraic residual graph with parsed nonlinear derivative residual Newton solves"
                } else if uses_time_series_inputs {
                    "dynamic component source solve executed semi-implicit algebraic residual graph with parsed derivative residual expressions and TimeSeries input materialization"
                } else {
                    "dynamic component source solve executed semi-implicit algebraic residual graph with parsed derivative residual expressions"
                },
                linear_derivative_step_diagnostics,
            )
        }
        Err(failure) if !linear_derivative_step_diagnostics.is_empty() => {
            let mut solution = failed_dynamic_component_source_solution(
                assembly,
                "dynamic_component_semi_implicit_euler",
                &options,
                &failure,
                "dynamic component semi-implicit source solve failed during parsed residual RHS evaluation",
            );
            append_source_derivative_step_diagnostics(
                &mut solution,
                linear_derivative_step_diagnostics,
            );
            return Ok(solution);
        }
        Err(failure) if should_fallback_to_newton_algebraic(&failure) => {
            let split = assembly.dynamic_component_split()?;
            let solver_input = SolverInput {
                plan: SolverPlan::new(
                    assembly.name.clone(),
                    SimulationPlan {
                        inputs: layout_names_from_unknowns(&assembly.inputs),
                        outputs: layout_names_from_unknowns(&assembly.states),
                        states: layout_names_from_unknowns(&assembly.states),
                        parameters: layout_names_from_unknowns(&assembly.parameters),
                    },
                    SolverOptions::fixed_step(
                        "dynamic_component_assembly_semi_implicit_euler",
                        solve_input.timestep_s,
                    ),
                ),
                time_grid: TimeGrid::fixed_step(solve_input.duration_s, solve_input.timestep_s)?,
                state_layout: split.state_layout.clone(),
                input_layout: split.input_layout.clone(),
                parameter_layout: split.parameter_layout.clone(),
                output_layout: OutputLayout {
                    entries: split.state_layout.entries.clone(),
                },
                initial_state: solve_input.initial_state.clone(),
                inputs: solve_input.inputs.clone(),
                parameters: solve_input.parameters.clone(),
            };
            let newton_static_inputs = solve_input.inputs.clone();
            let newton_input_series = input_series.clone();
            let mut newton_rhs_derivative_guess = vec![0.0; split.state_layout.len()];
            let mut newton_derivative_step_diagnostics = Vec::new();
            let mut newton_options = options.clone();
            if has_algebraic_residual_scale_overrides {
                newton_options.algebraic_residual_scales = Some(algebraic_residual_scales.clone());
            }
            let dynamic_result = match solve_explicit_euler_with_newton_algebraic_and_input_sampler(
                &solver_input,
                split.algebraic_layout,
                solve_input.initial_algebraic,
                newton_options.clone(),
                |sample| {
                    let symbols = source_dynamic_component_symbols(
                        assembly,
                        sample.time_s,
                        sample.state,
                        sample.algebraic,
                        sample.inputs,
                        sample.parameters,
                    );
                    source_residual_algebraic_residual_values(
                        assembly,
                        &parsed_residuals,
                        &symbols,
                        "dynamic component semi-implicit source",
                        has_algebraic_residual_scale_overrides
                            .then_some(algebraic_residual_scales.as_slice()),
                    )
                },
                |sample| {
                    let symbols = source_dynamic_component_symbols(
                        assembly,
                        sample.time_s,
                        sample.state,
                        sample.algebraic,
                        sample.inputs,
                        sample.parameters,
                    );
                    let derivatives = source_residual_derivatives_from_terms_or_newton(
                        assembly,
                        &parsed_residuals,
                        &symbols,
                        &newton_rhs_derivative_guess,
                        "dynamic component semi-implicit source",
                        &options,
                        &derivative_scale_overrides,
                    )?;
                    let failure = derivatives.failure.clone();
                    record_source_derivative_solve_diagnostics(
                        assembly,
                        &derivatives,
                        sample.time_s,
                        &mut newton_derivative_step_diagnostics,
                    );
                    if let Some(failure) = failure {
                        return Err(failure);
                    }
                    if !derivatives.values.is_empty() {
                        newton_rhs_derivative_guess.clone_from(&derivatives.values);
                    }
                    Ok(derivatives.values)
                },
                move |time_s| {
                    sampled_dynamic_component_inputs(
                        &newton_static_inputs,
                        &newton_input_series,
                        series,
                        assembly,
                        time_s,
                    )
                },
            ) {
                Ok(result) => result,
                Err(failure) => {
                    let mut solution = failed_dynamic_component_source_solution(
                        assembly,
                        "dynamic_component_semi_implicit_euler",
                        &options,
                        &failure,
                        "dynamic component semi-implicit source solve failed during parsed residual RHS evaluation",
                    );
                    append_source_derivative_step_diagnostics(
                        &mut solution,
                        newton_derivative_step_diagnostics,
                    );
                    return Ok(solution);
                }
            };
            let uses_derivative_newton = !newton_derivative_step_diagnostics.is_empty();
            (
                dynamic_result,
                if uses_derivative_newton && uses_time_series_inputs {
                    "dynamic component source solve executed semi-implicit Newton algebraic residuals with parsed nonlinear derivative residual Newton solves and TimeSeries input materialization"
                } else if uses_derivative_newton {
                    "dynamic component source solve executed semi-implicit Newton algebraic residuals with parsed nonlinear derivative residual Newton solves"
                } else if uses_time_series_inputs {
                    "dynamic component source solve executed semi-implicit Newton algebraic residuals with parsed derivative residual expressions and TimeSeries input materialization"
                } else {
                    "dynamic component source solve executed semi-implicit Newton algebraic residuals with parsed derivative residual expressions"
                },
                newton_derivative_step_diagnostics,
            )
        }
        Err(failure) => return Err(failure),
    };
    let mut solution = RuntimeComponentSolution::from_dynamic_component_assembly_result(
        assembly,
        &dynamic_result,
        reason,
    );
    solution.equation_count = assembly.equation_count();
    solution.unknown_count = assembly.unknown_count();
    append_source_derivative_step_diagnostics(&mut solution, derivative_step_diagnostics);
    Ok(solution)
}

fn expression_dynamic_component_solution_from_solve_request(
    assembly: &EquationAssembly,
    split: &crate::solver::assembly::DynamicComponentAssemblySplit,
    source_input: DynamicComponentSourceSolveInput,
    series: &[RuntimeTimeSeries],
    options: DynamicComponentOptions,
) -> Result<RuntimeComponentSolution, SolverFailure> {
    let DynamicComponentSourceSolveInput {
        solve_input,
        input_series,
        residual_scale_overrides,
    } = source_input;
    let derivative_residual_names = source_residual_derivative_residual_names(assembly);
    let derivative_scale_overrides =
        residual_scale_overrides_for_names(&residual_scale_overrides, &derivative_residual_names);
    let uses_time_series_inputs = input_series.iter().any(Option::is_some);
    let parse_symbols = source_dynamic_component_parse_symbols(assembly, &solve_input.parameters)?;
    let parsed_residuals = parse_source_residual_expressions(assembly, &parse_symbols)?;
    let solver_input = SolverInput {
        plan: SolverPlan::new(
            assembly.name.clone(),
            SimulationPlan {
                inputs: layout_names_from_unknowns(&assembly.inputs),
                outputs: layout_names_from_unknowns(&assembly.states),
                states: layout_names_from_unknowns(&assembly.states),
                parameters: layout_names_from_unknowns(&assembly.parameters),
            },
            SolverOptions::fixed_step(
                "dynamic_component_assembly_explicit_euler",
                solve_input.timestep_s,
            ),
        ),
        time_grid: TimeGrid::fixed_step(solve_input.duration_s, solve_input.timestep_s)?,
        state_layout: split.state_layout.clone(),
        input_layout: split.input_layout.clone(),
        parameter_layout: split.parameter_layout.clone(),
        output_layout: OutputLayout {
            entries: split.state_layout.entries.clone(),
        },
        initial_state: solve_input.initial_state.clone(),
        inputs: solve_input.inputs.clone(),
        parameters: solve_input.parameters.clone(),
    };
    let mut rhs_derivative_guess = vec![0.0; split.state_layout.len()];
    let mut derivative_step_diagnostics = Vec::new();
    let dynamic_result = match solve_explicit_euler_with_algebraic(
        &solver_input,
        split.algebraic_layout.clone(),
        solve_input.initial_algebraic,
        options.clone(),
        |sample| {
            let inputs = sampled_dynamic_component_inputs(
                &solve_input.inputs,
                &input_series,
                series,
                assembly,
                sample.time_s,
            )?;
            let symbols = source_dynamic_component_symbols(
                assembly,
                sample.time_s,
                sample.state,
                sample.algebraic,
                &inputs,
                sample.parameters,
            );
            source_residual_algebraic_values_from_affine_terms(
                assembly,
                &split.algebraic_layout,
                &parsed_residuals,
                &symbols,
                "dynamic component source",
            )
        },
        |sample| {
            let inputs = sampled_dynamic_component_inputs(
                &solve_input.inputs,
                &input_series,
                series,
                assembly,
                sample.time_s,
            )?;
            let symbols = source_dynamic_component_symbols(
                assembly,
                sample.time_s,
                sample.state,
                sample.algebraic,
                &inputs,
                sample.parameters,
            );
            let derivatives = source_residual_derivatives_from_terms_or_newton(
                assembly,
                &parsed_residuals,
                &symbols,
                &rhs_derivative_guess,
                "dynamic component source",
                &options,
                &derivative_scale_overrides,
            )?;
            let failure = derivatives.failure.clone();
            record_source_derivative_solve_diagnostics(
                assembly,
                &derivatives,
                sample.time_s,
                &mut derivative_step_diagnostics,
            );
            if let Some(failure) = failure {
                return Err(failure);
            }
            if !derivatives.values.is_empty() {
                rhs_derivative_guess.clone_from(&derivatives.values);
            }
            Ok(derivatives.values)
        },
    ) {
        Ok(result) => result,
        Err(failure) => {
            let mut solution = failed_dynamic_component_source_solution(
                assembly,
                "dynamic_component_explicit_euler",
                &options,
                &failure,
                "dynamic component explicit source solve failed during parsed residual RHS evaluation",
            );
            append_source_derivative_step_diagnostics(&mut solution, derivative_step_diagnostics);
            return Ok(solution);
        }
    };
    let uses_derivative_newton = !derivative_step_diagnostics.is_empty();
    let mut solution = RuntimeComponentSolution::from_dynamic_component_assembly_result(
        assembly,
        &dynamic_result,
        if uses_derivative_newton && uses_time_series_inputs {
            "dynamic component source solve executed parsed nonlinear derivative residual Newton solves with TimeSeries input materialization"
        } else if uses_derivative_newton {
            "dynamic component source solve executed parsed nonlinear derivative residual Newton solves"
        } else if uses_time_series_inputs {
            "dynamic component source solve executed parsed derivative residual expressions with TimeSeries input materialization"
        } else {
            "dynamic component source solve executed parsed derivative residual expressions"
        },
    );
    solution.equation_count = assembly.equation_count();
    solution.unknown_count = assembly.unknown_count();
    append_source_derivative_step_diagnostics(&mut solution, derivative_step_diagnostics);
    Ok(solution)
}

fn expression_dynamic_component_adaptive_solution_from_solve_request(
    assembly: &EquationAssembly,
    split: &crate::solver::assembly::DynamicComponentAssemblySplit,
    source_input: DynamicComponentSourceSolveInput,
    series: &[RuntimeTimeSeries],
    adaptive_options: AdaptiveOdeOptions,
    options: DynamicComponentOptions,
) -> Result<RuntimeComponentSolution, SolverFailure> {
    let DynamicComponentSourceSolveInput {
        solve_input,
        input_series,
        residual_scale_overrides,
    } = source_input;
    let derivative_residual_names = source_residual_derivative_residual_names(assembly);
    let derivative_scale_overrides =
        residual_scale_overrides_for_names(&residual_scale_overrides, &derivative_residual_names);
    let uses_time_series_inputs = input_series.iter().any(Option::is_some);
    let uses_algebraic_residuals = !split.algebraic_layout.is_empty();
    let parse_symbols = source_dynamic_component_parse_symbols(assembly, &solve_input.parameters)?;
    let parsed_residuals = parse_source_residual_expressions(assembly, &parse_symbols)?;
    let time_grid = TimeGrid::fixed_step(solve_input.duration_s, solve_input.timestep_s)?;
    let solver_input = SolverInput {
        plan: SolverPlan::new(
            assembly.name.clone(),
            SimulationPlan {
                inputs: layout_names_from_unknowns(&assembly.inputs),
                outputs: layout_names_from_unknowns(&assembly.states),
                states: layout_names_from_unknowns(&assembly.states),
                parameters: layout_names_from_unknowns(&assembly.parameters),
            },
            SolverOptions {
                method: "dynamic_component_adaptive_heun_source".to_owned(),
                timestep_s: solve_input.timestep_s,
                tolerance: adaptive_options.tolerance,
                max_iterations: adaptive_options.max_steps,
            },
        ),
        time_grid,
        state_layout: split.state_layout.clone(),
        input_layout: split.input_layout.clone(),
        parameter_layout: split.parameter_layout.clone(),
        output_layout: OutputLayout {
            entries: split.state_layout.entries.clone(),
        },
        initial_state: solve_input.initial_state.clone(),
        inputs: solve_input.inputs.clone(),
        parameters: solve_input.parameters.clone(),
    };
    let mut rhs_algebraic_guess = solve_input.initial_algebraic.clone();
    let mut rhs_derivative_guess = vec![0.0; split.state_layout.len()];
    let mut derivative_step_diagnostics = Vec::new();
    let algebraic_context = AdaptiveDynamicComponentAlgebraicContext {
        assembly,
        algebraic_layout: &split.algebraic_layout,
        parsed_residuals: &parsed_residuals,
        options: &options,
        scale_overrides: &residual_scale_overrides,
    };
    let adaptive_result = match solve_adaptive_heun_ode(
        &solver_input,
        &adaptive_options,
        |sample| {
            let inputs = sampled_dynamic_component_inputs(
                &solve_input.inputs,
                &input_series,
                series,
                assembly,
                sample.time_s,
            )?;
            let algebraic = adaptive_dynamic_component_algebraic_values(
                algebraic_context,
                AdaptiveDynamicComponentAlgebraicSample {
                    time_s: sample.time_s,
                    state: sample.state,
                    inputs: &inputs,
                    parameters: sample.parameters,
                    algebraic_guess: &rhs_algebraic_guess,
                },
            )?;
            if !algebraic.values.is_empty() {
                rhs_algebraic_guess.clone_from(&algebraic.values);
            }
            let symbols = source_dynamic_component_symbols(
                assembly,
                sample.time_s,
                sample.state,
                &algebraic.values,
                &inputs,
                sample.parameters,
            );
            let derivatives = source_residual_derivatives_from_terms_or_newton(
                assembly,
                &parsed_residuals,
                &symbols,
                &rhs_derivative_guess,
                "dynamic component adaptive source",
                &options,
                &derivative_scale_overrides,
            )?;
            let failure = derivatives.failure.clone();
            record_source_derivative_solve_diagnostics(
                assembly,
                &derivatives,
                sample.time_s,
                &mut derivative_step_diagnostics,
            );
            if let Some(failure) = failure {
                return Err(failure);
            }
            if !derivatives.values.is_empty() {
                rhs_derivative_guess.clone_from(&derivatives.values);
            }
            Ok(derivatives.values)
        },
    ) {
        Ok(result) => result,
        Err(failure) => {
            let mut solution = failed_dynamic_component_source_solution(
                assembly,
                "dynamic_component_adaptive_heun",
                &options,
                &failure,
                "dynamic component adaptive source solve failed during parsed residual RHS evaluation",
            );
            append_source_derivative_step_diagnostics(&mut solution, derivative_step_diagnostics);
            return Ok(solution);
        }
    };
    let mut solver_result = adaptive_result.solver_result;
    let (algebraic_trajectories, mut algebraic_step_diagnostics) =
        adaptive_dynamic_component_algebraic_trajectories(
            algebraic_context,
            &solve_input,
            &input_series,
            series,
            &solver_result,
        )?;
    solver_result.output.algebraic_trajectories = algebraic_trajectories;
    let uses_derivative_newton = !derivative_step_diagnostics.is_empty();
    let mut solution = RuntimeComponentSolution::from_dynamic_solver_result(
        &assembly.name,
        &solver_result,
        if uses_derivative_newton && uses_time_series_inputs && uses_algebraic_residuals {
            "dynamic component source solve executed adaptive Heun parsed nonlinear derivative residual Newton solves with algebraic residual materialization and TimeSeries input materialization"
        } else if uses_derivative_newton && uses_time_series_inputs {
            "dynamic component source solve executed adaptive Heun parsed nonlinear derivative residual Newton solves with TimeSeries input materialization"
        } else if uses_derivative_newton && uses_algebraic_residuals {
            "dynamic component source solve executed adaptive Heun parsed nonlinear derivative residual Newton solves with algebraic residual materialization"
        } else if uses_derivative_newton {
            "dynamic component source solve executed adaptive Heun parsed nonlinear derivative residual Newton solves"
        } else if uses_time_series_inputs && uses_algebraic_residuals {
            "dynamic component source solve executed adaptive Heun parsed derivative residual expressions with algebraic residual materialization and TimeSeries input materialization"
        } else if uses_time_series_inputs {
            "dynamic component source solve executed adaptive Heun parsed derivative residual expressions with TimeSeries input materialization"
        } else if uses_algebraic_residuals {
            "dynamic component source solve executed adaptive Heun parsed derivative residual expressions with algebraic residual materialization"
        } else {
            "dynamic component source solve executed adaptive Heun parsed derivative residual expressions"
        },
    );
    solution.equation_count = assembly.equation_count();
    solution.unknown_count = assembly.unknown_count();
    let mut step_diagnostics = adaptive_component_step_diagnostics(&adaptive_result.step_reports);
    let derivative_step_offset = step_diagnostics.len();
    for (index, diagnostic) in derivative_step_diagnostics.iter_mut().enumerate() {
        diagnostic.step_index = derivative_step_offset + index + 1;
    }
    step_diagnostics.extend(derivative_step_diagnostics);
    let step_offset = step_diagnostics.len();
    for (index, diagnostic) in algebraic_step_diagnostics.iter_mut().enumerate() {
        diagnostic.step_index = step_offset + index + 1;
    }
    step_diagnostics.extend(algebraic_step_diagnostics);
    solution.step_diagnostics = step_diagnostics;
    Ok(solution)
}

struct AdaptiveDynamicComponentAlgebraicSolve {
    values: Vec<f64>,
    newton: Option<NewtonResult>,
    residual_scales: Vec<f64>,
}

struct SourceDerivativeSolve {
    values: Vec<f64>,
    newton: Option<NewtonResult>,
    failure: Option<SolverFailure>,
    residual_scales: Vec<f64>,
}

fn record_source_derivative_solve_diagnostics(
    assembly: &EquationAssembly,
    solve: &SourceDerivativeSolve,
    time_s: f64,
    diagnostics: &mut Vec<RuntimeComponentStepDiagnostic>,
) {
    if let Some(newton) = &solve.newton {
        let residual_names = source_residual_derivative_residual_names(assembly);
        let residual_scales =
            (!solve.residual_scales.is_empty()).then_some(solve.residual_scales.as_slice());
        let mut step_diagnostics = source_newton_residual_history_diagnostics(
            newton,
            solve.failure.as_ref(),
            Some(&residual_names),
            residual_scales,
        );
        for diagnostic in &mut step_diagnostics {
            diagnostic.time_s = time_s;
        }
        diagnostics.extend(step_diagnostics);
    }
}

fn append_source_derivative_step_diagnostics(
    solution: &mut RuntimeComponentSolution,
    mut diagnostics: Vec<RuntimeComponentStepDiagnostic>,
) {
    let step_offset = solution.step_diagnostics.len();
    for (index, diagnostic) in diagnostics.iter_mut().enumerate() {
        diagnostic.step_index = step_offset + index + 1;
    }
    solution.step_diagnostics.extend(diagnostics);
}

#[derive(Clone, Copy)]
struct AdaptiveDynamicComponentAlgebraicContext<'a> {
    assembly: &'a EquationAssembly,
    algebraic_layout: &'a StateLayout,
    parsed_residuals: &'a [ParsedSourceResidual],
    options: &'a DynamicComponentOptions,
    scale_overrides: &'a [ResidualScaleOverride],
}

struct AdaptiveDynamicComponentAlgebraicSample<'a> {
    time_s: f64,
    state: &'a [f64],
    inputs: &'a [SolverScalar],
    parameters: &'a [SolverScalar],
    algebraic_guess: &'a [f64],
}

fn adaptive_dynamic_component_algebraic_values(
    context: AdaptiveDynamicComponentAlgebraicContext<'_>,
    sample: AdaptiveDynamicComponentAlgebraicSample<'_>,
) -> Result<AdaptiveDynamicComponentAlgebraicSolve, SolverFailure> {
    let AdaptiveDynamicComponentAlgebraicContext {
        assembly,
        algebraic_layout,
        parsed_residuals,
        options,
        scale_overrides,
    } = context;
    let AdaptiveDynamicComponentAlgebraicSample {
        time_s,
        state,
        inputs,
        parameters,
        algebraic_guess,
    } = sample;
    if algebraic_layout.is_empty() {
        return Ok(AdaptiveDynamicComponentAlgebraicSolve {
            values: Vec::new(),
            newton: None,
            residual_scales: Vec::new(),
        });
    }
    let algebraic_residual_names = source_residual_algebraic_residual_names(assembly);
    let algebraic_residual_scales =
        source_residual_scales_for_names(assembly, &algebraic_residual_names, scale_overrides)?;
    let has_scale_overrides = has_algebraic_residual_scale_overrides(assembly, scale_overrides);
    let symbols =
        source_dynamic_component_symbols(assembly, time_s, state, &[], inputs, parameters);
    match source_residual_algebraic_values_from_affine_terms(
        assembly,
        algebraic_layout,
        parsed_residuals,
        &symbols,
        "dynamic component adaptive source",
    ) {
        Ok(values) => {
            if has_scale_overrides {
                return Err(SolverFailure::new(
                    "E-SOURCE-RESIDUAL-SCALE",
                    "dynamic component algebraic residual scale overrides currently require algebraic Newton fallback; affine algebraic residuals do not emit scaled Newton diagnostics",
                ));
            }
            Ok(AdaptiveDynamicComponentAlgebraicSolve {
                values,
                newton: None,
                residual_scales: Vec::new(),
            })
        }
        Err(failure)
            if failure.code == "E-SOURCE-ALGEBRAIC-SHAPE"
                || should_fallback_to_newton_algebraic(&failure) =>
        {
            if algebraic_guess.len() != algebraic_layout.len() {
                return Err(SolverFailure::new(
                    "E-DYNAMIC-COMPONENT-ADAPTIVE-ALGEBRAIC-LAYOUT",
                    "adaptive dynamic component Newton algebraic guess length does not match the algebraic layout",
                ));
            }
            let mut newton_options = NewtonOptions {
                tolerance: options.algebraic.tolerance,
                max_iterations: options.algebraic.max_iterations,
                ..NewtonOptions::default()
            };
            newton_options.variable_scales = residual_scales_from_layout(algebraic_layout);
            newton_options.variable_scale_policy = "algebraic_layout_quantity_unit".to_owned();
            let newton = solve_newton(algebraic_guess, &newton_options, |guess| {
                let symbols = source_dynamic_component_symbols(
                    assembly, time_s, state, guess, inputs, parameters,
                );
                source_residual_algebraic_residual_values(
                    assembly,
                    parsed_residuals,
                    &symbols,
                    "dynamic component adaptive source",
                    has_scale_overrides.then_some(algebraic_residual_scales.as_slice()),
                )
            })?;
            if let Some(failure) = newton.failure {
                return Err(failure);
            }
            Ok(AdaptiveDynamicComponentAlgebraicSolve {
                values: newton.values.clone(),
                newton: Some(newton),
                residual_scales: if has_scale_overrides {
                    algebraic_residual_scales
                } else {
                    Vec::new()
                },
            })
        }
        Err(failure) => Err(failure),
    }
}

fn adaptive_dynamic_component_algebraic_trajectories(
    context: AdaptiveDynamicComponentAlgebraicContext<'_>,
    solve_input: &DynamicComponentAssemblySolveInput,
    input_series: &[Option<usize>],
    series: &[RuntimeTimeSeries],
    solver_result: &SolverResult,
) -> Result<(Vec<StateTrajectory>, Vec<RuntimeComponentStepDiagnostic>), SolverFailure> {
    let AdaptiveDynamicComponentAlgebraicContext {
        assembly,
        algebraic_layout,
        ..
    } = context;
    if algebraic_layout.is_empty() {
        return Ok((Vec::new(), Vec::new()));
    }
    let mut algebraic_values_by_variable =
        vec![Vec::with_capacity(solver_result.time_grid.step_count + 1); algebraic_layout.len()];
    let mut algebraic_guess = solve_input.initial_algebraic.clone();
    let residual_names = source_residual_algebraic_residual_names(assembly);
    let residual_scales = residual_scales_from_layout(algebraic_layout);
    let mut algebraic_step_diagnostics = Vec::new();
    for output_index in 0..=solver_result.time_grid.step_count {
        let time_s = solver_result.time_grid.step_time_s(output_index);
        let state = solver_result
            .output
            .state_trajectories
            .iter()
            .map(|trajectory| {
                trajectory.values.get(output_index).copied().ok_or_else(|| {
                    SolverFailure::new(
                        "E-DYNAMIC-COMPONENT-ADAPTIVE-TRAJECTORY",
                        "adaptive dynamic component state trajectory length did not match the output time grid",
                    )
                })
            })
            .collect::<Result<Vec<_>, _>>()?;
        let inputs = sampled_dynamic_component_inputs(
            &solve_input.inputs,
            input_series,
            series,
            assembly,
            time_s,
        )?;
        let algebraic = adaptive_dynamic_component_algebraic_values(
            context,
            AdaptiveDynamicComponentAlgebraicSample {
                time_s,
                state: &state,
                inputs: &inputs,
                parameters: &solve_input.parameters,
                algebraic_guess: &algebraic_guess,
            },
        )?;
        if !algebraic.values.is_empty() {
            algebraic_guess.clone_from(&algebraic.values);
        }
        if let Some(newton) = &algebraic.newton {
            let mut diagnostics = if algebraic.residual_scales.is_empty() {
                newton_residual_history_diagnostics(
                    newton,
                    None,
                    Some(&residual_names),
                    Some(&residual_scales),
                )
            } else {
                source_newton_residual_history_diagnostics(
                    newton,
                    None,
                    Some(&residual_names),
                    Some(&algebraic.residual_scales),
                )
            };
            for diagnostic in &mut diagnostics {
                diagnostic.time_s = time_s;
            }
            algebraic_step_diagnostics.extend(diagnostics);
        }
        for (index, value) in algebraic.values.iter().copied().enumerate() {
            algebraic_values_by_variable[index].push(value);
        }
    }
    let trajectories = algebraic_layout
        .entries
        .iter()
        .zip(algebraic_values_by_variable)
        .map(|(entry, values)| StateTrajectory {
            name: entry.name.clone(),
            quantity_kind: entry.quantity_kind.clone(),
            canonical_unit: entry.canonical_unit.clone(),
            values,
        })
        .collect();
    Ok((trajectories, algebraic_step_diagnostics))
}

fn source_residual_derivatives_from_terms_or_newton(
    assembly: &EquationAssembly,
    parsed_residuals: &[ParsedSourceResidual],
    symbols: &HashMap<String, f64>,
    derivative_guess: &[f64],
    context: &str,
    options: &DynamicComponentOptions,
    scale_overrides: &[ResidualScaleOverride],
) -> Result<SourceDerivativeSolve, SolverFailure> {
    match source_residual_derivatives_from_affine_derivative_terms(
        assembly,
        parsed_residuals,
        symbols,
        context,
    ) {
        Ok(values) => {
            if !scale_overrides.is_empty() {
                return Err(SolverFailure::new(
                    "E-SOURCE-RESIDUAL-SCALE",
                    "dynamic component residual scale overrides currently require derivative Newton fallback; affine derivative residuals do not emit scaled Newton diagnostics",
                ));
            }
            Ok(SourceDerivativeSolve {
                values,
                newton: None,
                failure: None,
                residual_scales: Vec::new(),
            })
        }
        Err(failure) if should_fallback_to_newton_derivatives(&failure) => {
            let derivative_names = source_residual_derivative_names(assembly);
            let residual_names = source_residual_derivative_residual_names(assembly);
            let residual_scales =
                source_residual_scales_for_names(assembly, &residual_names, scale_overrides)?;
            let initial = if derivative_guess.len() == derivative_names.len()
                && derivative_guess.iter().all(|value| value.is_finite())
            {
                derivative_guess.to_vec()
            } else {
                vec![0.0; derivative_names.len()]
            };
            let mut newton_options = NewtonOptions {
                tolerance: options.algebraic.tolerance,
                max_iterations: options.algebraic.max_iterations,
                ..NewtonOptions::default()
            };
            newton_options.variable_scales = vec![1.0; derivative_names.len()];
            newton_options.variable_scale_policy =
                "derivative_residual_finite_difference".to_owned();
            let newton = solve_newton(&initial, &newton_options, |guess| {
                let mut derivative_symbols = symbols.clone();
                for (name, value) in derivative_names.iter().zip(guess.iter().copied()) {
                    derivative_symbols.insert(name.clone(), value);
                }
                source_residual_derivative_residual_values(
                    assembly,
                    parsed_residuals,
                    &derivative_symbols,
                    context,
                    &residual_scales,
                )
            })?;
            let failure = newton.failure.clone();
            Ok(SourceDerivativeSolve {
                values: newton.values.clone(),
                newton: Some(newton),
                failure,
                residual_scales,
            })
        }
        Err(failure) => Err(failure),
    }
}

fn source_residual_derivative_names(assembly: &EquationAssembly) -> Vec<String> {
    assembly
        .states
        .iter()
        .map(|state| format!("der({})", state.name))
        .collect()
}

fn source_residual_derivative_residual_names(assembly: &EquationAssembly) -> Vec<String> {
    let derivative_names = source_residual_derivative_names(assembly)
        .into_iter()
        .collect::<HashSet<_>>();
    assembly
        .generated_equations
        .iter()
        .filter(|equation| {
            equation
                .dependencies
                .iter()
                .any(|dependency| derivative_names.contains(dependency))
        })
        .map(|equation| equation.name.clone())
        .collect()
}

fn source_residual_derivative_residual_values(
    assembly: &EquationAssembly,
    parsed_residuals: &[ParsedSourceResidual],
    symbols: &HashMap<String, f64>,
    context: &str,
    residual_scales: &[f64],
) -> Result<Vec<f64>, SolverFailure> {
    if parsed_residuals.len() != assembly.generated_equations.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-RHS-PARSE-LAYOUT",
            format!("{context} parsed residual count does not match generated equation count"),
        ));
    }
    let derivative_names = source_residual_derivative_names(assembly)
        .into_iter()
        .collect::<HashSet<_>>();
    let derivative_equations = assembly
        .generated_equations
        .iter()
        .zip(parsed_residuals.iter())
        .filter(|(equation, _parsed)| {
            equation
                .dependencies
                .iter()
                .any(|dependency| derivative_names.contains(dependency))
        })
        .collect::<Vec<_>>();
    if derivative_equations.len() != assembly.states.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-RHS-SHAPE",
            format!(
                "{context} solve expected one derivative residual per state, got {} residual(s) for {} state(s)",
                derivative_equations.len(),
                assembly.states.len()
            ),
        ));
    }
    derivative_equations
        .into_iter()
        .enumerate()
        .map(|(index, (equation, parsed))| {
            let target = equation.rhs_value.unwrap_or(0.0);
            let value = parsed.expression.evaluate(symbols)? - target;
            if !value.is_finite() {
                return Err(SolverFailure::new(
                    "E-SOURCE-RHS-FINITE",
                    format!(
                        "{context} residual `{}` produced a non-finite derivative residual value",
                        equation.name
                    ),
                ));
            }
            let scale = residual_scales
                .get(index)
                .copied()
                .filter(|scale| scale.is_finite() && *scale > 0.0)
                .unwrap_or(1.0);
            Ok(value / scale.max(f64::EPSILON))
        })
        .collect()
}

fn source_residual_scales_for_names(
    assembly: &EquationAssembly,
    residual_names: &[String],
    scale_overrides: &[ResidualScaleOverride],
) -> Result<Vec<f64>, SolverFailure> {
    let graph = ResidualGraph::from_assembly(assembly);
    residual_names
        .iter()
        .map(|name| {
            graph
                .residuals
                .iter()
                .find(|residual| residual.name == *name)
                .map(|residual| effective_residual_scale(residual, scale_overrides).value)
                .ok_or_else(|| {
                    SolverFailure::new(
                        "E-SOURCE-RESIDUAL-SCALE",
                        format!("source residual scale metadata is missing for `{name}`"),
                    )
                })
        })
        .collect()
}

fn dynamic_residual_scale_overrides_from_solve_request(
    assembly: &EquationAssembly,
    options: &[eng_compiler::WithOptionInfo],
) -> Result<Vec<ResidualScaleOverride>, SolverFailure> {
    let residual_graph = ResidualGraph::from_assembly(assembly);
    let overrides = residual_scale_overrides_from_solve_request(options, &residual_graph)?;
    if overrides.is_empty() {
        return Ok(overrides);
    }
    let derivative_residual_names = source_residual_derivative_residual_names(assembly)
        .into_iter()
        .collect::<HashSet<_>>();
    let algebraic_residual_names = source_residual_algebraic_residual_names(assembly)
        .into_iter()
        .collect::<HashSet<_>>();
    for override_scale in &overrides {
        if !derivative_residual_names.contains(&override_scale.residual)
            && !algebraic_residual_names.contains(&override_scale.residual)
        {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-SCALE",
                format!(
                    "dynamic component residual scale overrides currently apply only to derivative or algebraic residuals; `{}` is not a dynamic residual",
                    override_scale.residual
                ),
            ));
        }
    }
    Ok(overrides)
}

fn has_algebraic_residual_scale_overrides(
    assembly: &EquationAssembly,
    overrides: &[ResidualScaleOverride],
) -> bool {
    if overrides.is_empty() {
        return false;
    }
    let algebraic_residual_names = source_residual_algebraic_residual_names(assembly)
        .into_iter()
        .collect::<HashSet<_>>();
    overrides
        .iter()
        .any(|override_scale| algebraic_residual_names.contains(&override_scale.residual))
}

fn residual_scale_overrides_for_names(
    overrides: &[ResidualScaleOverride],
    residual_names: &[String],
) -> Vec<ResidualScaleOverride> {
    if overrides.is_empty() || residual_names.is_empty() {
        return Vec::new();
    }
    let residual_names = residual_names
        .iter()
        .map(String::as_str)
        .collect::<HashSet<_>>();
    overrides
        .iter()
        .filter(|override_scale| residual_names.contains(override_scale.residual.as_str()))
        .cloned()
        .collect()
}

fn source_residual_algebraic_residual_names(assembly: &EquationAssembly) -> Vec<String> {
    let algebraic_names = assembly
        .algebraic_variables
        .iter()
        .map(|variable| variable.name.as_str())
        .collect::<HashSet<_>>();
    assembly
        .generated_equations
        .iter()
        .filter(|equation| {
            !equation_has_derivative_dependency(equation)
                && equation
                    .dependencies
                    .iter()
                    .any(|dependency| algebraic_names.contains(dependency.as_str()))
        })
        .map(|equation| equation.name.clone())
        .collect()
}

fn residual_scales_from_layout(layout: &StateLayout) -> Vec<f64> {
    layout
        .entries
        .iter()
        .map(|entry| {
            ResidualScale::from_quantity_unit(&entry.quantity_kind, &entry.canonical_unit).value
        })
        .collect()
}

fn adaptive_component_step_diagnostics(
    reports: &[AdaptiveOdeStepReport],
) -> Vec<RuntimeComponentStepDiagnostic> {
    reports
        .iter()
        .enumerate()
        .map(|(index, report)| RuntimeComponentStepDiagnostic {
            step_index: index + 1,
            time_s: report.end_time_s,
            algebraic_iteration_count: 0,
            residual_norm: report.error_norm,
            residual_values: vec![report.error_norm],
            normalized_residual_values: vec![report.error_norm],
            line_search_scale: None,
            line_search_trial_count: None,
            jacobian_policy: None,
            variable_scale_policy: None,
            linear_condition_estimate: None,
            linear_minimum_pivot_abs: None,
            linear_maximum_pivot_abs: None,
            largest_residual_index: Some(0),
            largest_residual_name: Some("adaptive_error_norm".to_owned()),
            largest_residual_value: Some(report.error_norm),
            largest_residual_abs_value: Some(report.error_norm.abs()),
            convergence_status: format!("adaptive_heun_{}", report.status),
            failure_artifact: None,
        })
        .collect()
}

fn behavior_dynamic_component_solution_from_solve_request(
    report: &CheckReport,
    solver_assembly: &EquationAssembly,
    request: &ComponentSolveRequest,
    series: &[RuntimeTimeSeries],
    options: &DynamicComponentOptions,
) -> RuntimeComponentSolution {
    let method = "behavior_graph_explicit_euler_source";
    let dynamic_assembly = match explicit_dynamic_component_source_assembly(solver_assembly) {
        Ok(assembly) => assembly,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                solver_assembly,
                method,
                options,
                &failure,
                "behavior graph source solve could not isolate derivative residuals",
            );
        }
    };
    let split = match dynamic_assembly.dynamic_component_split() {
        Ok(split) => split,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                &dynamic_assembly,
                method,
                options,
                &failure,
                "behavior graph source solve could not split the component assembly",
            );
        }
    };
    let solve_input = match dynamic_component_solve_input_from_request(
        &dynamic_assembly,
        &split,
        &request.options,
        series,
    ) {
        Ok(input) => input,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                &dynamic_assembly,
                method,
                options,
                &failure,
                "behavior graph source solve options could not be materialized",
            );
        }
    };
    let DynamicComponentSourceSolveInput {
        solve_input,
        input_series,
        residual_scale_overrides: _,
    } = solve_input;
    let (mut behavior_graph, behavior_output_symbols) = match source_behavior_graph_from_report(
        report,
        &dynamic_assembly,
        SourceBehaviorGraphMode::ExplicitRhs,
    ) {
        Ok(graph) => graph,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                &dynamic_assembly,
                method,
                options,
                &failure,
                "behavior graph source solve could not materialize behavior nodes",
            );
        }
    };
    let parse_symbols = match source_behavior_parse_symbols(
        &dynamic_assembly,
        &solve_input.parameters,
        &behavior_output_symbols,
    ) {
        Ok(symbols) => symbols,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                &dynamic_assembly,
                method,
                options,
                &failure,
                "behavior graph source solve could not materialize residual parse symbols",
            );
        }
    };
    let parsed_residuals = match parse_source_residual_expressions_with_extra_symbol_metadata(
        &dynamic_assembly,
        &parse_symbols,
        &source_behavior_output_symbol_metadata(&behavior_output_symbols),
    ) {
        Ok(expressions) => expressions,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                &dynamic_assembly,
                method,
                options,
                &failure,
                "behavior graph source solve could not parse derivative residuals",
            );
        }
    };
    let time_grid = match TimeGrid::fixed_step(solve_input.duration_s, solve_input.timestep_s) {
        Ok(grid) => grid,
        Err(failure) => {
            return failed_dynamic_component_source_solution(
                &dynamic_assembly,
                method,
                options,
                &failure,
                "behavior graph source solve time grid could not be materialized",
            );
        }
    };
    let solver_input = SolverInput {
        plan: SolverPlan::new(
            dynamic_assembly.name.clone(),
            SimulationPlan {
                inputs: layout_names_from_unknowns(&dynamic_assembly.inputs),
                outputs: layout_names_from_unknowns(&dynamic_assembly.states),
                states: layout_names_from_unknowns(&dynamic_assembly.states),
                parameters: layout_names_from_unknowns(&dynamic_assembly.parameters),
            },
            SolverOptions {
                method: method.to_owned(),
                timestep_s: solve_input.timestep_s,
                tolerance: options.algebraic.tolerance,
                max_iterations: 1,
            },
        ),
        time_grid,
        state_layout: split.state_layout.clone(),
        input_layout: split.input_layout.clone(),
        parameter_layout: split.parameter_layout.clone(),
        output_layout: OutputLayout {
            entries: split.state_layout.entries.clone(),
        },
        initial_state: solve_input.initial_state.clone(),
        inputs: solve_input.inputs.clone(),
        parameters: solve_input.parameters.clone(),
    };
    let mut step_diagnostics = Vec::new();
    let solver_result =
        solve_fixed_step_ode(FixedStepMethod::ExplicitEuler, &solver_input, |sample| {
            let inputs = sampled_dynamic_component_inputs(
                &solve_input.inputs,
                &input_series,
                series,
                &dynamic_assembly,
                sample.time_s,
            )?;
            let behavior_evaluation = behavior_graph.evaluate_rhs(
                &BehaviorRhsSample::new(sample.time_s, sample.state, &inputs, sample.parameters),
                |behavior| {
                    step_diagnostics.push(RuntimeComponentStepDiagnostic {
                        step_index: step_diagnostics.len() + 1,
                        time_s: sample.time_s,
                        algebraic_iteration_count: 0,
                        residual_norm: 0.0,
                        residual_values: Vec::new(),
                        normalized_residual_values: Vec::new(),
                        line_search_scale: None,
                        line_search_trial_count: None,
                        jacobian_policy: None,
                        variable_scale_policy: None,
                        linear_condition_estimate: None,
                        linear_minimum_pivot_abs: None,
                        linear_maximum_pivot_abs: None,
                        largest_residual_index: None,
                        largest_residual_name: None,
                        largest_residual_value: None,
                        largest_residual_abs_value: None,
                        convergence_status: format!("behavior_graph_{}", behavior.status),
                        failure_artifact: None,
                    });
                    let symbols = source_behavior_symbols(
                        &dynamic_assembly,
                        sample.time_s,
                        sample.state,
                        &inputs,
                        sample.parameters,
                        behavior,
                        &behavior_output_symbols,
                    )?;
                    source_residual_derivatives_from_affine_derivative_terms(
                        &dynamic_assembly,
                        &parsed_residuals,
                        &symbols,
                        "behavior graph source",
                    )
                },
            )?;
            Ok(behavior_evaluation.derivatives)
        });
    match solver_result {
        Ok(solver_result) => {
            let mut solution = RuntimeComponentSolution::from_dynamic_solver_result(
                &dynamic_assembly.name,
                &solver_result,
                "behavior graph source solve executed typed behavior nodes during explicit-Euler RHS evaluation",
            );
            solution.equation_count = dynamic_assembly.equation_count();
            solution.unknown_count = dynamic_assembly.unknown_count();
            solution.step_diagnostics = step_diagnostics;
            solution.convergence_status = if solution
                .step_diagnostics
                .iter()
                .any(|diagnostic| diagnostic.convergence_status.contains("range_warning"))
            {
                "behavior_graph_range_warning".to_owned()
            } else {
                "behavior_graph_integrated".to_owned()
            };
            solution
        }
        Err(failure) => failed_dynamic_component_source_solution(
            &dynamic_assembly,
            method,
            options,
            &failure,
            "behavior graph source solve failed during RHS evaluation",
        ),
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum SourceBehaviorKind {
    Delay,
    Predictor,
    External,
}

struct SourceBehaviorCall {
    kind: SourceBehaviorKind,
    signal: String,
    delay_s: Option<f64>,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct SourceBehaviorOutputSymbol {
    name: String,
    quantity_kind: String,
    unit: String,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum SourceBehaviorGraphMode {
    ExplicitRhs,
    DaeImplicitEuler,
}

impl SourceBehaviorGraphMode {
    fn allows_delay(self) -> bool {
        matches!(self, Self::ExplicitRhs)
    }
}

fn source_behavior_graph_from_report(
    report: &CheckReport,
    assembly: &EquationAssembly,
    mode: SourceBehaviorGraphMode,
) -> Result<(BehaviorGraphRhsAdapter, Vec<SourceBehaviorOutputSymbol>), SolverFailure> {
    let assembly_components = assembly
        .components
        .iter()
        .map(|component| component.name.as_str())
        .collect::<HashSet<_>>();
    let mut nodes = Vec::new();
    let mut output_symbols = Vec::new();
    let mut output_indices = HashMap::new();
    for component in report.semantic_program.assembly_components() {
        if !assembly_components.contains(component.name.as_str()) {
            continue;
        }
        for local in &component.local_expressions {
            let Some(call) = source_behavior_call(&local.expression)? else {
                continue;
            };
            if output_indices.contains_key(&local.name) {
                return Err(SolverFailure::new(
                    "E-BEHAVIOR-SOURCE-DUPLICATE",
                    format!(
                        "behavior graph source solve found duplicate behavior output `{}`",
                        local.name
                    ),
                ));
            }
            let (source, signal_name, quantity_kind, canonical_unit) =
                source_behavior_signal_source(
                    assembly,
                    component,
                    local.line,
                    &call.signal,
                    &output_indices,
                )?;
            let output_symbol = SourceBehaviorOutputSymbol {
                name: local.name.clone(),
                quantity_kind: quantity_kind.clone(),
                unit: canonical_unit.clone(),
            };
            let node = match call.kind {
                SourceBehaviorKind::Delay => {
                    if !mode.allows_delay() {
                        return Err(SolverFailure::new(
                            "E-BEHAVIOR-SOURCE-DAE-DELAY",
                            "delay behavior nodes are not yet integrated into implicit-Euler DAE residual evaluation because delay history mutation during Newton iteration needs a dedicated replay policy",
                        ));
                    }
                    let delay_s = call.delay_s.ok_or_else(|| {
                        SolverFailure::new(
                            "E-BEHAVIOR-SOURCE-DELAY",
                            "source delay behavior node requires a finite delay duration",
                        )
                    })?;
                    let buffer = DelayBuffer::new(
                        signal_name,
                        quantity_kind,
                        canonical_unit,
                        delay_s,
                        DelayInterpolationPolicy::Linear,
                        DelayInitialHistoryPolicy::HoldInitial,
                    )?;
                    BehaviorRhsNode::delay(
                        local.name.clone(),
                        source,
                        DelayBehaviorNode::new(buffer),
                    )
                }
                SourceBehaviorKind::Predictor => {
                    let contract = PredictorContract::new(
                        format!("source_predictor_{}", local.name),
                        vec![BehaviorSignalContract::new(
                            signal_name.clone(),
                            quantity_kind.clone(),
                            canonical_unit.clone(),
                        )],
                        vec![BehaviorSignalContract::new(
                            local.name.clone(),
                            quantity_kind,
                            canonical_unit,
                        )],
                        format!("sha256:source-identity-predictor-{}", local.name),
                        PredictorDifferentiability::Differentiable,
                        PredictorSolverPolicy {
                            explicit_call_only: true,
                            finite_difference_allowed: true,
                            jacobian_policy: PredictorJacobianPolicy::FiniteDifferenceAllowed,
                        },
                    )?;
                    BehaviorRhsNode::predictor(
                        local.name.clone(),
                        vec![source],
                        contract,
                        |inputs| Ok(vec![inputs[0]]),
                    )
                }
                SourceBehaviorKind::External => {
                    let contract = ExternalBehaviorContract::new(
                        format!("source_external_{}", local.name),
                        ExternalBehaviorKind::Function,
                        vec![BehaviorSignalContract::new(
                            signal_name.clone(),
                            quantity_kind.clone(),
                            canonical_unit.clone(),
                        )],
                        vec![BehaviorSignalContract::new(
                            local.name.clone(),
                            quantity_kind,
                            canonical_unit,
                        )],
                        format!("sha256:source-identity-external-{}", local.name),
                        ExternalBehaviorDeterminism::Deterministic,
                        ExternalBehaviorProfilePolicy {
                            safe_allowed: true,
                            repro_allowed: true,
                        },
                    )?;
                    BehaviorRhsNode::external(
                        local.name.clone(),
                        BehaviorExecutionProfile::Repro,
                        vec![source],
                        contract,
                        |inputs| Ok(vec![inputs[0]]),
                    )
                }
            };
            output_indices.insert(local.name.clone(), output_symbols.len());
            output_symbols.push(output_symbol);
            nodes.push(node);
        }
    }
    if nodes.is_empty() {
        return Err(SolverFailure::new(
            "E-BEHAVIOR-SOURCE-SHAPE",
            "behavior graph source solve requires at least one behavior node",
        ));
    }
    Ok((BehaviorGraphRhsAdapter::new(nodes), output_symbols))
}

fn source_behavior_call(expression: &str) -> Result<Option<SourceBehaviorCall>, SolverFailure> {
    let trimmed = expression.trim();
    if let Some(arguments) = behavior_call_arguments_expression(trimmed, "delay") {
        let parts = split_behavior_arguments(&arguments);
        if parts.len() != 2 {
            return Err(SolverFailure::new(
                "E-BEHAVIOR-SOURCE-DELAY",
                "source delay behavior expression must use delay(signal, duration)",
            ));
        }
        let delay_s = parse_duration_seconds(parts[1].trim()).ok_or_else(|| {
            SolverFailure::new(
                "E-BEHAVIOR-SOURCE-DELAY",
                "source delay behavior expression requires a positive duration",
            )
        })?;
        return Ok(Some(SourceBehaviorCall {
            kind: SourceBehaviorKind::Delay,
            signal: parts[0].trim().to_owned(),
            delay_s: Some(delay_s),
        }));
    }
    for (name, kind) in [
        ("predictor", SourceBehaviorKind::Predictor),
        ("predict", SourceBehaviorKind::Predictor),
        ("external", SourceBehaviorKind::External),
        ("adapter", SourceBehaviorKind::External),
    ] {
        if let Some(arguments) = behavior_call_arguments_expression(trimmed, name) {
            let parts = split_behavior_arguments(&arguments);
            if parts.len() != 1 {
                return Err(SolverFailure::new(
                    "E-BEHAVIOR-SOURCE-CALL",
                    format!("source behavior expression `{name}` requires one signal argument"),
                ));
            }
            return Ok(Some(SourceBehaviorCall {
                kind,
                signal: parts[0].trim().to_owned(),
                delay_s: None,
            }));
        }
    }
    Ok(None)
}

fn behavior_call_arguments_expression(expression: &str, call_name: &str) -> Option<String> {
    let trimmed = expression.trim();
    let prefix = format!("{call_name}(");
    if !trimmed
        .to_ascii_lowercase()
        .starts_with(&prefix.to_ascii_lowercase())
        || !trimmed.ends_with(')')
    {
        return None;
    }
    let mut depth = 0usize;
    for (index, character) in trimmed.char_indices() {
        if character == '(' {
            depth += 1;
        } else if character == ')' {
            depth = depth.checked_sub(1)?;
            if depth == 0 && index + character.len_utf8() != trimmed.len() {
                return None;
            }
        }
    }
    (depth == 0).then(|| trimmed[prefix.len()..trimmed.len() - 1].to_owned())
}

fn split_behavior_arguments(arguments: &str) -> Vec<String> {
    let mut parts = Vec::new();
    let mut current = String::new();
    let mut depth = 0usize;
    for character in arguments.chars() {
        match character {
            '(' => {
                depth += 1;
                current.push(character);
            }
            ')' => {
                depth = depth.saturating_sub(1);
                current.push(character);
            }
            ',' if depth == 0 => {
                parts.push(current.trim().to_owned());
                current.clear();
            }
            _ => current.push(character),
        }
    }
    if !current.trim().is_empty() || !arguments.trim().is_empty() {
        parts.push(current.trim().to_owned());
    }
    parts
}

fn source_behavior_signal_source(
    assembly: &EquationAssembly,
    component: &eng_compiler::ComponentInfo,
    current_line: usize,
    signal: &str,
    output_indices: &HashMap<String, usize>,
) -> Result<(BehaviorSignalSource, String, String, String), SolverFailure> {
    let signal = signal.trim();
    if let Some(index) = output_indices.get(signal) {
        return Ok((
            BehaviorSignalSource::BehaviorOutput {
                node_index: *index,
                output_index: 0,
            },
            signal.to_owned(),
            "DimensionlessNumber".to_owned(),
            "1".to_owned(),
        ));
    }
    if let Some(source) = source_behavior_variable_source(assembly, &component.name, signal) {
        return Ok(source);
    }
    if let Some(prior) = component
        .local_expressions
        .iter()
        .find(|local| local.name == signal && local.line < current_line)
    {
        return source_behavior_signal_source(
            assembly,
            component,
            current_line,
            &prior.expression,
            output_indices,
        );
    }
    Err(SolverFailure::new(
        "E-BEHAVIOR-SOURCE-SIGNAL",
        format!(
            "source behavior signal `{signal}` is not available in the dynamic component layout"
        ),
    ))
}

fn source_behavior_variable_source(
    assembly: &EquationAssembly,
    component_name: &str,
    signal: &str,
) -> Option<(BehaviorSignalSource, String, String, String)> {
    let candidates = if signal.contains('.') {
        vec![signal.to_owned(), format!("{component_name}.{signal}")]
    } else {
        vec![signal.to_owned()]
    };
    for candidate in candidates {
        if let Some((index, variable)) = assembly
            .states
            .iter()
            .enumerate()
            .find(|(_, variable)| variable.name == candidate)
        {
            return Some((
                BehaviorSignalSource::State(index),
                variable.name.clone(),
                variable.quantity_kind.clone(),
                variable.unit.clone(),
            ));
        }
        if let Some((index, variable)) = assembly
            .inputs
            .iter()
            .enumerate()
            .find(|(_, variable)| variable.name == candidate)
        {
            return Some((
                BehaviorSignalSource::Input(index),
                variable.name.clone(),
                variable.quantity_kind.clone(),
                variable.unit.clone(),
            ));
        }
        if let Some((index, variable)) = assembly
            .parameters
            .iter()
            .enumerate()
            .find(|(_, variable)| variable.name == candidate)
        {
            return Some((
                BehaviorSignalSource::Parameter(index),
                variable.name.clone(),
                variable.quantity_kind.clone(),
                variable.unit.clone(),
            ));
        }
    }
    None
}

fn source_behavior_parse_symbols(
    assembly: &EquationAssembly,
    parameters: &[SolverScalar],
    behavior_output_symbols: &[SourceBehaviorOutputSymbol],
) -> Result<HashMap<String, f64>, SolverFailure> {
    source_residual_parse_symbols(
        assembly,
        parameters,
        behavior_output_symbols,
        "E-BEHAVIOR-SOURCE-PARAMETER-LAYOUT",
        "behavior graph source",
    )
}

fn source_residual_parse_symbols(
    assembly: &EquationAssembly,
    parameters: &[SolverScalar],
    behavior_output_symbols: &[SourceBehaviorOutputSymbol],
    parameter_layout_code: &str,
    context: &str,
) -> Result<HashMap<String, f64>, SolverFailure> {
    if parameters.len() != assembly.parameters.len() {
        return Err(SolverFailure::new(
            parameter_layout_code,
            format!(
                "{context} parameter vector length {} does not match assembly parameter count {}",
                parameters.len(),
                assembly.parameters.len()
            ),
        ));
    }
    let mut symbols = HashMap::new();
    symbols.insert("t".to_owned(), 0.0);
    symbols.insert("time".to_owned(), 0.0);
    for state in &assembly.states {
        symbols.insert(state.name.clone(), 0.0);
        symbols.insert(format!("der({})", state.name), 0.0);
    }
    for algebraic in &assembly.algebraic_variables {
        symbols.insert(algebraic.name.clone(), 0.0);
    }
    for input in &assembly.inputs {
        symbols.insert(input.name.clone(), 0.0);
    }
    for parameter in parameters {
        symbols.insert(parameter.name.clone(), parameter.value);
    }
    for symbol in behavior_output_symbols {
        symbols.insert(symbol.name.clone(), 0.0);
    }
    Ok(symbols)
}

fn source_dynamic_component_parse_symbols(
    assembly: &EquationAssembly,
    parameters: &[SolverScalar],
) -> Result<HashMap<String, f64>, SolverFailure> {
    source_residual_parse_symbols(
        assembly,
        parameters,
        &[],
        "E-DYNAMIC-COMPONENT-SOURCE-PARAMETER-LAYOUT",
        "dynamic component source",
    )
}

fn source_behavior_symbols(
    assembly: &EquationAssembly,
    time_s: f64,
    state: &[f64],
    inputs: &[SolverScalar],
    parameters: &[SolverScalar],
    behavior: &crate::solver::BehaviorGraphEvaluation,
    behavior_output_symbols: &[SourceBehaviorOutputSymbol],
) -> Result<HashMap<String, f64>, SolverFailure> {
    let mut symbols = HashMap::new();
    symbols.insert("t".to_owned(), time_s);
    symbols.insert("time".to_owned(), time_s);
    for (variable, value) in assembly.states.iter().zip(state.iter().copied()) {
        symbols.insert(variable.name.clone(), value);
    }
    for input in inputs {
        symbols.insert(input.name.clone(), input.value);
    }
    for parameter in parameters {
        symbols.insert(parameter.name.clone(), parameter.value);
    }
    for (index, symbol) in behavior_output_symbols.iter().enumerate() {
        let value = behavior.output(index, 0).ok_or_else(|| {
            SolverFailure::new(
                "E-BEHAVIOR-SOURCE-OUTPUT",
                format!(
                    "source behavior node `{}` did not produce output 0",
                    symbol.name
                ),
            )
        })?;
        symbols.insert(symbol.name.clone(), value);
    }
    Ok(symbols)
}

fn source_dynamic_component_symbols(
    assembly: &EquationAssembly,
    time_s: f64,
    state: &[f64],
    algebraic: &[f64],
    inputs: &[SolverScalar],
    parameters: &[SolverScalar],
) -> HashMap<String, f64> {
    let mut symbols = HashMap::new();
    symbols.insert("t".to_owned(), time_s);
    symbols.insert("time".to_owned(), time_s);
    for (variable, value) in assembly.states.iter().zip(state.iter().copied()) {
        symbols.insert(variable.name.clone(), value);
    }
    for (variable, value) in assembly
        .algebraic_variables
        .iter()
        .zip(algebraic.iter().copied())
    {
        symbols.insert(variable.name.clone(), value);
    }
    for input in inputs {
        symbols.insert(input.name.clone(), input.value);
    }
    for parameter in parameters {
        symbols.insert(parameter.name.clone(), parameter.value);
    }
    symbols
}

fn source_residual_algebraic_values_from_affine_terms(
    assembly: &EquationAssembly,
    algebraic_layout: &StateLayout,
    parsed_residuals: &[ParsedSourceResidual],
    symbols: &HashMap<String, f64>,
    context: &str,
) -> Result<Vec<f64>, SolverFailure> {
    if parsed_residuals.len() != assembly.generated_equations.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-ALGEBRAIC-PARSE-LAYOUT",
            format!("{context} parsed residual count does not match generated equation count"),
        ));
    }
    let algebraic_names = algebraic_layout
        .entries
        .iter()
        .map(|entry| entry.name.as_str())
        .collect::<Vec<_>>();
    let derivative_names = assembly
        .states
        .iter()
        .map(|state| format!("der({})", state.name))
        .collect::<Vec<_>>();
    let mut values = Vec::with_capacity(algebraic_names.len());
    for variable_name in algebraic_names {
        let (equation, parsed) = assembly
            .generated_equations
            .iter()
            .zip(parsed_residuals.iter())
            .find(|(equation, _parsed)| {
                !equation_has_derivative_dependency(equation)
                    && equation
                        .dependencies
                        .iter()
                        .any(|dependency| dependency == variable_name)
            })
            .ok_or_else(|| {
                SolverFailure::new(
                    "E-SOURCE-ALGEBRAIC-SHAPE",
                    format!(
                        "{context} solve could not find algebraic residual for `{variable_name}`"
                    ),
                )
            })?;
        let mut base_symbols = symbols.clone();
        for name in &derivative_names {
            base_symbols.insert(name.clone(), 0.0);
        }
        base_symbols.insert(variable_name.to_owned(), 0.0);
        let base = parsed.expression.evaluate(&base_symbols)?;
        let mut one_symbols = base_symbols.clone();
        one_symbols.insert(variable_name.to_owned(), 1.0);
        let coefficient = parsed.expression.evaluate(&one_symbols)? - base;
        let mut two_symbols = base_symbols;
        two_symbols.insert(variable_name.to_owned(), 2.0);
        let second_delta = parsed.expression.evaluate(&two_symbols)? - base;
        if !coefficient.is_finite()
            || coefficient.abs() <= f64::EPSILON
            || !second_delta.is_finite()
            || (second_delta - 2.0 * coefficient).abs() > 1e-9
        {
            return Err(SolverFailure::new(
                "E-SOURCE-ALGEBRAIC-SHAPE",
                format!(
                    "{context} residual `{}` does not contain a solvable affine algebraic coefficient for `{variable_name}`",
                    equation.name
                ),
            ));
        }
        let target = equation.rhs_value.unwrap_or(0.0);
        let value = (target - base) / coefficient;
        if !value.is_finite() {
            return Err(SolverFailure::new(
                "E-SOURCE-ALGEBRAIC-FINITE",
                format!(
                    "{context} residual `{}` produced a non-finite algebraic value",
                    equation.name
                ),
            ));
        }
        values.push(value);
    }
    Ok(values)
}

fn source_residual_algebraic_residual_values(
    assembly: &EquationAssembly,
    parsed_residuals: &[ParsedSourceResidual],
    symbols: &HashMap<String, f64>,
    context: &str,
    residual_scales: Option<&[f64]>,
) -> Result<Vec<f64>, SolverFailure> {
    if parsed_residuals.len() != assembly.generated_equations.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-ALGEBRAIC-PARSE-LAYOUT",
            format!("{context} parsed residual count does not match generated equation count"),
        ));
    }
    let algebraic_names = assembly
        .algebraic_variables
        .iter()
        .map(|variable| variable.name.as_str())
        .collect::<HashSet<_>>();
    let algebraic_equations = assembly
        .generated_equations
        .iter()
        .zip(parsed_residuals.iter())
        .filter(|(equation, _parsed)| {
            !equation_has_derivative_dependency(equation)
                && equation
                    .dependencies
                    .iter()
                    .any(|dependency| algebraic_names.contains(dependency.as_str()))
        })
        .collect::<Vec<_>>();
    if algebraic_equations.len() != assembly.algebraic_variables.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-ALGEBRAIC-SHAPE",
            format!(
                "{context} solve expected one algebraic residual per algebraic variable, got {} residual(s) for {} variable(s)",
                algebraic_equations.len(),
                assembly.algebraic_variables.len()
            ),
        ));
    }
    for variable in &assembly.algebraic_variables {
        if !algebraic_equations
            .iter()
            .any(|(equation, _parsed)| equation.dependencies.contains(&variable.name))
        {
            return Err(SolverFailure::new(
                "E-SOURCE-ALGEBRAIC-SHAPE",
                format!(
                    "{context} solve could not find algebraic residual for `{}`",
                    variable.name
                ),
            ));
        }
    }

    algebraic_equations
        .into_iter()
        .enumerate()
        .map(|(index, (equation, parsed))| {
            let target = equation.rhs_value.unwrap_or(0.0);
            let value = parsed.expression.evaluate(symbols)? - target;
            if !value.is_finite() {
                return Err(SolverFailure::new(
                    "E-SOURCE-ALGEBRAIC-FINITE",
                    format!(
                        "{context} residual `{}` produced a non-finite algebraic residual value",
                        equation.name
                    ),
                ));
            }
            let Some(residual_scales) = residual_scales else {
                return Ok(value);
            };
            let scale = residual_scales
                .get(index)
                .copied()
                .filter(|scale| scale.is_finite() && *scale > 0.0)
                .unwrap_or(1.0);
            Ok(value / scale.max(f64::EPSILON))
        })
        .collect()
}

fn source_residual_derivatives_from_affine_derivative_terms(
    assembly: &EquationAssembly,
    parsed_residuals: &[ParsedSourceResidual],
    symbols: &HashMap<String, f64>,
    context: &str,
) -> Result<Vec<f64>, SolverFailure> {
    if parsed_residuals.len() != assembly.generated_equations.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-RHS-PARSE-LAYOUT",
            format!("{context} parsed residual count does not match generated equation count"),
        ));
    }
    let mut derivatives = Vec::with_capacity(assembly.states.len());
    let derivative_names = assembly
        .states
        .iter()
        .map(|state| format!("der({})", state.name))
        .collect::<Vec<_>>();
    for (state_index, state) in assembly.states.iter().enumerate() {
        let derivative_name = &derivative_names[state_index];
        let (equation, parsed) = assembly
            .generated_equations
            .iter()
            .zip(parsed_residuals.iter())
            .find(|(equation, _parsed)| {
                equation
                    .dependencies
                    .iter()
                    .any(|dependency| dependency == derivative_name)
            })
            .ok_or_else(|| {
                SolverFailure::new(
                    "E-SOURCE-RHS-SHAPE",
                    format!(
                        "{context} solve could not find derivative residual for `{}`",
                        state.name
                    ),
                )
            })?;
        let mut base_symbols = symbols.clone();
        for name in &derivative_names {
            base_symbols.insert(name.clone(), 0.0);
        }
        let base = parsed.expression.evaluate(&base_symbols)?;
        let mut coefficient_symbols = base_symbols.clone();
        coefficient_symbols.insert(derivative_name.clone(), 1.0);
        let coefficient = parsed.expression.evaluate(&coefficient_symbols)? - base;
        let mut two_symbols = base_symbols;
        two_symbols.insert(derivative_name.clone(), 2.0);
        let second_delta = parsed.expression.evaluate(&two_symbols)? - base;
        if !coefficient.is_finite()
            || coefficient.abs() <= f64::EPSILON
            || !second_delta.is_finite()
            || (second_delta - 2.0 * coefficient).abs() > 1e-9
        {
            return Err(SolverFailure::new(
                "E-SOURCE-RHS-SHAPE",
                format!(
                    "{context} residual `{}` does not contain a solvable affine derivative coefficient",
                    equation.name
                ),
            ));
        }
        let target = equation.rhs_value.unwrap_or(0.0);
        let derivative = (target - base) / coefficient;
        if !derivative.is_finite() {
            return Err(SolverFailure::new(
                "E-SOURCE-RHS-FINITE",
                format!(
                    "{context} residual `{}` produced a non-finite derivative",
                    equation.name
                ),
            ));
        }
        derivatives.push(derivative);
    }
    Ok(derivatives)
}

fn should_fallback_to_newton_algebraic(failure: &SolverFailure) -> bool {
    failure.code == "E-DYNAMIC-COMPONENT-ASSEMBLY-RESIDUAL"
        || failure.code == "E-DYNAMIC-COMPONENT-ALGEBRAIC-SHAPE"
        || failure.message.contains("unsupported term")
        || failure.message.contains("not linear")
}

fn should_fallback_to_newton_derivatives(failure: &SolverFailure) -> bool {
    failure.code == "E-SOURCE-RHS-SHAPE"
        && failure
            .message
            .contains("solvable affine derivative coefficient")
}

fn equation_has_derivative_dependency(equation: &GeneratedEquation) -> bool {
    equation
        .dependencies
        .iter()
        .any(|dependency| dependency.trim().starts_with("der("))
}

fn explicit_dynamic_component_source_assembly(
    assembly: &EquationAssembly,
) -> Result<EquationAssembly, SolverFailure> {
    let algebraic_names = assembly
        .algebraic_variables
        .iter()
        .map(|variable| variable.name.as_str())
        .collect::<std::collections::HashSet<_>>();
    let generated_equations = assembly
        .generated_equations
        .iter()
        .filter(|equation| {
            equation_has_derivative_dependency(equation)
                || (equation.kind == "component_equation"
                    && equation
                        .dependencies
                        .iter()
                        .any(|dependency| algebraic_names.contains(dependency.as_str())))
        })
        .cloned()
        .collect::<Vec<_>>();
    if generated_equations.is_empty() {
        return Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-EXPLICIT-SHAPE",
            "explicit dynamic component source solve requires at least one derivative residual",
        ));
    }
    if assembly.states.is_empty() {
        return Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-EXPLICIT-SHAPE",
            "explicit dynamic component source solve requires at least one state variable",
        ));
    }
    let mut explicit = assembly.clone();
    explicit.generated_equations = generated_equations;
    let selected_algebraic_names = explicit
        .generated_equations
        .iter()
        .filter(|equation| !equation_has_derivative_dependency(equation))
        .flat_map(|equation| equation.dependencies.iter())
        .filter(|dependency| algebraic_names.contains(dependency.as_str()))
        .cloned()
        .collect::<std::collections::HashSet<_>>();
    explicit
        .algebraic_variables
        .retain(|variable| selected_algebraic_names.contains(variable.name.as_str()));
    explicit.unknowns = explicit
        .states
        .iter()
        .chain(explicit.algebraic_variables.iter())
        .cloned()
        .collect();
    Ok(explicit)
}

fn semi_implicit_algebraic_dynamic_component_source_assembly(
    assembly: &EquationAssembly,
) -> Result<EquationAssembly, SolverFailure> {
    if assembly.algebraic_variables.is_empty() {
        return Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-SEMI-IMPLICIT-SHAPE",
            "semi-implicit dynamic component source solve requires at least one algebraic variable",
        ));
    }
    let generated_equations = assembly
        .generated_equations
        .iter()
        .filter(|equation| !equation_has_derivative_dependency(equation))
        .cloned()
        .collect::<Vec<_>>();
    if generated_equations.is_empty() {
        return Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-SEMI-IMPLICIT-SHAPE",
            "semi-implicit dynamic component source solve requires algebraic residual equations",
        ));
    }
    let mut algebraic = assembly.clone();
    algebraic.generated_equations = generated_equations;
    Ok(algebraic)
}

fn dynamic_component_solve_input_from_request(
    assembly: &EquationAssembly,
    split: &crate::solver::assembly::DynamicComponentAssemblySplit,
    options: &[eng_compiler::WithOptionInfo],
    series: &[RuntimeTimeSeries],
) -> Result<DynamicComponentSourceSolveInput, SolverFailure> {
    let timestep_s = option_value(options, "timestep")
        .and_then(parse_duration_seconds)
        .ok_or_else(|| {
            SolverFailure::new(
                "E-DYNAMIC-COMPONENT-SOURCE-TIMESTEP",
                "dynamic component source solve requires a positive timestep duration",
            )
        })?;
    let duration_s = option_value(options, "duration")
        .and_then(parse_duration_seconds)
        .ok_or_else(|| {
            SolverFailure::new(
                "E-DYNAMIC-COMPONENT-SOURCE-DURATION",
                "dynamic component source solve requires a positive duration",
            )
        })?;
    let initial_state =
        component_initial_values_from_options(options, "initial", &assembly.states, 0.0)?;
    let initial_algebraic = component_initial_values_from_options(
        options,
        "initial_algebraic",
        &assembly.algebraic_variables,
        0.0,
    )?;
    if initial_algebraic.len() != split.algebraic_layout.len() {
        return Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-SOURCE-INITIAL-LAYOUT",
            format!(
                "dynamic component source option `initial_algebraic` materialized {} value(s) for {} algebraic variable(s)",
                initial_algebraic.len(),
                split.algebraic_layout.len()
            ),
        ));
    }
    let residual_scale_overrides =
        dynamic_residual_scale_overrides_from_solve_request(assembly, options)?;
    let input_materialization =
        component_input_values_from_options(options, &assembly.inputs, series)?;
    let inputs = assembly
        .inputs
        .iter()
        .zip(input_materialization.values)
        .map(|(input, value)| {
            Ok(SolverScalar::new(
                input.name.clone(),
                input.quantity_kind.clone(),
                input.unit.clone(),
                value,
            ))
        })
        .collect::<Result<Vec<_>, SolverFailure>>()?;
    let parameters = assembly
        .parameters
        .iter()
        .map(|parameter| {
            Ok(SolverScalar::new(
                parameter.name.clone(),
                parameter.quantity_kind.clone(),
                parameter.unit.clone(),
                parameter.value.unwrap_or(0.0),
            ))
        })
        .collect::<Result<Vec<_>, SolverFailure>>()?;

    Ok(DynamicComponentSourceSolveInput {
        solve_input: DynamicComponentAssemblySolveInput {
            duration_s,
            timestep_s,
            initial_state,
            initial_algebraic,
            inputs,
            parameters,
        },
        input_series: input_materialization.series_indices,
        residual_scale_overrides,
    })
}

fn derivative_variables_for_states(states: &[UnknownVariable]) -> Vec<UnknownVariable> {
    states
        .iter()
        .map(|state| UnknownVariable {
            name: format!("der({})", state.name),
            role: "state_derivative".to_owned(),
            quantity_kind: state.quantity_kind.clone(),
            unit: derivative_unit_for_state_unit(&state.unit),
            source: state.source.clone(),
            status: state.status.clone(),
            value: None,
        })
        .collect()
}

fn derivative_unit_for_state_unit(unit: &str) -> String {
    let unit = unit.trim();
    if unit.is_empty() || unit == "1" {
        "1/s".to_owned()
    } else {
        format!("{unit}/s")
    }
}

fn dae_mass_matrix_from_solve_request(
    options: &[eng_compiler::WithOptionInfo],
    state_count: usize,
) -> Result<Option<DaeMassMatrix>, SolverFailure> {
    let Some(value) = option_value(options, "mass_matrix") else {
        return Ok(None);
    };
    let trimmed = value.trim();
    if trimmed.eq_ignore_ascii_case("identity") {
        return Ok(None);
    }
    if state_count == 0 {
        return Err(SolverFailure::new(
            "E-DAE-MASS-MATRIX-LAYOUT",
            "DAE source option `mass_matrix` requires at least one state variable",
        ));
    }
    if let Some(rows) = parse_dae_mass_matrix_rows(trimmed) {
        validate_dae_mass_matrix_rows(&rows, state_count)?;
        return Ok(Some(DaeMassMatrix::new(rows)));
    }
    let Some((is_vector, values)) = parse_component_initial_option(trimmed) else {
        return Err(SolverFailure::new(
            "E-DAE-MASS-MATRIX",
            "DAE source option `mass_matrix` expects `identity`, a finite scalar, a finite vector of diagonal coefficients, or a finite square matrix with no units",
        ));
    };
    let mut coefficients = Vec::with_capacity(values.len());
    for (coefficient, unit) in values {
        if unit.is_some() || !coefficient.is_finite() {
            return Err(SolverFailure::new(
                "E-DAE-MASS-MATRIX",
                "DAE source option `mass_matrix` coefficients must be finite dimensionless numbers",
            ));
        }
        coefficients.push(coefficient);
    }
    if is_vector {
        if coefficients.len() != state_count {
            return Err(SolverFailure::new(
                "E-DAE-MASS-MATRIX-LAYOUT",
                format!(
                    "DAE source option `mass_matrix` provided {} diagonal coefficient(s) for {} state variable(s)",
                    coefficients.len(), state_count
                ),
            ));
        }
        return Ok(Some(DaeMassMatrix::new(diagonal_mass_matrix(coefficients))));
    }
    Ok(Some(DaeMassMatrix::new(diagonal_mass_matrix(vec![
        coefficients[0];
        state_count
    ]))))
}

fn parse_dae_mass_matrix_rows(value: &str) -> Option<Vec<Vec<f64>>> {
    let inner = value.strip_prefix('[')?.strip_suffix(']')?;
    let row_items = split_component_initial_items(inner);
    if row_items.is_empty() {
        return None;
    }
    let mut rows = Vec::with_capacity(row_items.len());
    for row_item in row_items {
        let row_inner = row_item.trim().strip_prefix('[')?.strip_suffix(']')?;
        let coefficients = split_component_initial_items(row_inner)
            .into_iter()
            .map(|item| parse_unitless_finite_number(&item))
            .collect::<Option<Vec<_>>>()?;
        if coefficients.is_empty() {
            return None;
        }
        rows.push(coefficients);
    }
    Some(rows)
}

fn parse_unitless_finite_number(value: &str) -> Option<f64> {
    let (number, unit) = parse_numeric_value_with_optional_unit(value)?;
    if unit.is_some() || !number.is_finite() {
        return None;
    }
    Some(number)
}

fn validate_dae_mass_matrix_rows(
    rows: &[Vec<f64>],
    state_count: usize,
) -> Result<(), SolverFailure> {
    if rows.len() != state_count || rows.iter().any(|row| row.len() != state_count) {
        return Err(SolverFailure::new(
            "E-DAE-MASS-MATRIX-LAYOUT",
            format!(
                "DAE source option `mass_matrix` must be a {state_count}x{state_count} square matrix for the DAE state layout"
            ),
        ));
    }
    if rows
        .iter()
        .flatten()
        .any(|coefficient| !coefficient.is_finite())
    {
        return Err(SolverFailure::new(
            "E-DAE-MASS-MATRIX",
            "DAE source option `mass_matrix` coefficients must be finite dimensionless numbers",
        ));
    }
    Ok(())
}

fn diagonal_mass_matrix(coefficients: Vec<f64>) -> Vec<Vec<f64>> {
    let size = coefficients.len();
    let mut rows = vec![vec![0.0; size]; size];
    for (index, coefficient) in coefficients.into_iter().enumerate() {
        rows[index][index] = coefficient;
    }
    rows
}

fn dae_mass_state_derivative_values(
    mass_matrix: Option<&DaeMassMatrix>,
    state_derivative: &[f64],
) -> Result<Option<Vec<f64>>, SolverFailure> {
    let Some(mass_matrix) = mass_matrix else {
        return Ok(None);
    };
    if mass_matrix.rows.len() != state_derivative.len()
        || mass_matrix
            .rows
            .iter()
            .any(|row| row.len() != state_derivative.len())
    {
        return Err(SolverFailure::new(
            "E-DAE-MASS-MATRIX-LAYOUT",
            "DAE source mass matrix must be square and match the state derivative length",
        ));
    }
    if mass_matrix
        .rows
        .iter()
        .flatten()
        .any(|value| !value.is_finite())
    {
        return Err(SolverFailure::new(
            "E-DAE-MASS-MATRIX",
            "DAE source mass matrix contains a non-finite value",
        ));
    }
    let values = mass_matrix
        .rows
        .iter()
        .map(|row| {
            row.iter()
                .zip(state_derivative.iter())
                .map(|(coefficient, derivative)| coefficient * derivative)
                .sum::<f64>()
        })
        .collect::<Vec<_>>();
    if values.iter().any(|value| !value.is_finite()) {
        return Err(SolverFailure::new(
            "E-DAE-MASS-MATRIX",
            "DAE source mass matrix application produced a non-finite derivative value",
        ));
    }
    Ok(Some(values))
}
fn component_initial_values_from_options(
    options: &[eng_compiler::WithOptionInfo],
    key: &str,
    variables: &[UnknownVariable],
    default_value: f64,
) -> Result<Vec<f64>, SolverFailure> {
    let Some(value) = option_value(options, key) else {
        return Ok(vec![default_value; variables.len()]);
    };
    let Some((is_vector, values)) = parse_component_initial_option(value) else {
        return Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-SOURCE-INITIAL",
            format!(
                "dynamic component source option `{key}` is not a finite numeric literal or bracketed list"
            ),
        ));
    };
    if is_vector && values.len() != variables.len() {
        return Err(SolverFailure::new(
            "E-DYNAMIC-COMPONENT-SOURCE-INITIAL-LAYOUT",
            format!(
                "dynamic component source option `{key}` provided {} initial value(s) for {} variable(s)",
                values.len(),
                variables.len()
            ),
        ));
    }
    variables
        .iter()
        .enumerate()
        .map(|(index, variable)| {
            let (raw_value, unit) = if is_vector {
                values[index].clone()
            } else {
                values[0].clone()
            };
            if !raw_value.is_finite() {
                return Err(SolverFailure::new(
                    "E-DYNAMIC-COMPONENT-SOURCE-INITIAL",
                    format!("dynamic component source option `{key}` is not finite"),
                ));
            }
            let source_unit = unit.as_deref().unwrap_or(variable.unit.as_str());
            Ok(convert_display_value(
                raw_value,
                source_unit,
                &variable.unit,
            ))
        })
        .collect()
}

#[derive(Clone, Debug)]
struct ComponentInputMaterialization {
    values: Vec<f64>,
    series_indices: Vec<Option<usize>>,
}

#[derive(Clone, Copy, Debug)]
struct SourceInputDiagnosticProfile {
    label: &'static str,
    invalid_code: &'static str,
    layout_code: &'static str,
    quantity_code: &'static str,
    sample_code: &'static str,
    unit_code: &'static str,
}

const DYNAMIC_COMPONENT_INPUT_PROFILE: SourceInputDiagnosticProfile =
    SourceInputDiagnosticProfile {
        label: "dynamic component",
        invalid_code: "E-DYNAMIC-COMPONENT-SOURCE-INPUT",
        layout_code: "E-DYNAMIC-COMPONENT-SOURCE-INPUT-LAYOUT",
        quantity_code: "E-DYNAMIC-COMPONENT-SOURCE-INPUT-QTY",
        sample_code: "E-DYNAMIC-COMPONENT-SOURCE-INPUT-SAMPLE",
        unit_code: "E-DYNAMIC-COMPONENT-SOURCE-INPUT-UNIT",
    };

const DAE_SOURCE_INPUT_PROFILE: SourceInputDiagnosticProfile = SourceInputDiagnosticProfile {
    label: "DAE",
    invalid_code: "E-DAE-SOURCE-INPUT",
    layout_code: "E-DAE-SOURCE-INPUT-LAYOUT",
    quantity_code: "E-DAE-SOURCE-INPUT-QTY",
    sample_code: "E-DAE-SOURCE-INPUT-SAMPLE",
    unit_code: "E-DAE-SOURCE-INPUT-UNIT",
};

#[derive(Clone, Debug)]
enum ComponentInputOptionValue {
    Numeric(f64, Option<String>),
    TimeSeries(usize),
}

fn component_input_values_from_options(
    options: &[eng_compiler::WithOptionInfo],
    variables: &[UnknownVariable],
    series: &[RuntimeTimeSeries],
) -> Result<ComponentInputMaterialization, SolverFailure> {
    source_input_values_from_options(options, variables, series, DYNAMIC_COMPONENT_INPUT_PROFILE)
}

fn source_input_values_from_options(
    options: &[eng_compiler::WithOptionInfo],
    variables: &[UnknownVariable],
    series: &[RuntimeTimeSeries],
    profile: SourceInputDiagnosticProfile,
) -> Result<ComponentInputMaterialization, SolverFailure> {
    let parsed_inputs = if let Some(value) = option_value(options, "inputs") {
        Some(parse_component_input_option(value, series).ok_or_else(|| {
            SolverFailure::new(
                profile.invalid_code,
                format!(
                    "{} source option `inputs` is not a finite numeric literal, bracketed list, or known TimeSeries name",
                    profile.label
                ),
            )
        })?)
    } else {
        None
    };
    if let Some((true, values)) = &parsed_inputs {
        if values.len() != variables.len() {
            return Err(SolverFailure::new(
                profile.layout_code,
                format!(
                    "{} source option `inputs` provided {} value(s) for {} input variable(s)",
                    profile.label,
                    values.len(),
                    variables.len()
                ),
            ));
        }
    }
    let mut input_series = Vec::with_capacity(variables.len());
    let values = variables
        .iter()
        .enumerate()
        .map(|(index, variable)| {
            let item = match &parsed_inputs {
                Some((true, values)) => Some(&values[index]),
                Some((false, values)) => values.first(),
                None => None,
            };
            match item {
                Some(ComponentInputOptionValue::Numeric(raw_value, unit)) => {
                    if !raw_value.is_finite() {
                        return Err(SolverFailure::new(
                            profile.invalid_code,
                            format!("{} source option `inputs` is not finite", profile.label),
                        ));
                    }
                    input_series.push(None);
                    let source_unit = unit.as_deref().unwrap_or(variable.unit.as_str());
                    Ok(convert_display_value(
                        *raw_value,
                        source_unit,
                        &variable.unit,
                    ))
                }
                Some(ComponentInputOptionValue::TimeSeries(series_index)) => {
                    input_series.push(Some(*series_index));
                    source_input_series_value(variable, &series[*series_index], 0.0, profile)
                }
                None => {
                    input_series.push(None);
                    Ok(variable.value.unwrap_or(0.0))
                }
            }
        })
        .collect::<Result<Vec<_>, SolverFailure>>()?;
    Ok(ComponentInputMaterialization {
        values,
        series_indices: input_series,
    })
}

fn parse_component_input_option(
    value: &str,
    series: &[RuntimeTimeSeries],
) -> Option<(bool, Vec<ComponentInputOptionValue>)> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return None;
    }
    if let Some(inner) = trimmed
        .strip_prefix('[')
        .and_then(|rest| rest.strip_suffix(']'))
    {
        let values = split_component_initial_items(inner)
            .into_iter()
            .map(|item| parse_component_input_option_item(&item, series))
            .collect::<Option<Vec<_>>>()?;
        if values.is_empty() {
            return None;
        }
        return Some((true, values));
    }
    parse_component_input_option_item(trimmed, series).map(|value| (false, vec![value]))
}

fn parse_component_input_option_item(
    item: &str,
    series: &[RuntimeTimeSeries],
) -> Option<ComponentInputOptionValue> {
    if let Some((value, unit)) = parse_numeric_value_with_optional_unit(item) {
        return Some(ComponentInputOptionValue::Numeric(value, unit));
    }
    let name = item.trim().trim_matches('"').trim_matches('\'');
    let series_index = series.iter().position(|candidate| candidate.name == name)?;
    Some(ComponentInputOptionValue::TimeSeries(series_index))
}

fn sampled_dynamic_component_inputs(
    static_inputs: &[SolverScalar],
    input_series: &[Option<usize>],
    series: &[RuntimeTimeSeries],
    assembly: &EquationAssembly,
    time_s: f64,
) -> Result<Vec<SolverScalar>, SolverFailure> {
    sampled_dynamic_component_inputs_for_variables(
        static_inputs,
        input_series,
        series,
        &assembly.inputs,
        time_s,
        DYNAMIC_COMPONENT_INPUT_PROFILE,
    )
}

fn sampled_dynamic_component_inputs_for_variables(
    static_inputs: &[SolverScalar],
    input_series: &[Option<usize>],
    series: &[RuntimeTimeSeries],
    variables: &[UnknownVariable],
    time_s: f64,
    profile: SourceInputDiagnosticProfile,
) -> Result<Vec<SolverScalar>, SolverFailure> {
    if input_series.iter().all(Option::is_none) {
        return Ok(static_inputs.to_vec());
    }
    if static_inputs.len() != input_series.len() || static_inputs.len() != variables.len() {
        return Err(SolverFailure::new(
            profile.layout_code,
            format!(
                "{} input TimeSeries layout does not match the assembly input layout",
                profile.label
            ),
        ));
    }
    static_inputs
        .iter()
        .zip(input_series.iter())
        .zip(variables.iter())
        .map(|((input, series_index), variable)| {
            let Some(series_index) = series_index else {
                return Ok(input.clone());
            };
            let series = series.get(*series_index).ok_or_else(|| {
                SolverFailure::new(
                    profile.layout_code,
                    format!(
                        "{} input TimeSeries index is outside the runtime series table",
                        profile.label
                    ),
                )
            })?;
            let mut sampled = input.clone();
            sampled.value = source_input_series_value(variable, series, time_s, profile)?;
            Ok(sampled)
        })
        .collect()
}

fn sampled_source_input_values(
    static_inputs: &[f64],
    input_series: &[Option<usize>],
    series: &[RuntimeTimeSeries],
    variables: &[UnknownVariable],
    time_s: f64,
    profile: SourceInputDiagnosticProfile,
) -> Result<Vec<f64>, SolverFailure> {
    if input_series.iter().all(Option::is_none) {
        return Ok(static_inputs.to_vec());
    }
    if static_inputs.len() != input_series.len() || static_inputs.len() != variables.len() {
        return Err(SolverFailure::new(
            profile.layout_code,
            format!(
                "{} input TimeSeries layout does not match the assembly input layout",
                profile.label
            ),
        ));
    }
    static_inputs
        .iter()
        .zip(input_series.iter())
        .zip(variables.iter())
        .map(|((input, series_index), variable)| {
            let Some(series_index) = series_index else {
                return Ok(*input);
            };
            let series = series.get(*series_index).ok_or_else(|| {
                SolverFailure::new(
                    profile.layout_code,
                    format!(
                        "{} input TimeSeries index is outside the runtime series table",
                        profile.label
                    ),
                )
            })?;
            source_input_series_value(variable, series, time_s, profile)
        })
        .collect()
}

fn source_input_series_value(
    variable: &UnknownVariable,
    series: &RuntimeTimeSeries,
    time_s: f64,
    profile: SourceInputDiagnosticProfile,
) -> Result<f64, SolverFailure> {
    if series.quantity_kind != variable.quantity_kind {
        return Err(SolverFailure::new(
            profile.quantity_code,
            format!(
                "{} input `{}` expects {}, but TimeSeries `{}` is {}",
                profile.label,
                variable.name,
                variable.quantity_kind,
                series.name,
                series.quantity_kind
            ),
        ));
    }
    let value = interpolate_series_value(series, time_s).ok_or_else(|| {
        SolverFailure::new(
            profile.sample_code,
            format!(
                "{} input TimeSeries `{}` has no sample at t={time_s}",
                profile.label, series.name
            ),
        )
    })?;
    convert_to_canonical_unit(
        value,
        Some(&series.display_unit),
        &variable.unit,
        &variable.quantity_kind,
    )
    .map_err(|message| {
        SolverFailure::new(
            profile.unit_code,
            format!(
                "{} input `{}` could not convert TimeSeries `{}`: {message}",
                profile.label, variable.name, series.name
            ),
        )
    })
}

fn source_initial_values_from_options(
    options: &[eng_compiler::WithOptionInfo],
    key: &str,
    variables: &[UnknownVariable],
    default_value: f64,
    source_label: &str,
    invalid_code: &'static str,
    layout_code: &'static str,
) -> Result<Vec<f64>, SolverFailure> {
    component_initial_values_from_options(options, key, variables, default_value).map_err(
        |failure| remap_source_initial_failure(failure, source_label, invalid_code, layout_code),
    )
}

fn residual_scale_overrides_from_solve_request(
    options: &[eng_compiler::WithOptionInfo],
    graph: &ResidualGraph,
) -> Result<Vec<ResidualScaleOverride>, SolverFailure> {
    let mut overrides = Vec::new();
    let mut seen = HashSet::new();
    for key in ["residual_scale", "residual_scales"] {
        let Some(raw_value) = option_value(options, key) else {
            continue;
        };
        let entries = parse_residual_scale_override_entries(raw_value);
        if entries.is_empty() {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-SCALE",
                format!("source residual scale option `{key}` is empty"),
            ));
        }
        for entry in entries {
            let (residual_name, raw_scale) = split_residual_scale_override_entry(&entry)?;
            if !seen.insert(residual_name.clone()) {
                return Err(SolverFailure::new(
                    "E-SOURCE-RESIDUAL-SCALE",
                    format!("source residual scale `{residual_name}` is specified more than once"),
                ));
            }
            let residual = graph
                .residuals
                .iter()
                .find(|residual| residual.name == residual_name)
                .ok_or_else(|| {
                    SolverFailure::new(
                        "E-SOURCE-RESIDUAL-SCALE",
                        format!(
                            "source residual scale references unknown residual `{residual_name}`"
                        ),
                    )
                })?;
            let (scale_value, scale_unit) = parse_numeric_value_with_optional_unit(&raw_scale)
                .ok_or_else(|| {
                    SolverFailure::new(
                        "E-SOURCE-RESIDUAL-SCALE",
                        format!(
                            "source residual scale `{residual_name}` is not a finite numeric literal"
                        ),
                    )
                })?;
            if !scale_value.is_finite() {
                return Err(SolverFailure::new(
                    "E-SOURCE-RESIDUAL-SCALE",
                    format!("source residual scale `{residual_name}` is not finite"),
                ));
            }
            let source_unit = scale_unit.as_deref().unwrap_or(residual.unit.unit.as_str());
            let converted_scale =
                convert_display_value(scale_value, source_unit, &residual.unit.unit);
            let scale = ResidualScale::user_provided(converted_scale, &residual_name).map_err(
                |failure| {
                    SolverFailure::new(
                        "E-SOURCE-RESIDUAL-SCALE",
                        format!("{} for residual `{residual_name}`", failure.message),
                    )
                },
            )?;
            overrides.push(ResidualScaleOverride {
                residual: residual_name,
                scale,
            });
        }
    }
    Ok(overrides)
}

fn parse_residual_scale_override_entries(value: &str) -> Vec<String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return Vec::new();
    }
    if let Some(inner) = trimmed
        .strip_prefix('[')
        .and_then(|rest| rest.strip_suffix(']'))
    {
        return split_component_initial_items(inner);
    }
    vec![trimmed.to_owned()]
}

fn split_residual_scale_override_entry(entry: &str) -> Result<(String, String), SolverFailure> {
    let trimmed = entry.trim();
    let separator = trimmed.find('=').or_else(|| trimmed.find(':'));
    let Some(separator) = separator else {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-SCALE",
            format!("source residual scale entry `{trimmed}` must use `residual = scale` syntax"),
        ));
    };
    let residual_name = trimmed[..separator].trim();
    let scale = trimmed[separator + 1..].trim();
    if residual_name.is_empty() || scale.is_empty() {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-SCALE",
            format!("source residual scale entry `{trimmed}` is incomplete"),
        ));
    }
    Ok((residual_name.to_owned(), scale.to_owned()))
}

fn remap_source_initial_failure(
    failure: SolverFailure,
    source_label: &str,
    invalid_code: &'static str,
    layout_code: &'static str,
) -> SolverFailure {
    let code = match failure.code.as_str() {
        "E-DYNAMIC-COMPONENT-SOURCE-INITIAL-LAYOUT" => layout_code,
        _ => invalid_code,
    };
    SolverFailure::new(
        code,
        failure
            .message
            .replace("dynamic component source", source_label),
    )
}

type ComponentInitialValues = Vec<(f64, Option<String>)>;

fn parse_component_initial_option(value: &str) -> Option<(bool, ComponentInitialValues)> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return None;
    }
    if let Some(inner) = trimmed
        .strip_prefix('[')
        .and_then(|rest| rest.strip_suffix(']'))
    {
        let values = split_component_initial_items(inner)
            .into_iter()
            .map(|item| parse_numeric_value_with_optional_unit(&item))
            .collect::<Option<Vec<_>>>()?;
        if values.is_empty() {
            return None;
        }
        return Some((true, values));
    }
    parse_numeric_value_with_optional_unit(trimmed).map(|value| (false, vec![value]))
}

fn split_component_initial_items(text: &str) -> Vec<String> {
    let mut items = Vec::new();
    let mut start = 0usize;
    let mut depth = 0i32;
    for (index, character) in text.char_indices() {
        match character {
            '[' | '(' | '{' => depth += 1,
            ']' | ')' | '}' => depth -= 1,
            ',' if depth == 0 => {
                let item = text[start..index].trim();
                if !item.is_empty() {
                    items.push(item.to_owned());
                }
                start = index + character.len_utf8();
            }
            _ => {}
        }
    }
    let item = text[start..].trim();
    if !item.is_empty() {
        items.push(item.to_owned());
    }
    items
}

fn failed_dynamic_component_source_solution(
    assembly: &EquationAssembly,
    method: &str,
    options: &DynamicComponentOptions,
    failure: &SolverFailure,
    reason: &str,
) -> RuntimeComponentSolution {
    let variables = assembly
        .states
        .iter()
        .chain(assembly.algebraic_variables.iter())
        .map(|variable| RuntimeComponentVariableSolution {
            name: variable.name.clone(),
            role: variable.role.clone(),
            value: 0.0,
            unit: variable.unit.clone(),
            status: "trajectory_failed".to_owned(),
        })
        .collect::<Vec<_>>();
    RuntimeComponentSolution {
        assembly: assembly.name.clone(),
        status: "failed".to_owned(),
        method: method.to_owned(),
        reason: reason.to_owned(),
        equation_count: assembly.equation_count(),
        unknown_count: assembly.unknown_count(),
        residual_norm: f64::INFINITY,
        linear_condition_estimate: None,
        linear_minimum_pivot_abs: None,
        linear_maximum_pivot_abs: None,
        variable_scale_policy: "not_applicable".to_owned(),
        variable_scale_min: None,
        variable_scale_max: None,
        tolerance: options.algebraic.tolerance,
        max_iterations: options.algebraic.max_iterations,
        iteration_count: 0,
        convergence_status: "dynamic_component_source_failed".to_owned(),
        variables,
        trajectories: Vec::new(),
        step_diagnostics: Vec::new(),
        residuals: Vec::new(),
        largest_residuals: Vec::new(),
        failure_artifact: Some(RuntimeSolverFailureArtifact {
            code: failure.code.clone(),
            message: failure.message.clone(),
        }),
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum SourceResidualSubset {
    All,
    AlgebraicOnly,
}

#[derive(Clone, Debug, PartialEq)]
struct SourceResidualEvaluation {
    residuals: Vec<RuntimeComponentResidualEvaluation>,
    normalized_values: Vec<f64>,
    residual_norm: f64,
}

#[derive(Clone, Debug, PartialEq)]
struct ParsedSourceResidual {
    name: String,
    expression: ParsedArithmeticExpression,
}

fn parse_source_residual_expressions(
    assembly: &EquationAssembly,
    symbols: &HashMap<String, f64>,
) -> Result<Vec<ParsedSourceResidual>, SolverFailure> {
    parse_source_residual_expressions_with_extra_symbol_metadata(assembly, symbols, &HashMap::new())
}

fn parse_source_residual_expressions_with_extra_symbol_metadata(
    assembly: &EquationAssembly,
    symbols: &HashMap<String, f64>,
    extra_symbol_units: &HashMap<String, ArithmeticUnitMetadata>,
) -> Result<Vec<ParsedSourceResidual>, SolverFailure> {
    let mut symbol_units = source_residual_symbol_metadata(assembly);
    symbol_units.extend(extra_symbol_units.clone());
    assembly
        .generated_equations
        .iter()
        .map(|equation| {
            let mut ignore_units = |value: f64, _unit: Option<&str>| Ok(value);
            let expression = parse_arithmetic_expression_with_symbol_metadata_and_unit_converter(
                &equation.residual,
                symbols,
                &symbol_units,
                &mut ignore_units,
                ArithmeticExpressionProfile::SOURCE_RESIDUAL,
            )
            .map_err(|failure| {
                SolverFailure::new(
                    failure.code,
                    format!(
                        "{} while parsing residual `{}`",
                        failure.message, equation.name
                    ),
                )
            })?;
            Ok(ParsedSourceResidual {
                name: equation.name.clone(),
                expression,
            })
        })
        .collect()
}

fn source_behavior_output_symbol_metadata(
    outputs: &[SourceBehaviorOutputSymbol],
) -> HashMap<String, ArithmeticUnitMetadata> {
    outputs
        .iter()
        .map(|output| {
            (
                output.name.clone(),
                ArithmeticUnitMetadata {
                    display_unit: output.unit.clone(),
                    canonical_unit: output.unit.clone(),
                    quantity_kind: output.quantity_kind.clone(),
                },
            )
        })
        .collect()
}

fn source_residual_symbol_metadata(
    assembly: &EquationAssembly,
) -> HashMap<String, ArithmeticUnitMetadata> {
    let mut metadata = HashMap::new();
    metadata.insert(
        "t".to_owned(),
        ArithmeticUnitMetadata {
            display_unit: "s".to_owned(),
            canonical_unit: "s".to_owned(),
            quantity_kind: "Time".to_owned(),
        },
    );
    metadata.insert(
        "time".to_owned(),
        ArithmeticUnitMetadata {
            display_unit: "s".to_owned(),
            canonical_unit: "s".to_owned(),
            quantity_kind: "Time".to_owned(),
        },
    );
    for variable in assembly
        .unknowns
        .iter()
        .chain(assembly.states.iter())
        .chain(assembly.algebraic_variables.iter())
        .chain(assembly.inputs.iter())
        .chain(assembly.parameters.iter())
    {
        metadata.insert(
            variable.name.clone(),
            source_variable_arithmetic_metadata(variable),
        );
    }
    for state in &assembly.states {
        metadata.insert(
            format!("der({})", state.name),
            ArithmeticUnitMetadata {
                display_unit: derivative_display_unit(&state.unit),
                canonical_unit: derivative_display_unit(&state.unit),
                quantity_kind: format!("Derivative[{}]", state.quantity_kind),
            },
        );
    }
    metadata
}

fn source_variable_arithmetic_metadata(variable: &UnknownVariable) -> ArithmeticUnitMetadata {
    let unit = if variable.unit.trim().is_empty() {
        "1"
    } else {
        variable.unit.trim()
    };
    ArithmeticUnitMetadata {
        display_unit: unit.to_owned(),
        canonical_unit: unit.to_owned(),
        quantity_kind: if variable.quantity_kind.trim().is_empty() {
            "unknown".to_owned()
        } else {
            variable.quantity_kind.clone()
        },
    }
}

fn derivative_display_unit(unit: &str) -> String {
    let unit = unit.trim();
    if unit.is_empty() || unit == "1" {
        "1/s".to_owned()
    } else {
        format!("{unit}/s")
    }
}
fn source_algebraic_parse_symbols(
    assembly: &EquationAssembly,
    parameter_values: &[f64],
) -> Result<HashMap<String, f64>, SolverFailure> {
    let mut symbols = assembly
        .unknowns
        .iter()
        .map(|variable| (variable.name.clone(), 0.0))
        .collect::<HashMap<_, _>>();
    insert_assembly_parameter_symbols(assembly, &mut symbols, Some(parameter_values))?;
    Ok(symbols)
}

fn source_dae_parse_symbols(
    assembly: &EquationAssembly,
    parameter_values: &[f64],
) -> Result<HashMap<String, f64>, SolverFailure> {
    let mut symbols = HashMap::from([("t".to_owned(), 0.0), ("time".to_owned(), 0.0)]);
    for state in &assembly.states {
        symbols.insert(state.name.clone(), 0.0);
        symbols.insert(format!("der({})", state.name), 0.0);
    }
    for variable in &assembly.algebraic_variables {
        symbols.insert(variable.name.clone(), 0.0);
    }
    for variable in &assembly.inputs {
        symbols.insert(variable.name.clone(), 0.0);
    }
    insert_assembly_parameter_symbols(assembly, &mut symbols, Some(parameter_values))?;
    Ok(symbols)
}

fn source_algebraic_residual_values(
    assembly: &EquationAssembly,
    graph: &ResidualGraph,
    parsed_residuals: &[ParsedSourceResidual],
    values: &[f64],
    parameter_values: &[f64],
    scale_overrides: &[ResidualScaleOverride],
) -> Result<Vec<f64>, SolverFailure> {
    source_residual_evaluation_for_unknowns(
        assembly,
        graph,
        parsed_residuals,
        values,
        parameter_values,
        DEFAULT_NEWTON_TOLERANCE,
        scale_overrides,
    )
    .map(|evaluation| evaluation.normalized_values)
}

const DEFAULT_NEWTON_TOLERANCE: f64 = 1e-9;

fn source_residual_evaluation_for_unknowns(
    assembly: &EquationAssembly,
    graph: &ResidualGraph,
    parsed_residuals: &[ParsedSourceResidual],
    values: &[f64],
    parameter_values: &[f64],
    tolerance: f64,
    scale_overrides: &[ResidualScaleOverride],
) -> Result<SourceResidualEvaluation, SolverFailure> {
    if values.len() != assembly.unknowns.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-LAYOUT",
            "source residual value vector length does not match assembly unknown count",
        ));
    }
    let mut symbols = assembly
        .unknowns
        .iter()
        .zip(values.iter().copied())
        .map(|(variable, value)| (variable.name.clone(), value))
        .collect::<HashMap<_, _>>();
    insert_assembly_parameter_symbols(assembly, &mut symbols, Some(parameter_values))?;
    source_residual_evaluation_with_symbols(
        assembly,
        graph,
        parsed_residuals,
        &symbols,
        tolerance,
        SourceResidualSubset::All,
        scale_overrides,
    )
}

#[derive(Clone, Copy)]
struct SourceResidualEvaluationContext<'a> {
    assembly: &'a EquationAssembly,
    graph: &'a ResidualGraph,
    parsed_residuals: &'a [ParsedSourceResidual],
    scale_overrides: &'a [ResidualScaleOverride],
}

fn source_dae_residual_values(
    context: SourceResidualEvaluationContext<'_>,
    sample: DaeSample<'_>,
    subset: SourceResidualSubset,
) -> Result<Vec<f64>, SolverFailure> {
    source_residual_evaluation_for_dae_sample(context, sample, DEFAULT_NEWTON_TOLERANCE, subset)
        .map(|evaluation| evaluation.normalized_values)
}

fn source_dae_residual_values_with_behavior(
    context: SourceResidualEvaluationContext<'_>,
    behavior_graph: &mut BehaviorGraphRhsAdapter,
    behavior_output_symbols: &[SourceBehaviorOutputSymbol],
    sample: DaeSample<'_>,
    subset: SourceResidualSubset,
) -> Result<Vec<f64>, SolverFailure> {
    let behavior_symbols = source_dae_behavior_symbols(
        context.assembly,
        sample.clone(),
        behavior_graph,
        behavior_output_symbols,
    )?;
    source_residual_evaluation_for_dae_sample_with_extra_symbols(
        context,
        sample,
        DEFAULT_NEWTON_TOLERANCE,
        subset,
        Some(&behavior_symbols),
    )
    .map(|evaluation| evaluation.normalized_values)
}

fn source_residual_evaluation_for_dae_sample(
    context: SourceResidualEvaluationContext<'_>,
    sample: DaeSample<'_>,
    tolerance: f64,
    subset: SourceResidualSubset,
) -> Result<SourceResidualEvaluation, SolverFailure> {
    source_residual_evaluation_for_dae_sample_with_extra_symbols(
        context, sample, tolerance, subset, None,
    )
}

fn source_residual_evaluation_for_dae_sample_with_extra_symbols(
    context: SourceResidualEvaluationContext<'_>,
    sample: DaeSample<'_>,
    tolerance: f64,
    subset: SourceResidualSubset,
    extra_symbols: Option<&HashMap<String, f64>>,
) -> Result<SourceResidualEvaluation, SolverFailure> {
    let SourceResidualEvaluationContext {
        assembly,
        graph,
        parsed_residuals,
        scale_overrides,
    } = context;
    if sample.state.len() != assembly.states.len()
        || sample.state_derivative.len() != assembly.states.len()
        || sample
            .mass_state_derivative
            .is_some_and(|values| values.len() != assembly.states.len())
        || sample.algebraic.len() != assembly.algebraic_variables.len()
        || sample.inputs.len() != assembly.inputs.len()
        || (!sample.parameters.is_empty() && sample.parameters.len() != assembly.parameters.len())
    {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-LAYOUT",
            "source DAE residual sample layout does not match assembly state/algebraic split",
        ));
    }
    let mut symbols = HashMap::new();
    symbols.insert("t".to_owned(), sample.time_s);
    symbols.insert("time".to_owned(), sample.time_s);
    for (state, value) in assembly.states.iter().zip(sample.state.iter().copied()) {
        symbols.insert(state.name.clone(), value);
    }
    let derivative_values = sample
        .mass_state_derivative
        .unwrap_or(sample.state_derivative);
    for (state, value) in assembly
        .states
        .iter()
        .zip(derivative_values.iter().copied())
    {
        symbols.insert(format!("der({})", state.name), value);
    }
    for (variable, value) in assembly
        .algebraic_variables
        .iter()
        .zip(sample.algebraic.iter().copied())
    {
        symbols.insert(variable.name.clone(), value);
    }
    for (variable, value) in assembly.inputs.iter().zip(sample.inputs.iter().copied()) {
        symbols.insert(variable.name.clone(), value);
    }
    insert_assembly_parameter_symbols(assembly, &mut symbols, Some(sample.parameters))?;
    if let Some(extra_symbols) = extra_symbols {
        for (name, value) in extra_symbols {
            symbols.insert(name.clone(), *value);
        }
    }
    source_residual_evaluation_with_symbols(
        assembly,
        graph,
        parsed_residuals,
        &symbols,
        tolerance,
        subset,
        scale_overrides,
    )
}

fn source_dae_behavior_symbols(
    assembly: &EquationAssembly,
    sample: DaeSample<'_>,
    behavior_graph: &mut BehaviorGraphRhsAdapter,
    behavior_output_symbols: &[SourceBehaviorOutputSymbol],
) -> Result<HashMap<String, f64>, SolverFailure> {
    let inputs = solver_scalars_from_unknown_values(
        &assembly.inputs,
        sample.inputs,
        "E-BEHAVIOR-SOURCE-DAE-INPUT-LAYOUT",
        "DAE behavior source input",
    )?;
    let parameters = solver_scalars_from_unknown_values(
        &assembly.parameters,
        sample.parameters,
        "E-BEHAVIOR-SOURCE-DAE-PARAMETER-LAYOUT",
        "DAE behavior source parameter",
    )?;
    let behavior = behavior_graph.evaluate(&BehaviorRhsSample::new(
        sample.time_s,
        sample.state,
        &inputs,
        &parameters,
    ))?;
    let mut symbols = HashMap::new();
    for (index, symbol) in behavior_output_symbols.iter().enumerate() {
        let value = behavior.output(index, 0).ok_or_else(|| {
            SolverFailure::new(
                "E-BEHAVIOR-SOURCE-DAE-OUTPUT",
                format!(
                    "DAE behavior source node `{}` did not produce output 0",
                    symbol.name
                ),
            )
        })?;
        symbols.insert(symbol.name.clone(), value);
    }
    Ok(symbols)
}

fn solver_scalars_from_unknown_values(
    variables: &[UnknownVariable],
    values: &[f64],
    layout_code: &'static str,
    context: &str,
) -> Result<Vec<SolverScalar>, SolverFailure> {
    if values.len() != variables.len() {
        return Err(SolverFailure::new(
            layout_code,
            format!(
                "{context} value vector length {} does not match layout count {}",
                values.len(),
                variables.len()
            ),
        ));
    }
    variables
        .iter()
        .zip(values.iter().copied())
        .map(|(variable, value)| {
            if !value.is_finite() {
                return Err(SolverFailure::new(
                    "E-BEHAVIOR-SOURCE-DAE-FINITE",
                    format!("{context} `{}` must be finite", variable.name),
                ));
            }
            Ok(SolverScalar::new(
                variable.name.clone(),
                variable.quantity_kind.clone(),
                variable.unit.clone(),
                value,
            ))
        })
        .collect()
}

fn source_assembly_parameter_values(
    assembly: &EquationAssembly,
) -> Result<Vec<f64>, SolverFailure> {
    assembly
        .parameters
        .iter()
        .map(|parameter| {
            parameter.value.ok_or_else(|| {
                SolverFailure::new(
                    "E-SOURCE-RESIDUAL-PARAMETER",
                    format!(
                        "source residual parameter `{}` has no materialized value",
                        parameter.name
                    ),
                )
            })
        })
        .collect()
}

fn insert_assembly_parameter_symbols(
    assembly: &EquationAssembly,
    symbols: &mut HashMap<String, f64>,
    sample_values: Option<&[f64]>,
) -> Result<(), SolverFailure> {
    if let Some(values) = sample_values {
        if values.len() != assembly.parameters.len() {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-PARAMETER-LAYOUT",
                format!(
                    "source residual parameter vector length {} does not match assembly parameter count {}",
                    values.len(),
                    assembly.parameters.len()
                ),
            ));
        }
    }
    for (index, parameter) in assembly.parameters.iter().enumerate() {
        let value = sample_values
            .and_then(|values| values.get(index).copied())
            .or(parameter.value)
            .ok_or_else(|| {
                SolverFailure::new(
                    "E-SOURCE-RESIDUAL-PARAMETER",
                    format!(
                        "source residual parameter `{}` has no materialized value",
                        parameter.name
                    ),
                )
            })?;
        symbols.insert(parameter.name.clone(), value);
    }
    Ok(())
}

struct SourceResidualFinalSample<'a> {
    input: &'a DaeInput,
    mass_matrix: Option<&'a DaeMassMatrix>,
    solver_result: &'a SolverResult,
    inputs: &'a [f64],
    tolerance: f64,
}

fn source_residual_evaluation_for_dae_final(
    context: SourceResidualEvaluationContext<'_>,
    behavior_graph: Option<&mut BehaviorGraphRhsAdapter>,
    behavior_output_symbols: &[SourceBehaviorOutputSymbol],
    final_sample: SourceResidualFinalSample<'_>,
) -> Result<SourceResidualEvaluation, SolverFailure> {
    let SourceResidualFinalSample {
        input,
        mass_matrix,
        solver_result,
        inputs,
        tolerance,
    } = final_sample;
    let state = solver_result
        .output
        .state_trajectories
        .iter()
        .map(|trajectory| trajectory.values.last().copied().unwrap_or(0.0))
        .collect::<Vec<_>>();
    let state_derivative = solver_result
        .output
        .state_trajectories
        .iter()
        .enumerate()
        .map(|(index, trajectory)| {
            if trajectory.values.len() >= 2 {
                let last = trajectory.values[trajectory.values.len() - 1];
                let previous = trajectory.values[trajectory.values.len() - 2];
                (last - previous) / solver_result.time_grid.timestep_s
            } else {
                input
                    .initial_state_derivatives
                    .get(index)
                    .copied()
                    .unwrap_or(0.0)
            }
        })
        .collect::<Vec<_>>();
    let algebraic = solver_result
        .output
        .algebraic_trajectories
        .iter()
        .map(|trajectory| trajectory.values.last().copied().unwrap_or(0.0))
        .collect::<Vec<_>>();
    let mass_state_derivative = dae_mass_state_derivative_values(mass_matrix, &state_derivative)?;
    let sample = DaeSample {
        time_s: solver_result.time_grid.duration_s,
        state: &state,
        state_derivative: &state_derivative,
        mass_state_derivative: mass_state_derivative.as_deref(),
        algebraic: &algebraic,
        inputs,
        parameters: &input.parameters,
    };
    let behavior_symbols = if let Some(graph) = behavior_graph {
        Some(source_dae_behavior_symbols(
            context.assembly,
            sample.clone(),
            graph,
            behavior_output_symbols,
        )?)
    } else {
        None
    };
    source_residual_evaluation_for_dae_sample_with_extra_symbols(
        context,
        sample,
        tolerance,
        SourceResidualSubset::All,
        behavior_symbols.as_ref(),
    )
}

fn source_residual_evaluation_with_symbols(
    assembly: &EquationAssembly,
    graph: &ResidualGraph,
    parsed_residuals: &[ParsedSourceResidual],
    symbols: &HashMap<String, f64>,
    tolerance: f64,
    subset: SourceResidualSubset,
    scale_overrides: &[ResidualScaleOverride],
) -> Result<SourceResidualEvaluation, SolverFailure> {
    if !tolerance.is_finite() || tolerance <= 0.0 {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-TOLERANCE",
            "source residual tolerance must be a positive finite number",
        ));
    }
    let metadata = graph
        .residuals
        .iter()
        .map(|residual| (residual.name.as_str(), residual))
        .collect::<HashMap<_, _>>();
    if parsed_residuals.len() != assembly.generated_equations.len() {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-PARSE-LAYOUT",
            "source residual parsed expression count does not match generated equation count",
        ));
    }
    let mut residuals = Vec::new();
    let mut normalized_values = Vec::new();
    for (equation, parsed) in assembly
        .generated_equations
        .iter()
        .zip(parsed_residuals.iter())
    {
        if subset == SourceResidualSubset::AlgebraicOnly
            && equation
                .dependencies
                .iter()
                .any(|dependency| dependency.trim().starts_with("der("))
        {
            continue;
        }
        if parsed.name != equation.name {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-PARSE-LAYOUT",
                format!(
                    "parsed source residual `{}` does not match equation `{}`",
                    parsed.name, equation.name
                ),
            ));
        }
        let raw_expression_value = parsed.expression.evaluate(symbols).map_err(|failure| {
            SolverFailure::new(
                failure.code,
                format!("{} in residual `{}`", failure.message, equation.name),
            )
        })?;
        let value = raw_expression_value - equation.rhs_value.unwrap_or(0.0);
        if !value.is_finite() {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-FINITE",
                format!(
                    "source residual `{}` evaluated to a non-finite value",
                    equation.name
                ),
            ));
        }
        let Some(residual_metadata) = metadata.get(equation.name.as_str()) else {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-METADATA",
                format!(
                    "source residual `{}` has no residual graph metadata",
                    equation.name
                ),
            ));
        };
        let residual_scale = effective_residual_scale(residual_metadata, scale_overrides);
        let scale = residual_scale.value;
        if !scale.is_finite() || scale <= 0.0 {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-SCALE",
                format!("source residual `{}` has an invalid scale", equation.name),
            ));
        }
        let normalized_value = value / scale.max(f64::EPSILON);
        if !normalized_value.is_finite() {
            return Err(SolverFailure::new(
                "E-SOURCE-RESIDUAL-FINITE",
                format!(
                    "source residual `{}` normalized value is non-finite",
                    equation.name
                ),
            ));
        }
        normalized_values.push(normalized_value);
        residuals.push(RuntimeComponentResidualEvaluation {
            name: equation.name.clone(),
            expression: equation.residual.clone(),
            source_expression: if residual_metadata.source.expression.is_empty() {
                equation.expression.clone()
            } else {
                residual_metadata.source.expression.clone()
            },
            source_line: residual_metadata.source.line,
            source_reason: residual_metadata.source.generated_reason.clone(),
            dependencies: residual_metadata
                .variable_indices
                .iter()
                .filter_map(|index| graph.variables.get(*index))
                .map(|variable| variable.name.clone())
                .collect(),
            value,
            unit: residual_metadata.unit.unit.clone(),
            expression_unit: parsed
                .expression
                .root_unit
                .as_ref()
                .map(|unit| unit.canonical_unit.clone())
                .unwrap_or_else(|| residual_metadata.unit.unit.clone()),
            expression_quantity_kind: parsed
                .expression
                .root_unit
                .as_ref()
                .map(|unit| unit.quantity_kind.clone())
                .unwrap_or_else(|| residual_metadata.unit.quantity_kind.clone()),
            normalized_value,
            scale,
            scale_policy: residual_scale.policy,
            lowering_status: "parsed_expression".to_owned(),
            lowering_failure_code: None,
            lowering_failure_reason: None,
            status: if normalized_value.abs() <= tolerance {
                "satisfied".to_owned()
            } else {
                "unsatisfied".to_owned()
            },
        });
    }
    if residuals.is_empty() {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-SHAPE",
            "source residual evaluation selected no residual equations",
        ));
    }
    let residual_norm = crate::solver::euclidean_norm(&normalized_values);
    if !residual_norm.is_finite() {
        return Err(SolverFailure::new(
            "E-SOURCE-RESIDUAL-FINITE",
            "source residual norm is non-finite",
        ));
    }
    Ok(SourceResidualEvaluation {
        residuals,
        normalized_values,
        residual_norm,
    })
}

fn source_linear_terms_jacobian(
    graph: &ResidualGraph,
    scale_overrides: &[ResidualScaleOverride],
) -> Result<Vec<Vec<f64>>, SolverFailure> {
    let system = graph.assemble_linear_system()?;
    Ok(system
        .matrix
        .iter()
        .zip(graph.residuals.iter())
        .map(|(row, residual)| {
            let scale = effective_residual_scale(residual, scale_overrides).value;
            row.iter()
                .map(|value| value / scale.max(f64::EPSILON))
                .collect::<Vec<_>>()
        })
        .collect())
}

fn effective_residual_scale(
    residual: &ResidualEquation,
    scale_overrides: &[ResidualScaleOverride],
) -> ResidualScale {
    scale_overrides
        .iter()
        .find(|override_scale| override_scale.residual == residual.name)
        .map(|override_scale| override_scale.scale.clone())
        .unwrap_or_else(|| residual.scale.clone())
}

fn variable_scales_from_unknowns(unknowns: &[UnknownVariable]) -> Vec<f64> {
    unknowns
        .iter()
        .map(|unknown| {
            ResidualScale::from_quantity_unit(&unknown.quantity_kind, &unknown.unit).value
        })
        .collect()
}

fn apply_newton_variable_scales_from_unknowns(
    options: &mut NewtonOptions,
    unknowns: &[UnknownVariable],
    policy: &str,
) {
    if options.variable_scales.is_empty() {
        options.variable_scales = variable_scales_from_unknowns(unknowns);
        options.variable_scale_policy = policy.to_owned();
    }
}

fn finite_minimum(values: &[f64]) -> Option<f64> {
    values
        .iter()
        .copied()
        .filter(|value| value.is_finite())
        .reduce(f64::min)
}

fn finite_maximum(values: &[f64]) -> Option<f64> {
    values
        .iter()
        .copied()
        .filter(|value| value.is_finite())
        .reduce(f64::max)
}
fn fixed_point_variable_scales_from_solve_request(
    options: &[eng_compiler::WithOptionInfo],
    variables: &[UnknownVariable],
) -> Result<Option<Vec<f64>>, SolverFailure> {
    let requested_keys = ["variable_scale", "variable_scales"]
        .into_iter()
        .filter(|key| option_value(options, key).is_some())
        .collect::<Vec<_>>();
    if requested_keys.is_empty() {
        return Ok(None);
    }
    if requested_keys.len() > 1 {
        return Err(SolverFailure::new(
            "E-FIXED-POINT-SOURCE-VARIABLE-SCALE",
            "specify either `variable_scale` or `variable_scales`, not both",
        ));
    }
    let key = requested_keys[0];
    let scales = source_initial_values_from_options(
        options,
        key,
        variables,
        1.0,
        "fixed-point source variable scale",
        "E-FIXED-POINT-SOURCE-VARIABLE-SCALE",
        "E-FIXED-POINT-SOURCE-VARIABLE-SCALE-LAYOUT",
    )?;
    if scales
        .iter()
        .any(|scale| !scale.is_finite() || *scale <= 0.0)
    {
        return Err(SolverFailure::new(
            "E-FIXED-POINT-SOURCE-VARIABLE-SCALE",
            format!("fixed-point source option `{key}` expects positive finite variable scales"),
        ));
    }
    Ok(Some(scales))
}
fn newton_variable_scales_from_solve_request(
    options: &[eng_compiler::WithOptionInfo],
    variables: &[UnknownVariable],
) -> Result<Option<Vec<f64>>, SolverFailure> {
    let requested_keys = ["variable_scale", "variable_scales"]
        .into_iter()
        .filter(|key| option_value(options, key).is_some())
        .collect::<Vec<_>>();
    if requested_keys.is_empty() {
        return Ok(None);
    }
    if requested_keys.len() > 1 {
        return Err(SolverFailure::new(
            "E-NEWTON-SOURCE-VARIABLE-SCALE",
            "specify either `variable_scale` or `variable_scales`, not both",
        ));
    }
    let key = requested_keys[0];
    let scales = source_initial_values_from_options(
        options,
        key,
        variables,
        1.0,
        "Newton source variable scale",
        "E-NEWTON-SOURCE-VARIABLE-SCALE",
        "E-NEWTON-SOURCE-VARIABLE-SCALE-LAYOUT",
    )?;
    if scales
        .iter()
        .any(|scale| !scale.is_finite() || *scale <= 0.0)
    {
        return Err(SolverFailure::new(
            "E-NEWTON-SOURCE-VARIABLE-SCALE",
            format!("Newton source option `{key}` expects positive finite variable scales"),
        ));
    }
    Ok(Some(scales))
}

fn newton_options_from_solve_request(options: &[eng_compiler::WithOptionInfo]) -> NewtonOptions {
    let mut newton = NewtonOptions::default();
    if let Some(tolerance) = option_value(options, "tolerance")
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value > 0.0)
    {
        newton.tolerance = tolerance;
    }
    if let Some(max_iterations) = option_value(options, "max_iter")
        .and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|value| *value > 0)
    {
        newton.max_iterations = max_iterations;
    }
    if let Some(step) = option_value(options, "finite_difference_step")
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value > 0.0)
    {
        newton.finite_difference_step = step;
    }
    if let Some(damping) = option_value(options, "damping")
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value > 0.0 && *value <= 1.0)
    {
        newton.damping = damping;
    }
    if let Some(steps) = option_value(options, "line_search_steps")
        .and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|value| *value > 0)
    {
        newton.line_search_steps = steps;
    }
    newton
}

fn dae_method_from_solve_request(
    options: &[eng_compiler::WithOptionInfo],
) -> Result<DaeMethod, SolverFailure> {
    let Some(raw_method) = option_value(options, "method")
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        return Ok(DaeMethod::ImplicitEuler);
    };
    let method = raw_method.to_ascii_lowercase().replace('-', "_");
    match method.as_str() {
        "implicit_euler" | "implicit_euler_dae" | "dae_implicit_euler" => {
            Ok(DaeMethod::ImplicitEuler)
        }
        "bdf" => Ok(DaeMethod::Bdf {
            order: dae_bdf_order_from_options(options).unwrap_or(2),
        }),
        _ => {
            if let Some(order_text) = method
                .strip_prefix("bdf_")
                .or_else(|| method.strip_prefix("bdf"))
            {
                if let Ok(order) = order_text.parse::<usize>() {
                    if order > 0 {
                        return Ok(DaeMethod::Bdf { order });
                    }
                }
            }
            Err(SolverFailure::new(
                "E-DAE-SOURCE-METHOD",
                format!("unsupported DAE source method `{raw_method}`"),
            ))
        }
    }
}

fn dae_bdf_order_from_options(options: &[eng_compiler::WithOptionInfo]) -> Option<usize> {
    option_value(options, "bdf_order")
        .or_else(|| option_value(options, "order"))
        .and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|order| *order > 0)
}

#[derive(Clone, Debug, PartialEq)]
struct NewtonStepLargestResidual {
    index: usize,
    name: Option<String>,
    value: f64,
    abs_value: f64,
}

fn largest_newton_residual_diagnostic(
    values: Option<&[f64]>,
    residual_names: Option<&[String]>,
) -> Option<NewtonStepLargestResidual> {
    let values = values?;
    values
        .iter()
        .copied()
        .enumerate()
        .filter(|(_, value)| value.is_finite())
        .map(|(index, value)| NewtonStepLargestResidual {
            index,
            name: residual_names.and_then(|names| names.get(index).cloned()),
            value,
            abs_value: value.abs(),
        })
        .max_by(|left, right| left.abs_value.total_cmp(&right.abs_value))
}

fn normalized_newton_residual_values(values: &[f64], residual_scales: Option<&[f64]>) -> Vec<f64> {
    values
        .iter()
        .enumerate()
        .map(|(index, value)| {
            residual_scales
                .and_then(|scales| scales.get(index))
                .copied()
                .filter(|scale| scale.is_finite() && *scale > 0.0)
                .map(|scale| *value / scale)
                .unwrap_or(*value)
        })
        .collect()
}

fn newton_residual_history_diagnostics(
    newton: &crate::solver::NewtonResult,
    failure: Option<&SolverFailure>,
    residual_names: Option<&[String]>,
    residual_scales: Option<&[f64]>,
) -> Vec<RuntimeComponentStepDiagnostic> {
    newton
        .residual_history
        .iter()
        .enumerate()
        .map(|(index, residual_norm)| {
            let residual_values = newton
                .residual_value_history
                .get(index)
                .cloned()
                .unwrap_or_default();
            let normalized_residual_values =
                normalized_newton_residual_values(&residual_values, residual_scales);
            let largest_residual = largest_newton_residual_diagnostic(
                Some(residual_values.as_slice()),
                residual_names,
            );
            RuntimeComponentStepDiagnostic {
                step_index: index,
                time_s: 0.0,
                algebraic_iteration_count: index,
                residual_norm: *residual_norm,
                residual_values,
                normalized_residual_values,
                line_search_scale: newton
                    .line_search_history
                    .iter()
                    .find(|step| step.iteration == index)
                    .map(|step| step.scale),
                line_search_trial_count: newton
                    .line_search_history
                    .iter()
                    .find(|step| step.iteration == index)
                    .map(|step| step.trial_count),
                jacobian_policy: (index > 0).then(|| newton.jacobian_policy.clone()),
                variable_scale_policy: (index > 0).then(|| newton.variable_scale_policy.clone()),
                linear_condition_estimate: newton
                    .linear_step_history
                    .iter()
                    .find(|step| step.iteration == index)
                    .map(|step| step.linear_condition_estimate),
                linear_minimum_pivot_abs: newton
                    .linear_step_history
                    .iter()
                    .find(|step| step.iteration == index)
                    .map(|step| step.linear_minimum_pivot_abs),
                linear_maximum_pivot_abs: newton
                    .linear_step_history
                    .iter()
                    .find(|step| step.iteration == index)
                    .map(|step| step.linear_maximum_pivot_abs),
                largest_residual_index: largest_residual.as_ref().map(|residual| residual.index),
                largest_residual_name: largest_residual
                    .as_ref()
                    .and_then(|residual| residual.name.clone()),
                largest_residual_value: largest_residual.as_ref().map(|residual| residual.value),
                largest_residual_abs_value: largest_residual
                    .as_ref()
                    .map(|residual| residual.abs_value),
                convergence_status: if index + 1 == newton.residual_history.len() {
                    newton.convergence_status.clone()
                } else {
                    "newton_iteration".to_owned()
                },
                failure_artifact: (index + 1 == newton.residual_history.len())
                    .then_some(failure)
                    .flatten()
                    .map(|failure| RuntimeSolverFailureArtifact {
                        code: failure.code.clone(),
                        message: failure.message.clone(),
                    }),
            }
        })
        .collect()
}

fn source_newton_residual_history_diagnostics(
    newton: &crate::solver::NewtonResult,
    failure: Option<&SolverFailure>,
    residual_names: Option<&[String]>,
    residual_scales: Option<&[f64]>,
) -> Vec<RuntimeComponentStepDiagnostic> {
    newton_residual_history_diagnostics(newton, failure, residual_names, None)
        .into_iter()
        .map(|diagnostic| diagnostic.with_source_residual_scales(residual_names, residual_scales))
        .collect()
}

fn fixed_point_residual_history_diagnostics(
    residual_history: &[f64],
    residual_value_history: &[Vec<f64>],
    residual_names: Option<&[String]>,
    residual_scales: Option<&[f64]>,
    variable_scale_policy: Option<&str>,
    convergence_status: &str,
    failure_artifact: Option<&RuntimeSolverFailureArtifact>,
) -> Vec<RuntimeComponentStepDiagnostic> {
    residual_history
        .iter()
        .enumerate()
        .map(|(index, residual_norm)| {
            let residual_values = residual_value_history
                .get(index)
                .cloned()
                .unwrap_or_default();
            let normalized_residual_values =
                normalized_newton_residual_values(&residual_values, residual_scales);
            let largest_residual = largest_newton_residual_diagnostic(
                Some(residual_values.as_slice()),
                residual_names,
            );
            RuntimeComponentStepDiagnostic {
                step_index: index,
                time_s: 0.0,
                algebraic_iteration_count: index + 1,
                residual_norm: *residual_norm,
                residual_values,
                normalized_residual_values,
                line_search_scale: None,
                line_search_trial_count: None,
                jacobian_policy: None,
                variable_scale_policy: variable_scale_policy.map(str::to_owned),
                linear_condition_estimate: None,
                linear_minimum_pivot_abs: None,
                linear_maximum_pivot_abs: None,
                largest_residual_index: largest_residual.as_ref().map(|residual| residual.index),
                largest_residual_name: largest_residual
                    .as_ref()
                    .and_then(|residual| residual.name.clone()),
                largest_residual_value: largest_residual.as_ref().map(|residual| residual.value),
                largest_residual_abs_value: largest_residual
                    .as_ref()
                    .map(|residual| residual.abs_value),
                convergence_status: if index + 1 == residual_history.len() {
                    convergence_status.to_owned()
                } else {
                    "fixed_point_iteration".to_owned()
                },
                failure_artifact: (index + 1 == residual_history.len())
                    .then(|| failure_artifact.cloned())
                    .flatten(),
            }
        })
        .collect()
}

fn failed_source_component_solution(
    assembly: &EquationAssembly,
    method: &str,
    reason: &str,
    failure: &SolverFailure,
    tolerance: f64,
    max_iterations: usize,
    convergence_status: &str,
) -> RuntimeComponentSolution {
    let variables = assembly
        .unknowns
        .iter()
        .map(|variable| RuntimeComponentVariableSolution {
            name: variable.name.clone(),
            role: variable.role.clone(),
            value: 0.0,
            unit: variable.unit.clone(),
            status: "source_solve_failed".to_owned(),
        })
        .collect::<Vec<_>>();
    RuntimeComponentSolution {
        assembly: assembly.name.clone(),
        status: "failed".to_owned(),
        method: method.to_owned(),
        reason: reason.to_owned(),
        equation_count: assembly.equation_count(),
        unknown_count: assembly.unknown_count(),
        residual_norm: f64::INFINITY,
        linear_condition_estimate: None,
        linear_minimum_pivot_abs: None,
        linear_maximum_pivot_abs: None,
        variable_scale_policy: "not_applicable".to_owned(),
        variable_scale_min: None,
        variable_scale_max: None,
        tolerance,
        max_iterations,
        iteration_count: 0,
        convergence_status: convergence_status.to_owned(),
        variables,
        trajectories: Vec::new(),
        step_diagnostics: Vec::new(),
        residuals: Vec::new(),
        largest_residuals: Vec::new(),
        failure_artifact: Some(RuntimeSolverFailureArtifact {
            code: failure.code.clone(),
            message: failure.message.clone(),
        }),
    }
}

fn layout_names_from_unknowns(variables: &[UnknownVariable]) -> Vec<String> {
    variables
        .iter()
        .map(|variable| variable.name.clone())
        .collect()
}

fn fixed_point_options_from_solve_request(
    options: &[eng_compiler::WithOptionInfo],
) -> FixedPointOptions {
    let mut fixed_point = FixedPointOptions::default();
    if let Some(tolerance) = option_value(options, "tolerance")
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value > 0.0)
    {
        fixed_point.tolerance = tolerance;
    }
    if let Some(max_iterations) = option_value(options, "max_iter")
        .and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|value| *value > 0)
    {
        fixed_point.max_iterations = max_iterations;
    }
    if let Some(relaxation) = option_value(options, "relaxation")
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value > 0.0 && *value <= 1.0)
    {
        fixed_point.relaxation = relaxation;
    }
    fixed_point
}

fn fixed_point_initial_values_from_solve_request(
    options: &[eng_compiler::WithOptionInfo],
    variables: &[UnknownVariable],
) -> Result<Vec<f64>, SolverFailure> {
    source_initial_values_from_options(
        options,
        "initial",
        variables,
        0.0,
        "fixed-point source",
        "E-FIXED-POINT-SOURCE-INITIAL",
        "E-FIXED-POINT-SOURCE-INITIAL-LAYOUT",
    )
}

#[derive(Clone, Debug, PartialEq)]
struct FixedPointPivot {
    variable_index: usize,
    residual_index: usize,
    coefficient: f64,
}

#[derive(Clone, Debug, PartialEq)]
struct FixedPointExpressionSideTerm {
    variable_index: usize,
    coefficient: f64,
}

#[derive(Clone, Debug, PartialEq)]
struct FixedPointExpressionMap {
    variable_index: usize,
    residual_index: usize,
    expression_text: String,
    expression: ParsedArithmeticExpression,
    side_constant: f64,
    side_terms: Vec<FixedPointExpressionSideTerm>,
}

#[derive(Clone, Debug, PartialEq)]
enum FixedPointUpdateRule {
    Linear(FixedPointPivot),
    Expression(Box<FixedPointExpressionMap>),
}

impl FixedPointUpdateRule {
    fn variable_index(&self) -> usize {
        match self {
            Self::Linear(pivot) => pivot.variable_index,
            Self::Expression(mapping) => mapping.variable_index,
        }
    }

    fn residual_index(&self) -> usize {
        match self {
            Self::Linear(pivot) => pivot.residual_index,
            Self::Expression(mapping) => mapping.residual_index,
        }
    }
}

fn fixed_point_update_plan(
    graph: &ResidualGraph,
    assembly: &EquationAssembly,
    parameter_values: &[f64],
) -> Result<Vec<FixedPointUpdateRule>, SolverFailure> {
    let variable_count = graph.variables.len();
    let residual_count = graph.residuals.len();
    if variable_count == 0 || residual_count == 0 || variable_count != residual_count {
        return Err(SolverFailure::new(
            "E-FIXED-POINT-GRAPH-SHAPE",
            format!(
                "fixed-point residual graph requires a non-empty square system, got {residual_count} residual(s) and {variable_count} variable(s)"
            ),
        ));
    }

    let expression_maps = fixed_point_expression_update_maps(graph, assembly, parameter_values)?;
    let mut residual_order = (0..residual_count).collect::<Vec<_>>();
    residual_order.sort_by_key(|index| {
        let residual = &graph.residuals[*index];
        let source_priority = if residual
            .source
            .generated_reason
            .as_deref()
            .is_some_and(|reason| reason.contains("component-local equation"))
        {
            1
        } else {
            2
        };
        if residual.terms.len() == 1 {
            (0, residual.terms.len())
        } else {
            (source_priority, residual.terms.len())
        }
    });

    let mut used_variables = HashSet::new();
    let mut used_residuals = HashSet::new();
    let mut rules = Vec::with_capacity(variable_count);
    for residual_index in residual_order {
        let residual = &graph.residuals[residual_index];
        if let Some(term) = residual.terms.iter().find(|term| {
            term.variable_index < variable_count
                && !used_variables.contains(&term.variable_index)
                && term.coefficient.is_finite()
                && term.coefficient.abs() > 1e-12
        }) {
            used_variables.insert(term.variable_index);
            used_residuals.insert(residual_index);
            rules.push(FixedPointUpdateRule::Linear(FixedPointPivot {
                variable_index: term.variable_index,
                residual_index,
                coefficient: term.coefficient,
            }));
            continue;
        }

        if let Some(mapping) = expression_maps.iter().find(|mapping| {
            mapping.residual_index == residual_index
                && !used_variables.contains(&mapping.variable_index)
        }) {
            used_variables.insert(mapping.variable_index);
            used_residuals.insert(residual_index);
            rules.push(FixedPointUpdateRule::Expression(Box::new(mapping.clone())));
        }
    }

    if rules.len() != variable_count {
        let missing = graph
            .variables
            .iter()
            .filter(|variable| !used_variables.contains(&variable.index))
            .map(|variable| variable.name.clone())
            .collect::<Vec<_>>();
        return Err(SolverFailure::new(
            "E-FIXED-POINT-GRAPH-PIVOT",
            format!(
                "fixed-point residual graph could not assign one update equation per variable; missing pivot(s): {}",
                missing.join(", ")
            ),
        ));
    }
    if used_residuals.len() != residual_count {
        return Err(SolverFailure::new(
            "E-FIXED-POINT-GRAPH-PIVOT",
            "fixed-point residual graph could not assign each residual to one variable update",
        ));
    }
    rules.sort_by_key(|rule| rule.variable_index());
    Ok(rules)
}

fn fixed_point_expression_update_maps(
    graph: &ResidualGraph,
    assembly: &EquationAssembly,
    parameter_values: &[f64],
) -> Result<Vec<FixedPointExpressionMap>, SolverFailure> {
    let variable_symbols = graph
        .variables
        .iter()
        .map(|variable| variable.name.clone())
        .collect::<Vec<_>>();
    let mut parameter_symbols = HashMap::new();
    insert_assembly_parameter_symbols(assembly, &mut parameter_symbols, Some(parameter_values))?;
    let mut symbols = variable_symbols
        .iter()
        .map(|variable| (variable.clone(), 0.0))
        .collect::<HashMap<_, _>>();
    symbols.extend(parameter_symbols.clone());
    let symbol_units = source_residual_symbol_metadata(assembly);
    let mut maps = Vec::new();
    for (residual_index, residual) in graph.residuals.iter().enumerate() {
        let Some((left, right)) = split_fixed_point_source_equation(&residual.source.expression)
        else {
            continue;
        };
        if let Some(side) = fixed_point_affine_variable_side(
            left,
            graph,
            &variable_symbols,
            &parameter_symbols,
            &symbol_units,
        ) {
            for term in &side.terms {
                maps.push(fixed_point_expression_update_map(
                    FixedPointExpressionMapInput {
                        graph,
                        residual_index,
                        variable_index: term.variable_index,
                        expression_text: right,
                        symbols: &symbols,
                        symbol_units: &symbol_units,
                        side_constant: side.constant,
                        side_terms: side.terms.clone(),
                    },
                )?);
            }
        } else if let Some(side) = fixed_point_affine_variable_side(
            right,
            graph,
            &variable_symbols,
            &parameter_symbols,
            &symbol_units,
        ) {
            for term in &side.terms {
                maps.push(fixed_point_expression_update_map(
                    FixedPointExpressionMapInput {
                        graph,
                        residual_index,
                        variable_index: term.variable_index,
                        expression_text: left,
                        symbols: &symbols,
                        symbol_units: &symbol_units,
                        side_constant: side.constant,
                        side_terms: side.terms.clone(),
                    },
                )?);
            }
        }
    }
    Ok(maps)
}

#[derive(Clone, Debug, PartialEq)]
struct FixedPointAffineSide {
    constant: f64,
    terms: Vec<FixedPointExpressionSideTerm>,
}

fn fixed_point_affine_variable_side(
    side: &str,
    graph: &ResidualGraph,
    variable_symbols: &[String],
    constant_symbols: &HashMap<String, f64>,
    symbol_units: &HashMap<String, ArithmeticUnitMetadata>,
) -> Option<FixedPointAffineSide> {
    let side = trim_wrapping_parentheses(side.trim());
    let mut ignore_units = |value: f64, _unit: Option<&str>| Ok(value);
    let linearized = linearize_arithmetic_expression_with_symbol_metadata_and_unit_converter(
        side,
        variable_symbols,
        constant_symbols,
        symbol_units,
        &mut ignore_units,
        ArithmeticExpressionProfile::SOURCE_RESIDUAL,
        1e-9,
    )
    .ok()?;
    if !linearized.constant.is_finite() {
        return None;
    }
    let terms = linearized
        .terms
        .into_iter()
        .filter(|term| term.coefficient.is_finite() && term.coefficient.abs() > 1e-12)
        .filter_map(|term| {
            graph
                .variables
                .iter()
                .find(|variable| variable.name == term.symbol)
                .map(|variable| FixedPointExpressionSideTerm {
                    variable_index: variable.index,
                    coefficient: term.coefficient,
                })
        })
        .collect::<Vec<_>>();
    (!terms.is_empty()).then_some(FixedPointAffineSide {
        constant: linearized.constant,
        terms,
    })
}

fn split_fixed_point_source_equation(expression: &str) -> Option<(&str, &str)> {
    expression.split_once(" eq ")
}

fn trim_wrapping_parentheses(mut value: &str) -> &str {
    loop {
        let trimmed = value.trim();
        if trimmed.len() >= 2 && trimmed.starts_with('(') && trimmed.ends_with(')') {
            value = &trimmed[1..trimmed.len() - 1];
        } else {
            return trimmed;
        }
    }
}

struct FixedPointExpressionMapInput<'a> {
    graph: &'a ResidualGraph,
    residual_index: usize,
    variable_index: usize,
    expression_text: &'a str,
    symbols: &'a HashMap<String, f64>,
    symbol_units: &'a HashMap<String, ArithmeticUnitMetadata>,
    side_constant: f64,
    side_terms: Vec<FixedPointExpressionSideTerm>,
}

fn fixed_point_expression_update_map(
    input: FixedPointExpressionMapInput<'_>,
) -> Result<FixedPointExpressionMap, SolverFailure> {
    let FixedPointExpressionMapInput {
        graph,
        residual_index,
        variable_index,
        expression_text,
        symbols,
        symbol_units,
        side_constant,
        side_terms,
    } = input;
    let mut ignore_units = |value: f64, _unit: Option<&str>| Ok(value);
    let expression = parse_arithmetic_expression_with_symbol_metadata_and_unit_converter(
        expression_text,
        symbols,
        symbol_units,
        &mut ignore_units,
        ArithmeticExpressionProfile::SOURCE_RESIDUAL,
    )
    .map_err(|failure| {
        let residual_name = graph
            .residuals
            .get(residual_index)
            .map(|residual| residual.name.as_str())
            .unwrap_or("unknown");
        SolverFailure::new(
            failure.code,
            format!(
                "{} while parsing fixed-point update expression `{}` for residual `{}`",
                failure.message,
                expression_text.trim(),
                residual_name
            ),
        )
    })?;
    Ok(FixedPointExpressionMap {
        variable_index,
        residual_index,
        expression_text: expression_text.trim().to_owned(),
        expression,
        side_constant,
        side_terms,
    })
}

fn fixed_point_update_values(
    graph: &ResidualGraph,
    update_plan: &[FixedPointUpdateRule],
    values: &[f64],
    assembly: &EquationAssembly,
    parameter_values: &[f64],
) -> Result<Vec<f64>, SolverFailure> {
    if values.len() != graph.variables.len() {
        return Err(SolverFailure::new(
            "E-FIXED-POINT-LAYOUT",
            "fixed-point update input length does not match residual graph variables",
        ));
    }
    let symbols = fixed_point_symbol_values(graph, values, assembly, parameter_values)?;
    let mut next = values.to_vec();
    for rule in update_plan {
        let residual_index = rule.residual_index();
        let Some(residual) = graph.residuals.get(residual_index) else {
            return Err(SolverFailure::new(
                "E-FIXED-POINT-GRAPH-PIVOT",
                "fixed-point update references an unknown residual",
            ));
        };
        match rule {
            FixedPointUpdateRule::Linear(pivot) => {
                if !residual.rhs_value.is_finite() {
                    return Err(SolverFailure::new(
                        "E-FIXED-POINT-VALUE",
                        format!("residual `{}` has a non-finite RHS value", residual.name),
                    ));
                }
                let mut rhs = residual.rhs_value;
                for term in &residual.terms {
                    if term.variable_index == pivot.variable_index {
                        continue;
                    }
                    let Some(value) = values.get(term.variable_index) else {
                        return Err(SolverFailure::new(
                            "E-FIXED-POINT-LAYOUT",
                            format!(
                                "fixed-point residual `{}` references variable index {} outside the update vector",
                                residual.name, term.variable_index
                            ),
                        ));
                    };
                    if !term.coefficient.is_finite() || !value.is_finite() {
                        return Err(SolverFailure::new(
                            "E-FIXED-POINT-VALUE",
                            format!(
                                "fixed-point residual `{}` contains a non-finite update term",
                                residual.name
                            ),
                        ));
                    }
                    rhs -= term.coefficient * value;
                }
                next[pivot.variable_index] = rhs / pivot.coefficient;
            }
            FixedPointUpdateRule::Expression(mapping) => {
                let value = mapping.expression.evaluate(&symbols).map_err(|failure| {
                    SolverFailure::new(
                        failure.code,
                        format!(
                            "{} while evaluating fixed-point update expression `{}` for residual `{}`",
                            failure.message, mapping.expression_text, residual.name
                        ),
                    )
                })?;
                let Some(target_term) = mapping
                    .side_terms
                    .iter()
                    .find(|term| term.variable_index == mapping.variable_index)
                else {
                    return Err(SolverFailure::new(
                        "E-FIXED-POINT-GRAPH-PIVOT",
                        format!(
                            "fixed-point expression map for residual `{}` lost its target coefficient",
                            residual.name
                        ),
                    ));
                };
                if !target_term.coefficient.is_finite() || target_term.coefficient.abs() <= 1e-12 {
                    return Err(SolverFailure::new(
                        "E-FIXED-POINT-VALUE",
                        format!(
                            "fixed-point expression map for residual `{}` has an invalid target coefficient",
                            residual.name
                        ),
                    ));
                }
                let mut side_without_target = mapping.side_constant;
                for term in &mapping.side_terms {
                    if term.variable_index == mapping.variable_index {
                        continue;
                    }
                    let Some(value) = values.get(term.variable_index) else {
                        return Err(SolverFailure::new(
                            "E-FIXED-POINT-LAYOUT",
                            format!(
                                "fixed-point expression map for residual `{}` references variable index {} outside the update vector",
                                residual.name, term.variable_index
                            ),
                        ));
                    };
                    side_without_target += term.coefficient * value;
                }
                next[mapping.variable_index] =
                    (value - side_without_target) / target_term.coefficient;
            }
        }
    }
    Ok(next)
}

fn fixed_point_symbol_values(
    graph: &ResidualGraph,
    values: &[f64],
    assembly: &EquationAssembly,
    parameter_values: &[f64],
) -> Result<HashMap<String, f64>, SolverFailure> {
    let mut symbols = graph
        .variables
        .iter()
        .zip(values.iter().copied())
        .map(|(variable, value)| (variable.name.clone(), value))
        .collect::<HashMap<_, _>>();
    insert_assembly_parameter_symbols(assembly, &mut symbols, Some(parameter_values))?;
    Ok(symbols)
}

fn fixed_point_source_residual_evaluation(
    assembly: &EquationAssembly,
    graph: &ResidualGraph,
    values: &[f64],
    parameter_values: Option<&[f64]>,
    tolerance: f64,
    scale_overrides: &[ResidualScaleOverride],
) -> Result<Option<SourceResidualEvaluation>, SolverFailure> {
    let Some(parameter_values) = parameter_values else {
        return Ok(None);
    };
    let parse_symbols = source_algebraic_parse_symbols(assembly, parameter_values)?;
    let parsed_residuals = parse_source_residual_expressions(assembly, &parse_symbols)?;
    source_residual_evaluation_for_unknowns(
        assembly,
        graph,
        &parsed_residuals,
        values,
        parameter_values,
        tolerance,
        scale_overrides,
    )
    .map(Some)
}
fn annotate_component_behavior_solution(
    solution: &mut RuntimeComponentSolution,
    assembly: &eng_compiler::ComponentAssemblyInfo,
) {
    if !component_assembly_has_behavior_seed(assembly) {
        return;
    }
    if solution.method.starts_with("behavior_graph_")
        || solution.convergence_status.starts_with("behavior_graph_")
    {
        return;
    }
    append_component_solution_reason(solution, COMPONENT_BEHAVIOR_NOT_INTEGRATED_NOTE);
    if solution.failure_artifact.is_none() {
        solution.status = "not_solved_behavior_not_integrated".to_owned();
        solution.convergence_status = "behavior_graph_not_integrated".to_owned();
        for variable in &mut solution.variables {
            if variable.status == "solved_linear" {
                variable.status = "behavior_not_integrated".to_owned();
            }
        }
        solution.failure_artifact = Some(RuntimeSolverFailureArtifact {
            code: COMPONENT_BEHAVIOR_NOT_INTEGRATED_CODE.to_owned(),
            message: COMPONENT_BEHAVIOR_NOT_INTEGRATED_NOTE.to_owned(),
        });
    } else if let Some(failure) = &mut solution.failure_artifact {
        if !failure
            .message
            .contains(COMPONENT_BEHAVIOR_NOT_INTEGRATED_NOTE)
        {
            failure.message = format!(
                "{}; {}",
                failure.message, COMPONENT_BEHAVIOR_NOT_INTEGRATED_NOTE
            );
        }
    }
}

fn component_assembly_has_behavior_seed(assembly: &eng_compiler::ComponentAssemblyInfo) -> bool {
    assembly.solver_preview.delay_history != "deferred_no_delay_calls"
        || assembly.solver_preview.predictor != "deferred_no_predictor_calls"
        || assembly.solver_preview.external_adapter != "deferred_no_external_behavior_adapter"
}

fn append_component_solution_reason(solution: &mut RuntimeComponentSolution, note: &str) {
    if !solution.reason.contains(note) {
        solution.reason = format!("{}; {}", solution.reason, note);
    }
}

#[allow(dead_code)]
fn component_trajectory_from_solver_trajectory(
    trajectory: &StateTrajectory,
    role: &str,
    time_grid: &TimeGrid,
) -> RuntimeComponentTrajectory {
    let points = trajectory
        .time_value_points(time_grid)
        .into_iter()
        .map(|(x, y)| RuntimePoint { x, y })
        .collect::<Vec<_>>();
    RuntimeComponentTrajectory {
        name: trajectory.name.clone(),
        role: role.to_owned(),
        quantity_kind: trajectory.quantity_kind.clone(),
        unit: trajectory.canonical_unit.clone(),
        initial_value: trajectory.initial_value().unwrap_or(0.0),
        final_value: trajectory.final_value().unwrap_or(0.0),
        point_count: points.len(),
        points,
    }
}

fn solver_equation_assembly_from_system_info(
    system: &eng_compiler::SystemInfo,
) -> EquationAssembly {
    let variables = system
        .variables
        .iter()
        .map(|variable| {
            let role = match variable.role.as_str() {
                "state" | "output" => "algebraic".to_owned(),
                other => other.to_owned(),
            };
            let value = (variable.role == "parameter" || variable.role == "input")
                .then(|| canonical_variable_value(variable))
                .flatten();
            UnknownVariable {
                name: variable.name.clone(),
                role,
                quantity_kind: variable.quantity_kind.clone(),
                unit: variable.canonical_unit.clone(),
                source: format!("system.{}", system.name),
                status: format!("source_system_{}", variable.role),
                value,
            }
        })
        .collect::<Vec<_>>();
    let unknowns = variables
        .iter()
        .filter(|variable| variable.role == "algebraic")
        .cloned()
        .collect::<Vec<_>>();
    let algebraic_variables = unknowns.clone();
    let inputs = variables
        .iter()
        .filter(|variable| variable.role == "input")
        .cloned()
        .collect::<Vec<_>>();
    let parameters = variables
        .iter()
        .filter(|variable| variable.role == "parameter" || variable.role == "input")
        .cloned()
        .collect::<Vec<_>>();
    let generated_equations = system
        .equations
        .iter()
        .enumerate()
        .map(|(index, equation)| GeneratedEquation {
            name: if equation.residual.trim().is_empty() {
                format!("{}.source_equation_{}", system.name, index + 1)
            } else {
                equation.residual.clone()
            },
            kind: "component_equation".to_owned(),
            domain: equation.left_dimension.clone(),
            expression: format!("{} {} {}", equation.left, equation.relation, equation.right),
            residual: system_equation_residual_expression(system, equation),
            rhs_value: None,
            dependencies: system_equation_dependencies(system, equation),
            source: "source_system_equation".to_owned(),
            reason: "source system algebraic equation".to_owned(),
            source_line: Some(equation.line),
            status: equation.status.clone(),
        })
        .collect::<Vec<_>>();

    EquationAssembly {
        name: system.name.clone(),
        components: Vec::new(),
        ports: Vec::new(),
        connections: Vec::new(),
        connection_sets: Vec::new(),
        generated_equations,
        component_equations: Vec::<ComponentEquation>::new(),
        unknowns,
        states: Vec::new(),
        algebraic_variables,
        inputs,
        parameters,
    }
}

fn system_equation_residual_expression(
    system: &eng_compiler::SystemInfo,
    equation: &eng_compiler::EquationInfo,
) -> String {
    system
        .residuals
        .iter()
        .find(|residual| residual.name == equation.residual && residual.line == equation.line)
        .map(|residual| residual.expression.clone())
        .filter(|expression| !expression.trim().is_empty())
        .unwrap_or_else(|| format!("{} - ({})", equation.left, equation.right))
}

fn system_equation_dependencies(
    system: &eng_compiler::SystemInfo,
    equation: &eng_compiler::EquationInfo,
) -> Vec<String> {
    system
        .equation_ir
        .iter()
        .find(|ir| ir.residual == equation.residual && ir.line == equation.line)
        .map(|ir| {
            ir.dependencies
                .iter()
                .map(|dependency| dependency.name.clone())
                .collect::<Vec<_>>()
        })
        .filter(|dependencies| !dependencies.is_empty())
        .unwrap_or_else(|| {
            let expression = format!("{} {}", equation.left, equation.right);
            system
                .variables
                .iter()
                .filter(|variable| expression_contains_identifier(&expression, &variable.name))
                .map(|variable| variable.name.clone())
                .collect::<Vec<_>>()
        })
}
fn solver_equation_assembly_from_component_info(
    report: &CheckReport,
    assembly: &eng_compiler::ComponentAssemblyInfo,
) -> EquationAssembly {
    let components = report
        .semantic_program
        .assembly_components()
        .iter()
        .map(|component| ComponentInstance {
            name: component.name.clone(),
            component_type: "component".to_owned(),
            ports: component
                .ports
                .iter()
                .map(|port| PortInstance {
                    name: port.name.clone(),
                    component: component.name.clone(),
                    domain: port.domain.clone(),
                    medium: port.type_arguments.first().cloned(),
                })
                .collect(),
        })
        .collect::<Vec<_>>();
    let ports = components
        .iter()
        .flat_map(|component| component.ports.iter().cloned())
        .collect::<Vec<_>>();
    let connections = report
        .semantic_program
        .connections
        .iter()
        .map(|connection| ConnectionEdge {
            from: connection.left.clone(),
            to: connection.right.clone(),
            source_line: connection.line,
        })
        .collect::<Vec<_>>();
    let connection_sets = assembly
        .connection_sets
        .iter()
        .map(|connection_set| ConnectionSet {
            name: connection_set.name.clone(),
            domain: connection_set.domain.clone(),
            ports: connection_set.ports.clone(),
        })
        .collect::<Vec<_>>();
    let generated_equations = assembly
        .equations
        .iter()
        .map(|equation| GeneratedEquation {
            name: equation.name.clone(),
            kind: equation.kind.clone(),
            domain: equation.domain.clone(),
            expression: equation.expression.clone(),
            residual: equation.residual.clone(),
            rhs_value: equation
                .rhs
                .as_ref()
                .and_then(|rhs| component_equation_rhs_value(report, assembly, equation, rhs)),
            dependencies: equation.dependencies.clone(),
            source: if equation.kind == "component_boundary" {
                "component_local_expression".to_owned()
            } else if equation.kind == "component_equation" {
                "component_local_equation".to_owned()
            } else {
                "component_connection".to_owned()
            },
            reason: equation.reason.clone(),
            source_line: Some(equation.line),
            status: equation.status.clone(),
        })
        .collect::<Vec<_>>();
    let variables = assembly
        .variables
        .iter()
        .map(|variable| {
            let (quantity_kind, unit) = assembly_variable_quantity_unit(report, variable);
            let value = assembly_variable_value(report, variable, &unit);
            UnknownVariable {
                name: variable.name.clone(),
                role: variable.role.clone(),
                quantity_kind,
                unit,
                source: variable.source.clone(),
                status: variable.status.clone(),
                value,
            }
        })
        .collect::<Vec<_>>();
    let unknowns = variables
        .iter()
        .filter(|variable| variable.role == "state" || variable.role == "algebraic")
        .cloned()
        .collect::<Vec<_>>();
    let states = variables
        .iter()
        .filter(|variable| variable.role == "state")
        .cloned()
        .collect::<Vec<_>>();
    let algebraic_variables = variables
        .iter()
        .filter(|variable| variable.role == "algebraic")
        .cloned()
        .collect::<Vec<_>>();
    let inputs = variables
        .iter()
        .filter(|variable| variable.role == "input")
        .cloned()
        .collect::<Vec<_>>();
    let parameters = variables
        .iter()
        .filter(|variable| variable.role == "parameter")
        .cloned()
        .collect::<Vec<_>>();

    EquationAssembly {
        name: assembly.name.clone(),
        components,
        ports,
        connections,
        connection_sets,
        generated_equations,
        component_equations: Vec::<ComponentEquation>::new(),
        unknowns,
        states,
        algebraic_variables,
        inputs,
        parameters,
    }
}

fn component_equation_rhs_value(
    report: &CheckReport,
    assembly: &eng_compiler::ComponentAssemblyInfo,
    equation: &eng_compiler::ComponentAssemblyEquationInfo,
    rhs: &str,
) -> Option<f64> {
    let dependency = equation.dependencies.first()?;
    let variable = assembly
        .variables
        .iter()
        .find(|variable| variable.name == *dependency)?;
    let (_quantity_kind, display_unit) = assembly_variable_quantity_unit(report, variable);
    let (value, unit) = parse_numeric_value_with_optional_unit(rhs)?;
    let source_unit = unit.as_deref().unwrap_or(display_unit.as_str());
    Some(convert_display_value(value, source_unit, &display_unit))
}

fn parse_numeric_value_with_optional_unit(value: &str) -> Option<(f64, Option<String>)> {
    let mut parts = value.split_whitespace();
    let number = parts.next()?.parse::<f64>().ok()?;
    let unit = parts.next().map(str::to_owned);
    Some((number, unit))
}

fn assembly_variable_value(
    report: &CheckReport,
    variable: &eng_compiler::ComponentAssemblyVariableInfo,
    display_unit: &str,
) -> Option<f64> {
    if variable.role != "parameter" && variable.role != "input" {
        return None;
    }
    let (component_name, local_name) = variable.name.split_once('.')?;
    let value = report
        .semantic_program
        .assembly_components()
        .iter()
        .find(|component| component.name == component_name)
        .and_then(|component| match variable.role.as_str() {
            "parameter" => component
                .parameters
                .iter()
                .find(|parameter| parameter.name == local_name)
                .and_then(|parameter| parameter.value.as_deref()),
            "input" => component
                .inputs
                .iter()
                .find(|input| input.name == local_name)
                .and_then(|input| input.value.as_deref()),
            _ => None,
        })?;
    let (value, unit) = parse_numeric_value_with_optional_unit(value)?;
    let source_unit = unit.as_deref().unwrap_or(display_unit);
    Some(convert_display_value(value, source_unit, display_unit))
}

fn assembly_variable_quantity_unit(
    report: &CheckReport,
    variable: &eng_compiler::ComponentAssemblyVariableInfo,
) -> (String, String) {
    if variable.role == "parameter" || variable.role == "input" {
        if let Some((component_name, local_name)) = variable.name.split_once('.') {
            if let Some(parameter) = report
                .semantic_program
                .assembly_components()
                .iter()
                .find(|component| component.name == component_name)
                .and_then(|component| match variable.role.as_str() {
                    "parameter" => component
                        .parameters
                        .iter()
                        .find(|parameter| parameter.name == local_name),
                    "input" => component
                        .inputs
                        .iter()
                        .find(|input| input.name == local_name),
                    _ => None,
                })
            {
                return (
                    parameter.quantity_kind.clone(),
                    parameter.display_unit.clone(),
                );
            }
        }
    }
    let Some((domain_name, variable_name)) = variable.source.split_once('.') else {
        return ("unknown".to_owned(), "1".to_owned());
    };
    report
        .semantic_program
        .domains
        .iter()
        .find(|domain| domain.name == domain_name)
        .and_then(|domain| {
            domain
                .variables
                .iter()
                .find(|domain_variable| domain_variable.name == variable_name)
        })
        .map(|domain_variable| {
            (
                domain_variable.quantity_kind.clone(),
                domain_variable.display_unit.clone(),
            )
        })
        .unwrap_or_else(|| ("unknown".to_owned(), "1".to_owned()))
}

#[derive(Clone, Debug, PartialEq)]
struct SimulateRequest {
    binding: String,
    options: Vec<eng_compiler::WithOptionInfo>,
}

fn simulate_requests(report: &CheckReport, system_name: &str) -> Vec<SimulateRequest> {
    report
        .inferred_declarations
        .iter()
        .filter_map(|declaration| {
            let expression = declaration.expression.trim();
            let requested_system = expression.strip_prefix("simulate ")?.trim();
            if requested_system != system_name {
                return None;
            }
            let options = report
                .semantic_program
                .with_blocks
                .iter()
                .find(|block| block.owner_line == Some(declaration.line))
                .map(|block| block.options.clone())
                .unwrap_or_default();
            Some(SimulateRequest {
                binding: declaration.name.clone(),
                options,
            })
        })
        .collect()
}

fn materialize_state_space_solutions(
    report: &CheckReport,
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    options: &[eng_compiler::WithOptionInfo],
    series: &[RuntimeTimeSeries],
) -> Option<Vec<RuntimeSystemSolution>> {
    let state_vector = report
        .semantic_program
        .state_space_vectors
        .iter()
        .find(|vector| vector.system == system.name && vector.role == "states")?;
    let input_vector = report
        .semantic_program
        .state_space_vectors
        .iter()
        .find(|vector| vector.system == system.name && vector.role == "inputs")?;
    let output_vector = report
        .semantic_program
        .state_space_vectors
        .iter()
        .find(|vector| vector.system == system.name && vector.role == "outputs");
    let states = state_vector
        .members
        .iter()
        .map(|name| {
            system
                .variables
                .iter()
                .find(|variable| variable.name == *name && variable.role == "state")
        })
        .collect::<Option<Vec<_>>>()?;
    let inputs = input_vector
        .members
        .iter()
        .map(|name| {
            system
                .variables
                .iter()
                .find(|variable| variable.name == *name && variable.role == "input")
        })
        .collect::<Option<Vec<_>>>()?;
    let operator_a = report
        .semantic_program
        .linear_operators
        .iter()
        .find(|operator| {
            operator.system == system.name
                && operator.from == "StateVector"
                && operator.to == "Derivative[StateVector]"
                && operator.status == "shape_checked"
        })?;
    let operator_b = report
        .semantic_program
        .linear_operators
        .iter()
        .find(|operator| {
            operator.system == system.name
                && operator.from == "InputVector"
                && operator.to == "Derivative[StateVector]"
                && operator.status == "shape_checked"
        })?;
    let matrix_a = operator_a.canonical_matrix.clone()?;
    let matrix_b = operator_b.canonical_matrix.clone()?;
    if matrix_a.len() != states.len()
        || matrix_a.iter().any(|row| row.len() != states.len())
        || matrix_b.len() != states.len()
        || matrix_b.iter().any(|row| row.len() != inputs.len())
    {
        return None;
    }

    let (input_series, input_overrides) = simulation_input_sources(&inputs, options, series);
    let initial_state = states
        .iter()
        .map(|state| canonical_variable_value(state))
        .collect::<Option<Vec<_>>>()?;
    let solver_input_values = simulation_input_values(
        &inputs,
        &input_series,
        &input_overrides,
        0.0,
        "E-SIM-MISSING-INPUT",
        "state-space solver",
    )
    .ok()?;
    let time_step_s = option_value(options, "timestep")
        .and_then(parse_duration_seconds)
        .unwrap_or(300.0);
    let series_duration_s = input_series
        .iter()
        .filter_map(|series| {
            series
                .and_then(|series| series.points.last())
                .map(|point| point.x)
                .filter(|duration| *duration > 0.0)
        })
        .reduce(f64::min);
    let duration_s = option_value(options, "duration")
        .and_then(parse_duration_seconds)
        .or(series_duration_s)
        .unwrap_or(3600.0);
    let time_grid = TimeGrid::fixed_step(duration_s, time_step_s).ok()?;
    let solver_name = option_value(options, "solver")
        .map(str::trim)
        .unwrap_or("fixed_step");
    let fixed_step_method = FixedStepMethod::from_solver_name(Some(solver_name));
    let is_discrete_state_space = system
        .equations
        .iter()
        .any(|equation| equation.left.trim().starts_with("next("));
    if is_discrete_state_space && solver_name == "adaptive_heun" {
        return None;
    }
    let use_adaptive_heun = solver_name == "adaptive_heun";
    let adaptive_options =
        use_adaptive_heun.then(|| adaptive_heun_options_from_simulation(options, time_step_s));
    let solver_method = if is_discrete_state_space {
        "state_space_discrete_fixed_step".to_owned()
    } else if use_adaptive_heun {
        "adaptive_heun".to_owned()
    } else {
        fixed_step_method.method_name("state_space")
    };
    let solver_options = adaptive_options
        .as_ref()
        .map(|options| SolverOptions {
            method: solver_method.clone(),
            timestep_s: time_step_s,
            tolerance: options.tolerance,
            max_iterations: options.max_steps,
        })
        .unwrap_or_else(|| SolverOptions::fixed_step(solver_method, time_step_s));
    let output_members = output_vector
        .map(|vector| vector.members.clone())
        .unwrap_or_else(|| state_vector.members.clone());
    let output_variables = output_members
        .iter()
        .map(|member| {
            system.variables.iter().find(|variable| {
                variable.name == *member && matches!(variable.role.as_str(), "state" | "output")
            })
        })
        .collect::<Option<Vec<_>>>()?;
    let outputs = output_variables
        .iter()
        .copied()
        .filter(|variable| variable.role == "output")
        .collect::<Vec<_>>();
    let parameters = if outputs.is_empty() {
        Vec::new()
    } else {
        system
            .variables
            .iter()
            .filter(|variable| variable.role == "parameter")
            .collect::<Vec<_>>()
    };
    let state_symbols = states
        .iter()
        .map(|state| {
            RhsStateInfo::new(
                state.name.clone(),
                state.quantity_kind.clone(),
                state.canonical_unit.clone(),
            )
        })
        .collect::<Vec<_>>();
    let input_symbols = inputs
        .iter()
        .map(|input| {
            RhsSymbolInfo::new(
                input.name.clone(),
                system_variable_value_quantity(input),
                input.canonical_unit.clone(),
            )
        })
        .collect::<Vec<_>>();
    let parameter_symbols = parameters
        .iter()
        .map(|parameter| {
            RhsSymbolInfo::new(
                parameter.name.clone(),
                parameter.quantity_kind.clone(),
                parameter.canonical_unit.clone(),
            )
        })
        .collect::<Vec<_>>();
    let solver_plan = SolverPlan::new(
        system.name.clone(),
        SimulationPlan {
            inputs: input_vector.members.clone(),
            outputs: output_members.clone(),
            states: state_vector.members.clone(),
            parameters: parameters
                .iter()
                .map(|parameter| parameter.name.clone())
                .collect(),
        },
        solver_options,
    );
    let solver_input = SolverInput {
        plan: solver_plan,
        time_grid,
        state_layout: StateLayout::new(
            states
                .iter()
                .enumerate()
                .map(|(index, state)| {
                    LayoutEntry::new(
                        index,
                        state.name.clone(),
                        state.quantity_kind.clone(),
                        state.canonical_unit.clone(),
                        state.display_unit.clone(),
                    )
                })
                .collect(),
        ),
        input_layout: InputLayout {
            entries: inputs
                .iter()
                .enumerate()
                .map(|(index, input)| {
                    LayoutEntry::new(
                        index,
                        input.name.clone(),
                        system_variable_value_quantity(input),
                        input.canonical_unit.clone(),
                        input.display_unit.clone(),
                    )
                })
                .collect(),
        },
        parameter_layout: ParameterLayout::new(
            parameters
                .iter()
                .enumerate()
                .map(|(index, parameter)| {
                    LayoutEntry::new(
                        index,
                        parameter.name.clone(),
                        parameter.quantity_kind.clone(),
                        parameter.canonical_unit.clone(),
                        parameter.display_unit.clone(),
                    )
                })
                .collect(),
        ),
        output_layout: OutputLayout {
            entries: output_variables
                .iter()
                .enumerate()
                .map(|(index, variable)| {
                    LayoutEntry::new(
                        index,
                        variable.name.clone(),
                        system_variable_value_quantity(variable),
                        variable.canonical_unit.clone(),
                        variable.display_unit.clone(),
                    )
                })
                .collect(),
        },
        initial_state,
        inputs: inputs
            .iter()
            .zip(solver_input_values.iter().copied())
            .map(|(input, value)| {
                SolverScalar::new(
                    input.name.clone(),
                    system_variable_value_quantity(input),
                    input.canonical_unit.clone(),
                    value,
                )
            })
            .collect(),
        parameters: simulation_parameter_scalars(&parameters, options)?,
    };
    let mut source_equations = state_space_system_equation_metadata(
        system,
        &states,
        &inputs,
        operator_a,
        operator_b,
        &[],
        is_discrete_state_space,
    );
    let output_expressions = match system_output_expressions(
        system,
        &outputs,
        &state_symbols,
        &input_symbols,
        &parameter_symbols,
    ) {
        Ok(expressions) => expressions,
        Err(failure) => {
            return failed_system_runtime_solutions_with_source_equations(
                system,
                binding,
                &states,
                &solver_input,
                &failure,
                "recognized state-space output declarations, but output evaluator creation failed",
                &source_equations,
            );
        }
    };
    source_equations = state_space_system_equation_metadata(
        system,
        &states,
        &inputs,
        operator_a,
        operator_b,
        &output_expressions,
        is_discrete_state_space,
    );
    let parameter_values = solver_input
        .parameters
        .iter()
        .map(|parameter| parameter.value)
        .collect::<Vec<_>>();
    if is_discrete_state_space {
        let mut solver_result = match solve_discrete_state_space(
            &solver_input,
            &matrix_a,
            &matrix_b,
            |sample_time_s| {
                simulation_input_values(
                    &inputs,
                    &input_series,
                    &input_overrides,
                    sample_time_s,
                    "E-SIM-MISSING-INPUT",
                    "discrete state-space solver",
                )
            },
        ) {
            Ok(result) => result,
            Err(failure) => {
                let reason = "recognized discrete-time state-space A/B operators, but solver evaluation failed";
                return failed_system_runtime_solutions_with_source_equations(
                    system,
                    binding,
                    &states,
                    &solver_input,
                    &failure,
                    reason,
                    &source_equations,
                );
            }
        };
        if let Err(failure) = append_system_output_trajectories(
            &mut solver_result,
            &output_expressions,
            &inputs,
            &input_series,
            &input_overrides,
            &parameters,
            &parameter_values,
        ) {
            let reason =
                "recognized discrete-time state-space A/B operators, but output evaluation failed";
            return failed_system_runtime_solutions_with_source_equations(
                system,
                binding,
                &states,
                &solver_input,
                &failure,
                reason,
                &source_equations,
            );
        }
        let reason = if input_series.iter().any(Option::is_some) {
            "recognized discrete-time state-space A/B operators and executed state update with TimeSeries input materialization"
        } else {
            "recognized discrete-time state-space A/B operators and executed state update"
        };
        let mut solutions =
            system_runtime_solutions(system, binding, &output_variables, &solver_result, reason)?;
        attach_system_source_equations(&mut solutions, &source_equations);
        return Some(solutions);
    }
    if let Some(adaptive_options) = adaptive_options {
        let adaptive_result = match solve_adaptive_state_space(
            &solver_input,
            &matrix_a,
            &matrix_b,
            &adaptive_options,
            |sample_time_s| {
                simulation_input_values(
                    &inputs,
                    &input_series,
                    &input_overrides,
                    sample_time_s,
                    "E-SIM-MISSING-INPUT",
                    "adaptive state-space solver",
                )
            },
        ) {
            Ok(result) => result,
            Err(failure) => {
                let reason = "recognized continuous state-space A/B operators, but adaptive Heun solver evaluation failed";
                return failed_system_runtime_solutions_with_source_equations(
                    system,
                    binding,
                    &states,
                    &solver_input,
                    &failure,
                    reason,
                    &source_equations,
                );
            }
        };
        let reason = if input_series.iter().any(Option::is_some) {
            "recognized continuous state-space A/B operators and executed adaptive Heun trajectories with TimeSeries input materialization"
        } else {
            "recognized continuous state-space A/B operators and executed adaptive Heun trajectories"
        };
        let step_diagnostics = runtime_system_step_diagnostics(&adaptive_result.step_reports);
        let mut solver_result = adaptive_result.solver_result;
        if let Err(failure) = append_system_output_trajectories(
            &mut solver_result,
            &output_expressions,
            &inputs,
            &input_series,
            &input_overrides,
            &parameters,
            &parameter_values,
        ) {
            let reason =
                "recognized continuous state-space A/B operators, but output evaluation failed";
            return failed_system_runtime_solutions_with_source_equations(
                system,
                binding,
                &states,
                &solver_input,
                &failure,
                reason,
                &source_equations,
            );
        }
        let mut solutions =
            system_runtime_solutions(system, binding, &output_variables, &solver_result, reason)?;
        attach_system_source_equations(&mut solutions, &source_equations);
        attach_system_step_diagnostics(&mut solutions, &step_diagnostics);
        return Some(solutions);
    }
    let mut solver_result = match solve_continuous_state_space(
        fixed_step_method,
        &solver_input,
        &matrix_a,
        &matrix_b,
        |sample_time_s| {
            simulation_input_values(
                &inputs,
                &input_series,
                &input_overrides,
                sample_time_s,
                "E-SIM-MISSING-INPUT",
                "state-space solver",
            )
        },
    ) {
        Ok(result) => result,
        Err(failure) => {
            let reason = "recognized continuous state-space A/B operators, but fixed-step solver evaluation failed";
            return failed_system_runtime_solutions_with_source_equations(
                system,
                binding,
                &states,
                &solver_input,
                &failure,
                reason,
                &source_equations,
            );
        }
    };

    if let Err(failure) = append_system_output_trajectories(
        &mut solver_result,
        &output_expressions,
        &inputs,
        &input_series,
        &input_overrides,
        &parameters,
        &parameter_values,
    ) {
        let reason =
            "recognized continuous state-space A/B operators, but output evaluation failed";
        return failed_system_runtime_solutions_with_source_equations(
            system,
            binding,
            &states,
            &solver_input,
            &failure,
            reason,
            &source_equations,
        );
    }
    let reason = if input_series.iter().any(Option::is_some) {
        "recognized multi-state state-space A/B operators and executed fixed-step trajectories with TimeSeries input materialization"
    } else {
        "recognized multi-state state-space A/B operators and executed fixed-step trajectories"
    };
    let mut solutions =
        system_runtime_solutions(system, binding, &output_variables, &solver_result, reason)?;
    attach_system_source_equations(&mut solutions, &source_equations);
    Some(solutions)
}

fn state_space_system_equation_metadata(
    system: &eng_compiler::SystemInfo,
    states: &[&eng_compiler::SystemVariableInfo],
    inputs: &[&eng_compiler::SystemVariableInfo],
    operator_a: &eng_compiler::LinearOperatorInfo,
    operator_b: &eng_compiler::LinearOperatorInfo,
    outputs: &[ParsedSystemOutputExpression],
    is_discrete: bool,
) -> Vec<RuntimeSystemEquationMetadata> {
    let dynamic_equation = system.equations.iter().find(|equation| {
        let left = equation.left.trim();
        if is_discrete {
            left.starts_with("next(")
        } else {
            left.starts_with("der(")
        }
    });
    let mut metadata = vec![
        state_space_operator_equation_metadata(operator_a),
        state_space_operator_equation_metadata(operator_b),
    ];
    metadata.extend(states.iter().map(|state| {
        let left = if is_discrete {
            format!("next({})", state.name)
        } else {
            format!("der({})", state.name)
        };
        let right = state_space_row_expression(state, inputs, operator_a, operator_b);
        RuntimeSystemEquationMetadata {
            kind: if is_discrete {
                "state_space_update".to_owned()
            } else {
                "state_space_derivative".to_owned()
            },
            target: state.name.clone(),
            left: left.clone(),
            right: right.clone(),
            residual_expression: format!("{} - ({})", left, right),
            quantity_kind: if is_discrete {
                state.quantity_kind.clone()
            } else {
                format!("Derivative[{}]", state.quantity_kind)
            },
            display_unit: if is_discrete {
                state.display_unit.clone()
            } else {
                derivative_display_unit(&state.display_unit)
            },
            canonical_unit: if is_discrete {
                state.canonical_unit.clone()
            } else {
                derivative_display_unit(&state.canonical_unit)
            },
            source_line: dynamic_equation.map(|equation| equation.line),
        }
    }));
    metadata.extend(outputs.iter().map(|output| RuntimeSystemEquationMetadata {
        kind: "algebraic_output".to_owned(),
        target: output.name.clone(),
        left: output.left.clone(),
        right: output.source.clone(),
        residual_expression: format!("{} - ({})", output.left, output.source),
        quantity_kind: output.quantity_kind.clone(),
        display_unit: output.display_unit.clone(),
        canonical_unit: output.canonical_unit.clone(),
        source_line: output.source_line,
    }));
    metadata
}

fn state_space_operator_equation_metadata(
    operator: &eng_compiler::LinearOperatorInfo,
) -> RuntimeSystemEquationMetadata {
    let right = operator.expression.clone().unwrap_or_else(|| {
        format!(
            "{}x{} canonical matrix",
            operator.row_count, operator.column_count
        )
    });
    RuntimeSystemEquationMetadata {
        kind: "state_space_operator".to_owned(),
        target: operator.name.clone(),
        left: format!("operator {}", operator.name),
        right: right.clone(),
        residual_expression: format!("operator {} = {}", operator.name, right),
        quantity_kind: format!("LinearOperator[{} -> {}]", operator.from, operator.to),
        display_unit: "matrix".to_owned(),
        canonical_unit: "canonical_matrix".to_owned(),
        source_line: Some(operator.line),
    }
}

fn state_space_row_expression(
    state: &eng_compiler::SystemVariableInfo,
    inputs: &[&eng_compiler::SystemVariableInfo],
    operator_a: &eng_compiler::LinearOperatorInfo,
    operator_b: &eng_compiler::LinearOperatorInfo,
) -> String {
    let mut terms = operator_a
        .canonical_entries
        .iter()
        .filter(|entry| entry.row_member == state.name)
        .map(|entry| {
            format!(
                "{}[{},{}] * {}",
                operator_a.name, entry.row_member, entry.column_member, entry.column_member
            )
        })
        .collect::<Vec<_>>();
    let input_names = inputs
        .iter()
        .map(|input| input.name.as_str())
        .collect::<HashSet<_>>();
    terms.extend(
        operator_b
            .canonical_entries
            .iter()
            .filter(|entry| {
                entry.row_member == state.name && input_names.contains(entry.column_member.as_str())
            })
            .map(|entry| {
                format!(
                    "{}[{},{}] * {}",
                    operator_b.name, entry.row_member, entry.column_member, entry.column_member
                )
            }),
    );
    if terms.is_empty() {
        "0".to_owned()
    } else {
        terms.join(" + ")
    }
}

fn system_runtime_solutions(
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    variables: &[&eng_compiler::SystemVariableInfo],
    solver_result: &SolverResult,
    reason: &str,
) -> Option<Vec<RuntimeSystemSolution>> {
    let output_names = solver_result
        .output_layout
        .entries
        .iter()
        .map(|entry| entry.name.as_str())
        .collect::<Vec<_>>();
    let include_all_outputs = output_names.is_empty();
    let solutions = solver_result
        .output
        .state_trajectories
        .iter()
        .chain(solver_result.output.algebraic_trajectories.iter())
        .filter(|trajectory| {
            include_all_outputs || output_names.iter().any(|name| *name == trajectory.name)
        })
        .filter_map(|trajectory| {
            variables
                .iter()
                .find(|variable| variable.name == trajectory.name)
                .and_then(|variable| {
                    RuntimeSystemSolution::from_solver_trajectory(
                        system,
                        binding,
                        variable,
                        solver_result,
                        trajectory,
                        reason,
                    )
                })
        })
        .collect::<Vec<_>>();

    (!solutions.is_empty()).then_some(solutions)
}

fn failed_system_runtime_solutions(
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    states: &[&eng_compiler::SystemVariableInfo],
    solver_input: &SolverInput,
    failure: &SolverFailure,
    reason: &str,
) -> Option<Vec<RuntimeSystemSolution>> {
    let output_names = solver_input
        .output_layout
        .entries
        .iter()
        .map(|entry| entry.name.as_str())
        .collect::<Vec<_>>();
    let include_all_states = output_names.is_empty();
    let solutions = states
        .iter()
        .filter(|state| include_all_states || output_names.iter().any(|name| *name == state.name))
        .filter_map(|state| {
            RuntimeSystemSolution::failed_from_solver_failure(
                system,
                binding,
                state,
                solver_input,
                failure,
                reason,
            )
        })
        .collect::<Vec<_>>();

    (!solutions.is_empty()).then_some(solutions)
}

fn failed_system_runtime_solutions_with_source_equations(
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    states: &[&eng_compiler::SystemVariableInfo],
    solver_input: &SolverInput,
    failure: &SolverFailure,
    reason: &str,
    source_equations: &[RuntimeSystemEquationMetadata],
) -> Option<Vec<RuntimeSystemSolution>> {
    let mut solutions =
        failed_system_runtime_solutions(system, binding, states, solver_input, failure, reason)?;
    attach_system_source_equations(&mut solutions, source_equations);
    Some(solutions)
}

fn failed_system_runtime_solution_with_source_equations(
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    state: &eng_compiler::SystemVariableInfo,
    solver_input: &SolverInput,
    failure: &SolverFailure,
    reason: &str,
    source_equations: &[RuntimeSystemEquationMetadata],
) -> Option<RuntimeSystemSolution> {
    let mut solution = RuntimeSystemSolution::failed_from_solver_failure(
        system,
        binding,
        state,
        solver_input,
        failure,
        reason,
    )?;
    solution.source_equations = source_equations.to_vec();
    Some(solution)
}

fn runtime_system_step_diagnostics(
    reports: &[AdaptiveOdeStepReport],
) -> Vec<RuntimeSystemStepDiagnostic> {
    reports
        .iter()
        .map(|report| RuntimeSystemStepDiagnostic {
            output_index: report.output_index,
            start_time_s: report.start_time_s,
            end_time_s: report.end_time_s,
            dt_s: report.dt_s,
            error_norm: report.error_norm,
            status: report.status.clone(),
        })
        .collect()
}

fn attach_system_step_diagnostics(
    solutions: &mut [RuntimeSystemSolution],
    diagnostics: &[RuntimeSystemStepDiagnostic],
) {
    for solution in solutions {
        solution.step_diagnostics = diagnostics.to_vec();
    }
}

fn simulation_input_sources<'a>(
    inputs: &[&eng_compiler::SystemVariableInfo],
    options: &[eng_compiler::WithOptionInfo],
    series: &'a [RuntimeTimeSeries],
) -> (Vec<Option<&'a RuntimeTimeSeries>>, Vec<Option<f64>>) {
    let mut input_series = Vec::with_capacity(inputs.len());
    let mut scalar_overrides = Vec::with_capacity(inputs.len());
    for input in inputs {
        let raw_value = option_value(options, &input.name).map(str::trim);
        let source = raw_value.and_then(|name| series.iter().find(|series| series.name == name));
        let scalar_override = if source.is_none() {
            raw_value.and_then(|value| canonical_simulation_input_value(input, value))
        } else {
            None
        };
        input_series.push(source);
        scalar_overrides.push(scalar_override);
    }
    (input_series, scalar_overrides)
}

fn simulation_input_values(
    inputs: &[&eng_compiler::SystemVariableInfo],
    input_series: &[Option<&RuntimeTimeSeries>],
    scalar_overrides: &[Option<f64>],
    sample_time_s: f64,
    failure_code: &'static str,
    context: &str,
) -> Result<Vec<f64>, SolverFailure> {
    if inputs.len() != input_series.len() || inputs.len() != scalar_overrides.len() {
        return Err(SolverFailure::new(
            "E-SIM-INPUT-LAYOUT",
            format!("{context} input layout does not match input bindings"),
        ));
    }
    inputs
        .iter()
        .enumerate()
        .map(|(index, input)| {
            dynamic_input_value(
                input,
                input_series[index],
                scalar_overrides[index],
                sample_time_s,
            )
            .ok_or_else(|| {
                SolverFailure::new(
                    failure_code,
                    format!(
                        "{context} input `{}` cannot be evaluated at t={} s",
                        input.name, sample_time_s
                    ),
                )
            })
        })
        .collect()
}

fn dynamic_input_value(
    input: &eng_compiler::SystemVariableInfo,
    series: Option<&RuntimeTimeSeries>,
    scalar_override: Option<f64>,
    time_s: f64,
) -> Option<f64> {
    let quantity_kind = system_variable_value_quantity(input);
    if let Some(series) = series {
        let value = interpolate_series_value(series, time_s)?;
        return convert_to_canonical_unit(
            value,
            Some(&series.display_unit),
            &input.canonical_unit,
            &quantity_kind,
        )
        .ok();
    }
    scalar_override.or_else(|| canonical_variable_value(input))
}

fn materialize_source_ode_solutions(
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    options: &[eng_compiler::WithOptionInfo],
    series: &[RuntimeTimeSeries],
) -> Option<Vec<RuntimeSystemSolution>> {
    let states = system
        .variables
        .iter()
        .filter(|variable| variable.role == "state")
        .collect::<Vec<_>>();
    if states.is_empty() {
        return None;
    }
    let equations = source_ode_equations_for_states(system, &states)?;
    let solver_name = option_value(options, "solver")
        .map(str::trim)
        .unwrap_or("fixed_step");
    let use_adaptive_heun = solver_name == "adaptive_heun";
    let fixed_step_method = FixedStepMethod::from_solver_name(Some(solver_name));
    let time_step_s = option_value(options, "timestep")
        .and_then(parse_duration_seconds)
        .unwrap_or(300.0);
    let adaptive_options =
        use_adaptive_heun.then(|| adaptive_heun_options_from_simulation(options, time_step_s));
    let inputs = system
        .variables
        .iter()
        .filter(|variable| variable.role == "input")
        .collect::<Vec<_>>();
    let (input_series, input_overrides) = simulation_input_sources(&inputs, options, series);
    let series_duration_s = input_series
        .iter()
        .flatten()
        .filter_map(|series| series.points.last().map(|point| point.x))
        .filter(|duration| *duration > 0.0)
        .reduce(f64::max);
    let duration_s = option_value(options, "duration")
        .and_then(parse_duration_seconds)
        .or(series_duration_s)
        .unwrap_or(3600.0);
    let time_grid = TimeGrid::fixed_step(duration_s, time_step_s).ok()?;

    let parameters = system
        .variables
        .iter()
        .filter(|variable| variable.role == "parameter")
        .collect::<Vec<_>>();
    let outputs = system
        .variables
        .iter()
        .filter(|variable| variable.role == "output")
        .collect::<Vec<_>>();
    let output_variables = states
        .iter()
        .copied()
        .chain(outputs.iter().copied())
        .collect::<Vec<_>>();
    let state_symbols = states
        .iter()
        .map(|state| {
            RhsStateInfo::new(
                state.name.clone(),
                state.quantity_kind.clone(),
                state.canonical_unit.clone(),
            )
        })
        .collect::<Vec<_>>();
    let input_symbols = inputs
        .iter()
        .map(|input| {
            RhsSymbolInfo::new(
                input.name.clone(),
                system_variable_value_quantity(input),
                input.canonical_unit.clone(),
            )
        })
        .collect::<Vec<_>>();
    let parameter_symbols = parameters
        .iter()
        .map(|parameter| {
            RhsSymbolInfo::new(
                parameter.name.clone(),
                parameter.quantity_kind.clone(),
                parameter.canonical_unit.clone(),
            )
        })
        .collect::<Vec<_>>();
    let initial_state = states
        .iter()
        .map(|state| canonical_variable_value(state))
        .collect::<Option<Vec<_>>>()?;
    let solver_input_values = simulation_input_values(
        &inputs,
        &input_series,
        &input_overrides,
        0.0,
        "E-RHS-INPUT-VALUE",
        "source RHS",
    )
    .ok()?;
    let solver_inputs = inputs
        .iter()
        .zip(solver_input_values.iter().copied())
        .map(|(input, value)| {
            SolverScalar::new(
                input.name.clone(),
                system_variable_value_quantity(input),
                input.canonical_unit.clone(),
                value,
            )
        })
        .collect::<Vec<_>>();
    let solver_parameters = simulation_parameter_scalars(&parameters, options)?;

    let solver_options = adaptive_options
        .as_ref()
        .map(|options| SolverOptions {
            method: "adaptive_heun".to_owned(),
            timestep_s: time_step_s,
            tolerance: options.tolerance,
            max_iterations: options.max_steps,
        })
        .unwrap_or_else(|| {
            SolverOptions::fixed_step(fixed_step_method.method_name(""), time_step_s)
        });
    let solver_plan = SolverPlan::new(
        system.name.clone(),
        SimulationPlan {
            inputs: inputs.iter().map(|input| input.name.clone()).collect(),
            outputs: output_variables
                .iter()
                .map(|variable| variable.name.clone())
                .collect(),
            states: states.iter().map(|state| state.name.clone()).collect(),
            parameters: parameters
                .iter()
                .map(|parameter| parameter.name.clone())
                .collect(),
        },
        solver_options,
    );
    let solver_input = SolverInput {
        plan: solver_plan,
        time_grid,
        state_layout: StateLayout::new(
            states
                .iter()
                .enumerate()
                .map(|(index, state)| {
                    LayoutEntry::new(
                        index,
                        state.name.clone(),
                        state.quantity_kind.clone(),
                        state.canonical_unit.clone(),
                        state.display_unit.clone(),
                    )
                })
                .collect(),
        ),
        input_layout: InputLayout::new(
            inputs
                .iter()
                .enumerate()
                .map(|(index, input)| {
                    LayoutEntry::new(
                        index,
                        input.name.clone(),
                        system_variable_value_quantity(input),
                        input.canonical_unit.clone(),
                        input.display_unit.clone(),
                    )
                })
                .collect(),
        ),
        parameter_layout: ParameterLayout::new(
            parameters
                .iter()
                .enumerate()
                .map(|(index, parameter)| {
                    LayoutEntry::new(
                        index,
                        parameter.name.clone(),
                        parameter.quantity_kind.clone(),
                        parameter.canonical_unit.clone(),
                        parameter.display_unit.clone(),
                    )
                })
                .collect(),
        ),
        output_layout: OutputLayout::new(
            output_variables
                .iter()
                .enumerate()
                .map(|(index, variable)| {
                    LayoutEntry::new(
                        index,
                        variable.name.clone(),
                        system_variable_value_quantity(variable),
                        variable.canonical_unit.clone(),
                        variable.display_unit.clone(),
                    )
                })
                .collect(),
        ),
        initial_state,
        inputs: solver_inputs,
        parameters: solver_parameters,
    };

    let mut source_equations = source_ode_system_equation_metadata(&equations, &[]);
    let output_expressions = match system_output_expressions(
        system,
        &outputs,
        &state_symbols,
        &input_symbols,
        &parameter_symbols,
    ) {
        Ok(expressions) => expressions,
        Err(failure) => {
            return failed_system_runtime_solutions_with_source_equations(
                system,
                binding,
                &states,
                &solver_input,
                &failure,
                "recognized system output declarations, but output evaluator creation failed",
                &source_equations,
            );
        }
    };
    source_equations = source_ode_system_equation_metadata(&equations, &output_expressions);

    let evaluator = match SourceRhsEvaluator::new_with_symbols(
        state_symbols.clone(),
        input_symbols.clone(),
        parameter_symbols.clone(),
        equations,
    ) {
        Ok(evaluator) => evaluator,
        Err(failure) => {
            return failed_system_runtime_solutions_with_source_equations(
                system,
                binding,
                &states,
                &solver_input,
                &failure,
                "recognized source derivative equations, but RHS evaluator creation failed",
                &source_equations,
            );
        }
    };
    let parameter_values = solver_input
        .parameters
        .iter()
        .map(|parameter| parameter.value)
        .collect::<Vec<_>>();
    let mut rhs = |sample: crate::solver::RhsSample<'_>| {
        let input_values = simulation_input_values(
            &inputs,
            &input_series,
            &input_overrides,
            sample.time_s,
            "E-RHS-INPUT-VALUE",
            "source RHS",
        )?;
        let output = evaluator.evaluate(&RhsInput {
            t: sample.time_s,
            x: sample.state.to_vec(),
            u: input_values,
            p: parameter_values.clone(),
        })?;
        Ok(output.derivatives)
    };

    let (mut solver_result, step_diagnostics) = if let Some(adaptive_options) = adaptive_options {
        let adaptive_result = match solve_adaptive_heun_ode(
            &solver_input,
            &adaptive_options,
            &mut rhs,
        ) {
            Ok(result) => result,
            Err(failure) => {
                return failed_system_runtime_solutions_with_source_equations(
                    system,
                    binding,
                    &states,
                    &solver_input,
                    &failure,
                    "recognized source derivative equations, but adaptive Heun solver evaluation failed",
                    &source_equations,
                );
            }
        };
        (
            adaptive_result.solver_result,
            runtime_system_step_diagnostics(&adaptive_result.step_reports),
        )
    } else {
        let solver_result = match solve_fixed_step_ode(fixed_step_method, &solver_input, &mut rhs) {
            Ok(result) => result,
            Err(failure) => {
                return failed_system_runtime_solutions_with_source_equations(
                    system,
                    binding,
                    &states,
                    &solver_input,
                    &failure,
                    "recognized source derivative equations, but fixed-step solver evaluation failed",
                    &source_equations,
                );
            }
        };
        (solver_result, Vec::new())
    };

    if let Err(failure) = append_system_output_trajectories(
        &mut solver_result,
        &output_expressions,
        &inputs,
        &input_series,
        &input_overrides,
        &parameters,
        &parameter_values,
    ) {
        return failed_system_runtime_solutions_with_source_equations(
            system,
            binding,
            &states,
            &solver_input,
            &failure,
            "recognized system output declarations, but output evaluation failed",
            &source_equations,
        );
    }

    let reason = if use_adaptive_heun {
        if input_series.iter().any(Option::is_some) {
            "recognized source derivative equations and executed adaptive Heun RHS with TimeSeries input materialization"
        } else {
            "recognized source derivative equations and executed adaptive Heun RHS"
        }
    } else if input_series.iter().any(Option::is_some) {
        "recognized source derivative equations and executed fixed-step RHS with TimeSeries input materialization"
    } else {
        "recognized source derivative equations and executed fixed-step RHS"
    };
    let mut solutions =
        system_runtime_solutions(system, binding, &output_variables, &solver_result, reason)?;
    attach_system_source_equations(&mut solutions, &source_equations);
    if use_adaptive_heun {
        attach_system_step_diagnostics(&mut solutions, &step_diagnostics);
    }
    Some(solutions)
}

fn source_ode_system_equation_metadata(
    derivative_equations: &[SourceRhsEquation],
    outputs: &[ParsedSystemOutputExpression],
) -> Vec<RuntimeSystemEquationMetadata> {
    let mut metadata = derivative_equations
        .iter()
        .map(|equation| RuntimeSystemEquationMetadata {
            kind: "derivative".to_owned(),
            target: equation.state.clone(),
            left: equation.left.clone(),
            right: equation.right.clone(),
            residual_expression: format!("{} - ({})", equation.left, equation.right),
            quantity_kind: equation.quantity_kind.clone(),
            display_unit: equation.display_unit.clone(),
            canonical_unit: equation.canonical_unit.clone(),
            source_line: equation.source_line,
        })
        .collect::<Vec<_>>();
    metadata.extend(outputs.iter().map(|output| RuntimeSystemEquationMetadata {
        kind: "algebraic_output".to_owned(),
        target: output.name.clone(),
        left: output.left.clone(),
        right: output.source.clone(),
        residual_expression: format!("{} - ({})", output.left, output.source),
        quantity_kind: output.quantity_kind.clone(),
        display_unit: output.display_unit.clone(),
        canonical_unit: output.canonical_unit.clone(),
        source_line: output.source_line,
    }));
    metadata
}

fn first_order_thermal_source_equations(
    equation: &eng_compiler::EquationInfo,
    state: &eng_compiler::SystemVariableInfo,
    residual_variable: &eng_compiler::SystemVariableInfo,
) -> Vec<RuntimeSystemEquationMetadata> {
    vec![RuntimeSystemEquationMetadata {
        kind: "first_order_thermal_balance".to_owned(),
        target: state.name.clone(),
        left: equation.left.clone(),
        right: equation.right.clone(),
        residual_expression: if equation.residual.trim().is_empty() {
            format!("{} - ({})", equation.left, equation.right)
        } else {
            equation.residual.clone()
        },
        quantity_kind: residual_variable.quantity_kind.clone(),
        display_unit: residual_variable.display_unit.clone(),
        canonical_unit: residual_variable.canonical_unit.clone(),
        source_line: Some(equation.line),
    }]
}

fn attach_system_source_equations(
    solutions: &mut [RuntimeSystemSolution],
    source_equations: &[RuntimeSystemEquationMetadata],
) {
    for solution in solutions {
        solution.source_equations = source_equations.to_vec();
    }
}

fn source_ode_equations_for_states(
    system: &eng_compiler::SystemInfo,
    states: &[&eng_compiler::SystemVariableInfo],
) -> Option<Vec<SourceRhsEquation>> {
    let mut equations = Vec::new();
    for state in states {
        let derivative = format!("der({})", state.name);
        let matches = system
            .equations
            .iter()
            .filter(|equation| equation.left.contains(&derivative))
            .collect::<Vec<_>>();
        if matches.len() != 1 {
            return None;
        }
        equations.push(
            SourceRhsEquation::new(
                state.name.clone(),
                matches[0].left.clone(),
                matches[0].right.clone(),
            )
            .with_metadata(
                Some(matches[0].line),
                format!("Derivative[{}]", state.quantity_kind),
                derivative_display_unit(&state.display_unit),
                derivative_display_unit(&state.canonical_unit),
            ),
        );
    }
    Some(equations)
}

#[derive(Clone, Debug, PartialEq)]
struct ParsedSystemOutputExpression {
    name: String,
    quantity_kind: String,
    display_unit: String,
    canonical_unit: String,
    left: String,
    source: String,
    source_line: Option<usize>,
    expression: ParsedArithmeticExpression,
    output_dependencies: Vec<String>,
}

#[derive(Clone, Debug, PartialEq)]
struct SystemOutputExpressionSource {
    left: String,
    right: String,
    line: Option<usize>,
}

fn system_output_expressions(
    system: &eng_compiler::SystemInfo,
    outputs: &[&eng_compiler::SystemVariableInfo],
    states: &[RhsStateInfo],
    inputs: &[RhsSymbolInfo],
    parameters: &[RhsSymbolInfo],
) -> Result<Vec<ParsedSystemOutputExpression>, SolverFailure> {
    if outputs.is_empty() {
        return Ok(Vec::new());
    }
    let mut symbols = source_rhs_parse_symbols(states, inputs, parameters);
    let mut symbol_metadata = source_rhs_symbol_metadata(states, inputs, parameters);
    let output_names = outputs
        .iter()
        .map(|output| output.name.clone())
        .collect::<HashSet<_>>();
    for output in outputs {
        symbols.insert(output.name.clone(), 0.0);
        symbol_metadata.insert(
            output.name.clone(),
            ArithmeticUnitMetadata {
                display_unit: output.display_unit.clone(),
                canonical_unit: output.canonical_unit.clone(),
                quantity_kind: system_variable_value_quantity(output),
            },
        );
    }

    let parsed = outputs
        .iter()
        .map(|output| {
            let source = system_output_expression_source(system, output)?;
            let expression = parse_source_rhs_expression(&source.right, &symbols, &symbol_metadata)
                .map_err(|failure| {
                    SolverFailure::new(
                        failure.code,
                        format!(
                            "{} while parsing system output `{}`",
                            failure.message, output.name
                        ),
                    )
                })?;
            let mut output_dependencies = expression
                .referenced_symbols()
                .into_iter()
                .filter(|symbol| output_names.contains(symbol))
                .collect::<Vec<_>>();
            output_dependencies.sort();
            output_dependencies.dedup();
            Ok(ParsedSystemOutputExpression {
                name: output.name.clone(),
                quantity_kind: system_variable_value_quantity(output),
                display_unit: output.display_unit.clone(),
                canonical_unit: output.canonical_unit.clone(),
                left: source.left,
                source: source.right,
                source_line: source.line,
                expression,
                output_dependencies,
            })
        })
        .collect::<Result<Vec<_>, SolverFailure>>()?;
    order_system_output_expressions(parsed)
}

fn order_system_output_expressions(
    mut outputs: Vec<ParsedSystemOutputExpression>,
) -> Result<Vec<ParsedSystemOutputExpression>, SolverFailure> {
    let mut ordered = Vec::with_capacity(outputs.len());
    let mut resolved = HashSet::new();
    while !outputs.is_empty() {
        let pending_before = outputs.len();
        let mut index = 0;
        while index < outputs.len() {
            if outputs[index]
                .output_dependencies
                .iter()
                .all(|dependency| resolved.contains(dependency))
            {
                let output = outputs.remove(index);
                resolved.insert(output.name.clone());
                ordered.push(output);
            } else {
                index += 1;
            }
        }
        if outputs.len() == pending_before {
            let unresolved = outputs
                .iter()
                .map(|output| {
                    format!(
                        "{} depends on [{}]",
                        output.name,
                        output.output_dependencies.join(", ")
                    )
                })
                .collect::<Vec<_>>()
                .join("; ");
            return Err(SolverFailure::new(
                "E-RHS-OUTPUT-ALGEBRAIC-LOOP",
                format!(
                    "system output algebraic dependency graph contains a cycle or unsupported dependency: {unresolved}"
                ),
            ));
        }
    }
    Ok(ordered)
}

fn system_output_expression_source(
    system: &eng_compiler::SystemInfo,
    output: &eng_compiler::SystemVariableInfo,
) -> Result<SystemOutputExpressionSource, SolverFailure> {
    let matches = system
        .equations
        .iter()
        .filter(|equation| equation.left.trim() == output.name)
        .collect::<Vec<_>>();
    if matches.len() > 1 {
        return Err(SolverFailure::new(
            "E-RHS-OUTPUT-EXPRESSION",
            format!(
                "system output `{}` has multiple algebraic equations",
                output.name
            ),
        ));
    }
    if let Some(equation) = matches.first() {
        return Ok(SystemOutputExpressionSource {
            left: equation.left.clone(),
            right: equation.right.clone(),
            line: Some(equation.line),
        });
    }
    output.initial_value.clone().map(|right| SystemOutputExpressionSource {
        left: output.name.clone(),
        right,
        line: Some(output.line),
    }).ok_or_else(|| {
        SolverFailure::new(
            "E-RHS-OUTPUT-EXPRESSION",
            format!(
                "system output `{}` requires either `output ... = expression` or an equation `{} eq expression`",
                output.name, output.name
            ),
        )
    })
}

fn append_system_output_trajectories(
    solver_result: &mut SolverResult,
    outputs: &[ParsedSystemOutputExpression],
    inputs: &[&eng_compiler::SystemVariableInfo],
    input_series: &[Option<&RuntimeTimeSeries>],
    input_overrides: &[Option<f64>],
    parameters: &[&eng_compiler::SystemVariableInfo],
    parameter_values: &[f64],
) -> Result<(), SolverFailure> {
    if outputs.is_empty() {
        return Ok(());
    }
    let mut trajectories = system_output_trajectories(
        solver_result,
        outputs,
        inputs,
        input_series,
        input_overrides,
        parameters,
        parameter_values,
    )?;
    solver_result
        .output
        .algebraic_trajectories
        .append(&mut trajectories);
    Ok(())
}
fn system_output_trajectories(
    solver_result: &SolverResult,
    outputs: &[ParsedSystemOutputExpression],
    inputs: &[&eng_compiler::SystemVariableInfo],
    input_series: &[Option<&RuntimeTimeSeries>],
    input_overrides: &[Option<f64>],
    parameters: &[&eng_compiler::SystemVariableInfo],
    parameter_values: &[f64],
) -> Result<Vec<StateTrajectory>, SolverFailure> {
    if outputs.is_empty() {
        return Ok(Vec::new());
    }
    if inputs.len() != input_series.len() || inputs.len() != input_overrides.len() {
        return Err(SolverFailure::new(
            "E-RHS-OUTPUT-INPUT-LAYOUT",
            "system output input layout does not match input bindings",
        ));
    }
    if parameters.len() != parameter_values.len() {
        return Err(SolverFailure::new(
            "E-RHS-OUTPUT-PARAMETER-LAYOUT",
            "system output parameter layout does not match parameter values",
        ));
    }
    let sample_count = solver_result
        .output
        .state_trajectories
        .first()
        .map(|trajectory| trajectory.values.len())
        .unwrap_or(0);
    let mut values_by_output = outputs
        .iter()
        .map(|_| Vec::with_capacity(sample_count))
        .collect::<Vec<_>>();
    for sample_index in 0..sample_count {
        let mut symbols = system_output_sample_symbols(
            solver_result,
            inputs,
            input_series,
            input_overrides,
            parameters,
            parameter_values,
            sample_index,
        )?;
        for (output_index, output) in outputs.iter().enumerate() {
            let value = output.expression.evaluate(&symbols).map_err(|failure| {
                SolverFailure::new(
                    failure.code,
                    format!(
                        "{} while evaluating system output `{}` expression `{}`",
                        failure.message, output.name, output.source
                    ),
                )
            })?;
            if !value.is_finite() {
                return Err(SolverFailure::new(
                    "E-RHS-OUTPUT-FINITE",
                    format!(
                        "system output `{}` must evaluate to a finite value",
                        output.name
                    ),
                ));
            }
            symbols.insert(output.name.clone(), value);
            values_by_output[output_index].push(value);
        }
    }
    Ok(outputs
        .iter()
        .zip(values_by_output)
        .map(|(output, values)| StateTrajectory {
            name: output.name.clone(),
            quantity_kind: output.quantity_kind.clone(),
            canonical_unit: output.canonical_unit.clone(),
            values,
        })
        .collect())
}

fn system_output_sample_symbols(
    solver_result: &SolverResult,
    inputs: &[&eng_compiler::SystemVariableInfo],
    input_series: &[Option<&RuntimeTimeSeries>],
    input_overrides: &[Option<f64>],
    parameters: &[&eng_compiler::SystemVariableInfo],
    parameter_values: &[f64],
    sample_index: usize,
) -> Result<HashMap<String, f64>, SolverFailure> {
    let time_s = solver_result.time_grid.step_time_s(sample_index);
    let mut symbols = HashMap::new();
    symbols.insert("t".to_owned(), time_s);
    symbols.insert("time".to_owned(), time_s);
    for trajectory in &solver_result.output.state_trajectories {
        let value = trajectory
            .values
            .get(sample_index)
            .copied()
            .ok_or_else(|| {
                SolverFailure::new(
                    "E-RHS-OUTPUT-STATE-SAMPLE",
                    format!(
                        "system output sample {} is missing state `{}`",
                        sample_index, trajectory.name
                    ),
                )
            })?;
        symbols.insert(trajectory.name.clone(), value);
    }
    for (index, (input, source)) in inputs.iter().zip(input_series.iter().copied()).enumerate() {
        let value = dynamic_input_value(input, source, input_overrides[index], time_s).ok_or_else(
            || {
                SolverFailure::new(
                    "E-RHS-OUTPUT-INPUT-VALUE",
                    format!(
                        "system output input `{}` cannot be evaluated at t={} s",
                        input.name, time_s
                    ),
                )
            },
        )?;
        symbols.insert(input.name.clone(), value);
    }
    for (parameter, value) in parameters.iter().zip(parameter_values.iter().copied()) {
        symbols.insert(parameter.name.clone(), value);
    }
    Ok(symbols)
}
fn materialize_first_order_thermal_solution(
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    options: &[eng_compiler::WithOptionInfo],
    series: &[RuntimeTimeSeries],
) -> Option<RuntimeSystemSolution> {
    let equation = system.equations.first()?;
    let states = system
        .variables
        .iter()
        .filter(|variable| variable.role == "state")
        .collect::<Vec<_>>();
    if states.len() != 1 || states[0].quantity_kind != "AbsoluteTemperature" {
        return None;
    }
    let state = states[0];
    let heat_capacity = system.variables.iter().find(|variable| {
        variable.role == "parameter" && variable.quantity_kind == "HeatCapacity"
    })?;
    let conductance = system
        .variables
        .iter()
        .find(|variable| variable.role == "parameter" && variable.quantity_kind == "Conductance")?;
    let outdoor_temperature = system.variables.iter().find(|variable| {
        variable.role == "input"
            && system_variable_matches_quantity(variable, "AbsoluteTemperature")
    })?;
    let internal_heat = system
        .variables
        .iter()
        .find(|variable| variable.role == "input" && variable.quantity_kind == "HeatRate")?;

    if !equation.left.contains(&heat_capacity.name)
        || !equation.left.contains(&format!("der({})", state.name))
        || !equation.right.contains(&conductance.name)
        || !equation.right.contains(&outdoor_temperature.name)
        || !equation.right.contains(&state.name)
        || !equation.right.contains(&internal_heat.name)
    {
        return None;
    }

    let source_equations = first_order_thermal_source_equations(equation, state, internal_heat);
    let heat_capacity_parameter = simulation_parameter_scalar(heat_capacity, options)?;
    let conductance_parameter = simulation_parameter_scalar(conductance, options)?;
    let heat_capacity_j_per_k = heat_capacity_parameter.value;
    let conductance_w_per_k = conductance_parameter.value;
    let thermal_inputs = vec![outdoor_temperature, internal_heat];
    let (thermal_input_series, thermal_input_overrides) =
        simulation_input_sources(&thermal_inputs, options, series);
    let outdoor_series = thermal_input_series[0];
    let outdoor_override = thermal_input_overrides[0];
    let internal_heat_series = thermal_input_series[1];
    let internal_heat_override = thermal_input_overrides[1];
    let outdoor_quantity_kind = system_variable_value_quantity(outdoor_temperature);
    let outdoor_temperature_k =
        dynamic_input_value(outdoor_temperature, outdoor_series, outdoor_override, 0.0)?;
    let internal_heat_w = dynamic_input_value(
        internal_heat,
        internal_heat_series,
        internal_heat_override,
        0.0,
    )?;
    let initial_temperature_k = canonical_variable_value(state)?;

    let time_step_s = option_value(options, "timestep")
        .and_then(parse_duration_seconds)
        .unwrap_or(300.0);
    let series_duration_s = outdoor_series
        .and_then(|series| series.points.last().map(|point| point.x))
        .filter(|duration| *duration > 0.0);
    let duration_s = option_value(options, "duration")
        .and_then(parse_duration_seconds)
        .or(series_duration_s)
        .unwrap_or(3600.0);
    let time_grid = TimeGrid::fixed_step(duration_s, time_step_s).ok()?;
    let solver_name = option_value(options, "solver")
        .map(str::trim)
        .unwrap_or("fixed_step");
    let use_adaptive_heun = solver_name == "adaptive_heun";
    let fixed_step_method = FixedStepMethod::from_solver_name(Some(solver_name));
    let adaptive_options =
        use_adaptive_heun.then(|| adaptive_heun_options_from_simulation(options, time_step_s));
    let solver_options = adaptive_options
        .as_ref()
        .map(|options| SolverOptions {
            method: "adaptive_heun".to_owned(),
            timestep_s: time_step_s,
            tolerance: options.tolerance,
            max_iterations: options.max_steps,
        })
        .unwrap_or_else(|| {
            SolverOptions::fixed_step(fixed_step_method.method_name(""), time_step_s)
        });
    let solver_plan = SolverPlan::new(
        system.name.clone(),
        SimulationPlan {
            inputs: vec![outdoor_temperature.name.clone(), internal_heat.name.clone()],
            outputs: vec![state.name.clone()],
            states: vec![state.name.clone()],
            parameters: vec![heat_capacity.name.clone(), conductance.name.clone()],
        },
        solver_options,
    );
    let solver_input = SolverInput {
        plan: solver_plan,
        time_grid,
        state_layout: StateLayout::new(vec![LayoutEntry::new(
            0,
            state.name.clone(),
            state.quantity_kind.clone(),
            state.canonical_unit.clone(),
            state.display_unit.clone(),
        )]),
        input_layout: InputLayout {
            entries: vec![
                LayoutEntry::new(
                    0,
                    outdoor_temperature.name.clone(),
                    outdoor_quantity_kind.clone(),
                    outdoor_temperature.canonical_unit.clone(),
                    outdoor_temperature.display_unit.clone(),
                ),
                LayoutEntry::new(
                    1,
                    internal_heat.name.clone(),
                    internal_heat.quantity_kind.clone(),
                    internal_heat.canonical_unit.clone(),
                    internal_heat.display_unit.clone(),
                ),
            ],
        },
        parameter_layout: ParameterLayout {
            entries: vec![
                LayoutEntry::new(
                    0,
                    heat_capacity.name.clone(),
                    heat_capacity.quantity_kind.clone(),
                    heat_capacity.canonical_unit.clone(),
                    heat_capacity.display_unit.clone(),
                ),
                LayoutEntry::new(
                    1,
                    conductance.name.clone(),
                    conductance.quantity_kind.clone(),
                    conductance.canonical_unit.clone(),
                    conductance.display_unit.clone(),
                ),
            ],
        },
        output_layout: OutputLayout {
            entries: vec![LayoutEntry::new(
                0,
                state.name.clone(),
                state.quantity_kind.clone(),
                state.canonical_unit.clone(),
                state.display_unit.clone(),
            )],
        },
        initial_state: vec![initial_temperature_k],
        inputs: vec![
            SolverScalar::new(
                outdoor_temperature.name.clone(),
                outdoor_quantity_kind.clone(),
                outdoor_temperature.canonical_unit.clone(),
                outdoor_temperature_k,
            ),
            SolverScalar::new(
                internal_heat.name.clone(),
                internal_heat.quantity_kind.clone(),
                internal_heat.canonical_unit.clone(),
                internal_heat_w,
            ),
        ],
        parameters: vec![
            heat_capacity_parameter.clone(),
            conductance_parameter.clone(),
        ],
    };

    let thermal_model = match FirstOrderThermalModel::new(
        heat_capacity_j_per_k,
        conductance_w_per_k,
        internal_heat_w,
    ) {
        Ok(model) => model,
        Err(failure) => {
            return failed_system_runtime_solution_with_source_equations(
                system,
                binding,
                state,
                &solver_input,
                &failure,
                "recognized first-order thermal ODE, but thermal model validation failed",
                &source_equations,
            );
        }
    };

    let (solver_result, step_diagnostics) = if let Some(adaptive_options) = adaptive_options {
        let adaptive_result = match solve_adaptive_heun_ode(
            &solver_input,
            &adaptive_options,
            |sample| {
                let temperature_k = sample.state[0];
                let outdoor_k = dynamic_input_value(
                    outdoor_temperature,
                    outdoor_series,
                    outdoor_override,
                    sample.time_s,
                )
                .unwrap_or(outdoor_temperature_k);
                if !outdoor_k.is_finite() {
                    return Err(SolverFailure::new(
                        "E-SOLVER-THERMAL-INPUT-INVALID",
                        "first-order thermal solver requires finite outdoor temperature input",
                    ));
                }
                let derivative_k_per_s = (thermal_model.conductance_w_per_k
                    * (outdoor_k - temperature_k)
                    + thermal_model.internal_heat_w)
                    / thermal_model.heat_capacity_j_per_k;
                Ok(vec![derivative_k_per_s])
            },
        ) {
            Ok(result) => result,
            Err(failure) => {
                return failed_system_runtime_solution_with_source_equations(
                    system,
                    binding,
                    state,
                    &solver_input,
                    &failure,
                    "recognized first-order thermal ODE, but adaptive Heun solver evaluation failed",
                    &source_equations,
                );
            }
        };
        (
            adaptive_result.solver_result,
            runtime_system_step_diagnostics(&adaptive_result.step_reports),
        )
    } else {
        (
            match solve_first_order_thermal(
                fixed_step_method,
                &solver_input,
                thermal_model,
                |time_s| {
                    let outdoor_k = dynamic_input_value(
                        outdoor_temperature,
                        outdoor_series,
                        outdoor_override,
                        time_s,
                    )
                    .unwrap_or(outdoor_temperature_k);
                    Ok(outdoor_k)
                },
            ) {
                Ok(result) => result,
                Err(failure) => {
                    return failed_system_runtime_solution_with_source_equations(
                        system,
                        binding,
                        state,
                        &solver_input,
                        &failure,
                        "recognized first-order thermal ODE, but fixed-step solver evaluation failed",
                        &source_equations,
                    );
                }
            },
            Vec::new(),
        )
    };
    let reason = if use_adaptive_heun {
        "recognized first-order thermal ODE and executed through SolverResult adaptive Heun one-state path"
    } else {
        "recognized first-order thermal ODE and executed through SolverResult fixed-step one-state path"
    };

    let mut solution =
        RuntimeSystemSolution::from_solver_result(system, binding, state, &solver_result, reason)?;
    solution.step_diagnostics = step_diagnostics;
    solution.source_equations = source_equations;
    Some(solution)
}

fn system_variable_matches_quantity(
    variable: &eng_compiler::SystemVariableInfo,
    quantity_kind: &str,
) -> bool {
    if variable.quantity_kind == quantity_kind {
        return true;
    }
    time_series_quantity(&variable.quantity_kind)
        .is_some_and(|(_, quantity)| quantity == quantity_kind)
}

fn system_variable_value_quantity(variable: &eng_compiler::SystemVariableInfo) -> String {
    time_series_quantity(&variable.quantity_kind)
        .map(|(_, quantity)| quantity)
        .unwrap_or_else(|| variable.quantity_kind.clone())
}

fn materialize_system_solution_series(
    solutions: &[RuntimeSystemSolution],
) -> Vec<RuntimeTimeSeries> {
    solutions
        .iter()
        .filter(|solution| solution.status == "computed")
        .map(|solution| RuntimeTimeSeries {
            name: match &solution.binding {
                Some(binding) => format!("{binding}.{}", solution.state),
                None => format!("{}.{}", solution.system, solution.state),
            },
            axis: "Time".to_owned(),
            x_unit: solution.time_unit.clone(),
            quantity_kind: solution.quantity_kind.clone(),
            display_unit: solution.display_unit.clone(),
            source_table: solution.system.clone(),
            source_expression: format!("simulate {}", solution.system),
            points: solution.points.clone(),
        })
        .collect()
}

fn materialize_component_solution_series(
    solutions: &[RuntimeComponentSolution],
) -> Vec<RuntimeTimeSeries> {
    solutions
        .iter()
        .filter(|solution| solution.status == "computed")
        .flat_map(|solution| {
            solution
                .trajectories
                .iter()
                .map(|trajectory| RuntimeTimeSeries {
                    name: format!("{}.{}", solution.assembly, trajectory.name),
                    axis: "Time".to_owned(),
                    x_unit: "s".to_owned(),
                    quantity_kind: trajectory.quantity_kind.clone(),
                    display_unit: trajectory.unit.clone(),
                    source_table: solution.assembly.clone(),
                    source_expression: format!("component solver {}", solution.assembly),
                    points: trajectory.points.clone(),
                })
                .collect::<Vec<_>>()
        })
        .collect()
}

fn skipped_system_solution(
    system: &eng_compiler::SystemInfo,
    binding: Option<&str>,
    options: &[eng_compiler::WithOptionInfo],
) -> RuntimeSystemSolution {
    let state = system
        .variables
        .iter()
        .find(|variable| variable.role == "state");
    let canonical_initial_value = state.and_then(canonical_variable_value).unwrap_or(0.0);
    let initial_value = state
        .map(|state| display_variable_value(canonical_initial_value, state))
        .unwrap_or(0.0);
    RuntimeSystemSolution {
        system: system.name.clone(),
        binding: binding.map(str::to_owned),
        status: "skipped_unsupported_shape".to_owned(),
        method: "explicit_euler_fixed_step".to_owned(),
        reason:
            "system shape is outside the supported state-space/source ODE/first-order thermal runners"
                .to_owned(),
        states: system_variable_names_by_role(system, "state"),
        algebraic_variables: system_variable_names_by_role(system, "algebraic"),
        inputs: system_variable_names_by_role(system, "input"),
        parameters: system_variable_names_by_role(system, "parameter"),
        outputs: Vec::new(),
        source_equations: unsupported_system_equation_metadata(system),
        state: state.map(|state| state.name.clone()).unwrap_or_default(),
        quantity_kind: state
            .map(|state| state.quantity_kind.clone())
            .unwrap_or_default(),
        display_unit: state
            .map(|state| state.display_unit.clone())
            .unwrap_or_default(),
        canonical_unit: state
            .map(|state| state.canonical_unit.clone())
            .unwrap_or_default(),
        time_unit: "s".to_owned(),
        duration_s: 0.0,
        time_step_s: option_value(options, "timestep")
            .and_then(parse_duration_seconds)
            .unwrap_or(0.0),
        step_count: 0,
        tolerance: SolverOptions::fixed_step("explicit_euler_fixed_step", 0.0).tolerance,
        max_iterations: SolverOptions::fixed_step("explicit_euler_fixed_step", 0.0).max_iterations,
        iteration_count: 0,
        convergence_status: "skipped_unsupported_shape".to_owned(),
        failure_code: Some("E-SIM-SYSTEM-SHAPE-UNSUPPORTED".to_owned()),
        failure_reason: Some(
            "system shape is outside the supported state-space/source ODE/first-order thermal runners"
                .to_owned(),
        ),
        initial_value,
        final_value: initial_value,
        canonical_initial_value,
        canonical_final_value: canonical_initial_value,
        step_diagnostics: Vec::new(),
        points: Vec::new(),
    }
}

fn unsupported_system_equation_metadata(
    system: &eng_compiler::SystemInfo,
) -> Vec<RuntimeSystemEquationMetadata> {
    system
        .equations
        .iter()
        .map(|equation| {
            let target = equation.left.trim().to_owned();
            let target_variable = system
                .variables
                .iter()
                .find(|variable| variable.name == target);
            RuntimeSystemEquationMetadata {
                kind: "unsupported_system_equation".to_owned(),
                target,
                left: equation.left.clone(),
                right: equation.right.clone(),
                residual_expression: if equation.residual.trim().is_empty() {
                    format!("{} - ({})", equation.left, equation.right)
                } else {
                    equation.residual.clone()
                },
                quantity_kind: target_variable
                    .map(|variable| variable.quantity_kind.clone())
                    .unwrap_or_else(|| equation.left_dimension.clone()),
                display_unit: target_variable
                    .map(|variable| variable.display_unit.clone())
                    .unwrap_or_default(),
                canonical_unit: target_variable
                    .map(|variable| variable.canonical_unit.clone())
                    .unwrap_or_default(),
                source_line: Some(equation.line),
            }
        })
        .collect()
}

fn system_variable_names_by_role(system: &eng_compiler::SystemInfo, role: &str) -> Vec<String> {
    system
        .variables
        .iter()
        .filter(|variable| variable.role == role)
        .map(|variable| variable.name.clone())
        .collect()
}

fn option_value<'a>(options: &'a [eng_compiler::WithOptionInfo], key: &str) -> Option<&'a str> {
    options
        .iter()
        .find(|option| option.key == key)
        .map(|option| option.value.as_str())
}

fn adaptive_heun_options_from_simulation(
    options: &[eng_compiler::WithOptionInfo],
    output_timestep_s: f64,
) -> AdaptiveOdeOptions {
    let mut adaptive = AdaptiveOdeOptions::default();
    if let Some(tolerance) = option_value(options, "tolerance")
        .and_then(|value| value.trim().parse::<f64>().ok())
        .filter(|value| value.is_finite() && *value > 0.0)
    {
        adaptive.tolerance = tolerance;
    }
    adaptive.initial_step_s = adaptive
        .initial_step_s
        .min(output_timestep_s)
        .max(adaptive.min_step_s);
    adaptive.max_step_s = adaptive
        .max_step_s
        .min(output_timestep_s)
        .max(adaptive.min_step_s);
    if let Some(max_steps) = option_value(options, "max_iter")
        .and_then(|value| value.trim().parse::<usize>().ok())
        .filter(|value| *value > 0)
    {
        adaptive.max_steps = max_steps;
    }
    adaptive
}

fn parse_duration_seconds(value: &str) -> Option<f64> {
    let (amount, unit) = number_with_optional_unit(value)?;
    let unit = unit.as_deref().map(normalize_unit);
    Some(match unit.as_deref() {
        Some("min") => amount * 60.0,
        Some("h") => amount * 3600.0,
        Some("s") | None => amount,
        _ => return None,
    })
}

fn interpolate_series_value(series: &RuntimeTimeSeries, x: f64) -> Option<f64> {
    let first = series.points.first()?;
    if x <= first.x {
        return Some(first.y);
    }
    let last = series.points.last()?;
    if x >= last.x {
        return Some(last.y);
    }
    for window in series.points.windows(2) {
        let a = window[0];
        let b = window[1];
        if x >= a.x && x <= b.x {
            let span = b.x - a.x;
            if span.abs() <= f64::EPSILON {
                return Some(a.y);
            }
            let t = (x - a.x) / span;
            return Some(a.y + (b.y - a.y) * t);
        }
    }
    None
}

fn canonical_variable_value(variable: &eng_compiler::SystemVariableInfo) -> Option<f64> {
    let expression = variable.initial_value.as_deref()?;
    let (value, unit) = number_with_optional_unit(expression)?;
    let quantity_kind = system_variable_value_quantity(variable);
    convert_to_canonical_unit(
        value,
        unit.as_deref(),
        &variable.canonical_unit,
        &quantity_kind,
    )
    .ok()
}

fn simulation_parameter_scalars(
    parameters: &[&eng_compiler::SystemVariableInfo],
    options: &[eng_compiler::WithOptionInfo],
) -> Option<Vec<SolverScalar>> {
    parameters
        .iter()
        .map(|parameter| simulation_parameter_scalar(parameter, options))
        .collect()
}

fn simulation_parameter_scalar(
    parameter: &eng_compiler::SystemVariableInfo,
    options: &[eng_compiler::WithOptionInfo],
) -> Option<SolverScalar> {
    simulation_parameter_value(parameter, options).map(|value| {
        SolverScalar::new(
            parameter.name.clone(),
            parameter.quantity_kind.clone(),
            parameter.canonical_unit.clone(),
            value,
        )
    })
}

fn simulation_parameter_value(
    parameter: &eng_compiler::SystemVariableInfo,
    options: &[eng_compiler::WithOptionInfo],
) -> Option<f64> {
    option_value(options, &parameter.name)
        .map(|value| canonical_simulation_parameter_value(parameter, value))
        .unwrap_or_else(|| canonical_variable_value(parameter))
}

fn canonical_simulation_input_value(
    input: &eng_compiler::SystemVariableInfo,
    expression: &str,
) -> Option<f64> {
    let (value, unit) = number_with_optional_unit(expression)?;
    if !value.is_finite() {
        return None;
    }
    let quantity_kind = system_variable_value_quantity(input);
    convert_to_canonical_unit(
        value,
        unit.as_deref(),
        &input.canonical_unit,
        &quantity_kind,
    )
    .ok()
}
fn canonical_simulation_parameter_value(
    parameter: &eng_compiler::SystemVariableInfo,
    expression: &str,
) -> Option<f64> {
    let (value, unit) = number_with_optional_unit(expression)?;
    if !value.is_finite() {
        return None;
    }
    let quantity_kind = system_variable_value_quantity(parameter);
    convert_to_canonical_unit(
        value,
        unit.as_deref(),
        &parameter.canonical_unit,
        &quantity_kind,
    )
    .ok()
}
fn display_variable_value(value: f64, variable: &eng_compiler::SystemVariableInfo) -> f64 {
    let quantity_kind = system_variable_value_quantity(variable);
    convert_from_canonical_unit(
        value,
        &variable.canonical_unit,
        &variable.display_unit,
        &quantity_kind,
    )
}

fn materialize_policy_results(
    report: &CheckReport,
    tables: &mut [RuntimeTable],
) -> Vec<RuntimePolicyResult> {
    let mut results = Vec::new();
    for promotion in &report.semantic_program.csv_promotions {
        let Some(schema) = report
            .semantic_program
            .schemas
            .iter()
            .find(|schema| schema.name == promotion.schema_name)
        else {
            continue;
        };
        let Some(table_index) = tables
            .iter()
            .position(|table| table.binding == promotion.binding)
        else {
            continue;
        };

        for policy in &schema.missing_policies {
            results.push(execute_missing_policy(
                &mut tables[table_index],
                schema,
                policy,
            ));
        }
        for constraint in &schema.constraints {
            results.push(execute_constraint_policy(
                &tables[table_index],
                schema,
                constraint,
            ));
        }
    }
    results
}

fn execute_constraint_policy(
    table: &RuntimeTable,
    schema: &SchemaInfo,
    constraint: &eng_compiler::SchemaConstraint,
) -> RuntimePolicyResult {
    let text = constraint.text.trim();
    if let Some(column) = text.strip_suffix(" is monotonic").map(str::trim) {
        return execute_monotonic_constraint(table, schema, constraint, column);
    }
    if let Some((column, min, max)) = parse_between_constraint(text) {
        return execute_between_constraint(table, schema, constraint, &column, min, max);
    }
    if let Some(bound) = parse_bound_constraint(text) {
        return execute_bound_constraint(table, schema, constraint, &bound);
    }
    policy_result(
        table,
        schema,
        PolicyResultDraft {
            kind: "constraint",
            target: text,
            policy: text,
            status: "recorded",
            checked_rows: 0,
            violations: Vec::new(),
            line: constraint.line,
        },
    )
}

fn execute_monotonic_constraint(
    table: &RuntimeTable,
    schema: &SchemaInfo,
    constraint: &eng_compiler::SchemaConstraint,
    column_name: &str,
) -> RuntimePolicyResult {
    let Some(column) = table.column(column_name) else {
        return policy_result(
            table,
            schema,
            PolicyResultDraft {
                kind: "constraint",
                target: column_name,
                policy: &constraint.text,
                status: "recorded",
                checked_rows: 0,
                violations: Vec::new(),
                line: constraint.line,
            },
        );
    };
    let RuntimeValues::Text(values) = &column.values else {
        return policy_result(
            table,
            schema,
            PolicyResultDraft {
                kind: "constraint",
                target: column_name,
                policy: &constraint.text,
                status: "recorded",
                checked_rows: 0,
                violations: Vec::new(),
                line: constraint.line,
            },
        );
    };
    let mut previous = None;
    let mut violations = Vec::new();
    for (index, value) in values.iter().enumerate() {
        let Some(timestamp) = parse_utc_timestamp_seconds(value) else {
            violations.push(RuntimePolicyViolation {
                row: index + 2,
                column: column_name.to_owned(),
                value: value.clone(),
                message: "cannot evaluate monotonic policy for invalid DateTime".to_owned(),
            });
            continue;
        };
        if previous.is_some_and(|previous| timestamp < previous) {
            violations.push(RuntimePolicyViolation {
                row: index + 2,
                column: column_name.to_owned(),
                value: value.clone(),
                message: "DateTime value is earlier than the previous row".to_owned(),
            });
        }
        previous = Some(timestamp);
    }
    policy_result(
        table,
        schema,
        PolicyResultDraft {
            kind: "constraint",
            target: column_name,
            policy: &constraint.text,
            status: "executed",
            checked_rows: values.len(),
            violations,
            line: constraint.line,
        },
    )
}

fn execute_between_constraint(
    table: &RuntimeTable,
    schema: &SchemaInfo,
    constraint: &eng_compiler::SchemaConstraint,
    column_name: &str,
    min: f64,
    max: f64,
) -> RuntimePolicyResult {
    let Some(column) = table.column(column_name) else {
        return policy_result(
            table,
            schema,
            PolicyResultDraft {
                kind: "constraint",
                target: column_name,
                policy: &constraint.text,
                status: "recorded",
                checked_rows: 0,
                violations: Vec::new(),
                line: constraint.line,
            },
        );
    };
    let values = numeric_values(column);
    let violations = values
        .iter()
        .enumerate()
        .filter_map(|(index, value)| {
            let value = (*value)?;
            if value < min || value > max {
                Some(RuntimePolicyViolation {
                    row: index + 2,
                    column: column_name.to_owned(),
                    value: value.to_string(),
                    message: format!("value is outside [{min}, {max}]"),
                })
            } else {
                None
            }
        })
        .collect::<Vec<_>>();
    policy_result(
        table,
        schema,
        PolicyResultDraft {
            kind: "constraint",
            target: column_name,
            policy: &constraint.text,
            status: "executed",
            checked_rows: values.len(),
            violations,
            line: constraint.line,
        },
    )
}

fn execute_bound_constraint(
    table: &RuntimeTable,
    schema: &SchemaInfo,
    constraint: &eng_compiler::SchemaConstraint,
    bound: &BoundConstraint,
) -> RuntimePolicyResult {
    let Some(column) = table.column(&bound.column) else {
        return policy_result(
            table,
            schema,
            PolicyResultDraft {
                kind: "constraint",
                target: &bound.column,
                policy: &constraint.text,
                status: "recorded",
                checked_rows: 0,
                violations: Vec::new(),
                line: constraint.line,
            },
        );
    };
    let values = numeric_values(column);
    let violations = values
        .iter()
        .enumerate()
        .filter_map(|(index, value)| {
            let value = (*value)?;
            if !bound.accepts(value) {
                Some(RuntimePolicyViolation {
                    row: index + 2,
                    column: bound.column.clone(),
                    value: value.to_string(),
                    message: bound.violation_message(),
                })
            } else {
                None
            }
        })
        .collect::<Vec<_>>();
    policy_result(
        table,
        schema,
        PolicyResultDraft {
            kind: "constraint",
            target: &bound.column,
            policy: &constraint.text,
            status: "executed",
            checked_rows: values.len(),
            violations,
            line: constraint.line,
        },
    )
}

fn execute_missing_policy(
    table: &mut RuntimeTable,
    schema: &SchemaInfo,
    policy: &eng_compiler::MissingPolicy,
) -> RuntimePolicyResult {
    let Some(column_index) = table
        .columns
        .iter()
        .position(|column| column.name == policy.column)
    else {
        return policy_result(
            table,
            schema,
            PolicyResultDraft {
                kind: "missing",
                target: &policy.column,
                policy: &policy.policy,
                status: "recorded",
                checked_rows: 0,
                violations: Vec::new(),
                line: policy.line,
            },
        );
    };
    let missing_rows = missing_rows(&table.columns[column_index]);
    if policy.policy.trim() == "error" {
        let violations = missing_rows
            .iter()
            .map(|row| RuntimePolicyViolation {
                row: *row,
                column: policy.column.clone(),
                value: String::new(),
                message: "missing value violates `error` policy".to_owned(),
            })
            .collect::<Vec<_>>();
        return policy_result(
            table,
            schema,
            PolicyResultDraft {
                kind: "missing",
                target: &policy.column,
                policy: &policy.policy,
                status: "executed",
                checked_rows: table.columns[column_index].len(),
                violations,
                line: policy.line,
            },
        );
    }

    if policy.policy.trim_start().starts_with("interpolate") {
        let violations =
            interpolate_missing_values(&mut table.columns[column_index], &missing_rows);
        return policy_result(
            table,
            schema,
            PolicyResultDraft {
                kind: "missing",
                target: &policy.column,
                policy: &policy.policy,
                status: "executed",
                checked_rows: table.columns[column_index].len(),
                violations,
                line: policy.line,
            },
        );
    }

    policy_result(
        table,
        schema,
        PolicyResultDraft {
            kind: "missing",
            target: &policy.column,
            policy: &policy.policy,
            status: "recorded",
            checked_rows: table.columns[column_index].len(),
            violations: Vec::new(),
            line: policy.line,
        },
    )
}

fn interpolate_missing_values(
    column: &mut RuntimeColumn,
    missing_rows: &[usize],
) -> Vec<RuntimePolicyViolation> {
    let RuntimeValues::Number(values) = &mut column.values else {
        return missing_rows
            .iter()
            .map(|row| RuntimePolicyViolation {
                row: *row,
                column: column.name.clone(),
                value: String::new(),
                message: "interpolation requires a numeric column".to_owned(),
            })
            .collect();
    };

    let mut violations = Vec::new();
    for row in missing_rows {
        let Some(index) = row.checked_sub(2) else {
            continue;
        };
        if values.get(index).and_then(|value| *value).is_some() {
            continue;
        }
        let previous = (0..index)
            .rev()
            .find_map(|candidate| values[candidate].map(|value| (candidate, value)));
        let next = ((index + 1)..values.len())
            .find_map(|candidate| values[candidate].map(|value| (candidate, value)));
        let (Some((previous_index, previous_value)), Some((next_index, next_value))) =
            (previous, next)
        else {
            violations.push(RuntimePolicyViolation {
                row: *row,
                column: column.name.clone(),
                value: String::new(),
                message: "cannot interpolate without surrounding numeric values".to_owned(),
            });
            continue;
        };
        let fraction = (index - previous_index) as f64 / (next_index - previous_index) as f64;
        values[index] = Some(previous_value + (next_value - previous_value) * fraction);
    }
    column.missing_count = values.iter().filter(|value| value.is_none()).count();
    violations
}

struct PolicyResultDraft<'a> {
    kind: &'a str,
    target: &'a str,
    policy: &'a str,
    status: &'a str,
    checked_rows: usize,
    violations: Vec<RuntimePolicyViolation>,
    line: usize,
}

fn policy_result(
    table: &RuntimeTable,
    schema: &SchemaInfo,
    draft: PolicyResultDraft<'_>,
) -> RuntimePolicyResult {
    RuntimePolicyResult {
        schema: schema.name.clone(),
        binding: table.binding.clone(),
        kind: draft.kind.to_owned(),
        target: draft.target.to_owned(),
        policy: draft.policy.to_owned(),
        status: draft.status.to_owned(),
        checked_rows: draft.checked_rows,
        violations: draft.violations,
        line: draft.line,
    }
}

impl RuntimeTable {
    fn column(&self, name: &str) -> Option<&RuntimeColumn> {
        self.columns.iter().find(|column| column.name == name)
    }

    fn time_index_column(&self) -> Option<&RuntimeColumn> {
        self.columns
            .iter()
            .find(|column| column.is_index && column.type_name == "DateTime")
    }

    fn numeric_column_by_type(&self, type_name: &str) -> Option<&RuntimeColumn> {
        self.columns.iter().find(|column| {
            column.type_name == type_name && matches!(&column.values, RuntimeValues::Number(_))
        })
    }

    fn temperature_column(&self, name_hint: &str) -> Option<&RuntimeColumn> {
        self.columns.iter().find(|column| {
            column.type_name == "AbsoluteTemperature"
                && column.name.to_ascii_lowercase().contains(name_hint)
                && matches!(&column.values, RuntimeValues::Number(_))
        })
    }

    fn axis_values(&self) -> (Vec<f64>, String) {
        if let Some(values) = self.normalized_time_axis_values() {
            return (values, "s".to_owned());
        }
        (sample_axis_values(self.row_count), "sample".to_owned())
    }

    fn normalized_time_axis_values(&self) -> Option<Vec<f64>> {
        let column = self.time_index_column()?;
        let RuntimeValues::Text(values) = &column.values else {
            return None;
        };
        let timestamps = values
            .iter()
            .map(|value| parse_utc_timestamp_seconds(value))
            .collect::<Option<Vec<_>>>();
        let timestamps = timestamps?;
        let Some(first) = timestamps.first().copied() else {
            return Some(Vec::new());
        };
        Some(
            timestamps
                .iter()
                .map(|timestamp| (*timestamp - first) as f64)
                .collect(),
        )
    }
}

fn numeric_values(column: &RuntimeColumn) -> &[Option<f64>] {
    let RuntimeValues::Number(values) = &column.values else {
        return &[];
    };
    values
}

fn missing_rows(column: &RuntimeColumn) -> Vec<usize> {
    match &column.values {
        RuntimeValues::Text(values) => values
            .iter()
            .enumerate()
            .filter(|(_, value)| value.trim().is_empty())
            .map(|(index, _)| index + 2)
            .collect(),
        RuntimeValues::Number(values) => values
            .iter()
            .enumerate()
            .filter(|(_, value)| value.is_none())
            .map(|(index, _)| index + 2)
            .collect(),
    }
}

fn parse_between_constraint(text: &str) -> Option<(String, f64, f64)> {
    let (column, rest) = text.split_once(" between ")?;
    let (min_part, max_part) = rest.split_once(" and ")?;
    Some((
        column.trim().to_owned(),
        first_number(min_part)?,
        first_number(max_part)?,
    ))
}

#[derive(Clone, Debug, PartialEq)]
struct BoundConstraint {
    column: String,
    operator: String,
    threshold: f64,
}

impl BoundConstraint {
    fn accepts(&self, value: f64) -> bool {
        match self.operator.as_str() {
            ">=" => value >= self.threshold,
            ">" => value > self.threshold,
            "<=" => value <= self.threshold,
            "<" => value < self.threshold,
            _ => true,
        }
    }

    fn violation_message(&self) -> String {
        match self.operator.as_str() {
            ">=" => format!("value is below lower bound {}", self.threshold),
            ">" => format!("value is not greater than {}", self.threshold),
            "<=" => format!("value is above upper bound {}", self.threshold),
            "<" => format!("value is not less than {}", self.threshold),
            _ => "value violates bound constraint".to_owned(),
        }
    }
}

fn parse_bound_constraint(text: &str) -> Option<BoundConstraint> {
    for operator in [">=", "<=", ">", "<"] {
        if let Some((column, rest)) = text.split_once(operator) {
            return Some(BoundConstraint {
                column: column.trim().to_owned(),
                operator: operator.to_owned(),
                threshold: first_number(rest)?,
            });
        }
    }
    None
}

fn first_number(text: &str) -> Option<f64> {
    text.split_whitespace()
        .find_map(|part| part.parse::<f64>().ok())
}

fn parse_plot_options(source: &str) -> PlotOptions {
    let mut options = PlotOptions::default();
    let Some(plot_index) = source.find("plot ") else {
        return options;
    };
    let after_plot = &source[plot_index + "plot ".len()..];
    let header_end = [after_plot.find('{'), after_plot.find('\n')]
        .into_iter()
        .flatten()
        .min()
        .unwrap_or(after_plot.len());
    let header = after_plot[..header_end].trim();
    if let Some(histogram) = parse_histogram_header(header) {
        options.histogram = Some(histogram);
        options.plot_type = Some("histogram".to_owned());
    } else if let Some(distribution) = parse_distribution_header(header) {
        options.distribution = Some(distribution);
        options.plot_type = Some("histogram".to_owned());
    } else if let Some(model_plot) = parse_model_plot_header(header) {
        options.plot_type = Some(if model_plot.kind == "parity" {
            "scatter".to_owned()
        } else {
            "bar".to_owned()
        });
        options.model_plot = Some(model_plot);
    } else if let Some((series, axis)) = header.split_once(" over ") {
        options.series_list = series
            .split(" and ")
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_owned)
            .collect();
        options.series = options.series_list.first().cloned();
        options.axis = axis.split_whitespace().next().map(str::to_owned);
    }

    let Some(block_start) = after_plot.find('{') else {
        return options;
    };
    let Some(block_end) = after_plot[block_start + 1..].find('}') else {
        return options;
    };
    let block = &after_plot[block_start + 1..block_start + 1 + block_end];
    for line in block.lines().map(str::trim) {
        if let Some(rest) = line.strip_prefix("unit x =") {
            options.x_unit = rest.split_whitespace().next().map(str::to_owned);
        } else if let Some(rest) = line.strip_prefix("unit y =") {
            options.y_unit = rest.split_whitespace().next().map(str::to_owned);
        } else if let Some(rest) = line.strip_prefix("type =") {
            options.plot_type = supported_plot_type(rest.trim());
        } else if let Some(rest) = line.strip_prefix("title =") {
            options.title = quoted_value(rest.trim());
        } else if let Some(rest) = line.strip_prefix("confidence_band =") {
            options.confidence_band = supported_confidence_band(rest.trim());
        }
    }
    options
}

fn supported_confidence_band(value: &str) -> Option<String> {
    let band = value.split_whitespace().next()?;
    matches!(band, "sensor_std").then(|| band.to_owned())
}

fn parse_model_plot_header(header: &str) -> Option<ModelPlotOptions> {
    parse_call_header(header, "parity")
        .map(|source| ModelPlotOptions {
            kind: "parity".to_owned(),
            source,
        })
        .or_else(|| {
            parse_call_header(header, "residuals").map(|source| ModelPlotOptions {
                kind: "residuals".to_owned(),
                source,
            })
        })
}

fn parse_distribution_header(header: &str) -> Option<String> {
    parse_call_header(header, "distribution")
}

fn parse_histogram_header(header: &str) -> Option<String> {
    parse_call_header(header, "histogram")
}

fn parse_call_header(header: &str, name: &str) -> Option<String> {
    let header = header.trim();
    let prefix = format!("{name}(");
    let inner = header
        .strip_prefix(&prefix)
        .and_then(|rest| rest.strip_suffix(')'))?;
    inner
        .split(',')
        .next()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned)
}

fn supported_plot_type(value: &str) -> Option<String> {
    let plot_type = value.split_whitespace().next()?;
    matches!(plot_type, "line" | "bar" | "histogram" | "scatter").then(|| plot_type.to_owned())
}

fn quoted_value(value: &str) -> Option<String> {
    let rest = value.strip_prefix('"')?;
    let (quoted, _) = rest.split_once('"')?;
    Some(quoted.to_owned())
}

fn specific_heat_value(report: &CheckReport, expression: &str) -> Option<f64> {
    if let Some(value) = number_before_unit(expression, "J/kg/K") {
        return Some(value);
    }

    report
        .inferred_declarations
        .iter()
        .filter(|declaration| expression_contains_identifier(expression, &declaration.name))
        .find_map(|declaration| number_before_unit(&declaration.expression, "J/kg/K"))
}

fn expression_contains_identifier(expression: &str, identifier: &str) -> bool {
    expression
        .split(|character: char| !(character.is_ascii_alphanumeric() || character == '_'))
        .any(|token| token == identifier)
}

fn number_before_unit(expression: &str, unit: &str) -> Option<f64> {
    let unit_index = expression.find(unit)?;
    expression[..unit_index]
        .split_whitespace()
        .rev()
        .find_map(|part| part.parse::<f64>().ok())
}

fn number_with_optional_unit(text: &str) -> Option<(f64, Option<String>)> {
    let parts = text.split_whitespace().collect::<Vec<_>>();
    for (index, part) in parts.iter().enumerate() {
        let number_part = part.trim_matches(|character| matches!(character, '(' | ')' | ','));
        if let Ok(value) = number_part.parse::<f64>() {
            let unit = parts
                .get(index + 1)
                .map(|unit| unit.trim_matches(|character| matches!(character, '(' | ')' | ',')))
                .filter(|unit| !unit.is_empty())
                .map(str::to_owned);
            return Some((value, unit));
        }
    }
    None
}

fn statistic_value(name: &str, series: &RuntimeTimeSeries) -> Option<RuntimeStatisticValue> {
    let values = series
        .points
        .iter()
        .map(|point| point.y)
        .collect::<Vec<_>>();
    if values.is_empty() {
        return None;
    }
    let (value, unit) = match name {
        "mean" => (
            values.iter().sum::<f64>() / values.len() as f64,
            series.display_unit.clone(),
        ),
        "time_weighted_mean" => (time_weighted_mean(series)?, series.display_unit.clone()),
        "max" => (
            values.iter().copied().reduce(f64::max)?,
            series.display_unit.clone(),
        ),
        "min" => (
            values.iter().copied().reduce(f64::min)?,
            series.display_unit.clone(),
        ),
        "median" => (median(&values)?, series.display_unit.clone()),
        "std" => (population_std(&values)?, series.display_unit.clone()),
        percentile if percentile_fraction(percentile).is_some() => (
            nearest_rank_percentile(&values, percentile_fraction(percentile)?)?,
            series.display_unit.clone(),
        ),
        _ => {
            let threshold = duration_above_threshold(name, &series.display_unit)?;
            (duration_above(series, threshold)?, "s".to_owned())
        }
    };
    Some(RuntimeStatisticValue {
        name: name.to_owned(),
        value,
        unit,
    })
}

fn nearest_rank_percentile(values: &[f64], percentile: f64) -> Option<f64> {
    if values.is_empty() {
        return None;
    }
    let mut sorted = values.to_vec();
    sorted.sort_by(f64::total_cmp);
    let rank = (percentile * sorted.len() as f64).ceil() as usize;
    sorted.get(rank.saturating_sub(1)).copied()
}

fn percentile_fraction(name: &str) -> Option<f64> {
    let percentile = name.strip_prefix('p')?.parse::<u32>().ok()?;
    (1..=100)
        .contains(&percentile)
        .then_some(percentile as f64 / 100.0)
}

fn median(values: &[f64]) -> Option<f64> {
    if values.is_empty() {
        return None;
    }
    let mut sorted = values.to_vec();
    sorted.sort_by(f64::total_cmp);
    let midpoint = sorted.len() / 2;
    if sorted.len() & 1 == 0 {
        Some((sorted[midpoint - 1] + sorted[midpoint]) * 0.5)
    } else {
        sorted.get(midpoint).copied()
    }
}

fn population_std(values: &[f64]) -> Option<f64> {
    if values.is_empty() {
        return None;
    }
    let mean = values.iter().sum::<f64>() / values.len() as f64;
    let variance = values
        .iter()
        .map(|value| {
            let delta = value - mean;
            delta * delta
        })
        .sum::<f64>()
        / values.len() as f64;
    Some(variance.sqrt())
}

fn duration_above_threshold(name: &str, display_unit: &str) -> Option<f64> {
    let inside = name
        .trim()
        .strip_prefix("duration_above(")?
        .strip_suffix(')')?;
    let (value, unit) = number_with_optional_unit(inside)?;
    Some(
        unit.as_deref()
            .map(|unit| convert_display_value(value, unit, display_unit))
            .unwrap_or(value),
    )
}

fn duration_above(series: &RuntimeTimeSeries, threshold: f64) -> Option<f64> {
    if series.x_unit != "s" || series.points.len() < 2 {
        return None;
    }
    let mut duration = 0.0;
    for window in series.points.windows(2) {
        let dt = window[1].x - window[0].x;
        if dt <= 0.0 {
            return None;
        }
        let y0 = window[0].y;
        let y1 = window[1].y;
        let y0_above = y0 > threshold;
        let y1_above = y1 > threshold;
        if y0_above && y1_above {
            duration += dt;
        } else if y0_above != y1_above {
            let dy = y1 - y0;
            if dy.abs() <= f64::EPSILON {
                continue;
            }
            let fraction = ((threshold - y0) / dy).clamp(0.0, 1.0);
            duration += if y0_above {
                fraction * dt
            } else {
                (1.0 - fraction) * dt
            };
        }
    }
    Some(duration)
}

fn time_weighted_mean(series: &RuntimeTimeSeries) -> Option<f64> {
    let total_duration = series.points.last()?.x - series.points.first()?.x;
    if series.x_unit != "s" || total_duration <= 0.0 {
        return None;
    }
    Some(trapezoidal_integral(series)? / total_duration)
}

fn trapezoidal_integral(series: &RuntimeTimeSeries) -> Option<f64> {
    if series.x_unit != "s" || series.points.len() < 2 {
        return None;
    }
    let mut integral = 0.0;
    for window in series.points.windows(2) {
        let dt = window[1].x - window[0].x;
        if dt <= 0.0 {
            return None;
        }
        integral += (window[0].y + window[1].y) * 0.5 * dt;
    }
    Some(integral)
}

fn trapezoidal_energy_joules(series: &RuntimeTimeSeries) -> Option<f64> {
    let integral = trapezoidal_integral(series)?;
    Some(convert_display_value(integral, &series.display_unit, "W"))
}

fn optional_number_at(column: &RuntimeColumn, index: usize) -> Option<f64> {
    let RuntimeValues::Number(values) = &column.values else {
        return None;
    };
    values.get(index).copied().flatten()
}

fn convert_display_value(value: f64, from_unit: &str, to_unit: &str) -> f64 {
    let from_unit = normalize_unit(from_unit);
    let to_unit = normalize_unit(to_unit);
    match (from_unit.as_str(), to_unit.as_str()) {
        ("w", "kw") => value / 1000.0,
        ("kw", "w") => value * 1000.0,
        ("pa", "kpa") => value / 1000.0,
        ("kpa", "pa") => value * 1000.0,
        ("degc", "degc") => value,
        ("k", "degc") => value - 273.15,
        ("degc", "k") => value + 273.15,
        _ => value,
    }
}

fn convert_delta_value(value: f64, from_unit: &str, to_unit: &str) -> f64 {
    let from_unit = normalize_unit(from_unit);
    let to_unit = normalize_unit(to_unit);
    match (from_unit.as_str(), to_unit.as_str()) {
        ("w", "kw") => value / 1000.0,
        ("kw", "w") => value * 1000.0,
        ("pa", "kpa") => value / 1000.0,
        ("k", "degc") | ("degc", "k") => value,
        _ => value,
    }
}

fn accepted_sensor_std_value<'a>(
    report: &'a CheckReport,
    series_name: &str,
) -> Option<&'a eng_compiler::WithOptionInfo> {
    let binding = report
        .semantic_program
        .typed_bindings
        .iter()
        .find(|binding| binding.name == series_name)?;
    report
        .semantic_program
        .with_blocks
        .iter()
        .filter(|block| block.owner_line == Some(binding.line))
        .flat_map(|block| block.options.iter())
        .find(|option| option.key == "sensor_std" && option.status == "accepted")
}

fn first_numeric_value(text: &str) -> Option<f64> {
    number_with_optional_unit(text).map(|(value, _)| value)
}

fn relative_error_fraction(text: &str) -> Option<f64> {
    let value = first_numeric_value(text)?;
    if text.contains('%') {
        Some(value / 100.0)
    } else {
        Some(value)
    }
}

fn interval_samples(lower: Option<f64>, upper: Option<f64>) -> Vec<f64> {
    match (lower, upper) {
        (Some(lower), Some(upper)) if (upper - lower).abs() > f64::EPSILON => {
            vec![lower, (lower + upper) * 0.5, upper]
        }
        (Some(value), _) | (_, Some(value)) => vec![value],
        _ => Vec::new(),
    }
}

fn normal_samples(mean: f64, stddev: f64, count: usize) -> Vec<f64> {
    let count = count.clamp(1, 256);
    if count == 1 || stddev == 0.0 {
        return vec![mean; count];
    }
    (0..count)
        .map(|index| {
            let probability = (index as f64 + 0.5) / count as f64;
            mean + inverse_standard_normal(probability) * stddev
        })
        .collect()
}

fn uniform_samples(lower: Option<f64>, upper: Option<f64>, count: usize) -> Vec<f64> {
    let Some(lower) = lower else {
        return Vec::new();
    };
    let Some(upper) = upper else {
        return Vec::new();
    };
    let count = count.clamp(1, 256);
    if count == 1 || (upper - lower).abs() <= f64::EPSILON {
        return vec![(lower + upper) * 0.5; count];
    }
    (0..count)
        .map(|index| {
            let fraction = (index as f64 + 0.5) / count as f64;
            lower + (upper - lower) * fraction
        })
        .collect()
}

fn resample_deterministic(values: &[f64], count: usize) -> Vec<f64> {
    if values.is_empty() {
        return Vec::new();
    }
    let count = count.clamp(1, 256);
    (0..count)
        .map(|index| values[index % values.len()])
        .collect()
}

fn quantile(values: &[f64], probability: f64) -> Option<f64> {
    if values.is_empty() {
        return None;
    }
    let mut sorted = values.to_vec();
    sorted.sort_by(f64::total_cmp);
    if sorted.len() == 1 {
        return sorted.first().copied();
    }
    let position = probability.clamp(0.0, 1.0) * (sorted.len() - 1) as f64;
    let lower_index = position.floor() as usize;
    let upper_index = position.ceil() as usize;
    let lower = sorted[lower_index];
    let upper = sorted[upper_index];
    Some(lower + (upper - lower) * (position - lower_index as f64))
}

fn inverse_standard_normal(probability: f64) -> f64 {
    let p = probability.clamp(1.0e-12, 1.0 - 1.0e-12);
    const A: [f64; 6] = [
        -3.969_683_028_665_376e1,
        2.209_460_984_245_205e2,
        -2.759_285_104_469_687e2,
        1.383_577_518_672_69e2,
        -3.066_479_806_614_716e1,
        2.506_628_277_459_239,
    ];
    const B: [f64; 5] = [
        -5.447_609_879_822_406e1,
        1.615_858_368_580_409e2,
        -1.556_989_798_598_866e2,
        6.680_131_188_771_972e1,
        -1.328_068_155_288_572e1,
    ];
    const C: [f64; 6] = [
        -7.784_894_002_430_293e-3,
        -3.223_964_580_411_365e-1,
        -2.400_758_277_161_838,
        -2.549_732_539_343_734,
        4.374_664_141_464_968,
        2.938_163_982_698_783,
    ];
    const D: [f64; 4] = [
        7.784_695_709_041_462e-3,
        3.224_671_290_700_398e-1,
        2.445_134_137_142_996,
        3.754_408_661_907_416,
    ];
    let plow = 0.02425;
    let phigh = 1.0 - plow;
    if p < plow {
        let q = (-2.0 * p.ln()).sqrt();
        return (((((C[0] * q + C[1]) * q + C[2]) * q + C[3]) * q + C[4]) * q + C[5])
            / ((((D[0] * q + D[1]) * q + D[2]) * q + D[3]) * q + 1.0);
    }
    if p <= phigh {
        let q = p - 0.5;
        let r = q * q;
        return (((((A[0] * r + A[1]) * r + A[2]) * r + A[3]) * r + A[4]) * r + A[5]) * q
            / (((((B[0] * r + B[1]) * r + B[2]) * r + B[3]) * r + B[4]) * r + 1.0);
    }
    let q = (-2.0 * (1.0 - p).ln()).sqrt();
    -(((((C[0] * q + C[1]) * q + C[2]) * q + C[3]) * q + C[4]) * q + C[5])
        / ((((D[0] * q + D[1]) * q + D[2]) * q + D[3]) * q + 1.0)
}

#[derive(Clone, Copy, Debug)]
struct SampleSummary {
    mean: Option<f64>,
    stddev: Option<f64>,
    lower: Option<f64>,
    upper: Option<f64>,
}

fn sample_summary(values: &[f64]) -> SampleSummary {
    if values.is_empty() {
        return SampleSummary {
            mean: None,
            stddev: None,
            lower: None,
            upper: None,
        };
    }
    let mean = values.iter().sum::<f64>() / values.len() as f64;
    let variance = values
        .iter()
        .map(|value| {
            let delta = value - mean;
            delta * delta
        })
        .sum::<f64>()
        / values.len() as f64;
    let lower = values.iter().copied().fold(f64::INFINITY, f64::min);
    let upper = values.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    SampleSummary {
        mean: Some(mean),
        stddev: Some(variance.sqrt()),
        lower: Some(lower),
        upper: Some(upper),
    }
}

fn histogram_bins(values: &[f64]) -> Vec<PlotBin> {
    if values.is_empty() {
        return Vec::new();
    }
    let lower = values.iter().copied().fold(f64::INFINITY, f64::min);
    let upper = values.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    if (upper - lower).abs() <= f64::EPSILON {
        return vec![PlotBin {
            lower,
            upper,
            center: lower,
            count: values.len(),
        }];
    }
    let bin_count = values.len().clamp(3, 12);
    let width = (upper - lower) / bin_count as f64;
    let mut bins = vec![0usize; bin_count];
    for value in values {
        let mut index = ((value - lower) / width).floor() as usize;
        if index >= bin_count {
            index = bin_count - 1;
        }
        bins[index] += 1;
    }
    bins.into_iter()
        .enumerate()
        .map(|(index, count)| {
            let bin_lower = lower + index as f64 * width;
            let bin_upper = if index + 1 == bin_count {
                upper
            } else {
                bin_lower + width
            };
            PlotBin {
                lower: bin_lower,
                upper: bin_upper,
                center: bin_lower + (bin_upper - bin_lower) * 0.5,
                count,
            }
        })
        .collect()
}

fn histogram_points_from_bins(bins: &[PlotBin]) -> Vec<PlotPoint> {
    bins.iter()
        .map(|bin| PlotPoint {
            x: bin.center,
            y: bin.count as f64,
        })
        .collect()
}

fn format_number(value: f64) -> String {
    let mut text = format!("{value:.6}");
    while text.contains('.') && text.ends_with('0') {
        text.pop();
    }
    if text.ends_with('.') {
        text.pop();
    }
    text
}

fn parse_fraction(value: Option<&str>) -> Option<f64> {
    let value = value?.trim().trim_end_matches('%');
    let parsed = value.parse::<f64>().ok()?;
    if parsed > 1.0 {
        Some((parsed / 100.0).clamp(0.05, 0.95))
    } else {
        Some(parsed.clamp(0.05, 0.95))
    }
}

fn leakage_findings(
    info: &eng_compiler::MlInfo,
    source_series: Option<&RuntimeTimeSeries>,
    tables: &[RuntimeTable],
) -> Vec<String> {
    let mut findings = Vec::new();
    if let Some(target) = info.target.as_deref() {
        if info.features.iter().any(|feature| feature == target) {
            findings.push(format!("target_in_features:{target}"));
        }
    } else if info.kind == "TrainTestSplit" {
        findings.push("missing_target".to_owned());
    }
    if info.features.is_empty() && info.kind == "TrainTestSplit" {
        findings.push("missing_features".to_owned());
    }
    let Some(source_series) = source_series else {
        if info.kind == "TrainTestSplit" {
            findings.push("missing_source_series".to_owned());
        }
        findings.sort();
        findings.dedup();
        return findings;
    };
    let Some(table) = tables
        .iter()
        .find(|table| table.binding == source_series.source_table)
    else {
        findings.push(format!(
            "missing_source_table:{}",
            source_series.source_table
        ));
        findings.sort();
        findings.dedup();
        return findings;
    };
    for feature in &info.features {
        match table.column(feature) {
            Some(column) if !matches!(&column.values, RuntimeValues::Number(_)) => {
                findings.push(format!("non_numeric_feature:{feature}"));
            }
            Some(column) if column.is_index => {
                findings.push(format!("index_feature_requires_temporal_review:{feature}"));
            }
            Some(_) => {}
            None => findings.push(format!("missing_feature:{feature}")),
        }
    }
    findings.sort();
    findings.dedup();
    findings
}

fn leakage_status_from_findings(findings: &[String]) -> String {
    if findings.is_empty() {
        return "passed".to_owned();
    }
    if findings
        .iter()
        .any(|finding| finding.starts_with("target_in_features:"))
    {
        return "failed_target_in_features".to_owned();
    }
    format!("failed_{}_findings", findings.len())
}

fn ml_dataset(
    source_name: &str,
    target_name: Option<&str>,
    features: &[String],
    series: &[RuntimeTimeSeries],
    tables: &[RuntimeTable],
) -> Result<MlDataset, Vec<String>> {
    let Some(source_series) = series.iter().find(|series| series.name == source_name) else {
        let table = tables
            .iter()
            .find(|table| table.binding == source_name)
            .ok_or_else(|| vec![format!("missing_source_series_or_table:{source_name}")])?;
        return table_ml_dataset(table, target_name, features);
    };
    let target_name = target_name.unwrap_or(source_name);
    let target_series = series
        .iter()
        .find(|series| series.name == target_name)
        .unwrap_or(source_series);
    let table = tables
        .iter()
        .find(|table| table.binding == source_series.source_table)
        .ok_or_else(|| {
            vec![format!(
                "missing_source_table:{}",
                source_series.source_table
            )]
        })?;
    if features.is_empty() {
        return Err(vec!["missing_features".to_owned()]);
    }
    let mut feature_columns = Vec::new();
    let mut findings = Vec::new();
    for feature in features {
        match table.column(feature) {
            Some(column) if matches!(&column.values, RuntimeValues::Number(_)) => {
                feature_columns.push(column);
            }
            Some(_) => findings.push(format!("non_numeric_feature:{feature}")),
            None => findings.push(format!("missing_feature:{feature}")),
        }
    }
    if !findings.is_empty() {
        return Err(findings);
    }
    let row_count = table
        .row_count
        .min(source_series.points.len())
        .min(target_series.points.len());
    let mut rows = Vec::new();
    for index in 0..row_count {
        let mut feature_values = Vec::with_capacity(feature_columns.len());
        let mut complete = true;
        for column in &feature_columns {
            match numeric_column_value(column, index) {
                Some(value) => feature_values.push(value),
                None => {
                    complete = false;
                    break;
                }
            }
        }
        if complete {
            rows.push(MlRow {
                features: feature_values,
                target: target_series.points[index].y,
            });
        }
    }
    if rows.len() < 2 {
        return Err(vec![format!("insufficient_complete_rows:{}", rows.len())]);
    }
    Ok(MlDataset {
        feature_names: features.to_vec(),
        target_name: target_name.to_owned(),
        target_quantity: target_series.quantity_kind.clone(),
        display_unit: target_series.display_unit.clone(),
        rows,
    })
}

fn table_ml_dataset(
    table: &RuntimeTable,
    target_name: Option<&str>,
    features: &[String],
) -> Result<MlDataset, Vec<String>> {
    let target_name = target_name.ok_or_else(|| vec!["missing_target".to_owned()])?;
    let target_column = table
        .column(target_name)
        .ok_or_else(|| vec![format!("missing_target:{target_name}")])?;
    if !matches!(&target_column.values, RuntimeValues::Number(_)) {
        return Err(vec![format!("non_numeric_target:{target_name}")]);
    }
    if features.is_empty() {
        return Err(vec!["missing_features".to_owned()]);
    }

    let mut feature_columns = Vec::new();
    let mut findings = Vec::new();
    for feature in features {
        match table.column(feature) {
            Some(column) if matches!(&column.values, RuntimeValues::Number(_)) => {
                feature_columns.push(column);
            }
            Some(_) => findings.push(format!("non_numeric_feature:{feature}")),
            None => findings.push(format!("missing_feature:{feature}")),
        }
    }
    if !findings.is_empty() {
        return Err(findings);
    }

    let mut rows = Vec::new();
    for index in 0..table.row_count {
        let Some(target) = numeric_column_value(target_column, index) else {
            continue;
        };
        let mut feature_values = Vec::with_capacity(feature_columns.len());
        let mut complete = true;
        for column in &feature_columns {
            match numeric_column_value(column, index) {
                Some(value) => feature_values.push(value),
                None => {
                    complete = false;
                    break;
                }
            }
        }
        if complete {
            rows.push(MlRow {
                features: feature_values,
                target,
            });
        }
    }
    if rows.len() < 2 {
        return Err(vec![format!("insufficient_complete_rows:{}", rows.len())]);
    }

    Ok(MlDataset {
        feature_names: features.to_vec(),
        target_name: target_name.to_owned(),
        target_quantity: target_column.type_name.clone(),
        display_unit: target_column.unit.clone().unwrap_or_else(|| "1".to_owned()),
        rows,
    })
}

fn numeric_column_value(column: &RuntimeColumn, index: usize) -> Option<f64> {
    column
        .canonical_values
        .get(index)
        .copied()
        .flatten()
        .or_else(|| optional_number_at(column, index))
}

fn ml_training_data_hash(dataset: &MlDataset, train_count: usize) -> String {
    let mut payload = format!(
        "target={}\nquantity={}\nunit={}\nfeatures={}\ntrain={}\n",
        dataset.target_name,
        dataset.target_quantity,
        dataset.display_unit,
        dataset.feature_names.join(","),
        train_count
    );
    for row in dataset.rows.iter().take(train_count) {
        payload.push_str(&format!(
            "features={:?};target={}\n",
            row.features, row.target
        ));
    }
    stable_hash_text(&payload)
}

fn ml_model_artifact_hash(artifact: &RuntimeMlArtifact) -> String {
    let mut payload = format!(
        "binding={}\nkind={}\nalgorithm={}\ntarget={}\nquantity={}\nunit={}\nstatus={}\n",
        artifact.binding,
        artifact.kind,
        artifact.algorithm.as_deref().unwrap_or(""),
        artifact.target.as_deref().unwrap_or(""),
        artifact.target_quantity.as_deref().unwrap_or(""),
        artifact.display_unit,
        artifact.status
    );
    payload.push_str(&format!("features={:?}\n", artifact.features));
    payload.push_str(&format!("coefficients={:?}\n", artifact.coefficients));
    payload.push_str(&format!("intercept={:?}\n", artifact.intercept));
    payload.push_str(&format!(
        "metrics={:?},{:?},{:?}\n",
        artifact.rmse, artifact.mae, artifact.r2
    ));
    payload.push_str(&format!(
        "training_data_hash={}\n",
        artifact.training_data_hash.as_deref().unwrap_or("")
    ));
    stable_hash_text(&payload)
}

fn train_linear_model(
    info: &eng_compiler::MlInfo,
    dataset: &MlDataset,
    train_count: usize,
    test_count: usize,
) -> MlTrainingResult {
    let (train_rows, test_rows) = split_ml_rows(dataset, train_count, test_count);
    let feature_count = dataset.feature_names.len();
    let standardization = standardization(train_rows, feature_count);
    let mut coefficients = vec![0.0; feature_count];
    let mut intercept = mean_target(train_rows);
    let epochs = info.epochs.unwrap_or(320).max(1);
    let learning_rate = 0.08 / (feature_count.max(1) as f64).sqrt();
    let checkpoint = (epochs / 5).max(1);
    let mut loss_history = Vec::new();

    for epoch in 0..epochs {
        let mut intercept_gradient = 0.0;
        let mut coefficient_gradients = vec![0.0; feature_count];
        for row in train_rows {
            let features = standardized_features(row, &standardization);
            let predicted = intercept + dot(&coefficients, &features);
            let error = predicted - row.target;
            intercept_gradient += error;
            for index in 0..feature_count {
                coefficient_gradients[index] += error * features[index];
            }
        }
        let scale = train_rows.len().max(1) as f64;
        intercept -= learning_rate * intercept_gradient / scale;
        for index in 0..feature_count {
            coefficients[index] -= learning_rate * coefficient_gradients[index] / scale;
        }
        if epoch == 0 || (epoch + 1) % checkpoint == 0 || epoch + 1 == epochs {
            loss_history.push(linear_rmse(
                train_rows,
                &standardization,
                &coefficients,
                intercept,
            ));
        }
    }

    let predicted = test_rows
        .iter()
        .map(|row| {
            let features = standardized_features(row, &standardization);
            intercept + dot(&coefficients, &features)
        })
        .collect::<Vec<_>>();
    let actual = test_rows.iter().map(|row| row.target).collect::<Vec<_>>();
    let (rmse, mae, r2) = regression_metrics(&actual, &predicted);
    let original_intercept = intercept
        - coefficients
            .iter()
            .enumerate()
            .map(|(index, coefficient)| {
                coefficient * standardization.means[index] / standardization.scales[index]
            })
            .sum::<f64>();
    let original_coefficients = coefficients
        .iter()
        .enumerate()
        .map(|(index, coefficient)| RuntimeMlCoefficient {
            feature: dataset.feature_names[index].clone(),
            value: coefficient / standardization.scales[index],
        })
        .collect();

    MlTrainingResult {
        status: "trained_linear".to_owned(),
        actual,
        predicted,
        coefficients: original_coefficients,
        intercept: original_intercept,
        loss_history,
        rmse,
        mae,
        r2,
    }
}

fn train_mlp_model(
    info: &eng_compiler::MlInfo,
    dataset: &MlDataset,
    train_count: usize,
    test_count: usize,
) -> MlTrainingResult {
    let (train_rows, test_rows) = split_ml_rows(dataset, train_count, test_count);
    let feature_count = dataset.feature_names.len();
    let hidden_count = info
        .hidden_layers
        .first()
        .copied()
        .unwrap_or(4)
        .clamp(1, 16);
    let standardization = standardization(train_rows, feature_count);
    let (target_mean, target_scale) = target_mean_scale(train_rows);
    let seed = info
        .seed
        .as_deref()
        .and_then(|seed| seed.parse::<u64>().ok())
        .unwrap_or(1);
    let mut hidden_weights = (0..hidden_count)
        .map(|hidden| {
            (0..feature_count)
                .map(|feature| deterministic_weight(seed, hidden, feature))
                .collect::<Vec<_>>()
        })
        .collect::<Vec<_>>();
    let mut hidden_bias = vec![0.0; hidden_count];
    let mut output_weights = (0..hidden_count)
        .map(|hidden| deterministic_weight(seed.wrapping_add(17), hidden, 0))
        .collect::<Vec<_>>();
    let mut output_bias = 0.0;
    let epochs = info.epochs.unwrap_or(240).max(1);
    let learning_rate = 0.03;
    let checkpoint = (epochs / 5).max(1);
    let mut loss_history = Vec::new();

    for epoch in 0..epochs {
        for row in train_rows {
            let features = standardized_features(row, &standardization);
            let hidden = mlp_hidden(&features, &hidden_weights, &hidden_bias);
            let predicted = output_bias + dot(&output_weights, &hidden);
            let expected = (row.target - target_mean) / target_scale;
            let error = predicted - expected;
            let previous_output_weights = output_weights.clone();
            output_bias -= learning_rate * error;
            for hidden_index in 0..hidden_count {
                output_weights[hidden_index] -= learning_rate * error * hidden[hidden_index];
            }
            for hidden_index in 0..hidden_count {
                let hidden_delta = error
                    * previous_output_weights[hidden_index]
                    * (1.0 - hidden[hidden_index] * hidden[hidden_index]);
                hidden_bias[hidden_index] -= learning_rate * hidden_delta;
                for feature_index in 0..feature_count {
                    hidden_weights[hidden_index][feature_index] -=
                        learning_rate * hidden_delta * features[feature_index];
                }
            }
        }
        if epoch == 0 || (epoch + 1) % checkpoint == 0 || epoch + 1 == epochs {
            loss_history.push(mlp_rmse(
                train_rows,
                &standardization,
                &hidden_weights,
                &hidden_bias,
                &output_weights,
                output_bias,
            ));
        }
    }

    let predicted = test_rows
        .iter()
        .map(|row| {
            let features = standardized_features(row, &standardization);
            let normalized = output_bias
                + dot(
                    &output_weights,
                    &mlp_hidden(&features, &hidden_weights, &hidden_bias),
                );
            target_mean + normalized * target_scale
        })
        .collect::<Vec<_>>();
    let actual = test_rows.iter().map(|row| row.target).collect::<Vec<_>>();
    let (rmse, mae, r2) = regression_metrics(&actual, &predicted);
    let coefficients = (0..feature_count)
        .map(|feature_index| RuntimeMlCoefficient {
            feature: dataset.feature_names[feature_index].clone(),
            value: output_weights
                .iter()
                .enumerate()
                .map(|(hidden_index, output_weight)| {
                    hidden_weights[hidden_index][feature_index] * output_weight * target_scale
                        / standardization.scales[feature_index]
                })
                .sum::<f64>(),
        })
        .collect::<Vec<_>>();
    let intercept = target_mean + output_bias * target_scale;

    MlTrainingResult {
        status: "trained_mlp".to_owned(),
        actual,
        predicted,
        coefficients,
        intercept,
        loss_history,
        rmse,
        mae,
        r2,
    }
}

fn split_ml_rows(
    dataset: &MlDataset,
    train_count: usize,
    test_count: usize,
) -> (&[MlRow], &[MlRow]) {
    let train_end = train_count.min(dataset.rows.len().saturating_sub(1));
    let test_end = train_end.saturating_add(test_count).min(dataset.rows.len());
    let train_rows = &dataset.rows[..train_end.max(1)];
    let test_rows = if test_end > train_end {
        &dataset.rows[train_end..test_end]
    } else {
        train_rows
    };
    (train_rows, test_rows)
}

fn standardization(rows: &[MlRow], feature_count: usize) -> Standardization {
    let mut means = vec![0.0; feature_count];
    for row in rows {
        for (index, value) in row.features.iter().enumerate() {
            means[index] += value;
        }
    }
    let row_count = rows.len().max(1) as f64;
    for mean in &mut means {
        *mean /= row_count;
    }
    let mut scales = vec![0.0; feature_count];
    for row in rows {
        for (index, value) in row.features.iter().enumerate() {
            let delta = value - means[index];
            scales[index] += delta * delta;
        }
    }
    for scale in &mut scales {
        *scale = (*scale / row_count).sqrt();
        if *scale <= f64::EPSILON {
            *scale = 1.0;
        }
    }
    Standardization { means, scales }
}

fn standardized_features(row: &MlRow, standardization: &Standardization) -> Vec<f64> {
    row.features
        .iter()
        .enumerate()
        .map(|(index, value)| {
            (value - standardization.means[index]) / standardization.scales[index]
        })
        .collect()
}

fn mean_target(rows: &[MlRow]) -> f64 {
    rows.iter().map(|row| row.target).sum::<f64>() / rows.len().max(1) as f64
}

fn target_mean_scale(rows: &[MlRow]) -> (f64, f64) {
    let mean = mean_target(rows);
    let variance = rows
        .iter()
        .map(|row| {
            let delta = row.target - mean;
            delta * delta
        })
        .sum::<f64>()
        / rows.len().max(1) as f64;
    let scale = variance.sqrt();
    (mean, if scale <= f64::EPSILON { 1.0 } else { scale })
}

fn dot(left: &[f64], right: &[f64]) -> f64 {
    left.iter()
        .zip(right)
        .map(|(left, right)| left * right)
        .sum()
}

fn linear_rmse(
    rows: &[MlRow],
    standardization: &Standardization,
    coefficients: &[f64],
    intercept: f64,
) -> f64 {
    let actual = rows.iter().map(|row| row.target).collect::<Vec<_>>();
    let predicted = rows
        .iter()
        .map(|row| intercept + dot(coefficients, &standardized_features(row, standardization)))
        .collect::<Vec<_>>();
    regression_metrics(&actual, &predicted).0
}

fn mlp_hidden(features: &[f64], weights: &[Vec<f64>], bias: &[f64]) -> Vec<f64> {
    weights
        .iter()
        .enumerate()
        .map(|(index, row)| (bias[index] + dot(row, features)).tanh())
        .collect()
}

fn mlp_rmse(
    rows: &[MlRow],
    standardization: &Standardization,
    hidden_weights: &[Vec<f64>],
    hidden_bias: &[f64],
    output_weights: &[f64],
    output_bias: f64,
) -> f64 {
    if rows.is_empty() {
        return 0.0;
    }
    let actual = rows
        .iter()
        .map(|row| {
            let (mean, scale) = target_mean_scale(rows);
            (row.target - mean) / scale
        })
        .collect::<Vec<_>>();
    let predicted = rows
        .iter()
        .map(|row| {
            let features = standardized_features(row, standardization);
            output_bias
                + dot(
                    output_weights,
                    &mlp_hidden(&features, hidden_weights, hidden_bias),
                )
        })
        .collect::<Vec<_>>();
    regression_metrics(&actual, &predicted).0
}

fn deterministic_weight(seed: u64, row: usize, column: usize) -> f64 {
    let mut value = seed
        .wrapping_add((row as u64 + 1).wrapping_mul(1_103_515_245))
        .wrapping_add((column as u64 + 1).wrapping_mul(12_345));
    value ^= value >> 13;
    value = value.wrapping_mul(0xff51afd7ed558ccd);
    let unit = (value % 10_000) as f64 / 10_000.0;
    (unit - 0.5) * 0.4
}

fn regression_metrics(actual: &[f64], predicted: &[f64]) -> (f64, f64, f64) {
    if actual.is_empty() || predicted.is_empty() {
        return (0.0, 0.0, 0.0);
    }
    let count = actual.len().min(predicted.len());
    let actual = &actual[..count];
    let predicted = &predicted[..count];
    let mean_actual = actual.iter().sum::<f64>() / count as f64;
    let mut squared_error = 0.0;
    let mut absolute_error = 0.0;
    let mut total_sum_squares = 0.0;
    for (actual, predicted) in actual.iter().zip(predicted) {
        let error = actual - predicted;
        squared_error += error * error;
        absolute_error += error.abs();
        let centered = actual - mean_actual;
        total_sum_squares += centered * centered;
    }
    let rmse = (squared_error / count as f64).sqrt();
    let mae = absolute_error / count as f64;
    let r2 = if total_sum_squares <= f64::EPSILON {
        1.0
    } else {
        1.0 - squared_error / total_sum_squares
    };
    (rmse, mae, r2)
}

fn model_card_text(
    info: &eng_compiler::MlInfo,
    artifact: &RuntimeMlArtifact,
    dataset: &MlDataset,
) -> String {
    let coefficient_summary = artifact
        .coefficients
        .iter()
        .take(4)
        .map(|coefficient| {
            format!(
                "{}={}",
                coefficient.feature,
                format_number(coefficient.value)
            )
        })
        .collect::<Vec<_>>()
        .join(", ");
    let loss_summary = match (artifact.loss_history.first(), artifact.loss_history.last()) {
        (Some(first), Some(last)) => {
            format!("loss {} -> {}", format_number(*first), format_number(*last))
        }
        _ => "loss unavailable".to_owned(),
    };
    format!(
        "{} {}: target={}, target_quantity={}, target_unit={}, features=[{}], rows={}, train={}, test={}, rmse={} {}, mae={} {}, r2={}, {}, coefficients=[{}], training_data_hash={}, model_artifact_hash={}",
        info.binding,
        info.algorithm.as_deref().unwrap_or(info.kind.as_str()),
        dataset.target_name,
        dataset.target_quantity,
        dataset.display_unit,
        dataset.feature_names.join(", "),
        dataset.rows.len(),
        artifact.train_count.unwrap_or(0),
        artifact.test_count.unwrap_or(0),
        format_number(artifact.rmse.unwrap_or(0.0)),
        dataset.display_unit,
        format_number(artifact.mae.unwrap_or(0.0)),
        dataset.display_unit,
        format_number(artifact.r2.unwrap_or(0.0)),
        loss_summary,
        coefficient_summary,
        artifact.training_data_hash.as_deref().unwrap_or("not_available"),
        artifact.model_artifact_hash.as_deref().unwrap_or("not_available")
    )
}

fn canonical_unit_for_quantity(quantity_kind: &str) -> Option<String> {
    all_quantity_completions()
        .iter()
        .find(|completion| completion.quantity_kind == quantity_kind)
        .map(|completion| completion.canonical_unit.to_owned())
}

fn convert_to_canonical_unit(
    value: f64,
    source_unit: Option<&str>,
    target_unit: &str,
    quantity_kind: &str,
) -> Result<f64, String> {
    let source_unit = source_unit
        .map(str::trim)
        .filter(|unit| !unit.is_empty())
        .unwrap_or(target_unit);

    let normalized_source_unit = normalize_unit(source_unit);
    let normalized_target_unit = normalize_unit(target_unit);

    if normalized_source_unit == normalized_target_unit {
        return Ok(value);
    }

    let Some(info) = all_unit_infos()
        .iter()
        .find(|info| normalize_unit(info.symbol) == normalized_source_unit)
    else {
        return Err(format!(
            "unsupported source unit `{source_unit}` for {quantity_kind}"
        ));
    };

    if normalize_unit(info.canonical_unit) != normalized_target_unit
        || !unit_seed_matches_quantity(info.quantity_hint, quantity_kind)
    {
        return Err(format!(
            "cannot convert `{source_unit}` to canonical `{target_unit}` for {quantity_kind}"
        ));
    }

    let scale = info.scale_to_canonical.parse::<f64>().map_err(|_| {
        format!(
            "invalid conversion scale `{}` for unit `{source_unit}`",
            info.scale_to_canonical
        )
    })?;
    let offset = info
        .affine_offset
        .map(|offset| {
            offset
                .parse::<f64>()
                .map_err(|_| format!("invalid affine offset `{offset}` for unit `{source_unit}`"))
        })
        .transpose()?
        .unwrap_or(0.0);

    Ok(value * scale + offset)
}

fn convert_from_canonical_unit(
    value: f64,
    canonical_unit: &str,
    display_unit: &str,
    quantity_kind: &str,
) -> f64 {
    let normalized_canonical_unit = normalize_unit(canonical_unit);
    let normalized_display_unit = normalize_unit(display_unit);
    if normalized_canonical_unit == normalized_display_unit {
        return value;
    }

    match (
        normalized_canonical_unit.as_str(),
        normalized_display_unit.as_str(),
        quantity_kind,
    ) {
        ("k", "degc", "AbsoluteTemperature") => value - 273.15,
        ("w", "kw", "HeatRate" | "ElectricPower" | "MechanicalPower") => value / 1000.0,
        ("pa", "kpa", "Pressure") => value / 1000.0,
        ("j/k", "kj/k", "HeatCapacity") => value / 1000.0,
        _ => value,
    }
}

fn unit_seed_matches_quantity(seed_quantity: &str, quantity_kind: &str) -> bool {
    seed_quantity == quantity_kind
        || seed_quantity == "Power"
            && matches!(
                quantity_kind,
                "HeatRate" | "ElectricPower" | "MechanicalPower"
            )
        || seed_quantity == "TemperatureDelta" && quantity_kind == "AbsoluteTemperature"
}

fn is_numeric_schema_type(type_name: &str) -> bool {
    !matches!(type_name, "DateTime" | "String")
}

fn time_series_quantity(quantity_kind: &str) -> Option<(String, String)> {
    let rest = quantity_kind.strip_prefix("TimeSeries[")?;
    let (axis, after_axis) = rest.split_once(']')?;
    let quantity = after_axis.trim().strip_prefix("of ")?;
    Some((axis.trim().to_owned(), quantity.trim().to_owned()))
}

fn parse_csv(source: &str) -> Vec<Vec<String>> {
    source
        .lines()
        .filter(|line| !line.trim().is_empty())
        .map(parse_csv_line)
        .collect()
}

fn parse_csv_line(line: &str) -> Vec<String> {
    let mut fields = Vec::new();
    let mut field = String::new();
    let mut in_quotes = false;
    let mut chars = line.chars().peekable();
    while let Some(character) = chars.next() {
        match character {
            '"' if in_quotes && chars.peek() == Some(&'"') => {
                field.push('"');
                chars.next();
            }
            '"' => in_quotes = !in_quotes,
            ',' if !in_quotes => {
                fields.push(field.trim().to_owned());
                field.clear();
            }
            _ => field.push(character),
        }
    }
    fields.push(field.trim().to_owned());
    fields
}

fn parse_utc_timestamp_seconds(value: &str) -> Option<i64> {
    let (date, time_with_zone) = value.trim().split_once('T')?;
    let mut date_parts = date.split('-');
    let year = date_parts.next()?.parse::<i32>().ok()?;
    let month = date_parts.next()?.parse::<u32>().ok()?;
    let day = date_parts.next()?.parse::<u32>().ok()?;
    if date_parts.next().is_some() {
        return None;
    }
    let (time, offset_seconds) = split_time_and_utc_offset(time_with_zone)?;
    let mut time_parts = time.split(':');
    let hour = time_parts.next()?.parse::<u32>().ok()?;
    let minute = time_parts.next()?.parse::<u32>().ok()?;
    let second = time_parts.next()?.parse::<u32>().ok()?;
    if time_parts.next().is_some()
        || !(1..=12).contains(&month)
        || !(1..=31).contains(&day)
        || hour > 23
        || minute > 59
        || second > 59
    {
        return None;
    }
    let local_seconds =
        days_from_civil(year, month, day) * 86_400 + i64::from(hour * 3600 + minute * 60 + second);
    Some(local_seconds - offset_seconds)
}

fn first_timestamp_utc_offset_seconds(column: &RuntimeColumn) -> Option<i64> {
    let RuntimeValues::Text(values) = &column.values else {
        return None;
    };
    values
        .iter()
        .find_map(|value| timestamp_utc_offset_seconds(value.trim()))
}

fn timestamp_utc_offset_seconds(value: &str) -> Option<i64> {
    let (_date, time_with_zone) = value.split_once('T')?;
    let (_time, offset_seconds) = split_time_and_utc_offset(time_with_zone)?;
    Some(offset_seconds)
}

fn seconds_from_civil(year: i32, month: u32, day: u32, hour: u32, minute: u32, second: u32) -> i64 {
    days_from_civil(year, month, day) * 86_400 + i64::from(hour * 3600 + minute * 60 + second)
}

fn split_time_and_utc_offset(value: &str) -> Option<(&str, i64)> {
    if let Some(time) = value.strip_suffix('Z') {
        return Some((time, 0));
    }
    let (offset_index, sign) = value
        .char_indices()
        .rev()
        .find(|(_, character)| *character == '+' || *character == '-')?;
    let time = &value[..offset_index];
    let offset = &value[offset_index + 1..];
    let mut parts = offset.split(':');
    let hours = parts.next()?.parse::<i64>().ok()?;
    let minutes = parts.next()?.parse::<i64>().ok()?;
    if parts.next().is_some() || hours > 23 || minutes > 59 {
        return None;
    }
    let seconds = hours * 3600 + minutes * 60;
    let signed_seconds = if sign == '-' { -seconds } else { seconds };
    Some((time, signed_seconds))
}

fn days_from_civil(year: i32, month: u32, day: u32) -> i64 {
    let year = year - i32::from(month <= 2);
    let era = if year >= 0 { year } else { year - 399 } / 400;
    let year_of_era = (year - era * 400) as u32;
    let month = month as i32;
    let day_of_year =
        ((153 * (month + if month > 2 { -3 } else { 9 }) + 2) / 5 + day as i32 - 1) as u32;
    let day_of_era = year_of_era * 365 + year_of_era / 4 - year_of_era / 100 + day_of_year;
    i64::from(era) * 146_097 + i64::from(day_of_era) - 719_468
}

