    #[test]
    fn state_space_runtime_materializes_scalar_output_series() {
        let source = r#"
system OutputAlgebraicStateSpace {
    parameter base_load: HeatRate [kW] = 1 kW
    state T_air: AbsoluteTemperature = 20 degC
    state T_wall: AbsoluteTemperature = 20 degC
    input Q_hvac: HeatRate = 1000 W
    output Q_total: HeatRate [kW]

    states x = [T_air, T_wall]
    inputs u = [Q_hvac]
    outputs y = [T_air, Q_total]

    A: LinearOperator[StateVector -> Derivative[StateVector]] = [[1.0, 0.0]; [0.0, 1.0]]
    B: LinearOperator[InputVector -> Derivative[StateVector]] = [[0.001]; [0.002]]

    equation {
        next(x) eq A * x + B * u
        Q_total eq Q_hvac + base_load
    }
}

sim = simulate OutputAlgebraicStateSpace
with {
    timestep = 10 min
    duration = 20 min
    solver = fixed_step
}
"#;
        let report = check_source("state_space_output.eng", source, &CheckOptions::default());
        assert!(!report.has_errors(), "{:?}", report.diagnostics);
        let runtime = materialize_runtime_data(&report, source);

        let sim_solutions = runtime
            .system_solutions
            .iter()
            .filter(|solution| solution.binding.as_deref() == Some("sim"))
            .collect::<Vec<_>>();
        assert_eq!(sim_solutions.len(), 2);
        assert!(sim_solutions.iter().all(|solution| {
            solution.outputs == vec!["T_air".to_owned(), "Q_total".to_owned()]
                && solution.parameters == vec!["base_load".to_owned()]
        }));
        assert!(sim_solutions
            .iter()
            .any(|solution| solution.state == "T_air"));
        let load = sim_solutions
            .iter()
            .find(|solution| solution.state == "Q_total")
            .unwrap();
        assert_eq!(load.quantity_kind, "HeatRate");
        assert_eq!(load.display_unit, "kW");
        assert_eq!(load.points.len(), 3);
        assert!(load.points.iter().all(|point| (point.y - 2.0).abs() < 1e-9));
        assert!(load
            .source_equations
            .iter()
            .any(|equation| equation.kind == "state_space_update"
                && equation.target == "T_air"
                && equation
                    .residual_expression
                    .contains("A[T_air,T_air] * T_air")));
        assert!(load
            .source_equations
            .iter()
            .any(|equation| equation.kind == "algebraic_output"
                && equation.target == "Q_total"
                && equation.residual_expression == "Q_total - (Q_hvac + base_load)"));
        let load_series = runtime
            .time_series
            .iter()
            .find(|series| series.name == "sim.Q_total")
            .unwrap();
        assert_eq!(load_series.quantity_kind, "HeatRate");
        assert_eq!(load_series.display_unit, "kW");
        assert_eq!(load_series.points.len(), 3);
    }

    #[test]
    fn failed_state_space_output_dependency_retains_source_equations() {
        let source = r#"
system StateSpaceOutputLoop {
    state x: DimensionlessNumber = 1
    input u: DimensionlessNumber = 0
    output a: DimensionlessNumber [1]
    output b: DimensionlessNumber [1]

    states sx = [x]
    inputs su = [u]
    outputs y = [x, a, b]

    A: LinearOperator[StateVector -> Derivative[StateVector]] = [[0 1/s]]
    B: LinearOperator[InputVector -> Derivative[StateVector]] = [[0 1/s]]

    equation {
        der(sx) eq A * sx + B * su
        a eq b + 1
        b eq a + 1
    }
}

sim = simulate StateSpaceOutputLoop
with {
    timestep = 1 s
    duration = 1 s
    solver = rk4
}
"#;
        let report = check_source(
            "state_space_output_loop.eng",
            source,
            &CheckOptions::default(),
        );
        assert!(!report.has_errors(), "{:?}", report.diagnostics);
        let runtime = materialize_runtime_data(&report, source);

        let sim_solutions = runtime
            .system_solutions
            .iter()
            .filter(|solution| solution.binding.as_deref() == Some("sim"))
            .collect::<Vec<_>>();
        assert_eq!(sim_solutions.len(), 1);
        let solution = sim_solutions[0];
        assert_eq!(solution.status, "failed");
        assert_eq!(
            solution.failure_code.as_deref(),
            Some("E-RHS-OUTPUT-ALGEBRAIC-LOOP")
        );
        assert!(solution.source_equations.iter().any(|equation| {
            equation.kind == "state_space_derivative"
                && equation.target == "x"
                && equation.left == "der(x)"
                && equation.source_line.is_some()
        }));
        assert_eq!(
            solution.to_report_solution().source_equations.len(),
            solution.source_equations.len()
        );
    }

