    #[test]
    fn materializes_derived_table_columns_for_table_regression() {
        let source = r#"
training_designs = sample lhs
with {
    count = 4
    seed = 5
    cooling_cop = uniform(2.5, 5.0)
    envelope_load_index = uniform(0.85, 1.20)
}

energy_results = derive training_designs column annual_electricity = 10200 kWh + envelope_load_index * 2600 kWh - cooling_cop * 750 kWh
peak_cooling_results = derive energy_results column peak_cooling = 7 kW + envelope_load_index * 7 kW - cooling_cop * 0.6 kW
training_results = derive peak_cooling_results column unmet_hours = 3 h - cooling_cop * 0.2 h
surrogate_model = train regression training_results
with {
    target = annual_electricity
    features = [cooling_cop, envelope_load_index]
    test = 0.25
    seed = 7
}
"#;
        let report = check_source("derived_regression.eng", source, &CheckOptions::default());
        assert!(!report.has_errors(), "{:?}", report.diagnostics);

        let runtime = materialize_runtime_data(&report, source);
        let table = runtime
            .tables
            .iter()
            .find(|table| table.binding == "training_results")
            .unwrap();
        assert_eq!(table.schema_name, "DerivedTable");
        assert_eq!(table.row_count, 4);

        let cop = table
            .columns
            .iter()
            .find(|column| column.name == "cooling_cop")
            .unwrap();
        let envelope = table
            .columns
            .iter()
            .find(|column| column.name == "envelope_load_index")
            .unwrap();
        let annual = table
            .columns
            .iter()
            .find(|column| column.name == "annual_electricity")
            .unwrap();
        let peak = table
            .columns
            .iter()
            .find(|column| column.name == "peak_cooling")
            .unwrap();
        assert_eq!(annual.type_name, "Energy");
        assert_eq!(annual.unit.as_deref(), Some("kWh"));
        assert_eq!(peak.type_name, "Power");
        assert_eq!(peak.unit.as_deref(), Some("kW"));

        let expected_annual = 10200.0 + numeric_column_value(envelope, 0).unwrap() * 2600.0
            - numeric_column_value(cop, 0).unwrap() * 750.0;
        assert_eq!(
            round2(numeric_column_value(annual, 0).unwrap()),
            round2(expected_annual)
        );

        let regression = runtime
            .ml_artifacts
            .iter()
            .find(|artifact| artifact.binding == "surrogate_model")
            .unwrap();
        assert_eq!(regression.status, "trained_linear");
        assert_eq!(regression.target_quantity.as_deref(), Some("Energy"));
        assert_eq!(regression.display_unit, "kWh");
        assert_eq!(regression.train_count, Some(3));
        assert!(regression.training_data_hash.is_some());
        assert!(runtime
            .sample_tables
            .iter()
            .any(|sample| sample.binding == "training_designs"));
        assert!(!runtime
            .sample_tables
            .iter()
            .any(|sample| sample.binding == "training_results"));
    }

    #[test]
    fn materializes_ml_metrics_and_parity_plot() {
        let source_path = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../..")
            .join("examples/internal/05_data_driven_modeling/main.eng");
        let source = std::fs::read_to_string(&source_path).unwrap();
        let report = check_file(&source_path, &CheckOptions::default()).unwrap();
        let runtime = materialize_runtime_data(&report, &source);
        let mut plot_spec = eng_report::plot_spec_from_report(&report);
        runtime.apply_plot_spec(&report, &mut plot_spec);

        let regression = runtime
            .ml_artifacts
            .iter()
            .find(|artifact| artifact.kind == "RegressionModel")
            .unwrap();
        let mlp = runtime
            .ml_artifacts
            .iter()
            .find(|artifact| artifact.kind == "MlpModel")
            .unwrap();
        assert_eq!(regression.status, "trained_linear");
        assert_eq!(mlp.status, "trained_mlp");
        assert_eq!(regression.coefficients.len(), 3);
        assert_eq!(mlp.coefficients.len(), 3);
        assert!(regression.intercept.is_some());
        assert!(mlp.intercept.is_some());
        assert!(regression.loss_history.len() >= 2);
        assert!(!mlp.loss_history.is_empty());
        assert!(mlp
            .loss_history
            .iter()
            .all(|loss| loss.is_finite() && *loss >= 0.0));
        assert!(regression.rmse.unwrap() > 0.0);
        assert!(mlp.rmse.unwrap() > 0.0);
        assert_eq!(regression.target_quantity.as_deref(), Some("HeatRate"));
        assert_eq!(regression.display_unit, "W");
        assert_eq!(regression.training_data_hash.as_deref().unwrap().len(), 16);
        assert_eq!(regression.model_artifact_hash.as_deref().unwrap().len(), 16);
        let regression_card = regression.model_card.as_deref().unwrap();
        assert!(regression_card.contains("coefficients=["));
        assert!(regression_card.contains("training_data_hash="));
        assert!(regression_card.contains("model_artifact_hash="));
        assert!(!regression_card.contains("not_available"));
        let card = runtime
            .ml_artifacts
            .iter()
            .find(|artifact| artifact.kind == "ModelCard")
            .unwrap();
        assert_eq!(card.target, regression.target);
        assert_eq!(card.target_quantity, regression.target_quantity);
        assert_eq!(card.model_artifact_hash, regression.model_artifact_hash);
        assert!(runtime
            .ml_artifacts
            .iter()
            .any(|artifact| artifact.leakage_status.as_deref() == Some("passed")));
        assert_eq!(plot_spec.plot_type, "scatter");
        assert_eq!(plot_spec.title, "Regression parity");
        assert!(!plot_spec.series[0].points.is_empty());

        let residual_source_path = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../..")
            .join("examples/internal/05_data_driven_modeling/residuals.eng");
        let residual_source = std::fs::read_to_string(&residual_source_path).unwrap();
        let residual_report = check_file(&residual_source_path, &CheckOptions::default()).unwrap();
        let residual_runtime = materialize_runtime_data(&residual_report, &residual_source);
        let mut residual_plot_spec = eng_report::plot_spec_from_report(&residual_report);
        residual_runtime.apply_plot_spec(&residual_report, &mut residual_plot_spec);

        assert_eq!(residual_plot_spec.plot_type, "bar");
        assert_eq!(residual_plot_spec.title, "Regression residuals");
        assert_eq!(residual_plot_spec.y_axis.name, "Residual");
        assert!(!residual_plot_spec.series[0].points.is_empty());
    }

