    #[test]
    fn materializes_explicit_timeseries_coverage_with_year_policy() {
        let repo_root = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../..")
            .canonicalize()
            .expect("repo root");
        let source_dir = repo_root
            .join("build")
            .join("runtime-data-timeseries-coverage");
        let _ = std::fs::remove_dir_all(&source_dir);
        std::fs::create_dir_all(source_dir.join("data")).expect("source data dir");
        std::fs::write(
            source_dir.join("data").join("weather.csv"),
            concat!(
                "time,dry_bulb\n",
                "2024-01-01T00:00:00+09:00,-2.1\n",
                "2024-01-01T01:00:00+09:00,-2.4\n",
            ),
        )
        .expect("weather csv");
        let source_path = source_dir.join("main.eng");
        let source = concat!(
            "schema WeatherHourly {\n",
            "    time: DateTime index\n",
            "    dry_bulb: AbsoluteTemperature [degC]\n",
            "}\n\n",
            "args {\n",
            "    year: Int = 2024\n",
            "    weather_file: CsvFile = file(\"data/weather.csv\")\n",
            "}\n\n",
            "weather = promote csv args.weather_file as WeatherHourly\n",
            "coverage = check coverage weather.time\n",
            "with {\n",
            "    expected_step = 1 h\n",
            "    year = args.year\n",
            "}\n",
        );
        let report = check_source(&source_path, source, &CheckOptions::default());
        assert!(!report.has_errors(), "{:?}", report.diagnostics);

        let runtime = materialize_runtime_data(&report, source);
        let coverage = runtime
            .timeseries_coverage
            .iter()
            .find(|coverage| coverage.binding == "coverage")
            .expect("explicit coverage");

        assert_eq!(coverage.source_table, "weather");
        assert_eq!(coverage.source_column, "time");
        assert_eq!(coverage.expected_step, Some(3600.0));
        assert_eq!(coverage.expected_count, Some(8784));
        assert_eq!(coverage.actual_count, 2);
        assert_eq!(coverage.missing_count, 8782);
        assert_eq!(coverage.missing_intervals.len(), 1);
        assert_eq!(coverage.missing_intervals[0].missing_count, 8782);
        assert_eq!(coverage.max_gap, Some(3600.0));
        assert_eq!(coverage.coverage_year, Some(2024));
        assert_eq!(coverage.leap_year_policy, "gregorian_year");
        assert_eq!(coverage.status, "gapped");
    }

    #[test]
    fn materializes_timeseries_fill_missing_command() {
        let repo_root = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../..")
            .canonicalize()
            .expect("repo root");
        let source_dir = repo_root.join("build").join("runtime-data-timeseries-fill");
        let _ = std::fs::remove_dir_all(&source_dir);
        std::fs::create_dir_all(source_dir.join("data")).expect("source data dir");
        std::fs::write(
            source_dir.join("data").join("weather.csv"),
            concat!(
                "time,wind_speed\n",
                "2024-01-01T00:00:00Z,1.0\n",
                "2024-01-01T01:00:00Z,2.0\n",
                "2024-01-01T03:00:00Z,4.0\n",
            ),
        )
        .expect("weather csv");
        let source_path = source_dir.join("main.eng");
        let source = concat!(
            "schema WeatherHourly {\n",
            "    time: DateTime index\n",
            "    wind_speed: DimensionlessNumber [1]\n",
            "}\n\n",
            "args {\n",
            "    weather_file: CsvFile = file(\"data/weather.csv\")\n",
            "}\n\n",
            "weather = promote csv args.weather_file as WeatherHourly\n",
            "filled = fill missing weather.wind_speed\n",
            "with {\n",
            "    method = interpolate\n",
            "    expected_step = 1 h\n",
            "    max_gap = 3 h\n",
            "}\n",
        );
        let report = check_source(&source_path, source, &CheckOptions::default());
        assert!(!report.has_errors(), "{:?}", report.diagnostics);

        let runtime = materialize_runtime_data(&report, source);
        let fill = runtime
            .timeseries_fill
            .iter()
            .find(|fill| fill.binding == "filled")
            .expect("timeseries fill");

        assert_eq!(fill.source_table, "weather");
        assert_eq!(fill.source_column, "wind_speed");
        assert_eq!(fill.time_column, "time");
        assert_eq!(fill.method, "interpolate");
        assert_eq!(fill.expected_step, Some(3600.0));
        assert_eq!(fill.max_gap, Some(10800.0));
        assert_eq!(fill.missing_count, 1);
        assert_eq!(fill.fillable_count, 1);
        assert_eq!(fill.filled_count, 1);
        assert_eq!(fill.skipped_count, 0);
        assert!(!fill.fallback_required);
        assert_eq!(fill.status, "applied");

        let quality = runtime
            .timeseries_quality
            .iter()
            .find(|quality| quality.binding == "filled")
            .expect("timeseries quality summary");
        assert_eq!(
            quality.coverage_binding.as_deref(),
            Some("weather.Time.coverage")
        );
        assert_eq!(quality.fill_binding.as_deref(), Some("filled"));
        assert_eq!(quality.missing_count, 1);
        assert_eq!(quality.filled_count, 1);
        assert_eq!(quality.remaining_missing_count, 0);
        assert_eq!(quality.quality_score, Some(1.0));
        assert_eq!(quality.status, "passed");

        let quality_result = runtime
            .quality_results
            .iter()
            .find(|result| result.binding == "filled.quality_result")
            .expect("quality result");
        assert_eq!(quality_result.kind, "timeseries_quality_result");
        assert_eq!(quality_result.target, "filled");
        assert_eq!(quality_result.subject, "weather.wind_speed");
        assert_eq!(quality_result.score, Some(1.0));
        assert_eq!(quality_result.passed_count, 1);
        assert_eq!(quality_result.status, "passed");

        let filled_series = runtime
            .time_series
            .iter()
            .find(|series| series.name == "filled")
            .expect("filled series");
        assert_eq!(filled_series.points.len(), 4);
        assert_eq!(filled_series.points[2].x, 7200.0);
        assert_eq!(filled_series.points[2].y, 3.0);
    }

